  ('65f118c8-28e1-5f08-b17e-6a047540e1ca', 'd8d6ec9f-7a57-57d2-993b-75e3e48d7235', 'ما ناتجُ تفكيك العدد 30 إلى جُداء عوامل أوّليّة؟', '[{"id":"a","text":"2 × 15"},{"id":"b","text":"3 × 10"},{"id":"c","text":"5 × 6"},{"id":"d","text":"2 × 3 × 5"}]'::jsonb, 'd', '30 = 2 × 15 = 2 × 3 × 5 ✓. الأعدادُ 15 و10 و6 ليست أوّليّة، فيجب متابعةُ التفكيك حتى نصل إلى عواملَ أوّليّةٍ فقط.', 1, 'mcq', NULL, NULL)
