INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('cc987f8b-c64e-5f3c-8aee-7964849e2763', 'd8d6ec9f-7a57-57d2-993b-75e3e48d7235', 'بما أنّ 36 = 2² × 3² و48 = 2⁴ × 3، ما م.م.ق(36 ; 48)؟', '[{"id":"a","text":"6"},{"id":"b","text":"12"},{"id":"c","text":"24"},{"id":"d","text":"144"}]'::jsonb, 'b', 'العوامل المشتركة بأصغر أُسّ: 2^min(2,4) = 2² و3^min(2,1) = 3¹، فم.م.ق(36 ; 48) = 2² × 3 = 12 ✓. الخطأُ الشائع: حساب 144 وهو في الحقيقة م.م.أ(36 ; 48) (بأخذ أكبر أُسّ لا أصغره).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
