  ('b366ce35-0bb3-58d1-9d1d-f55ee4e78456', 'd8d6ec9f-7a57-57d2-993b-75e3e48d7235', 'ما م.م.أ(15 ; 20)؟', '[{"id":"a","text":"5"},{"id":"b","text":"35"},{"id":"c","text":"60"},{"id":"d","text":"300"}]'::jsonb, 'c', '15 = 3 × 5 و20 = 2² × 5، فم.م.أ(15 ; 20) = 2² × 3 × 5 = 60 ✓. الخطأُ الشائع: 5 هو م.م.ق(15 ; 20) لا م.م.أ؛ و300 = 15 × 20 ناتجٌ عن نسيان القسمة على م.م.ق؛ و35 = 15 + 20 خطأُ جمعٍ بدل الحساب الصحيح.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
