  ('d2c66956-7f3c-5667-945f-b66e3bcd54eb', 'd8d6ec9f-7a57-57d2-993b-75e3e48d7235', 'عددٌ تفكيكُه إلى عوامل أوّليّة هو 2² × 3 × 7. ما هو هذا العدد؟', '[{"id":"a","text":"42"},{"id":"b","text":"63"},{"id":"c","text":"84"},{"id":"d","text":"168"}]'::jsonb, 'c', '2² × 3 × 7 = 4 × 3 × 7 = 84 ✓. الخطأُ الشائع: 42 = 2 × 3 × 7 (نسيانُ تربيع العامل 2)؛ و168 = 2³ × 3 × 7 (زيادةُ عاملِ 2)؛ و63 = 3² × 7 (تربيعُ العامل الخطأ).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
