  ('00b981ea-c4a9-53f9-b671-b89b80fc9f3a', 'a2c0673b-9377-556c-a813-36a5419651ea', 'أيُّ عددٍ من التالية يقبل القسمة على 6؟', '[{"id":"a","text":"522"},{"id":"b","text":"524"},{"id":"c","text":"526"},{"id":"d","text":"532"}]'::jsonb, 'a', '522 عددٌ زوجيّ (يقبل القسمة على 2)، ومجموعُ أرقامه 5 + 2 + 2 = 9 يقبل القسمة على 3، فهو يقبل القسمة على 2 و3 معًا، أي على 6 ✓. الأعدادُ 524 و526 و532 زوجيّة لكنّ مجموعَ أرقامها لا يقبل القسمة على 3.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
