INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ec2103e5-70d3-5fae-a271-6edbf937436c', 'e9a2931c-375b-517b-acb2-68beba9a01a6', 'صاحبُ متجرٍ لديه 84 قلمًا و126 كرّاسة، ويريد توزيعَها على أكياسَ متطابقة، بحيث يحتوي كلُّ كيسٍ نفسَ العدد من الأقلام ونفسَ العدد من الكراسات، دون أن يتبقّى شيء. ما أكبرُ عددٍ من الأكياس يمكنه تحضيرُه؟', '[{"id":"a","text":"21"},{"id":"b","text":"42"},{"id":"c","text":"84"},{"id":"d","text":"126"}]'::jsonb, 'b', 'أكبرُ عددٍ من الأكياس هو م.م.ق(84 ; 126)؛ 84 = 2² × 3 × 7 و126 = 2 × 3² × 7، فم.م.ق = 2 × 3 × 7 = 42 ✓. الخيارات 84 و126 مجرّدُ العددين الأصليَّين، و21 نصفُ الجواب الصحيح.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('46aff8ef-5e54-5647-9954-1c1141c8ecab', 'e9a2931c-375b-517b-acb2-68beba9a01a6', 'يمرّ حافلتان بمحطّةٍ واحدة: الأولى كلَّ 18 دقيقة، والثانية كلَّ 24 دقيقة. انطلقتا معًا في الساعة 8:00. بعد كم دقيقةٍ ستلتقيان في المحطّة معًا مرّةً أخرى؟', '[{"id":"a","text":"6"},{"id":"b","text":"18"},{"id":"c","text":"24"},{"id":"d","text":"72"}]'::jsonb, 'd', 'لحظةُ اللقاء التالية هي م.م.أ(18 ; 24)؛ 18 = 2 × 3² و24 = 2³ × 3، فم.م.أ = 2³ × 3² = 72 ✓. الخيارُ 6 هو م.م.ق(18 ; 24) لا م.م.أ، و18 و24 مجرّدُ زمنَي مرور الحافلتين منفردتَين.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ff6db49c-2e34-574d-88a2-07e0619de9a5', 'e9a2931c-375b-517b-acb2-68beba9a01a6', 'عددٌ تفكيكُه 2 × 3² × 5 (أي 90)، وعددٌ آخر تفكيكُه 2³ × 3 × 5² (أي 600). ما م.م.ق لهذين العددين؟', '[{"id":"a","text":"15"},{"id":"b","text":"30"},{"id":"c","text":"90"},{"id":"d","text":"600"}]'::jsonb, 'b', 'نأخذ كلَّ عاملٍ مشتركٍ بأصغر أُسٍّ ظهر به: 2^min(1,3) = 2 ، 3^min(2,1) = 3 ، 5^min(1,2) = 5، فم.م.ق = 2 × 3 × 5 = 30 ✓. الخيارُ 90 هو العددُ الأوّل نفسه (نسيانُ مقارنته بالثاني)، و600 هو العددُ الثاني نفسه، و15 ناقصٌ عاملَ 2.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('83b81cc7-0f24-531e-964c-80fc7a455f81', 'e9a2931c-375b-517b-acb2-68beba9a01a6', 'أراد أحمد إيجادَ م.م.ق(45 ; 60)، وفكَّك: 45 = 3² × 5 ، 60 = 2² × 3 × 5، فاختار القاسمَ المشتركَ 3² × 5 = 45. أين الخطأ في حلِّه؟', '[{"id":"a","text":"نسي معاملَ العدد 5"},{"id":"b","text":"لم يُدرج العددَ 2 أصلًا وهذا صحيح"},{"id":"c","text":"الحلُّ صحيحٌ تمامًا"},{"id":"d","text":"أخذ العددَ 3 بالأُسّ 2 بدلًا من الأُسّ 1 (لم يأخذ الأصغر)"}]'::jsonb, 'd', 'قاعدةُ م.م.ق تأخذ كلَّ عاملٍ مشتركٍ بأصغر أُسٍّ ظهر به؛ للعامل 3 الأُسّان هما 2 (في 45) و1 (في 60)، فالأصغرُ هو 1 لا 2. الحلُّ الصحيح: 3¹ × 5 = 15. العددُ 2 غيرُ مشتركٍ بين 45 و60 (45 فرديّ) فاستبعادُه صحيح، لكنّ خطأ أحمد هو في العامل 3.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('fc8c2031-82b9-534d-ace5-6c3a52ed6b31', 'e9a2931c-375b-517b-acb2-68beba9a01a6', 'عددٌ صحيحٌ طبيعيٌّ n يقبل القسمةَ على 4 وعلى 9 معًا، وهو محصورٌ بين 100 و140. ما هو العددُ n؟', '[{"id":"a","text":"72"},{"id":"b","text":"108"},{"id":"c","text":"126"},{"id":"d","text":"144"}]'::jsonb, 'b', 'بما أنّ 4 و9 ليس بينهما قاسمٌ مشتركٌ غيرُ 1، فقابليّةُ القسمة على كليهما تعني القابليّة على 4 × 9 = 36. مضاعفاتُ 36 هي 36 ، 72 ، 108 ، 144…؛ الوحيدُ المحصورُ بين 100 و140 هو 108 ✓ (72 أصغرُ من 100، و144 أكبرُ من 140). العددُ 126 يقبل القسمة على 9 لكن ليس على 4 (آخر رقمَين 26 لا يقبلان القسمة على 4).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d896f87d-5305-57eb-979e-9e1ee5c16dad', 'e9a2931c-375b-517b-acb2-68beba9a01a6', 'لدى تلميذةٍ 72 قلمَ رصاص و90 قلمَ حبر، وزّعتهما بالتساوي (نفسُ العدد من كلّ نوعٍ لكلّ تلميذ) على أكبرِ عددٍ ممكنٍ من زملائها دون أن يتبقّى شيء. ثمّ انضمّ إلى الفصل تلاميذُ إضافيّون حتى أصبح عددُ التلاميذ الكليّ يساوي م.م.أ(8 ; 12). كم تلميذًا انضمّ إلى الفصل؟', '[{"id":"a","text":"6"},{"id":"b","text":"18"},{"id":"c","text":"24"},{"id":"d","text":"42"}]'::jsonb, 'a', 'العددُ الأوّليّ للتلاميذ هو م.م.ق(72 ; 90)؛ 72 = 2³ × 3² و90 = 2 × 3² × 5، فم.م.ق = 2 × 3² = 18. العددُ النهائيّ هو م.م.أ(8 ; 12) = 24 (8 = 2³ ، 12 = 2² × 3، فم.م.أ = 2³ × 3 = 24). عددُ المنضمّين = 24 − 18 = 6 ✓. الخطأُ الشائع: نسيانُ خطوة الطرح (24) أو جمعُ العددين بدل طرحهما (42).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

