  ('5e5936c4-de38-534a-b2e8-684cc91222ef', 'a0ea280d-eaee-571e-af16-3bdffe759f32', 'ما قواسمُ العدد 15؟', '[{"id":"a","text":"1 ، 2 ، 3 ، 5 ، 15"},{"id":"b","text":"1 ، 5 ، 15"},{"id":"c","text":"1 ، 3 ، 15"},{"id":"d","text":"1 ، 3 ، 5 ، 15"}]'::jsonb, 'd', 'قواسمُ 15 هي: 1 ، 3 ، 5 ، 15 (العددُ 2 ليس قاسمًا لأنّ 15 فرديّ).', 2, 'mcq', NULL, NULL)
