  ('fad8e1a8-bbee-5db2-a8f7-ba05dcaa23d5', 'a0ea280d-eaee-571e-af16-3bdffe759f32', 'ما ناتجُ تفكيك العدد 45 إلى جُداء عوامل أوّليّة؟', '[{"id":"a","text":"3 × 15"},{"id":"b","text":"3² × 5"},{"id":"c","text":"5 × 9"},{"id":"d","text":"3 × 5²"}]'::jsonb, 'b', '45 = 9 × 5 = 3 × 3 × 5 = 3² × 5 ✓. الأعدادُ 15 و9 ليست أوّليّة، والخيارُ 3 × 5² يقلب الأُسّ على العامل الخطأ (يساوي 75 لا 45).', 3, 'mcq', NULL, NULL)
