  ('255f514c-24af-5ae1-8c9a-5c7fa98ae334', 'a0ea280d-eaee-571e-af16-3bdffe759f32', 'ما المضاعفُ المشتركُ الأصغر للعددين 9 و12؟', '[{"id":"a","text":"3"},{"id":"b","text":"12"},{"id":"c","text":"36"},{"id":"d","text":"108"}]'::jsonb, 'c', '9 = 3² و12 = 2² × 3، فم.م.أ(9 ; 12) = 2² × 3² = 36 ✓. الخطأُ الشائع: 3 هو م.م.ق(9 ; 12) لا م.م.أ؛ و108 = 9 × 12 ناتجٌ عن نسيان القسمة على م.م.ق؛ و12 ناتجٌ عن أخذ الأُسّ 1 فقط للعامل 3 بدل 2.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
