  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f2db975c-811a-5be9-a525-b0c0ff0d36ce', 'a0ea280d-eaee-571e-af16-3bdffe759f32', 'بسِّط الكسر 30/48 إلى أبسط صورة.', '[{"id":"a","text":"5/6"},{"id":"b","text":"5/8"},{"id":"c","text":"10/16"},{"id":"d","text":"15/24"}]'::jsonb, 'b', '30 = 2 × 3 × 5 و48 = 2⁴ × 3، فم.م.ق(30 ; 48) = 2 × 3 = 6؛ 30 ÷ 6 = 5 و48 ÷ 6 = 8، فالكسرُ المبسَّط هو 5/8 ✓. الكسران 15/24 و10/16 غيرُ مبسَّطَين بالكامل، و5/6 ناتجٌ عن خطأ حسابيّ.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
