INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9261ab25-9fa9-5bce-be07-03d8e5d9fa52', '2d240ce1-fa7d-5db8-b8a0-23a854a16fa1', 'ما ناتجُ تفكيك العدد 210 إلى جُداء عوامل أوّليّة؟', '[{"id":"a","text":"2 × 3 × 5"},{"id":"b","text":"2² × 3 × 5 × 7"},{"id":"c","text":"2 × 3 × 5 × 7"},{"id":"d","text":"2 × 3 × 7²"}]'::jsonb, 'c', '210 = 2 × 105 = 2 × 3 × 35 = 2 × 3 × 5 × 7 ✓. الخطأُ الشائع: التوقّفُ قبل الأوان بنسيان العامل 7 (الخيار 2 × 3 × 5، ناتجُه 30 لا 210)، أو إضافةُ عاملٍ زائد أو تربيعُ عاملٍ خطأ.', 1, 'mcq', NULL, NULL)
