INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0268bf6b-aa2f-5dd5-9141-8cf92c02a191', '2d240ce1-fa7d-5db8-b8a0-23a854a16fa1', 'أيُّ العبارات التالية صحيحة؟', '[{"id":"a","text":"كلُّ عددٍ زوجيٍّ عددٌ أوّليّ"},{"id":"b","text":"العددُ 1 عددٌ أوّليّ"},{"id":"c","text":"كلُّ عددٍ يقبل القسمة على 3 يقبلها على 9"},{"id":"d","text":"كلُّ عددٍ يقبل القسمة على 9 يقبلها على 3"}]'::jsonb, 'd', 'بما أنّ 9 = 3 × 3، فكلُّ مضاعفٍ للعدد 9 هو مضاعفٌ للعدد 3 أيضًا، فالعبارة (د) صحيحة. العبارة (أ) خاطئة (4 زوجيّ وليس أوّليًّا)، و(ب) خاطئة (1 له قاسمٌ واحدٌ فقط)، و(ج) خاطئة لأنّ العكس ليس صحيحًا دائمًا (مثلًا 21 يقبل القسمة على 3 لا على 9).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
