  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4a135e7d-cdfb-5832-86fd-5bd857e2edbd', '2d240ce1-fa7d-5db8-b8a0-23a854a16fa1', 'ما قواسمُ العدد 1؟', '[{"id":"a","text":"1 فقط"},{"id":"b","text":"1 و0"},{"id":"c","text":"كلُّ الأعداد"},{"id":"d","text":"لا يوجد قاسم"}]'::jsonb, 'a', 'قاسمُ 1 الوحيد هو 1 نفسُه، لهذا لا يُعدّ 1 عددًا أوّليًّا (لا يملك قاسمَين مختلفَين). الخلطُ الشائع هو تبديلُ «قواسم 1» بـ«الأعداد التي 1 قاسمٌ لها» (وهي كلُّ الأعداد)، وهما فكرتان مختلفتان.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('257bba56-938e-5d5b-a80e-dde4c4e71f63', '2d240ce1-fa7d-5db8-b8a0-23a854a16fa1', 'ثلاثةُ أعدادٍ تفكيكُها كالتالي: A = 2² × 3 × 5 ، B = 2 × 3² × 7 ، C = 2³ × 3. ما م.م.ق للأعداد الثلاثة معًا؟', '[{"id":"a","text":"2"},{"id":"b","text":"3"},{"id":"c","text":"6"},{"id":"d","text":"30"}]'::jsonb, 'c', 'أصغرُ أُسٍّ للعامل 2 بين الأعداد الثلاثة هو 1 (في B)، وأصغرُ أُسٍّ للعامل 3 هو 1 (في A وC)؛ العاملان 5 و7 غيرُ مشتركَين بين الأعداد الثلاثة معًا. فم.م.ق = 2 × 3 = 6 ✓. الخيارُ 30 يضيف خطأً العاملَ 5 غيرَ المشترك بين الثلاثة.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c82ef060-a75f-52c6-8d60-1a9c917b4c86', '2d240ce1-fa7d-5db8-b8a0-23a854a16fa1', 'عددٌ صحيحٌ طبيعيّ عواملُه الأوّليّة هي 2 و5 فقط، وهو مضاعفٌ للعدد 20، ومحصورٌ بين 150 و250. ما أصغرُ عددٍ ممكنٍ يحقّق هذه الشروط؟', '[{"id":"a","text":"160"},{"id":"b","text":"180"},{"id":"c","text":"200"},{"id":"d","text":"240"}]'::jsonb, 'a', 'مضاعفاتُ 20 بين 150 و250 هي 160 ، 180 ، 200 ، 220 ، 240. نستبعد كلَّ عددٍ يحتوي عاملًا أوّليًّا غيرَ 2 و5: 180 = 2² × 3² × 5 (فيه 3) و220 = 2² × 5 × 11 (فيه 11) و240 = 2⁴ × 3 × 5 (فيه 3) مستبعَدة. يبقى 160 = 2⁵ × 5 و200 = 2³ × 5²، وأصغرُهما هو 160 ✓.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
