INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('00e462b6-5ba9-5884-8cfd-58202884cec4', '5cfde5a1-a8db-549b-8684-0f605e66dc03', 'بسّط الكتابة: 3² × 3³ ÷ 3⁴.', '[{"id":"a","text":"3¹"},{"id":"b","text":"3²"},{"id":"c","text":"3⁵"},{"id":"d","text":"3⁹"}]'::jsonb, 'a', 'أوّلًا نجمع أُسّي الجُداء: 3² × 3³ = 3²⁺³ = 3⁵، ثمّ نطرح أُسّ الخارج: 3⁵ ÷ 3⁴ = 3⁵⁻⁴ = 3¹. الخطأ الشائع: معاملةُ القسمة كأنّها جُداءٌ آخر، فيُجمَع الأُسّ الثالث بدل طرحِه (3⁹ = 2+3+4)، أو الاكتفاءُ بخطوة الجُداء دون تطبيق القسمة (3⁵).', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('34bb26a8-d07b-54b9-a636-7d9c52f6b658', '5cfde5a1-a8db-549b-8684-0f605e66dc03', 'إذا كان 2ⁿ = 32، فما قيمةُ n؟', '[{"id":"a","text":"4"},{"id":"b","text":"5"},{"id":"c","text":"6"},{"id":"d","text":"16"}]'::jsonb, 'b', 'نبحث عن الأُسّ الذي يعطي 32: 2⁵ = 32، إذن n = 5. (2⁴ = 16 و2⁶ = 64، وكلاهما لا يساوي 32؛ و16 هو ناتج 2⁴ لا قيمةُ n.)', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f5ed849a-0af8-58c0-a985-13bfc24293e0', '5cfde5a1-a8db-549b-8684-0f605e66dc03', 'أيّ عبارةٍ من هذه العباراتِ الأربع صحيحةٌ؟', '[{"id":"a","text":"3⁴ × 3² = 3⁸"},{"id":"b","text":"(2³)⁴ = 2⁷"},{"id":"c","text":"5⁶ ÷ 5² = 5³"},{"id":"d","text":"10³ × 10² = 10⁵"}]'::jsonb, 'd', '10³ × 10² = 10³⁺² = 10⁵ (صحيح). أمّا الباقي فخاطئٌ: 3⁴ × 3² = 3⁶ (نجمع الأُسّين، لا نضربُهما)، (2³)⁴ = 2¹² (نضرب الأُسّين، لا نجمعُهما)، و5⁶ ÷ 5² = 5⁴ (6 − 2 = 4 وليس 3).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c3686b7a-0423-5259-a3f6-4edb210f9830', '5cfde5a1-a8db-549b-8684-0f605e66dc03', 'ما الخطأُ في الحلّ التالي؟ الخطوة: (2⁴)² = 2⁴⁺² = 2⁶ = 64.', '[{"id":"a","text":"الخطأ في الخطوة الأولى: يجب ضربُ الأُسّين لا جمعُهما، فالناتجُ الصحيح 2⁸ = 256"},{"id":"b","text":"لا يوجد خطأٌ، الحلُّ صحيحٌ"},{"id":"c","text":"الخطأ في حساب 2⁶، فهو يساوي 32 لا 64"},{"id":"d","text":"الخطأ أنّ الأساس يجب أن يكون 4 لا 2"}]'::jsonb, 'a', 'في «قوّة قوّة» نضرب الأُسّين لا نجمعُهما: (2⁴)² = 2⁴×² = 2⁸ = 256. الحلُّ المعروضُ جمع الأُسّين خطأً (4 + 2 = 6) فحصل على 2⁶ = 64 بدل الناتج الصحيح.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

