  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c03d0bcf-174c-5bb6-bcac-4fd8958cfe5a', 'a14ab941-8ed8-59ce-9243-f405029280cb', 'اكتب العددَ 7 253 باستعمال قوى العدد 10.', '[{"id":"a","text":"7×10³ + 2×10² + 5×10¹ + 3"},{"id":"b","text":"7×10⁴ + 2×10³ + 5×10² + 3×10¹"},{"id":"c","text":"3×10³ + 5×10² + 2×10¹ + 7"},{"id":"d","text":"7×10² + 2×10¹ + 5 + 3"}]'::jsonb, 'a', 'نفكّك 7 253 حسب مرتبة كلّ رقمٍ: 7 آلاف، 2 مئات، 5 عشرات، 3 آحاد، أي 7×10³ + 2×10² + 5×10¹ + 3. (الخطأ الشائع: تحريكُ الأُسّين مرتبةً كاملةً، أو ترتيبُ الأرقام بشكلٍ معكوسٍ.)', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
