INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('442acca2-eb4d-5a1d-8a20-5df19dd1aa52', '48e85a78-dc96-5bc0-b9ad-2cea60131dd4', 'أيّ عبارةٍ من هذه العباراتِ **خاطئةٌ**؟', '[{"id":"a","text":"2² × 2⁵ = 2⁷"},{"id":"b","text":"(3²)⁴ = 3⁸"},{"id":"c","text":"6⁵ ÷ 6² = 6³"},{"id":"d","text":"9² = 9 × 2"}]'::jsonb, 'd', '9² = 9 × 9 = 81، وليس 9 × 2 = 18؛ فالعبارةُ «9² = 9 × 2» خاطئةٌ. أمّا الباقي فصحيحٌ: 2² × 2⁵ = 2⁷ (2+5)، (3²)⁴ = 3⁸ (2×4)، 6⁵ ÷ 6² = 6³ (5−2).', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('706f5b32-95a6-52e4-863e-36131ad0b13e', '48e85a78-dc96-5bc0-b9ad-2cea60131dd4', 'عددٌ صحيحٌ n يحقّق 3ⁿ = 243. ما ناتج 3ⁿ⁺¹؟', '[{"id":"a","text":"244"},{"id":"b","text":"243"},{"id":"c","text":"729"},{"id":"d","text":"2 187"}]'::jsonb, 'c', 'أوّلًا نوجد n: 3⁵ = 243، إذن n = 5. ثمّ نحسب 3ⁿ⁺¹ = 3⁶ = 729. الخطأ الشائع: زيادةُ 1 على القيمة 243 بدل زيادة 1 على الأُسّ (244)، أو نسيانُ العملية والاكتفاءُ بالقيمة الأصلية (243)، أو الخطأُ في إيجاد n (لو أُخِذ n = 6 خطأً لَحصلنا على 3⁷ = 2 187).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e7b54fb7-a625-549a-b618-9a5c9b741011', '48e85a78-dc96-5bc0-b9ad-2cea60131dd4', 'قارِن: أيّهما أكبر، 3⁴ أم 4³؟', '[{"id":"a","text":"3⁴ أكبر من 4³"},{"id":"b","text":"4³ أكبر من 3⁴"},{"id":"c","text":"3⁴ يساوي 4³"},{"id":"d","text":"كلاهما يساوي 12"}]'::jsonb, 'a', '3⁴ = 81 و4³ = 64؛ إذن 3⁴ أكبر من 4³. الخطأ الشائع: افتراضُ أنّ الأساسَ الأكبر (4) يعطي دائمًا نتيجةً أكبر، أو الخلطُ بين aᵇ والضرب a × b (3 × 4 = 12).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('25c2ae12-0846-536c-b427-c014353b8ac3', '48e85a78-dc96-5bc0-b9ad-2cea60131dd4', 'أوجد قيمةَ n بحيث (2ⁿ)² = 2¹⁰.', '[{"id":"a","text":"5"},{"id":"b","text":"8"},{"id":"c","text":"10"},{"id":"d","text":"20"}]'::jsonb, 'a', 'في «قوّة قوّة» نضرب الأُسّين: n × 2 = 10، إذن n = 5. الخطأ الشائع: طرحُ الأُسّ الخارجي بدل القسمة عليه (10 − 2 = 8)، ضربُه بدل القسمة (10 × 2 = 20)، أو نسخُ الأُسّ الناتج مباشرةً (n = 10).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6d565c0e-f67f-52eb-a981-2576ddb2547a', '48e85a78-dc96-5bc0-b9ad-2cea60131dd4', 'اكتب العددَ 128 كقوّةٍ للعدد 2، ثمّ أوجد مربّعَ هذه القوّة.', '[{"id":"a","text":"2⁹"},{"id":"b","text":"2¹⁴"},{"id":"c","text":"2¹⁶"},{"id":"d","text":"2⁴⁹"}]'::jsonb, 'b', '128 = 2⁷ (لأنّ 2⁷ = 128)؛ ومربّعُ هذه القوّة هو (2⁷)² = 2⁷×² = 2¹⁴. الخطأ الشائع: جمعُ الأُسّين بدل ضربِهما (2⁹ = 7+2)، الخطأُ في تحديد أُسّ 128 من البداية (لو اعتُبر 128 = 2⁸ خطأً لَحصلنا على 2¹⁶ = 8×2)، أو ضربُ الأُسّ الأصليّ (7) في نفسه بدل ضربِه في 2 (2⁴⁹ = 7×7).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('973ed126-371a-51ed-9f64-a626ff6dd12d', '48e85a78-dc96-5bc0-b9ad-2cea60131dd4', 'بسّط الكتابة: (2³ × 2²)² ÷ 2⁶، ثمّ اذكر الناتجَ كعددٍ.', '[{"id":"a","text":"2"},{"id":"b","text":"16"},{"id":"c","text":"64"},{"id":"d","text":"1 024"}]'::jsonb, 'b', 'أوّلًا: 2³ × 2² = 2⁵. ثمّ: (2⁵)² = 2⁵×² = 2¹⁰. أخيرًا: 2¹⁰ ÷ 2⁶ = 2¹⁰⁻⁶ = 2⁴ = 16. الخطأ الشائع: جمعُ الأُسّين في خطوة «قوّة قوّة» بدل ضربِهما (يُعطي خطأً 2)، ضربُ الأُسّين في خطوة الجُداء بدل جمعِهما (يُعطي خطأً 64)، أو نسيانُ خطوة القسمة الأخيرة (يُعطي خطأً 1024).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

