INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('eedf38d3-7f53-58a9-bce5-bcc793e067ae', 'dc6b48cc-6d95-59ec-a494-5a5efdcb8955', 'احسب: 4 − 9', '[{"id":"a","text":"−13"},{"id":"b","text":"−5"},{"id":"c","text":"5"},{"id":"d","text":"13"}]'::jsonb, 'b', '4 − 9 = 4 + (−9)؛ إشارتان مختلفتان: نطرح 4 من 9 (9 − 4 = 5) ونحتفظ بإشارة العدد الأكبر قيمةً مطلقة وهو −9، فـ4 − 9 = −5 ✓. الخطأُ الشائع: جمعُ العددين للحصول على 13 بدل طرحهما، أو نسيانُ الإشارة فيصبح الناتجُ 5.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
