  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('537cd16a-ea09-536b-bec3-6affc3cd6246', 'dc6b48cc-6d95-59ec-a494-5a5efdcb8955', 'احسب: (−7) × 3', '[{"id":"a","text":"−28"},{"id":"b","text":"−21"},{"id":"c","text":"−4"},{"id":"d","text":"21"}]'::jsonb, 'b', 'إشارتان مختلفتان (سالب × موجب): الناتجُ سالب؛ 7 × 3 = 21، فـ(−7) × 3 = −21 ✓. الخطأُ الشائع: نسيانُ الإشارة السالبة فيصبح الناتجُ 21؛ أو الخلطُ بين الضرب والجمع فيُحسب −7 + 3 = −4؛ أو خطأٌ في جدول الضرب (−28 بدل −21).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
