  ('ac428af9-e3eb-5b14-9e18-709449882980', 'dc6b48cc-6d95-59ec-a494-5a5efdcb8955', 'أيُّ عددٍ أصغر: −3,8 أم −3,2؟', '[{"id":"a","text":"−3,2 أصغر"},{"id":"b","text":"العددان متساويان"},{"id":"c","text":"−3,8 أصغر"},{"id":"d","text":"لا يمكن مقارنةُ عددين عشريّين سالبين"}]'::jsonb, 'c', 'بين عددين سالبَين، الأصغرُ هو الأبعدُ عن الصفر (صاحبُ القيمة المطلقة الأكبر)؛ |−3,8| = 3,8 أكبرُ من |−3,2| = 3,2، فـ−3,8 أصغرُ من −3,2 ✓. الخطأُ الشائع: مقارنةُ العددين كما لو كانا موجبَين، فيُظنّ أنّ 3,8 > 3,2 يعني أنّ −3,8 أكبر.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
