  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f1529f54-e454-54bb-931a-ed0e61a3c2ff', 'dc6b48cc-6d95-59ec-a494-5a5efdcb8955', 'رصيدُ حساب أحمد البنكي −250 دينارًا. سحب مبلغًا إضافيًّا قدرُه 130 دينارًا. ما رصيدُه الجديد؟', '[{"id":"a","text":"−380"},{"id":"b","text":"−120"},{"id":"c","text":"120"},{"id":"d","text":"380"}]'::jsonb, 'a', 'السحبُ الإضافيّ يعني رصيدًا سالبًا آخر: −250 + (−130). إشارتان متماثلتان (سالبتان): نجمعُ 250 و130 = 380 ونحتفظ بالإشارة السالبة، فالرصيدُ الجديد −380 دينارًا ✓. الخطأُ الشائع: طرحُ 130 من 250 بدل جمعهما فيُحصل على −120، أو نسيانُ الإشارة السالبة كليًّا فيصبح 380 أو 120.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

