  ('c5bc80a3-ca05-5ba6-b074-000ab0246b0d', '818bbb2d-4f1b-5f94-bdb9-3add2404f5ca', 'إذا كان |x| = 6، فما القيمتان الممكنتان للعدد x؟', '[{"id":"a","text":"6 فقط"},{"id":"b","text":"−6 فقط"},{"id":"c","text":"0 و6"},{"id":"d","text":"6 و−6"}]'::jsonb, 'd', 'القيمةُ المطلقة لعددين متقابلَين متساوية؛ العددان اللذان قيمتُهما المطلقة تساوي 6 هما 6 و−6.', 2, 'mcq', NULL, NULL)
