  ('1714056a-e8e7-591b-b8dd-da06d3d36a4e', '818bbb2d-4f1b-5f94-bdb9-3add2404f5ca', 'رتّب تصاعديًّا الأعدادَ التالية: 4 ، −9 ، 0 ، −1', '[{"id":"a","text":"−9 < −1 < 0 < 4"},{"id":"b","text":"−1 < −9 < 0 < 4"},{"id":"c","text":"4 < 0 < −1 < −9"},{"id":"d","text":"0 < −1 < −9 < 4"}]'::jsonb, 'a', 'الأعدادُ السالبة أصغرُ من الصفر، وبينها −9 أصغرُ من −1 (لأنّ |−9| = 9 أكبرُ من |−1| = 1)؛ فالترتيبُ التصاعديّ الصحيح هو −9 < −1 < 0 < 4.', 3, 'mcq', NULL, NULL)
