INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e4489094-3772-5815-b781-e03d194e8b2e', '29bdd686-4d01-5522-a3ae-b7479f21076f', 'احسب: 7 − (−3) + (−5)', '[{"id":"a","text":"−15"},{"id":"b","text":"−1"},{"id":"c","text":"5"},{"id":"d","text":"15"}]'::jsonb, 'c', '7 − (−3) + (−5) = 7 + 3 + (−5) = 10 + (−5) = 5 ✓ (طرحُ −3 يعني جمعَ مقابله +3). الخطأُ الشائع: معاملةُ −(−3) كأنّه −3 فيُحسب 7 − 3 − 5 = −1، أو نسيانُ إشارة الحدّ الأخير فيصبح الناتجُ 15.', 1, 'mcq', NULL, NULL)
