INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e1619f52-04be-5550-ba51-ea8f127b39ca', '29bdd686-4d01-5522-a3ae-b7479f21076f', 'احسب: (−4) × (−3) − 2', '[{"id":"a","text":"−14"},{"id":"b","text":"10"},{"id":"c","text":"14"},{"id":"d","text":"20"}]'::jsonb, 'b', 'الأولويةُ للضرب: (−4) × (−3) = 12 (إشارتان متماثلتان)، ثمّ 12 − 2 = 10 ✓. الخطأُ الشائع: تجاهلُ أولويّة العمليّات وحسابُ (−4) × (−3 − 2) = (−4) × (−5) = 20، أو نسيانُ إشارة الجداء فيصبح −12 − 2 = −14، أو قلبُ الطرح إلى جمعٍ فيصبح 12 + 2 = 14.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('349f32a4-80e1-546e-a5a0-78ef6530c83b', '29bdd686-4d01-5522-a3ae-b7479f21076f', 'رصيدُ حساب فاطمة البنكي كان −180 دينارًا. أودعت 250 دينارًا، ثمّ سحبت 90 دينارًا. ما رصيدُها النهائيّ؟', '[{"id":"a","text":"−520"},{"id":"b","text":"−20"},{"id":"c","text":"20"},{"id":"d","text":"160"}]'::jsonb, 'b', 'الخطواتُ: −180 + 250 = 70 (الإيداعُ موجب)، ثمّ 70 − 90 = −20 (السحبُ يُطرح) ✓. الخطأُ الشائع: جمعُ السحب بدل طرحه فيُحصل على 160، أو نسيانُ إشارة الرصيد الابتدائيّ فيُحصل على 20، أو معاملةُ الإيداع كأنّه سالبٌ أيضًا فيُحصل على −520.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('72a1b984-7521-5945-8609-5553985cfa89', '29bdd686-4d01-5522-a3ae-b7479f21076f', 'عددٌ نسبيّ x يحقّق: x + (−7) = −12. ما قيمةُ x؟', '[{"id":"a","text":"−19"},{"id":"b","text":"−12"},{"id":"c","text":"−5"},{"id":"d","text":"5"}]'::jsonb, 'c', 'لعزل x نطرح −7 من الطرفين، أي نجمع مقابله: x = −12 + 7 = −5 ✓. الخطأُ الشائع: جمعُ −7 بدل طرحه فيُحصل على −19، أو نسخُ العددِ −12 كما هو دون حلّ المعادلة، أو قلبُ الإشارة النهائية فيصبح 5.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6bd85097-8ec6-5973-a5ad-65ee8eb848a5', '29bdd686-4d01-5522-a3ae-b7479f21076f', 'حاول أحمد حسابَ: (−6) × (−2) × (−1) × (−5)، فكتب: −60. أين الخطأ في حلّه؟', '[{"id":"a","text":"عددُ العوامل السالبة هنا زوجيٌّ (4)، فكان يجب أن يكون الناتجُ موجبًا +60"},{"id":"b","text":"الحسابُ صحيحٌ تمامًا"},{"id":"c","text":"نسي ضربَ أحد العوامل"},{"id":"d","text":"القيمةُ المطلقة للناتج خاطئة (يجب أن تكون 65 لا 60)"}]'::jsonb, 'a', 'عددُ العوامل السالبة هنا هو 4 (زوجيّ)، فالناتجُ يجب أن يكون موجبًا: 6 × 2 × 1 × 5 = 60، أي +60 لا −60 ✓. خطأُ أحمد أنّه عامل الأعداد الأربعة السالبة وكأنّ عددها فرديّ.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c53b6bac-160b-5e0a-84d1-0acbe174ea38', '29bdd686-4d01-5522-a3ae-b7479f21076f', 'غطس غوّاصٌ في نقطةٍ بحريّةٍ إلى عمق 35,5 مترًا تحت سطح البحر، ثمّ صعد 12,5 مترًا. ما ارتفاعُه عن سطح البحر الآن؟', '[{"id":"a","text":"−23"},{"id":"b","text":"12,5"},{"id":"c","text":"23"},{"id":"d","text":"35,5"}]'::jsonb, 'a', 'العمقُ الابتدائيّ هو −35,5 م (تحت سطح البحر)؛ الصعودُ يعني إضافةَ +12,5: −35,5 + 12,5 = −23 م ✓ (إشارتان مختلفتان: نطرح 12,5 من 35,5 ونحتفظ بإشارة العمق لأنّ قيمتَه المطلقة أكبر). الخطأُ الشائع: نسيانُ العمق الابتدائيّ فيبقى الجوابُ 12,5 (الصعودُ فقط)، أو إسقاطُ الإشارة السالبة فيصبح الناتجُ 23، أو نسيانُ الصعود كليًّا فيبقى الجوابُ 35,5 (العمقُ الابتدائيّ فقط).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

