INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('36afca6b-49bf-53f9-b008-08f3f9883457', 'fcb0d339-0b00-5b33-9fb8-972aa83293cb', 'ارتفاعُ طائرةٍ 850 مترًا فوق سطح البحر. انخفضت 1200 متر، ثمّ ارتفعت 300 متر. ما ارتفاعُها النهائيّ بالنسبة إلى سطح البحر؟', '[{"id":"a","text":"−50"},{"id":"b","text":"50"},{"id":"c","text":"350"},{"id":"d","text":"850"}]'::jsonb, 'a', '850 + (−1200) = −350 (انخفاضٌ تحت مستوى الانطلاق)؛ ثمّ −350 + 300 = −50 ✓. الخطأُ الشائع: نسيانُ الإشارة السالبة في خطوة الانخفاض فيُحصل على 350، أو قلبُ إشارة الناتج النهائيّ فيصبح 50، أو عدمُ إجراء أيّ حسابٍ والاكتفاءُ بالارتفاع الابتدائيّ 850.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0b976b13-9db3-51df-a91a-d2ea3198bc8a', 'fcb0d339-0b00-5b33-9fb8-972aa83293cb', 'حاولت سلمى حسابَ: (−2,5) × (−4) − 6، فكتبت الخطواتِ التالية: (−2,5) × (−4) = −10 ثمّ −10 − 6 = −16. أين الخطأ في حلّها؟', '[{"id":"a","text":"الخطأُ في الطرح، والصحيحُ −10 + 6"},{"id":"b","text":"الخطأُ في الضرب: الناتجُ يجب أن يكون +10 لا −10"},{"id":"c","text":"لا يوجد خطأ، الحلُّ صحيحٌ تمامًا"},{"id":"d","text":"الخطأُ في القيمة المطلقة: 2,5 × 4 يجب أن يساوي 8 لا 10"}]'::jsonb, 'b', 'إشارتان متماثلتان (سالب × سالب): الناتجُ موجب، أي (−2,5) × (−4) = +10 لا −10. خطأُ سلمى في تحديد إشارة الجداء؛ لو تابعت بشكل صحيح لكانت النتيجةُ 10 − 6 = 4.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e6d1f47b-7e49-5e52-8db5-f4adee759fd7', 'fcb0d339-0b00-5b33-9fb8-972aa83293cb', 'بداية الشهر، كان رصيدُ حساب يوسف البنكي 120 دينارًا. دفع فاتورةً بـ 45 دينارًا، ثمّ اقترض من صديقه فتغيّر رصيدُه بمقدار −80 دينارًا إضافيّة، ثمّ أودع مبلغًا يساوي ضعفَ ما اقترضه (أي 2 × 80 دينارًا). ما رصيدُه في نهاية الشهر؟', '[{"id":"a","text":"−165"},{"id":"b","text":"−5"},{"id":"c","text":"75"},{"id":"d","text":"155"}]'::jsonb, 'd', 'الخطواتُ: 120 − 45 = 75 (دفعُ الفاتورة)؛ 75 − 80 = −5 (تأثيرُ الاقتراض)؛ الإيداعُ يساوي 2 × 80 = 160 دينارًا (موجب): −5 + 160 = 155 دينارًا ✓. الخطأُ الشائع: التوقّفُ عند خطوةٍ وسيطة (75 أو −5) دون إتمام كلّ العمليّات، أو معاملةُ الإيداع الأخير كأنّه سالبٌ فيُحصل على −165.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

