  ('d963efc8-186a-5b93-ad5d-baa0b7cbfade', 'e6ffb5f2-2493-5b4c-8f65-f2a69b40c411', 'math-7eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
