INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('315b86e5-7bb7-5e05-979d-13144e41adaa', 'd963efc8-186a-5b93-ad5d-baa0b7cbfade', 'أيُّ كسرٍ من التالية يُساوي الكسرَ 3/5؟', '[{"id":"a","text":"3/10"},{"id":"b","text":"6/10"},{"id":"c","text":"6/5"},{"id":"d","text":"5/3"}]'::jsonb, 'b', 'نضربُ البسطَ والمقامَ معًا في 2: (3×2)/(5×2) = 6/10، فهو يساوي 3/5. الخيارُ 3/10 نتيجةُ ضرب المقام فقط، و6/5 نتيجةُ ضرب البسط فقط، و5/3 هو مقلوبُ الكسر لا كسرٌ يساويه.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('33641160-a3c3-514d-bbe8-12674ac843a5', 'd963efc8-186a-5b93-ad5d-baa0b7cbfade', 'ما أبسطُ صورةٍ للكسر 24/36؟', '[{"id":"a","text":"8/12"},{"id":"b","text":"6/9"},{"id":"c","text":"4/6"},{"id":"d","text":"2/3"}]'::jsonb, 'd', 'م.م.ق(24 ; 36) = 12، فـ 24/36 = (24÷12)/(36÷12) = 2/3، وهو غيرُ قابلٍ للاختزال (م.م.ق(2 ; 3) = 1). الخياراتُ 8/12 و6/9 و4/6 تساوي نفسَ القيمة لكنّها ناتجةٌ عن القسمة على قاسمٍ مشتركٍ غيرِ م.م.ق (3 أو 4 أو 6 لا 12)، فهي ليست أبسطَ صورة.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

