  ('ef4c0943-318b-5ee7-b4d7-514d40141485', 'd963efc8-186a-5b93-ad5d-baa0b7cbfade', 'أيُّ الكسرين أكبر: 4/9 أم 4/7؟', '[{"id":"a","text":"4/9"},{"id":"b","text":"4/7"},{"id":"c","text":"متساويان"},{"id":"d","text":"لا يمكن المقارنة دون توحيد المقام"}]'::jsonb, 'b', 'الكسران لهما نفسُ البسط 4، فالكسرُ الأكبرُ هو صاحبُ المقام الأصغر: 4/7 > 4/9 لأنّ 7 < 9 (تخيّل بيتزا مقسومةً على 7 أجزاء مقابل 9 أجزاء: الجزءُ في الحالة الأولى أكبر).', 3, 'mcq', NULL, NULL)
