  ('800fd684-97f3-522e-8dfc-ff08b4186c55', 'd963efc8-186a-5b93-ad5d-baa0b7cbfade', 'احسب: 3/4 × 2/5', '[{"id":"a","text":"3/10"},{"id":"b","text":"5/9"},{"id":"c","text":"6/5"},{"id":"d","text":"15/8"}]'::jsonb, 'a', 'نضربُ البسطَ في البسط والمقامَ في المقام: (3×2)/(4×5) = 6/20 = 3/10 بعد التبسيط. الخيارُ 5/9 ناتجٌ عن جمع البسطَين والمقامَين خطأً بدلَ ضربهما، و6/5 نسي ضربَ المقام الثاني، و15/8 ناتجٌ عن الضرب في المقلوب (كأنّها قسمة).', 5, 'mcq', NULL, NULL)
