  ('e198b46a-3384-50c3-8e7e-928c50df0eed', '9400189b-2193-545b-a302-912c71d02450', 'أيُّ الكسرين أكبر: 5/9 أم 7/9؟', '[{"id":"a","text":"7/9"},{"id":"b","text":"5/9"},{"id":"c","text":"متساويان"},{"id":"d","text":"لا يمكن المقارنة دون توحيد المقام"}]'::jsonb, 'a', 'المقامُ مشتركٌ (9)، فيكفي مقارنةُ البسطَين: 7 > 5، إذن 7/9 > 5/9 ✓. لا حاجةَ لتوحيد المقام لأنّه مشتركٌ أصلًا.', 3, 'mcq', NULL, NULL)
