INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('bd308b9d-9e3e-51c5-ba4f-2c6692bb4256', '9400189b-2193-545b-a302-912c71d02450', 'لدى خبّازٍ 9/11 من كيسِ الدقيق، استعمل 4/11 منه في تحضير الخبز. ما الكسرُ المتبقّي من الكيس؟', '[{"id":"a","text":"13/11"},{"id":"b","text":"4/11"},{"id":"c","text":"5/22"},{"id":"d","text":"5/11"}]'::jsonb, 'd', 'المقامُ مشترك، فنطرح البسوطَ: 9/11 − 4/11 = 5/11 ✓. الخيارُ 13/11 ناتجٌ عن جمعٍ بدلَ الطرح، و5/22 ناتجٌ عن طرح المقامَين أيضًا، و4/11 مجرّدُ الكمّيّة المستعملة لا المتبقّية.', 6, 'mcq', NULL, NULL)
