  ('55e5509b-2a21-5cb1-a1e8-cde3c3fd6e04', 'e6ffb5f2-2493-5b4c-8f65-f2a69b40c411', 'math-7eme', '⚔️ زعيم الفصل ⭐⭐⭐: تبسيطٌ ومقارنةٌ وعمليّاتٌ على الكسور', 3, 120, 30, 'boss', 'admin', 2)
