INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e12e2e00-9863-53d9-8656-99f38cf43115', '55e5509b-2a21-5cb1-a1e8-cde3c3fd6e04', 'بسِّط الكسر 45/60 إلى أبسط صورة.', '[{"id":"a","text":"3/4"},{"id":"b","text":"9/12"},{"id":"c","text":"15/20"},{"id":"d","text":"4/3"}]'::jsonb, 'a', '45 = 3² × 5 و60 = 2² × 3 × 5، فم.م.ق(45 ; 60) = 3 × 5 = 15؛ 45 ÷ 15 = 3 و60 ÷ 15 = 4، فالكسرُ المبسَّط هو 3/4 ✓. الكسران 9/12 و15/20 يساويان نفسَ القيمة لكنّهما غيرُ مبسَّطَين بالكامل (قُسِّم فقط على 5 أو على 3)، و4/3 كتابةٌ مقلوبةٌ خاطئة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
