INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('79e419db-3fab-5879-ab3e-ad3fc3c0384b', '55e5509b-2a21-5cb1-a1e8-cde3c3fd6e04', 'قارن بين 3/8 و2/5 بتحويلهما إلى كتابةٍ عشريّة. أيُّهما أكبر؟', '[{"id":"a","text":"3/8"},{"id":"b","text":"2/5"},{"id":"c","text":"متساويان"},{"id":"d","text":"لا يمكن مقارنتهما إلّا بتوحيد المقام"}]'::jsonb, 'b', '3/8 = 0,375 و2/5 = 0,4؛ بما أنّ 0,4 > 0,375، فإنّ 2/5 > 3/8 ✓. التحويلُ إلى كتابةٍ عشريّة طريقةٌ صحيحةٌ للمقارنة، وليست توحيدُ المقام الطريقةَ الوحيدة.', 2, 'mcq', NULL, NULL)
