  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9670d806-1f55-5c4c-9a6f-d6c29f850985', '55e5509b-2a21-5cb1-a1e8-cde3c3fd6e04', 'أيُّ الكسرين أكبر: 5/6 أم 7/9؟ (وحِّد المقامَ أوّلًا)', '[{"id":"a","text":"7/9 أكبر"},{"id":"b","text":"الكسران متساويان"},{"id":"c","text":"5/6 أكبر"},{"id":"d","text":"7/9 أكبر بفارق 1/18"}]'::jsonb, 'c', 'م.م.أ(6 ; 9) = 18؛ 5/6 = 15/18 و7/9 = 14/18. بما أنّ 15 > 14، فإنّ 5/6 > 7/9 بفارق 1/18 ✓. الخيارُ (د) يحسبُ الفارقَ الصحيح (1/18) لكن ينسبُه للكسر الخطأ.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
