  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0ec4d214-e327-5825-be15-1db0796777b6', '55e5509b-2a21-5cb1-a1e8-cde3c3fd6e04', 'استعملت خيّاطةٌ 2/3 من مترٍ من القماش لخياطة قميص، و3/5 من مترٍ لخياطة تنّورة. ما مجموعُ طول القماش الذي استعملته؟', '[{"id":"a","text":"5/8"},{"id":"b","text":"19/30"},{"id":"c","text":"11/15"},{"id":"d","text":"19/15"}]'::jsonb, 'd', 'م.م.أ(3 ; 5) = 15؛ 2/3 = 10/15 و3/5 = 9/15، فالمجموعُ 10/15 + 9/15 = 19/15 مترًا ✓. الخيارُ 5/8 ناتجٌ عن جمع البسطَين والمقامَين مباشرةً، و11/15 نسي تحويلَ بسط الكسر الأوّل، و19/30 استعمل مقامًا مشتركًا خاطئًا.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c497387f-55c3-5b53-8ad6-6cbb0f165949', '55e5509b-2a21-5cb1-a1e8-cde3c3fd6e04', 'تحتاج وصفةُ حلوى إلى 3/4 كأسٍ من السكّر لكلّ دفعة. حضّرت أمُّ ريم 2/3 من دفعةٍ واحدة. كم كأسًا من السكّر استعملت؟', '[{"id":"a","text":"9/8"},{"id":"b","text":"1/2"},{"id":"c","text":"5/7"},{"id":"d","text":"3/2"}]'::jsonb, 'b', 'نضربُ البسطَ في البسط والمقامَ في المقام: (3×2)/(4×3) = 6/12 = 1/2 كأسٍ ✓. الخيارُ 5/7 ناتجٌ عن جمع البسطَين والمقامَين بدلَ ضربهما، و3/2 نسي ضربَ المقام الثاني (اكتفى بـ 3×2/4)، و9/8 ناتجٌ عن قسمةِ 3/4 على 2/3 بدلَ ضربهما.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e1a00d9c-3bed-5764-b5c5-e963ebac8478', '55e5509b-2a21-5cb1-a1e8-cde3c3fd6e04', 'لدى بائعٍ 4/5 كلغ من التمر، يريد توزيعَه في أكياسَ سعةُ كلٍّ منها 2/15 كلغ. كم كيسًا يمكنه ملؤه؟', '[{"id":"a","text":"8/75"},{"id":"b","text":"1/6"},{"id":"c","text":"6"},{"id":"d","text":"60"}]'::jsonb, 'c', 'قسمةُ كسرٍ على كسرٍ = الضربُ في مقلوب الثاني: 4/5 ÷ 2/15 = 4/5 × 15/2 = 60/10 = 6 أكياس ✓. الخطأُ الشائع: 8/75 ناتجٌ عن الضرب مباشرةً دون قلب الكسر الثاني، و1/6 ناتجٌ عن قلب الكسر الخطأ (الأوّل بدلَ الثاني)، و60 توقّفَ عند البسط دون إتمام القسمة على 10.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

