  ('81ca8fcb-3204-5a79-b5a7-52114f99218c', 'e6ffb5f2-2493-5b4c-8f65-f2a69b40c411', 'math-7eme', '⭐⭐ تمرين مراجعة: الكسور (نمط امتحان)', 2, 70, 15, 'practice', 'admin', 3)
