INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d9de4f25-6951-5c69-b2b7-a2a2e5afa1f3', '81ca8fcb-3204-5a79-b5a7-52114f99218c', 'بسِّط الكسر 28/42 إلى أبسط صورة.', '[{"id":"a","text":"3/2"},{"id":"b","text":"2/3"},{"id":"c","text":"4/6"},{"id":"d","text":"14/21"}]'::jsonb, 'b', '28 = 2² × 7 و42 = 2 × 3 × 7، فم.م.ق(28 ; 42) = 2 × 7 = 14؛ 28 ÷ 14 = 2 و42 ÷ 14 = 3، فالكسرُ المبسَّط هو 2/3 ✓. الكسران 4/6 و14/21 يساويان نفسَ القيمة لكنّهما غيرُ مبسَّطَين بالكامل، و3/2 كتابةٌ مقلوبةٌ خاطئة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4d0b722d-2a86-531e-8556-55e6eac8b11e', '81ca8fcb-3204-5a79-b5a7-52114f99218c', 'أيُّ الكسرين أكبر: 7/10 أم 5/8؟ (وحِّد المقامَ أوّلًا)', '[{"id":"a","text":"5/8 أكبر"},{"id":"b","text":"الكسران متساويان"},{"id":"c","text":"7/10 أكبر بفارق 1/40"},{"id":"d","text":"7/10 أكبر"}]'::jsonb, 'd', 'م.م.أ(10 ; 8) = 40؛ 7/10 = 28/40 و5/8 = 25/40. بما أنّ 28 > 25، فإنّ 7/10 > 5/8 بفارق 3/40 ✓. الخيارُ (ج) يحدّدُ الاتّجاهَ الصحيح لكن يحسبُ فارقًا خاطئًا (1/40 بدلَ 3/40).', 2, 'mcq', NULL, NULL)
