INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9f59b563-b366-5d14-b211-2182edc1e88a', '81ca8fcb-3204-5a79-b5a7-52114f99218c', 'اشترى محمّد 3/4 كلغ من التفّاح و1/6 كلغ من الموز. ما وزنُ ما اشتراه؟', '[{"id":"a","text":"4/10"},{"id":"b","text":"7/12"},{"id":"c","text":"10/12"},{"id":"d","text":"11/12"}]'::jsonb, 'd', 'م.م.أ(4 ; 6) = 12؛ 3/4 = 9/12 و1/6 = 2/12، فالمجموعُ 9/12 + 2/12 = 11/12 كلغ ✓. الخيارُ 4/10 جمع البسطَين والمقامَين مباشرةً، و10/12 خطأٌ حسابيّ في جمع البسوط، و7/12 طرحَ بدلَ الجمع.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
