  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3823bc8d-75b6-5c96-a62b-5a2336297e07', '81ca8fcb-3204-5a79-b5a7-52114f99218c', 'لدى تلميذةٍ 5/6 من علبةِ حلوى، أعطت صديقتَها 1/4 من علبةٍ مماثلة. ما الكسرُ المتبقّي لديها؟', '[{"id":"a","text":"1/2"},{"id":"b","text":"7/12"},{"id":"c","text":"13/12"},{"id":"d","text":"2"}]'::jsonb, 'b', 'م.م.أ(6 ; 4) = 12؛ 5/6 = 10/12 و1/4 = 3/12، فالمتبقّي 10/12 − 3/12 = 7/12 من العلبة ✓. الخيارُ 1/2 حوّل 1/4 خطأً إلى 4/12 بدلَ 3/12، و13/12 جمع بدلَ الطرح، و2 طرح المقامَين مباشرةً (6 − 4 = 2).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('410d9471-9db7-5a59-8c71-7b0bc064c9b9', '81ca8fcb-3204-5a79-b5a7-52114f99218c', 'يملك مزارعٌ 5/8 من هكتار، زرع 4/5 من هذه المساحة قمحًا. ما مساحةُ الأرض المزروعة بالقمح؟', '[{"id":"a","text":"1/2"},{"id":"b","text":"9/13"},{"id":"c","text":"25/32"},{"id":"d","text":"20/13"}]'::jsonb, 'a', 'نضربُ البسطَ في البسط والمقامَ في المقام: (5×4)/(8×5) = 20/40 = 1/2 هكتار ✓. الخيارُ 9/13 جمع البسطَين والمقامَين بدلَ ضربهما، و25/32 حسب القسمةَ 5/8 ÷ 4/5 بدلَ الضرب، و20/13 ضرب البسطَين لكن جمع المقامَين.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
