  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('438ccba9-73a2-50a6-b6e7-dfe4a94fea5d', '81ca8fcb-3204-5a79-b5a7-52114f99218c', 'لدى ممرّضةٍ 3/5 من لترِ محلولٍ طبّي، تريد توزيعَه في حقنٍ سعةُ كلٍّ منها 3/20 من اللتر. كم حقنةً يمكنها ملؤها؟', '[{"id":"a","text":"9/100"},{"id":"b","text":"1/4"},{"id":"c","text":"4"},{"id":"d","text":"60"}]'::jsonb, 'c', 'قسمةُ كسرٍ على كسرٍ = الضربُ في مقلوب الثاني: 3/5 ÷ 3/20 = 3/5 × 20/3 = 60/15 = 4 حقن ✓. الخطأُ الشائع: 9/100 ناتجٌ عن الضرب مباشرةً دون قلب الكسر الثاني، و1/4 ناتجٌ عن قلب الكسر الأوّل بدلَ الثاني، و60 توقّفَ عند البسط دون إتمام القسمة على 15.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
