  ('fa22bb88-5b0a-5b3b-a345-76ca134ed351', 'e6ffb5f2-2493-5b4c-8f65-f2a69b40c411', 'math-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: مسائلُ مركّبةٌ على الكسور', 4, 300, 60, 'challenge', 'admin', 4)
