INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ed36d084-1108-587d-ae11-aa2736406e02', 'fa22bb88-5b0a-5b3b-a345-76ca134ed351', 'قماشٌ طولُه 5/6 من المتر. استعملت خيّاطةٌ 2/5 منه لخياطة قميص. ما طولُ القماش المتبقّي؟', '[{"id":"a","text":"7/6"},{"id":"b","text":"1/2"},{"id":"c","text":"1/3"},{"id":"d","text":"2/7"}]'::jsonb, 'b', 'الجزءُ المستعمل = 5/6 × 2/5 = 10/30 = 1/3 من المتر. المتبقّي = 5/6 − 1/3 = 5/6 − 2/6 = 3/6 = 1/2 متر ✓. الخيارُ 1/3 توقّفَ عند الجزء المستعمل دون طرحه، و7/6 جمع بدلَ الطرح، و2/7 خطأُ جمعٍ مباشر للبسوط والمقامات في خطوةٍ مختلفة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
