  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7f2b191a-fc97-5440-80a1-586b2e1f7171', 'fa22bb88-5b0a-5b3b-a345-76ca134ed351', 'كسرٌ بعد أن ضُرب في 2/3 أصبح يساوي 4/9. ما كان هذا الكسرُ قبل الضرب؟', '[{"id":"a","text":"8/27"},{"id":"b","text":"4/3"},{"id":"c","text":"2/3"},{"id":"d","text":"3/2"}]'::jsonb, 'c', 'إن كان الكسرُ الأصليّ x، فـ x × 2/3 = 4/9، إذن x = 4/9 ÷ 2/3 = 4/9 × 3/2 = 12/18 = 2/3 ✓ (تحقّق: 2/3 × 2/3 = 4/9). الخيارُ 8/27 ضرب بدلَ القسمة للعودة إلى الأصل، و3/2 قلب الكسر الخطأ عند القسمة.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b9ad79a5-0ec3-5724-a938-286988e1aae7', 'fa22bb88-5b0a-5b3b-a345-76ca134ed351', 'في فصلٍ دراسيّ، 3/5 من التلاميذ حصلوا على معدّلٍ يفوق 15 في الرياضيات، بينما حصل 7/12 منهم على معدّلٍ يفوق 15 في العلوم. في أيّ مادّةٍ كانت نسبةُ النجاح أعلى؟', '[{"id":"a","text":"الرياضيات"},{"id":"b","text":"العلوم"},{"id":"c","text":"متساويتان"},{"id":"d","text":"لا يمكن تحديد ذلك دون معطياتٍ إضافية"}]'::jsonb, 'a', 'م.م.أ(5 ; 12) = 60؛ 3/5 = 36/60 و7/12 = 35/60. بما أنّ 36 > 35، فنسبةُ النجاح في الرياضيات أعلى (بفارقٍ ضئيلٍ 1/60) ✓. الكسران وحدهما كافيان لتحديد الأكبر، فلا حاجةَ لأيّ معطياتٍ إضافية.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e32fc187-c774-5400-b519-b720a2acc95c', 'fa22bb88-5b0a-5b3b-a345-76ca134ed351', 'اشترى فلاحٌ 3/4 من طنٍّ من الأسمدة، واستعمل 2/3 منها في الأسبوع الأوّل. ثمّ اشترى 1/2 طنٍّ إضافيٍّ. كم طنًّا من الأسمدة أصبح لديه؟', '[{"id":"a","text":"1/4"},{"id":"b","text":"1/2"},{"id":"c","text":"5/4"},{"id":"d","text":"3/4"}]'::jsonb, 'd', 'المستعمل = 3/4 × 2/3 = 6/12 = 1/2 طنّ. المتبقّي بعد الاستعمال = 3/4 − 1/2 = 1/4 طنّ. بعد شراء 1/2 طنٍّ إضافيّ: 1/4 + 1/2 = 1/4 + 2/4 = 3/4 طنّ ✓. الخيارُ 1/4 نسي إضافةَ الشراء الجديد، و5/4 نسي طرحَ المستعمل ابتداءً، و1/2 خلط بين المستعمل والناتج النهائيّ.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6fd05f9f-af01-578f-8c83-206201abcb5c', 'fa22bb88-5b0a-5b3b-a345-76ca134ed351', 'احسب: 2/3 + 1/4 × 2/5', '[{"id":"a","text":"11/30"},{"id":"b","text":"23/30"},{"id":"c","text":"3/13"},{"id":"d","text":"1/15"}]'::jsonb, 'b', 'الضربُ أوّلًا: 1/4 × 2/5 = 2/20 = 1/10. ثمّ الجمعُ: 2/3 + 1/10 = 20/30 + 3/30 = 23/30 ✓. الخيارُ 11/30 جمع 2/3 و1/4 أوّلًا (تجاهل أولويّةَ الضرب)، و3/13 جمع البسوطَ والمقاماتِ مباشرةً، و1/15 عامل كلَّ العمليّة كأنّها ضربٌ فقط.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f32d611b-c188-512b-8166-2aac22a6dba9', 'fa22bb88-5b0a-5b3b-a345-76ca134ed351', 'أيُّ العبارات التالية صحيحة؟', '[{"id":"a","text":"لضرب كسرين، نضرب البسطين ونجمع المقامين"},{"id":"b","text":"عند طرح كسرين مختلفَي المقام، نطرح البسطين مباشرةً دون توحيد المقام"},{"id":"c","text":"كلّما كبُر مقامُ الكسر (والبسط ثابت)، كبرت قيمةُ الكسر"},{"id":"d","text":"قسمةُ كسرٍ على كسرٍ آخر تكافئ ضربَه في مقلوب الكسر الثاني"}]'::jsonb, 'd', 'هذه هي قاعدةُ قسمة الكسور بالضبط: القسمةُ على كسرٍ = الضربُ في مقلوبه ✓. العبارةُ (أ) خاطئة (ضربُ المقامَين لا جمعُهما)، و(ب) خاطئة (يجبُ توحيدُ المقام قبل الطرح)، و(ج) خاطئة (كبرُ المقامِ مع بسطٍ ثابتٍ يُصغِّرُ الكسر لا يكبِّره).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('0ff4f6b8-d048-558b-be8e-c8d5d21e5614', 'e6ffb5f2-2493-5b4c-8f65-f2a69b40c411', 'math-7eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة للكسور', 3, 120, 30, 'boss', 'admin', 5)
