INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6455de64-0f10-5c78-afff-3196113274f0', '0ff4f6b8-d048-558b-be8e-c8d5d21e5614', 'اكتب كسرًا يساوي 4/5 بضرب البسط والمقام في 4.', '[{"id":"a","text":"16/5"},{"id":"b","text":"16/20"},{"id":"c","text":"4/20"},{"id":"d","text":"8/9"}]'::jsonb, 'b', 'نضربُ البسطَ والمقامَ معًا في 4: (4×4)/(5×4) = 16/20، وهو يساوي 4/5 ✓. الخيارُ 16/5 ضرب البسطَ فقط، و4/20 ضرب المقامَ فقط، و8/9 جمع 4 مع البسط والمقام بدلَ الضرب.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d61828af-bdfa-53f3-988a-5fe287e9b6c8', '0ff4f6b8-d048-558b-be8e-c8d5d21e5614', 'بسِّط الكسر 18/24 إلى أبسط صورة.', '[{"id":"a","text":"9/12"},{"id":"b","text":"6/8"},{"id":"c","text":"4/3"},{"id":"d","text":"3/4"}]'::jsonb, 'd', '18 = 2 × 3² و24 = 2³ × 3، فم.م.ق(18 ; 24) = 2 × 3 = 6؛ 18 ÷ 6 = 3 و24 ÷ 6 = 4، فالكسرُ المبسَّط هو 3/4 ✓. الكسران 9/12 و6/8 يساويان نفسَ القيمة لكنّهما غيرُ مبسَّطَين بالكامل، و4/3 كتابةٌ مقلوبةٌ خاطئة.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d29fbc6e-5b3d-5730-a9e5-a441620fc344', '0ff4f6b8-d048-558b-be8e-c8d5d21e5614', 'أيُّ الكسرين أصغر: 5/6 أم 5/11؟', '[{"id":"a","text":"5/6"},{"id":"b","text":"متساويان"},{"id":"c","text":"5/11"},{"id":"d","text":"لا يمكن المقارنة دون توحيد المقام"}]'::jsonb, 'c', 'البسطُ مشتركٌ (5)، فالكسرُ الأصغرُ هو صاحبُ المقام الأكبر: 11 > 6، إذن 5/11 < 5/6 ✓. تخيّل كعكةً مقسومةً على 11 جزءًا مقابل 6 أجزاء: الجزءُ في الحالة الأولى أصغر.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('616b4832-a78d-5ba2-afcc-42bc7f9f7c6b', '0ff4f6b8-d048-558b-be8e-c8d5d21e5614', 'قارن بين 7/20 و1/3 بتحويلهما إلى كتابةٍ عشريّة.', '[{"id":"a","text":"7/20 أكبر"},{"id":"b","text":"1/3 أكبر"},{"id":"c","text":"متساويان"},{"id":"d","text":"7/20 أكبر، لكن بفارقٍ أقلَّ من 0,01"}]'::jsonb, 'a', '7/20 = 0,35 و1/3 ≈ 0,333، فـ 7/20 > 1/3 ✓. الفارقُ الفعليّ هو 1/60 ≈ 0,017، وهو أكبرُ من 0,01، فالخيارُ (د) يحدّدُ الاتّجاهَ الصحيح لكن يقدّرُ الفارقَ بأقلَّ من قيمته الحقيقيّة.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('34c2a238-8c26-52f9-b612-0f38db69da4e', '0ff4f6b8-d048-558b-be8e-c8d5d21e5614', 'سقت بستانيّةٌ 5/8 من الحديقة صباحًا و1/6 منها مساءً. ما نسبةُ الحديقة التي سقتها في اليوم كلّه؟', '[{"id":"a","text":"3/7"},{"id":"b","text":"19/24"},{"id":"c","text":"16/24"},{"id":"d","text":"3/8"}]'::jsonb, 'b', 'م.م.أ(8 ; 6) = 24؛ 5/8 = 15/24 و1/6 = 4/24، فالمجموعُ 15/24 + 4/24 = 19/24 ✓. الخيارُ 3/7 جمع البسطَين والمقامَين مباشرةً، و16/24 خطأٌ حسابيّ في جمع البسوط، و3/8 نسي تحويلَ بسط الكسر الأوّل.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('149c3d04-5512-5715-bdd3-076d59f9b9f9', '0ff4f6b8-d048-558b-be8e-c8d5d21e5614', 'لدى مزارعةٍ 7/9 من هكتارٍ من الأرض، تريد تقسيمَها إلى قطعٍ صغيرة، كلُّ قطعةٍ مساحتُها 7/27 من هكتار. كم قطعةً ستحصل عليها؟', '[{"id":"a","text":"49/243"},{"id":"b","text":"1/3"},{"id":"c","text":"3"},{"id":"d","text":"189"}]'::jsonb, 'c', 'قسمةُ كسرٍ على كسرٍ = الضربُ في مقلوب الثاني: 7/9 ÷ 7/27 = 7/9 × 27/7 = 189/63 = 3 قطع ✓. الخطأُ الشائع: 49/243 ناتجٌ عن الضرب مباشرةً دون قلب الكسر الثاني، و1/3 ناتجٌ عن قلب الكسر الأوّل بدلَ الثاني، و189 توقّفَ عند البسط دون إتمام القسمة على 63.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

