  ('55dc7ba6-acc5-57e5-84b2-22086295d21d', 'e6ffb5f2-2493-5b4c-8f65-f2a69b40c411', 'math-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّةُ الكسور', 4, 300, 60, 'challenge', 'admin', 6)
