INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('81ccdd5a-5ff8-5882-8cdc-a1e13315ce00', '55dc7ba6-acc5-57e5-84b2-22086295d21d', 'حوضُ ماءٍ يحتوي 5/6 من سعته. استُعمل 3/5 من الماء الموجود في الحوض للريّ. ثمّ أُضيف 1/4 من سعة الحوض ماءً جديدًا. ما نسبةُ الماء في الحوض الآن؟', '[{"id":"a","text":"7/12"},{"id":"b","text":"1/3"},{"id":"c","text":"13/12"},{"id":"d","text":"2/7"}]'::jsonb, 'a', 'المستعمل = 5/6 × 3/5 = 15/30 = 1/2 من سعة الحوض. المتبقّي = 5/6 − 1/2 = 5/6 − 3/6 = 2/6 = 1/3. بعد إضافة 1/4: 1/3 + 1/4 = 4/12 + 3/12 = 7/12 ✓. الخيارُ 1/3 توقّفَ قبل إضافة الماء الجديد، و13/12 نسي طرحَ الماء المستعمل ابتداءً، و2/7 جمع البسطَين والمقامَين مباشرةً في الخطوة الأخيرة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('01b8eda3-a73b-5ab6-bc9c-5d0995f7a878', '55dc7ba6-acc5-57e5-84b2-22086295d21d', 'كسرٌ بعد أن ضُرب في 2/3 أصبح يساوي 4/9. ما كان هذا الكسرُ قبل الضرب؟', '[{"id":"a","text":"8/27"},{"id":"b","text":"4/3"},{"id":"c","text":"2/3"},{"id":"d","text":"3/2"}]'::jsonb, 'c', 'إن كان الكسرُ الأصليّ x، فـ x × 2/3 = 4/9، إذن x = 4/9 ÷ 2/3 = 4/9 × 3/2 = 12/18 = 2/3 ✓ (تحقّق: 2/3 × 2/3 = 4/9). الخيارُ 8/27 ضرب بدلَ القسمة للعودة إلى الأصل، و3/2 قلب الكسر الخطأ عند القسمة، و4/3 خلطٌ عشوائيّ بين البسط والمقام.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('88fa06c0-6082-5498-87ab-dca925ea03b1', '55dc7ba6-acc5-57e5-84b2-22086295d21d', 'في فصلٍ دراسيّ، 2/5 من التلاميذ يفضّلون الرياضيات، و3/10 يفضّلون العلوم، والباقي يفضّلون موادَّ أخرى. ما الكسرُ الذي يمثّل التلاميذ الذين يفضّلون موادَّ أخرى؟', '[{"id":"a","text":"7/10"},{"id":"b","text":"1/10"},{"id":"c","text":"2/3"},{"id":"d","text":"3/10"}]'::jsonb, 'd', 'الذين يفضّلون الرياضيات أو العلوم: 2/5 + 3/10 = 4/10 + 3/10 = 7/10. الباقون: 1 − 7/10 = 3/10 ✓. الخيارُ 7/10 توقّفَ عند المجموع دون طرحه من الكلّ، و1/10 خطأٌ في عمليّة الطرح النهائيّة، و2/3 ناتجٌ عن جمع البسطَين والمقامَين مباشرةً ثمّ الطرح من الكلّ.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a156829f-2fe0-5615-9923-cb85a3257978', '55dc7ba6-acc5-57e5-84b2-22086295d21d', 'أيُّ العبارات التالية صحيحة؟', '[{"id":"a","text":"لتبسيط كسرٍ، يكفي أن نقسم بسطَه فقط على عددٍ يقسمه"},{"id":"b","text":"لجمع كسرين مختلفَي المقام، نجمع البسطين ونجمع المقامين مباشرةً"},{"id":"c","text":"لمقارنة كسرين بالعبور إلى الكتابة العشريّة، نقسم البسطَ على المقام في كلّ كسر ثمّ نقارن الناتجَين"},{"id":"d","text":"لقسمة كسرٍ على كسرٍ آخر، نضربه في مقلوب الكسر الأوّل لا الثاني"}]'::jsonb, 'c', 'هذه هي بالضبط طريقةُ المقارنة بالعبور إلى الكتابة العشريّة ✓. العبارةُ (أ) خاطئة (يجبُ قسمةُ البسط والمقام معًا على قاسمٍ مشترك، لا البسط وحده)، و(ب) خاطئة (يجبُ توحيدُ المقام قبل الجمع)، و(د) خاطئة (نضربُ في مقلوب الكسر **الثاني** لا الأوّل).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
