  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7d5ede05-4ced-5715-ab84-ca3cd8eb008f', '55dc7ba6-acc5-57e5-84b2-22086295d21d', 'لدى تاجرٍ 7/8 من طنٍّ من الأرزّ، باع 2/7 منه في الصباح. ثمّ وزّع ما تبقّى بالتساوي على 3 محلّات. ما الكسرُ الذي حصل عليه كلُّ محلٍّ من الطنّ الأصليّ؟', '[{"id":"a","text":"5/8"},{"id":"b","text":"5/24"},{"id":"c","text":"15/8"},{"id":"d","text":"7/24"}]'::jsonb, 'b', 'المباعُ = 7/8 × 2/7 = 14/56 = 1/4 طنّ. المتبقّي = 7/8 − 1/4 = 7/8 − 2/8 = 5/8 طنّ. نصيبُ كلّ محلّ = 5/8 ÷ 3 = 5/8 × 1/3 = 5/24 طنّ ✓. الخيارُ 5/8 توقّفَ قبل التوزيع على المحلّات، و15/8 ضرب في 3 بدلَ القسمة عليها، و7/24 نسي طرحَ الكمّيّة المباعة قبل التوزيع.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6c7df98a-df69-53fa-a85a-8ec703e7d2c3', '55dc7ba6-acc5-57e5-84b2-22086295d21d', 'احسب ناتجَ العبارة: (2/3 + 1/6) ÷ 5/4 − 1/10', '[{"id":"a","text":"7/10"},{"id":"b","text":"2/3"},{"id":"c","text":"44/75"},{"id":"d","text":"17/30"}]'::jsonb, 'd', 'الأقواسُ أوّلًا: 2/3 + 1/6 = 4/6 + 1/6 = 5/6. ثمّ القسمة: 5/6 ÷ 5/4 = 5/6 × 4/5 = 20/30 = 2/3. أخيرًا الطرح: 2/3 − 1/10 = 20/30 − 3/30 = 17/30 ✓. الخيارُ 7/10 قسم 1/6 فقط على 5/4 متجاهلًا الأقواس، و2/3 توقّفَ بعد القسمة دون الطرح الأخير، و44/75 نفّذ الجمعَ والطرحَ قبل القسمة (عكس الأولويّة الصحيحة تمامًا).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

