INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2ccec03b-fb1a-5e6f-938e-d2ba5524a998', '7e0f2778-e466-50cf-9253-2c1df8dbb36f', 'أيّ العبارات التالية عبارةٌ حرفية؟', '[{"id":"a","text":"5 + 3"},{"id":"b","text":"2x + 7"},{"id":"c","text":"12"},{"id":"d","text":"3 × 4 − 1"}]'::jsonb, 'b', 'العبارةُ الحرفية تحتوي على الأقلّ حرفًا واحدًا يمثّل عددًا (متغيّرًا)؛ العبارة 2x + 7 تحتوي الحرفَ x، أمّا باقي الخيارات فعباراتٌ عدديّة نتيجتُها عددٌ محدَّد (8 و12 و11).', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e28581c6-5fc5-5a3c-8bda-f2f38559533b', '7e0f2778-e466-50cf-9253-2c1df8dbb36f', 'احسب القيمةَ العدديّة للعبارة 3x + 2 عندما x = 4.', '[{"id":"a","text":"12"},{"id":"b","text":"20"},{"id":"c","text":"14"},{"id":"d","text":"11"}]'::jsonb, 'c', 'نُعوّض x بـ 4: 3×4 + 2 = 12 + 2 = 14 ✓. الخطأُ الشائع: نسيانُ إضافة 2 (12)، أو ضربُ المجموع (3+2) في 4 فتُعطي 20، أو التعويضُ بقيمةٍ خطأ لـ x فتُعطي 11.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0d22f52a-5f6e-5ba1-be8a-7a7ed95d7e46', '7e0f2778-e466-50cf-9253-2c1df8dbb36f', 'عبّر حرفيًّا عن: «ضعفُ عددٍ x زائد 3».', '[{"id":"a","text":"x + 2 + 3"},{"id":"b","text":"3x + 2"},{"id":"c","text":"2x + 3"},{"id":"d","text":"2(x + 3)"}]'::jsonb, 'c', '«ضعفُ عددٍ x» يعني 2x، و«زائد 3» يعني إضافةَ 3، فالعبارةُ هي 2x + 3 ✓. الخيارُ x+2+3 يقرأ «ضعف» على أنّها إضافةُ 2؛ والخيارُ 2(x+3) يضع الجمعَ داخل القوسين خطأً؛ والخيارُ 3x+2 يبدّل المعاملَ مع الحدّ الثابت.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

