  ('e26f87fd-0fe9-5980-88ce-fd146ed97494', '7e0f2778-e466-50cf-9253-2c1df8dbb36f', 'اختزل العبارة: 5x + 3x.', '[{"id":"a","text":"15x"},{"id":"b","text":"8x²"},{"id":"c","text":"2x"},{"id":"d","text":"8x"}]'::jsonb, 'd', 'الحدّان 5x و3x متشابهان فنجمع معامليهما: 5 + 3 = 8، فالنتيجة 8x ✓. الخطأُ الشائع: تربيعُ الأسّ بدل جمع المعاملَين (8x²)، أو ضربُ المعاملَين بدل جمعهما (15x)، أو طرحُهما بدل جمعهما (2x).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
