  ('deac2cc3-d7ea-5fb5-a8ad-feb60f3e402d', '7e0f2778-e466-50cf-9253-2c1df8dbb36f', 'انشر العبارة: 2×(x + 5).', '[{"id":"a","text":"2x + 10"},{"id":"b","text":"2x + 5"},{"id":"c","text":"x + 10"},{"id":"d","text":"2x + 7"}]'::jsonb, 'a', 'نوزّع 2 على الحدّين: 2×x + 2×5 = 2x + 10 ✓. الخطأُ الشائع: توزيعُ 2 على x فقط ونسيانُ الحدّ 5 (2x+5)، أو نسيانُ ضرب الحدّ الأوّل (x+10)، أو جمعُ 2+5=7 بدل توزيع الضرب (2x+7).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
