INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e5e08c2e-ac37-5c36-95df-d987fe60b2b8', '36ac72c5-70c1-54ae-aab6-25075ad59de8', 'ماذا يمثّل الحرفُ x في العبارة الحرفية 2x + 5؟', '[{"id":"a","text":"عددًا ثابتًا لا يتغيّر"},{"id":"b","text":"عمليّةَ الجمع"},{"id":"c","text":"عددًا متغيّرًا أو مجهولًا"},{"id":"d","text":"إشارةَ الضرب"}]'::jsonb, 'c', 'الحرفُ في العبارة الحرفية (كـ x) يمثّل **متغيّرًا**، أي عددًا مجهولًا أو قابلًا للتغيّر بحسب الحالة؛ هو ليس عمليّةً ولا إشارةً ولا عددًا ثابتًا.', 1, 'mcq', NULL, NULL)
