  ('97c495b9-8a65-5481-a69a-a00d5a382dc9', '36ac72c5-70c1-54ae-aab6-25075ad59de8', 'احسب القيمةَ العدديّة للعبارة x + 5 عندما x = 3.', '[{"id":"a","text":"2"},{"id":"b","text":"53"},{"id":"c","text":"8"},{"id":"d","text":"15"}]'::jsonb, 'c', 'نُعوّض x بـ 3 فنحصل على 3 + 5 = 8 ✓. الخطأُ الشائع: حسابُ 5 − 3 = 2 بدل الجمع، أو كتابةُ الرقمَين متجاورَين 53 دون حساب، أو ضربُ 3 × 5 = 15.', 3, 'mcq', NULL, NULL)
