  ('085167b1-56b6-56d4-82b1-fedce07aca08', '36ac72c5-70c1-54ae-aab6-25075ad59de8', 'احسب القيمةَ العدديّة للعبارة 2x + 3 عندما x = 5.', '[{"id":"a","text":"10"},{"id":"b","text":"16"},{"id":"c","text":"25"},{"id":"d","text":"13"}]'::jsonb, 'd', 'نُعوّض x بـ 5: 2 × 5 + 3 = 10 + 3 = 13 ✓. الخطأُ الشائع: نسيانُ إضافة 3 (فنحصل على 10)، أو ضربُ 2 في المجموع (5 + 3) فنحصل على 16، أو جمعُ 2 + 3 = 5 ثمّ ضربُه في x فنحصل على 25.', 4, 'mcq', NULL, NULL)
