INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('240d3727-192a-5189-9bdf-dbb01864a43d', '4e8a462f-63bb-57bb-933a-eed78e2aa96d', 'انشر العبارة: 4×(x − 3).', '[{"id":"a","text":"4x − 3"},{"id":"b","text":"4x + 12"},{"id":"c","text":"4x − 12"},{"id":"d","text":"x − 12"}]'::jsonb, 'c', 'نوزّع 4 على الحدَّين: 4×x − 4×3 = 4x − 12 ✓. الخطأُ الشائع: عدمُ توزيع 4 على الحدّ الثاني (4x−3)، أو الخطأُ في الإشارة فنكتب 4x+12 بدل الطرح، أو نسيانُ ضرب الحدّ الأوّل (x−12).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0e1a7b0e-dc58-5b7d-a715-2ce2c423da69', '4e8a462f-63bb-57bb-933a-eed78e2aa96d', 'عمِّل العبارة التالية بإخراج عاملٍ مشترك: 3x + 12.', '[{"id":"a","text":"3(x + 12)"},{"id":"b","text":"x(3 + 12)"},{"id":"c","text":"3x(1 + 4)"},{"id":"d","text":"3(x + 4)"}]'::jsonb, 'd', 'القاسمُ المشتركُ للعددين 3 و12 هو 3؛ 3x ÷ 3 = x و12 ÷ 3 = 4، فالعبارةُ المعمّلة هي 3(x + 4) ✓. الخطأُ الشائع: إخراجُ العامل 3 من الحدّ الثاني فقط (3(x+12))، أو اختيارُ عاملٍ خطأ لا يقسم الحدَّين معًا بشكل صحيح.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('1227c0cd-c372-5f31-a520-28b32e2f503a', '4e8a462f-63bb-57bb-933a-eed78e2aa96d', 'ثمنُ الكرّاس x دينار. اشترت سارة 4 كرّاريس ودفعت أيضًا 2 دينار ثمن قلم. عبّر عن المبلغ الكليّ الذي دفعته سارة حرفيًّا.', '[{"id":"a","text":"4(x + 2)"},{"id":"b","text":"x + 6"},{"id":"c","text":"4x + 2"},{"id":"d","text":"6x"}]'::jsonb, 'c', 'ثمنُ الكرّاريس الأربعة هو 4×x = 4x، ويُضاف إليه ثمنُ القلم 2 دينار، فالمبلغُ الكليّ هو 4x + 2 ✓. الخطأُ الشائع: توزيعُ العدد 4 على المبلغَين معًا فتصبح 4(x+2) وهذا يعني تكرارَ ثمن القلم 4 مرّات، أو نسيانُ ضرب x في 4 فتُكتب x+4+2 المختزلة إلى x+6، أو جمعُ 4+2 خطأً كمعامل واحد (6x).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ba9185fe-a5c8-5fbd-b0f0-e5b863add17d', '4e8a462f-63bb-57bb-933a-eed78e2aa96d', 'احسب القيمةَ العدديّة للعبارة 3(x + 2) عندما x = 4، بعد نشرها أوّلًا.', '[{"id":"a","text":"14"},{"id":"b","text":"18"},{"id":"c","text":"12"},{"id":"d","text":"24"}]'::jsonb, 'b', 'أوّلًا ننشر العبارة: 3(x+2) = 3x+6. ثمّ نعوّض x بـ 4: 3×4+6 = 12+6 = 18 ✓. الخطأُ الشائع: نسيانُ توزيع 3 على الحدّ الثاني فنحصل على 14 (3×4+2)، أو نسيانُ الحدّ الثابت تمامًا فنحصل على 12، أو الخلطُ بين الجمع والضرب داخل القوسين فنحصل على 24.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

