INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d51aff5e-e4fa-5756-9cfe-c84803a28eac', '90fc036f-950f-5740-9270-303740534813', 'ما القيمةُ العدديّة للعبارة 3x عندما x = 6؟', '[{"id":"a","text":"18"},{"id":"b","text":"9"},{"id":"c","text":"63"},{"id":"d","text":"3"}]'::jsonb, 'a', 'نعوّض x بـ 6: 3×6=18 ✓. الخطأُ الشائع: جمعُ 3+6=9 بدل الضرب، أو كتابةُ الرقمَين متجاورَين 63، أو نسيانُ ضرب المعامل تمامًا.', 1, 'mcq', NULL, NULL)
