  ('855e735e-c3ca-5e68-8437-33f3362daa21', '90fc036f-950f-5740-9270-303740534813', 'انشر العبارة: 2×(3x + 5).', '[{"id":"a","text":"6x + 5"},{"id":"b","text":"6x + 10"},{"id":"c","text":"3x + 10"},{"id":"d","text":"5x + 10"}]'::jsonb, 'b', 'نوزّع 2 على الحدَّين: 2×3x + 2×5 = 6x + 10 ✓. الخطأُ الشائع: نسيانُ توزيع 2 على الحدّ الثاني (6x+5)، أو ضربُ العدد 2 في المعامل بشكل غير مكتمل (3x+10)، أو جمعُ 2+3 بدل ضربهما (5x+10).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
