INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8ebd10d1-ae8f-50d7-84e1-5b122519ed87', '90fc036f-950f-5740-9270-303740534813', 'عمِّل بإخراج عاملٍ مشترك: 5x + 20.', '[{"id":"a","text":"5(x + 20)"},{"id":"b","text":"x(5 + 20)"},{"id":"c","text":"5(x + 4)"},{"id":"d","text":"4(x + 5)"}]'::jsonb, 'c', 'القاسمُ المشتركُ للعددين 5 و20 هو 5؛ 5x÷5=x و20÷5=4، فالعبارةُ المعمّلة هي 5(x + 4) ✓. الخطأُ الشائع: إخراجُ 5 من الحدّ الأوّل فقط (5(x+20))، أو اختيارُ عاملٍ خطأ يبدّل دورَ الحدَّين (4(x+5) ينشر إلى 4x+20 وهذا غيرُ مطابقٍ للعبارة الأصليّة).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
