  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a43859e6-519f-56e3-a6da-b7d8125007ab', '90fc036f-950f-5740-9270-303740534813', 'عمرُ كريم الآن x سنة. عبّر حرفيًّا عن عمره بعد 6 سنوات.', '[{"id":"a","text":"6x"},{"id":"b","text":"x − 6"},{"id":"c","text":"x + 6"},{"id":"d","text":"6 − x"}]'::jsonb, 'c', '«بعد 6 سنوات» يعني إضافةَ 6 إلى العمر الحاليّ، فالعبارةُ هي x + 6 ✓. الخيارُ 6x يستعمل الضربَ بدل الجمع، والخياران x − 6 و6 − x يستعملان الطرحَ (اتّجاهٌ معاكسٌ للزمن) بدل الجمع.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5fda8956-ceb7-5ce4-8c2c-7cc677a66207', '90fc036f-950f-5740-9270-303740534813', 'احسب القيمةَ العدديّة للعبارة 4x + 2×(x + 1) بعد اختزالها، عندما x = 3.', '[{"id":"a","text":"18"},{"id":"b","text":"19"},{"id":"c","text":"24"},{"id":"d","text":"20"}]'::jsonb, 'd', 'نبسّط أوّلًا: 4x + 2(x+1) = 4x + 2x + 2 = 6x + 2. نعوّض x بـ 3: 6×3+2 = 18+2 = 20 ✓. الخطأُ الشائع: نسيانُ الحدّ الثابت 2 الناتج عن التوزيع فتكون النتيجة 18، أو نسيانُ توزيع 2 على الحدّ 1 داخل القوسين فتكون النتيجة 19، أو ضمُّ 4x مع 2(x+1) في حدٍّ واحدٍ 6(x+1) فتكون النتيجة 24.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

