INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('cba2b68b-88e5-57b1-a902-9aa7ee9e1f53', '66dcaa66-c046-54f0-b0a5-4f035b199f28', 'محيطُ مستطيلٍ طولُه (x + 3) وعرضُه x. عبّر حرفيًّا عن محيط هذا المستطيل، ثمّ اختزل العبارة.', '[{"id":"a","text":"4x + 6"},{"id":"b","text":"2x + 3"},{"id":"c","text":"4x + 3"},{"id":"d","text":"2x + 6"}]'::jsonb, 'a', 'طولُ المستطيل L = x+3 وعرضُه l = x، فمحيطُه P = 2×(L+l) = 2×((x+3)+x) = 2×(2x+3) = 4x+6 ✓. الخطأُ الشائع: نسيانُ ضرب المجموع في 2 (2x+3)، أو توزيعُ 2 على حدٍّ واحدٍ فقط (4x+3)، أو خطأٌ في جمع الطول والعرض قبل الضرب (2x+6 بدل 2x+3).', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0da79d01-e3c8-54d7-895a-60d2d3978ccc', '66dcaa66-c046-54f0-b0a5-4f035b199f28', 'بسِّط ثمّ انشر لتختزل: العبارة x + 2x + 3(x + 4).', '[{"id":"a","text":"6x + 4"},{"id":"b","text":"6x + 12"},{"id":"c","text":"4x + 12"},{"id":"d","text":"5x + 12"}]'::jsonb, 'b', 'نبسّط الحدود المتشابهة أوّلًا: x + 2x = 3x. ثمّ ننشر: 3(x+4) = 3x+12. فيصبح المجموع: 3x + 3x + 12 = 6x + 12 ✓. الخطأُ الشائع: نسيانُ توزيع 3 على الحدّ الثابت 4 (فتكون النتيجة 6x+4)، أو توزيعُ 3 على 4 فقط دون x (فتكون النتيجة 4x+12)، أو خطأٌ في جمع معاملَي x الأوّلَين (1+2 يُحسب خطأً 2 بدل 3، فتكون النتيجة 5x+12).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0b1282ee-fa9d-5b7b-a096-d08df9c10852', '66dcaa66-c046-54f0-b0a5-4f035b199f28', 'أيُّ العبارات التالية صحيحة مهما تكن قيمةُ x؟', '[{"id":"a","text":"2x + 3x = 5x²"},{"id":"b","text":"4(x + 1) = 4x + 1"},{"id":"c","text":"x + x = x²"},{"id":"d","text":"3x + 5x = 8x"}]'::jsonb, 'd', '3x+5x=8x صحيحةٌ دائمًا لأنّ الحدَّين متشابهان فنجمع معامليهما 3+5=8 ✓. العبارة (أ) خاطئة (2x+3x=5x لا 5x²)، و(ب) خاطئة (4(x+1)=4x+4 لا 4x+1، نسيانُ توزيع 4 على 1)، و(ج) خاطئة (x+x=2x لا x²، جمعٌ لا ضرب).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b4eb204f-95c0-5c32-b89b-53ec847c3221', '66dcaa66-c046-54f0-b0a5-4f035b199f28', 'حلّت منى العبارةَ 5(x − 2) فكتبت: 5(x − 2) = 5x − 2. أين الخطأ في حلّها؟', '[{"id":"a","text":"لم تُخطئ، الحلُّ صحيح"},{"id":"b","text":"كان يجب أن تجمع بدل الطرح"},{"id":"c","text":"نسيت توزيعَ 5 على الحدّ 2 (الصحيح: 5x − 10)"},{"id":"d","text":"الخطأ في توزيع 5 على x فقط"}]'::jsonb, 'c', 'التوزيعُ الصحيح: 5×(x−2) = 5×x − 5×2 = 5x − 10. منى وزّعت 5 على x فقط ونسيت ضربَه في 2، فكتبت 5x−2 بدل 5x−10 ✓. (سؤالُ اكتشاف خطأ: الخيارُ الصحيح يصف الخطأ، لا يمثّل حلًّا خاطئًا بديلًا.)', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d5fca7ad-c196-558d-8d12-d62837be224b', '66dcaa66-c046-54f0-b0a5-4f035b199f28', 'عبارةٌ حرفيةٌ على الشكل k(x + 3) تساوي بعد نشرها 7x + 21. ما قيمةُ k؟', '[{"id":"a","text":"3"},{"id":"b","text":"7"},{"id":"c","text":"4"},{"id":"d","text":"10"}]'::jsonb, 'b', 'بما أنّ k(x+3) = kx + 3k، ونعلم أنّها تساوي 7x+21، فمقارنةُ الحدّ الحرفيّ تعطي k=7 (نتحقّق: 3×7=21 وهو الحدُّ الثابتُ المطابق ✓). الخطأُ الشائع: الخلطُ بين k والعددِ 3 الأصليّ داخل القوسين، أو عمليّاتُ جمعٍ وطرحٍ عشوائيّة (4 أو 10) لا تحقّق الشرطَ 3k=21.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f4fcf3fc-7933-5d3f-acf3-49f124fe4472', '66dcaa66-c046-54f0-b0a5-4f035b199f28', 'عمرُ ليلى الآن x سنة. عمرُ أختها يفوق عمرَها بـ 5 سنوات. عبّر حرفيًّا عن مجموع عمرَي الأختين بعد 3 سنوات من الآن، مختزَلًا.', '[{"id":"a","text":"2x + 11"},{"id":"b","text":"2x + 8"},{"id":"c","text":"2x + 6"},{"id":"d","text":"x + 11"}]'::jsonb, 'a', 'عمرُ ليلى بعد 3 سنوات: x+3. عمرُ أختها الآن x+5، وبعد 3 سنوات: (x+5)+3 = x+8. المجموع: (x+3)+(x+8) = 2x+11 ✓. الخطأُ الشائع: نسيانُ إضافة 3 سنوات لعمر الأخت (فيبقى المجموع 2x+8)، أو نسيانُ فارق السنوات الخمس بين الأختين (فيُحسب 2x+6)، أو حسابُ عمرٍ واحدٍ فقط بدل الأختين معًا (x+11).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

