  ('919bf39e-348b-5dce-8ef8-9609a665d7ad', '899066c6-61c0-553f-8452-bca9147bdebc', 'math-7eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة للحساب الحرفي', 3, 120, 30, 'boss', 'admin', 5)
