INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d84424b7-cf52-545e-a3f5-a3626e690b08', '919bf39e-348b-5dce-8ef8-9609a665d7ad', 'ما اسمُ الحرف الذي يمثّل عددًا مجهولًا أو متغيّرًا في عبارةٍ حرفية؟', '[{"id":"a","text":"المعامل"},{"id":"b","text":"الحدّ"},{"id":"c","text":"المتغيّر"},{"id":"d","text":"الأساس"}]'::jsonb, 'c', 'الحرفُ الذي يمثّل عددًا مجهولًا أو متغيّرًا يُسمّى **المتغيّر** (مثل x)؛ أمّا **المعامل** فهو العددُ الذي يُضرب فيه، و**الحدّ** هو كلُّ جزءٍ من العبارة مفصولٌ بجمعٍ أو طرح.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b1cc09a9-694a-5b08-93ba-8dd8701786b7', '919bf39e-348b-5dce-8ef8-9609a665d7ad', 'احسب القيمةَ العدديّة للعبارة 7x عندما x = 0.', '[{"id":"a","text":"0"},{"id":"b","text":"7"},{"id":"c","text":"70"},{"id":"d","text":"1"}]'::jsonb, 'a', 'نعوّض x بـ 0: 7×0 = 0 ✓ (أيّ عددٍ مضروبٍ في 0 يساوي 0). الخطأُ الشائع: الاعتقادُ بأنّ النتيجة هي المعاملُ نفسُه 7 لأنّ x «غيرُ موجودة»، وهذا خطأ — يجب إجراءُ الضرب فعليًّا.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e81066f3-9677-556d-91ff-cc031e89adea', '919bf39e-348b-5dce-8ef8-9609a665d7ad', 'اختزل العبارة: 9x + x.', '[{"id":"a","text":"9x"},{"id":"b","text":"10x"},{"id":"c","text":"9x²"},{"id":"d","text":"10x²"}]'::jsonb, 'b', 'الحدُّ x معاملُه 1، فـ 9x + x = 9x + 1x = 10x ✓. الخطأُ الشائع: تجاهلُ الحدّ x تمامًا (فتبقى النتيجة 9x)، أو تربيعُ الأسّ بدل جمع المعاملَين (9x² أو 10x²).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('391dec15-bb8c-54ec-8884-c51df72961b6', '919bf39e-348b-5dce-8ef8-9609a665d7ad', 'انشر العبارة: 6×(2 + x).', '[{"id":"a","text":"6x + 2"},{"id":"b","text":"8x"},{"id":"c","text":"12x"},{"id":"d","text":"6x + 12"}]'::jsonb, 'd', 'نوزّع 6 على الحدَّين: 6×2 + 6×x = 12 + 6x، أي 6x+12 ✓. الخطأُ الشائع: نسيانُ توزيع 6 على العدد 2 (6x+2)، أو جمعُ 6+2=8 بدل التوزيع (8x)، أو ضربُ كلّ الحدود معًا في حدٍّ واحدٍ (12x).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5dcec62f-cb5a-57ad-b99e-37652a315c2a', '919bf39e-348b-5dce-8ef8-9609a665d7ad', 'عمِّل بإخراج أكبر عاملٍ مشترك ممكن: 8x + 12.', '[{"id":"a","text":"2(4x + 6)"},{"id":"b","text":"4(2x + 3)"},{"id":"c","text":"8(x + 12)"},{"id":"d","text":"4(2x + 12)"}]'::jsonb, 'b', 'القاسمُ المشتركُ الأكبر للعددين 8 و12 هو 4 (وليس 2)؛ 8x÷4=2x و12÷4=3، فالتعميلُ الأمثل هو 4(2x + 3) ✓. الخطأُ الشائع: التوقّفُ عند عاملٍ مشتركٍ غيرِ أكبريّ مثل 2 (فتبقى العبارةُ 2(4x+6) قابلةً للتبسيط أكثر)، أو أخطاءُ قسمةٍ عند إخراج 4 (4(2x+12))، أو اختيارُ 8 وهو ليس قاسمًا لـ 12.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('abe7c4a8-8c07-5cf0-9921-8d3588752a02', '919bf39e-348b-5dce-8ef8-9609a665d7ad', 'ثمنُ الوردة x دينار. اشترت هدى 5 وردات، ودفعت أيضًا 3 دنانير ثمن شريطٍ لتزيينها. إذا كان ثمنُ الوردة 2 دينار، فكم دفعت هدى بالكامل؟', '[{"id":"a","text":"10"},{"id":"b","text":"16"},{"id":"c","text":"13"},{"id":"d","text":"25"}]'::jsonb, 'c', 'العبارةُ الحرفية للمبلغ الكليّ هي 5x+3. نعوّض x بـ 2: 5×2+3 = 10+3 = 13 دينارًا ✓. الخطأُ الشائع: نسيانُ إضافة ثمن الشريط (10)، أو جمعُ 5+3 أوّلًا ثمّ الضربُ في 2 (16)، أو ضربُ 5 في المجموع (2+3) بدل توزيع الضرب (25).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

