  ('2112b5f1-7b80-59b2-840e-19832bc3367d', '899066c6-61c0-553f-8452-bca9147bdebc', 'math-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّةُ الحساب الحرفي', 4, 300, 60, 'challenge', 'admin', 6)
