INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('679eed2e-cb8e-5775-b73f-426cea60ee97', '2112b5f1-7b80-59b2-840e-19832bc3367d', 'احسب القيمةَ العدديّة للعبارة 3(x + 4) − 2x بعد اختزالها، عندما x = 5.', '[{"id":"a","text":"17"},{"id":"b","text":"9"},{"id":"c","text":"27"},{"id":"d","text":"37"}]'::jsonb, 'a', 'نبسّط العبارة أوّلًا: 3(x+4) − 2x = 3x+12−2x = x+12 (نجمع 3x و−2x فنحصل على x). نعوّض x بـ 5: 5+12=17 ✓. الخطأُ الشائع: نسيانُ توزيع 3 على الحدّ 4 (فتكون النتيجة 9)، أو نسيانُ طرح 2x تمامًا فتبقى 3x+12 وتُعطي 27، أو جمعُ 2x بدل طرحها فتُعطي 5x+12 وتُعطي 37.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('abcffe4a-5a16-54e3-9f9a-58938c89055a', '2112b5f1-7b80-59b2-840e-19832bc3367d', 'عبارةٌ حرفيةٌ هي 5x − 5×3. أيّ ممّا يلي يعمّلها بطريقةٍ صحيحة؟', '[{"id":"a","text":"5(x − 15)"},{"id":"b","text":"5(x − 3)"},{"id":"c","text":"x(5 − 15)"},{"id":"d","text":"5x(1 − 3)"}]'::jsonb, 'b', 'العبارةُ 5x − 5×3 = 5x − 15. القاسمُ المشتركُ هو 5؛ 5x÷5=x و15÷5=3، فالتعميلُ الصحيح هو 5(x − 3) ✓. الخطأُ الشائع: نسيانُ قسمة 15 على 5 فتبقى 15 كما هي (5(x−15))، أو اختيارُ عاملٍ مشتركٍ خطأ لا يقسم الحدَّين معًا بشكل صحيح.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e65d45ba-2058-5f53-b6d3-53a7dcb41ff3', '2112b5f1-7b80-59b2-840e-19832bc3367d', 'أيُّ العبارات التالية **غيرُ** صحيحةٍ مهما تكن قيمةُ x؟', '[{"id":"a","text":"x + 2x + 3x = 6x"},{"id":"b","text":"2(x + 4) = 2x + 8"},{"id":"c","text":"4x + x = 5x"},{"id":"d","text":"10x − 4x = 6x²"}]'::jsonb, 'd', 'العبارة (د) خاطئة: 10x − 4x = 6x (فرقُ المعاملَين 10−4=6، مع بقاء الحرف x بلا تربيع)، وليس 6x². أمّا العباراتُ الثلاثُ الأخرى فصحيحةٌ: (أ) 1+2+3=6، (ب) التوزيعُ الصحيح 2×x+2×4=2x+8، (ج) 4+1=5 لأنّ x=1x.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2c36b1db-fb7f-5d44-8997-6c65480ee4f7', '2112b5f1-7b80-59b2-840e-19832bc3367d', 'جدولٌ يبيّن ثمنَ الاشتراك الشهريّ في ناديين رياضيّين: النادي أ يتقاضى 10 دنانير ثابتة زائد 3 دنانير عن كلّ حصّة، والنادي ب يتقاضى 5 دنانير ثابتة زائد 5 دنانير عن كلّ حصّة. إذا رمزنا لعدد الحصص بـ x، فما العبارةُ الحرفيةُ لمجموع ما يدفعه مشتركٌ في النادي أ والنادي ب معًا (بعد الاختزال)؟', '[{"id":"a","text":"8x + 10"},{"id":"b","text":"15x + 8"},{"id":"c","text":"8x + 15"},{"id":"d","text":"8x + 5"}]'::jsonb, 'c', 'نجمع الثوابت: 10+5=15، ونجمع معاملات x: 3+5=8، فمجموعُ المصروفَين هو 8x+15 ✓. الخطأُ الشائع: نسيانُ ثابت أحد الناديين (8x+10 أو 8x+5)، أو الخلطُ بين موضعَي المعامل والثابت (15x+8).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('85848e65-5cf1-55fe-bb47-19db7a880656', '2112b5f1-7b80-59b2-840e-19832bc3367d', 'عبارةٌ حرفيةٌ على الشكل ax + b، حيث a وb عددان صحيحان، تساوي 6x + 18 بعد اختزالها، وتساوي أيضًا 2(3x + 9) بعد نشرها من صورةٍ معمَّلة. ما ناتجُ الجمع a + b؟', '[{"id":"a","text":"24"},{"id":"b","text":"20"},{"id":"c","text":"12"},{"id":"d","text":"9"}]'::jsonb, 'a', 'بمقارنة 6x+18 مع الصورة ax+b نستنتج a=6 وb=18، فمجموعُهما a+b=6+18=24 ✓. الخطأُ الشائع: الخلطُ بين a وb وبين العددين 3 و9 الظاهرين في الصورة المعمّلة 2(3x+9) (فيُحسب 3+9=12)، أو الخلطُ بين a والعامل الخارجيّ 2 في الصورة المعمّلة (2+18=20).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('842704b2-25f6-51c3-9b8c-fa5fea71f700', '2112b5f1-7b80-59b2-840e-19832bc3367d', 'ثمنُ القلم x دينار. اشترى وليد 4 أقلام، ثمّ أعاد قلمًا واحدًا لأنّه معطوب واسترجع ثمنَه. عبِّر حرفيًّا عن المبلغ الذي دفعه وليد فعليًّا (مختزَلًا)، ثمّ احسب قيمتَه إذا كان ثمنُ القلم 4 دنانير.', '[{"id":"a","text":"3"},{"id":"b","text":"12"},{"id":"c","text":"15"},{"id":"d","text":"16"}]'::jsonb, 'b', 'عبّر عن المبلغ حرفيًّا: اشترى 4 أقلامٍ بثمن 4x، ثمّ استرجع ثمنَ قلمٍ واحدٍ x، فالمبلغُ الفعليّ هو 4x − x = 3x (بعد اختزال الحدود المتشابهة). نعوّض x بـ 4: 3×4=12 دينارًا ✓. الخطأُ الشائع: نسيانُ خصم ثمن القلم المعادِ (فتكون النتيجة 16)، أو خصمُ دينارٍ واحدٍ فقط بدل ثمن القلم الكامل (4x−1 تُعطي 15)، أو نسيانُ ضرب المعامل 3 في قيمة x فتبقى النتيجة 3 فقط.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

