INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b925469a-df9a-5c8c-8e80-a524a733cb73', 'af07fc66-948e-511f-8cf3-38e14e7bb2f5', 'ما اسمُ الحرف الذي يمثّل العددَ غيرَ المعروف في معادلة؟', '[{"id":"a","text":"الحلّ"},{"id":"b","text":"المجهول"},{"id":"c","text":"المعامل"},{"id":"d","text":"الطرف"}]'::jsonb, 'b', 'المجهولُ هو الحرفُ (غالبًا x) الذي يرمز إلى عددٍ غيرِ معروف في المعادلة؛ الحلُّ هو قيمتُه العدديّة، والمعاملُ هو العددُ الذي يضربه.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8086f9f0-c543-5cc3-8ef6-7d9920f6576e', 'af07fc66-948e-511f-8cf3-38e14e7bb2f5', 'أيٌّ ممّا يلي معادلةٌ ذاتُ مجهول؟', '[{"id":"a","text":"7 + 5 = 12"},{"id":"b","text":"x + 4"},{"id":"c","text":"12 − 4"},{"id":"d","text":"x + 4 = 12"}]'::jsonb, 'd', 'المعادلةُ تحتاج إشارةَ = ومجهولًا معًا؛ (x + 4 = 12) تحقّق الشرطَين. أمّا (7 + 5 = 12) فمساواةٌ عدديّةٌ بلا مجهول، و(x + 4) و(12 − 4) عبارتان بلا إشارة =.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

