  ('48fcf01b-24f1-5981-a342-305d972d9fa9', 'af07fc66-948e-511f-8cf3-38e14e7bb2f5', 'هل x = 5 حلٌّ للمعادلة 2x + 1 = 11؟', '[{"id":"a","text":"نعم، لأنّ 2 × 5 + 1 = 11"},{"id":"b","text":"لا، لأنّ 2 × 5 + 1 = 10"},{"id":"c","text":"نعم، لأنّ 5 + 1 = 11"},{"id":"d","text":"لا، لأنّ المعادلة ليس لها حلّ"}]'::jsonb, 'a', 'نعوّض x = 5 في الطرف الأوّل: 2 × 5 + 1 = 10 + 1 = 11، وهو يساوي الطرفَ الثاني (11)، فـ x = 5 حلٌّ للمعادلة ✓.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

