  ('788c6b97-ff7f-5749-8d2a-764a4b658a68', 'af07fc66-948e-511f-8cf3-38e14e7bb2f5', 'ما حلُّ المعادلة x + 7 = 15؟', '[{"id":"a","text":"−8"},{"id":"b","text":"7"},{"id":"c","text":"8"},{"id":"d","text":"22"}]'::jsonb, 'c', 'نطرح 7 من الطرفَين: x = 15 − 7 = 8. التحقّق: 8 + 7 = 15 ✓. الخطأُ الشائع: جمعُ 7 بدل طرحه يعطي 22، أو عكسُ ترتيب الطرح (7 − 15) يعطي −8.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('24d7a099-471e-5452-98dc-0012731f99c1', 'af07fc66-948e-511f-8cf3-38e14e7bb2f5', 'ما حلُّ المعادلة 3x + 6 = 21؟', '[{"id":"a","text":"−5"},{"id":"b","text":"5"},{"id":"c","text":"9"},{"id":"d","text":"15"}]'::jsonb, 'b', 'نعزل الحدَّ الحرفيّ: 3x = 21 − 6 = 15، ثمّ نقسم على 3: x = 15 ÷ 3 = 5. التحقّق: 3 × 5 + 6 = 21 ✓. الخطأُ الشائع: جمعُ 6 بدل طرحه يعطي 9، أو نسيانُ القسمة النهائية يعطي 15.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

