INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6cbe2a4c-1662-5cf6-87be-fec97819a976', '173aab04-08f9-5048-9995-3f5bb4561155', 'ما معنى عبارة «حلُّ المعادلة»؟', '[{"id":"a","text":"العددُ الذي يجعل طرفَي المعادلة متساويَين"},{"id":"b","text":"أيُّ عددٍ نختاره عشوائيًّا"},{"id":"c","text":"الحرفُ الذي يمثّل المجهول"},{"id":"d","text":"الطرفُ الأيمن للمعادلة"}]'::jsonb, 'a', 'حلُّ المعادلة هو العددُ الذي، إذا عوّضنا به المجهولَ x، يجعل طرفَي المعادلة متساويَين. ليس أيَّ عددٍ عشوائيًّا، وليس هو الحرفَ نفسَه ولا طرفًا من طرفَي المعادلة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
