  ('8944c163-2bb0-5bc2-81d4-de91e25968c6', '173aab04-08f9-5048-9995-3f5bb4561155', 'في المعادلة 5x + 8 = 33، ما الحدُّ العدديُّ في الطرف الأوّل؟', '[{"id":"a","text":"5"},{"id":"b","text":"8"},{"id":"c","text":"33"},{"id":"d","text":"x"}]'::jsonb, 'b', 'الطرفُ الأوّل 5x + 8 يتكوّن من الحدّ الحرفيّ 5x (يضمّ المجهول) والحدّ العدديّ 8؛ أمّا 33 فهو الطرفُ الثاني كاملًا، وx هو المجهولُ نفسُه.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
