  ('8b2417b5-0dee-5be4-9c8b-1a49f4a846dd', '173aab04-08f9-5048-9995-3f5bb4561155', 'ما حلّ المعادلة x − 4 = 9؟', '[{"id":"a","text":"−5"},{"id":"b","text":"5"},{"id":"c","text":"9"},{"id":"d","text":"13"}]'::jsonb, 'd', 'نضيف 4 إلى الطرفَين: x = 9 + 4 = 13 ✓. التحقّق: 13 − 4 = 9 ✓. الخطأُ الشائع: طرحُ 4 بدل جمعه يعطي 5، أو عكسُ الترتيب (4 − 9) يعطي −5، أو تكرارُ العدد المعطى (9).', 4, 'mcq', NULL, NULL)
