  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d217f1b1-a820-5102-ad1b-9dad920ade9d', '173aab04-08f9-5048-9995-3f5bb4561155', 'ما حلّ المعادلة 4x = 28؟', '[{"id":"a","text":"7"},{"id":"b","text":"24"},{"id":"c","text":"28"},{"id":"d","text":"112"}]'::jsonb, 'a', 'نقسم الطرفَين على 4: x = 28 ÷ 4 = 7 ✓. التحقّق: 4 × 7 = 28 ✓. الخطأُ الشائع: ضربُ 28 × 4 بدل القسمة يعطي 112، أو نسيانُ القسمة والاكتفاءُ بـ 28، أو طرحُ 4 بدل القسمة عليه يعطي 24.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('45c97891-060e-58f2-86b2-ef31168e4eaf', '173aab04-08f9-5048-9995-3f5bb4561155', 'ما قيمة x في المعادلة 2x + 5 = 13؟', '[{"id":"a","text":"−4"},{"id":"b","text":"4"},{"id":"c","text":"8"},{"id":"d","text":"9"}]'::jsonb, 'b', 'نعزل الحدّ الحرفيّ: 2x = 13 − 5 = 8، نقسم على 2: x = 8 ÷ 2 = 4 ✓. التحقّق: 2×4+5 = 13 ✓. الخطأُ الشائع: نسيانُ القسمة النهائية يعطي 8 (وهو قيمة 2x لا x)، أو نقلُ 5 بإشارةٍ خاطئة (جمعُه بدل طرحه) يعطي 2x = 18 → x = 9، أو عكسُ ترتيب الطرح (5−13=−8) يعطي x = −4.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

