  ('2812b826-3841-5581-ad06-cd93ac7015dc', '55aac055-e3b9-5226-8743-2e0b2d950baf', 'عمرُ ليلى بعد أن يزيدَ 6 سنوات يصبح 17 سنة. ما عمرُ ليلى الآن؟', '[{"id":"a","text":"23"},{"id":"b","text":"17"},{"id":"c","text":"11"},{"id":"d","text":"−11"}]'::jsonb, 'c', 'المعادلة: x + 6 = 17. نطرح 6 من الطرفَين: x = 17 − 6 = 11 ✓. التحقّق: 11 + 6 = 17 ✓. عمرُ ليلى الآن 11 سنة. الخطأُ الشائع: جمعُ 6 بدل طرحه يعطي 23، أو تكرارُ العدد المعطى (17) دون حلّ، أو عكسُ الترتيب (6−17) يعطي −11.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
