  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('658dfe42-4a88-51f2-8990-e40b9c22600f', '55aac055-e3b9-5226-8743-2e0b2d950baf', 'ما حلّ المعادلة 6x + 9 = 39؟', '[{"id":"a","text":"−5"},{"id":"b","text":"5"},{"id":"c","text":"8"},{"id":"d","text":"30"}]'::jsonb, 'b', 'نعزل الحدّ الحرفيّ: 6x = 39 − 9 = 30، نقسم على 6: x = 30 ÷ 6 = 5 ✓. التحقّق: 6×5+9 = 39 ✓. الخطأُ الشائع: جمعُ 9 بدل طرحه يعطي 6x = 48 → x = 8، أو عكسُ الترتيب (9−39=−30) يعطي x = −5، أو نسيانُ القسمة النهائية يعطي 30.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b55dc743-f7cd-5b64-94c4-cae71b613629', '55aac055-e3b9-5226-8743-2e0b2d950baf', 'ما حلّ المعادلة −3x + 5 = 23؟', '[{"id":"a","text":"18"},{"id":"b","text":"6"},{"id":"c","text":"−6"},{"id":"d","text":"−18"}]'::jsonb, 'c', 'نعزل الحدّ الحرفيّ: −3x = 23 − 5 = 18، نقسم على −3: x = 18 ÷ (−3) = −6 ✓. التحقّق: −3×(−6)+5 = 18+5 = 23 ✓. الخطأُ الشائع: نسيانُ إشارة القسمة (القسمة على 3 بدل −3) يعطي 6 بدل −6، أو نسيانُ القسمة النهائية يعطي 18 (وهو قيمة −3x لا x).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d785f13d-9695-5740-9eab-bb4876e812e7', '55aac055-e3b9-5226-8743-2e0b2d950baf', 'ثمنُ تذكرة الحافلة x دينارًا. اشترى وسيمٌ 5 تذاكر، ودفع 10 دنانير رسمَ حجزٍ إضافيّ، فكان المجموعُ الكليّ 25 دينارًا. ما ثمنُ التذكرة الواحدة؟', '[{"id":"a","text":"3"},{"id":"b","text":"7"},{"id":"c","text":"15"},{"id":"d","text":"75"}]'::jsonb, 'a', 'نترجم المسألة: 5x + 10 = 25. نعزل الحدّ الحرفيّ: 5x = 25 − 10 = 15، نقسم على 5: x = 15 ÷ 5 = 3 ✓. التحقّق: 5×3+10 = 25 ✓. ثمنُ التذكرة الواحدة 3 دنانير. الخطأُ الشائع: جمعُ 10 بدل طرحه يعطي 5x = 35 → x = 7، أو نسيانُ القسمة يعطي 15، أو الضربُ بدل القسمة في الخطوة الأخيرة يعطي 75.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('920c47f2-ce0a-5df1-8963-4e7f35a7e1cb', '55aac055-e3b9-5226-8743-2e0b2d950baf', 'حلّ خالدٌ المعادلة 6x − 9 = 15 فكتب: 6x = 15 − 9 = 6، إذن x = 6 ÷ 6 = 1. لكن عند التحقّق: 6×1 − 9 = −3 ≠ 15. أين الخطأُ في حلّ خالد؟', '[{"id":"a","text":"نسي تغييرَ إشارة −9 عند نقلها؛ الصحيحُ 6x = 15 + 9 = 24"},{"id":"b","text":"أخطأ في القسمة الأخيرة فقط"},{"id":"c","text":"حلُّه صحيحٌ ولا يوجد خطأ"},{"id":"d","text":"نسي أن يتحقّق من الحلّ"}]'::jsonb, 'a', 'عند نقل الحدّ −9 من الطرف الأوّل، يجب تغييرُ إشارته إلى +9: 6x = 15 + 9 = 24، ثمّ x = 24 ÷ 6 = 4. بالتحقّق: 6×4−9 = 24−9 = 15 ✓. خطأُ خالد هو نسيانُ تغيير الإشارة عند النقل، فحصل على 6x = 6 بدل 6x = 24.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

