  ('13f350b4-e02c-591a-99a2-bd2c8dbd7c02', '70ff2bb3-60dd-5004-85d1-75e1cd839ea8', 'math-7eme', '⭐⭐ تمرينُ مراجعة (نمط امتحان): المعادلات', 2, 70, 15, 'practice', 'admin', 3)
