INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('eddc6074-1a52-5906-a66a-ff8987cf4758', '13f350b4-e02c-591a-99a2-bd2c8dbd7c02', 'أيٌّ ممّا يلي **ليست** معادلةً ذاتَ مجهول؟', '[{"id":"a","text":"2x = 10"},{"id":"b","text":"x + 3 = 7"},{"id":"c","text":"4x − 1 = 9"},{"id":"d","text":"5 + 2 = 7"}]'::jsonb, 'd', 'المعادلةُ ذاتُ المجهول تحتوي حرفًا يمثّل عددًا غيرَ معروف؛ (5 + 2 = 7) مساواةٌ عدديّةٌ صحيحة لكن بلا مجهول، فليست معادلةً ذاتَ مجهول، بخلاف الخيارات الأخرى التي تحتوي جميعًا الحرفَ x.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ef8249ff-98de-5ceb-80ad-cdd41fa0f6f4', '13f350b4-e02c-591a-99a2-bd2c8dbd7c02', 'هل x = 7 حلٌّ للمعادلة 2x − 3 = 11؟', '[{"id":"a","text":"نعم، لأنّ 2 × 7 − 3 = 11"},{"id":"b","text":"لا، لأنّ 2 × 7 − 3 = 17"},{"id":"c","text":"نعم، لأنّ 7 − 3 = 11"},{"id":"d","text":"لا، لأنّ 2 × 7 = 11"}]'::jsonb, 'a', 'نعوّض x = 7 في الطرف الأوّل: 2 × 7 − 3 = 14 − 3 = 11، وهو يساوي الطرفَ الثاني (11)، فـ x = 7 حلٌّ للمعادلة ✓.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('043a782d-ddb1-5117-9dc4-50ca5ef61c98', '13f350b4-e02c-591a-99a2-bd2c8dbd7c02', 'ما حلّ المعادلة x + 12 = 20؟', '[{"id":"a","text":"32"},{"id":"b","text":"20"},{"id":"c","text":"8"},{"id":"d","text":"−8"}]'::jsonb, 'c', 'نطرح 12 من الطرفَين: x = 20 − 12 = 8 ✓. التحقّق: 8 + 12 = 20 ✓. الخطأُ الشائع: جمعُ 12 بدل طرحه يعطي 32، أو تكرارُ العدد المعطى (20)، أو عكسُ الترتيب (12 − 20) يعطي −8.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('cdfab27c-c215-5e0f-8016-693efa47d908', '13f350b4-e02c-591a-99a2-bd2c8dbd7c02', 'ما حلّ المعادلة 5x − 10 = 20؟', '[{"id":"a","text":"−2"},{"id":"b","text":"2"},{"id":"c","text":"6"},{"id":"d","text":"30"}]'::jsonb, 'c', 'نعزل الحدّ الحرفيّ: 5x = 20 + 10 = 30 (الحدّ −10 يعبر فيصبح +10)، نقسم على 5: x = 30 ÷ 5 = 6 ✓. التحقّق: 5×6−10 = 20 ✓. الخطأُ الشائع: نسيانُ تغيير الإشارة يعطي 5x = 20−10 = 10 → x = 2، أو عكسُ الترتيب (10−20=−10) يعطي x = −2، أو نسيانُ القسمة النهائية يعطي 30.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8d56bc2d-265e-5ff7-aad9-b7050d2bc1c5', '13f350b4-e02c-591a-99a2-bd2c8dbd7c02', 'اشترت سامية 4 علبِ حليبٍ متماثلة الثمن، ودفعت 4 دنانير أجرةَ توصيل، فكان المجموعُ الكليّ 24 دينارًا. ما ثمنُ العلبة الواحدة؟', '[{"id":"a","text":"−5"},{"id":"b","text":"5"},{"id":"c","text":"7"},{"id":"d","text":"20"}]'::jsonb, 'b', 'نترجم المسألة: 4x + 4 = 24. نعزل الحدّ الحرفيّ: 4x = 24 − 4 = 20، نقسم على 4: x = 20 ÷ 4 = 5 ✓. التحقّق: 4×5+4 = 24 ✓. ثمنُ العلبة الواحدة 5 دنانير. الخطأُ الشائع: جمعُ 4 بدل طرحه يعطي 4x = 28 → x = 7، أو عكسُ الترتيب يعطي −5، أو نسيانُ القسمة يعطي 20.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('cb390459-1407-5208-88f8-c87d3c438151', '13f350b4-e02c-591a-99a2-bd2c8dbd7c02', 'ما حلّ المعادلة −4x + 6 = 18؟', '[{"id":"a","text":"−12"},{"id":"b","text":"−3"},{"id":"c","text":"3"},{"id":"d","text":"12"}]'::jsonb, 'b', 'نعزل الحدّ الحرفيّ: −4x = 18 − 6 = 12، نقسم على −4: x = 12 ÷ (−4) = −3 ✓. التحقّق: −4×(−3)+6 = 12+6 = 18 ✓. الخطأُ الشائع: نسيانُ إشارة القسمة (القسمة على 4 بدل −4) يعطي 3 بدل −3، أو نسيانُ القسمة النهائية يعطي 12، أو التوقّفُ عند خطوة الحدّ العدديّ فقط (6−18=−12) دون إتمام العزل والقسمة الصحيحة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a015f48c-e5b7-5fd5-91ec-790aaeaee58d', '70ff2bb3-60dd-5004-85d1-75e1cd839ea8', 'math-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: مسائلُ المعادلات', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
