INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('751c5af3-5cb1-5615-a203-98f3fe405251', 'a015f48c-e5b7-5fd5-91ec-790aaeaee58d', 'معادلةٌ من الشكل ax + 8 = 32، حيث a عددٌ صحيحٌ. عُلم أنّ حلَّها هو x = 4. ما قيمةُ a؟', '[{"id":"a","text":"−6"},{"id":"b","text":"6"},{"id":"c","text":"10"},{"id":"d","text":"24"}]'::jsonb, 'b', 'نعوّض x = 4 في المعادلة: 4a + 8 = 32. نعزل الحدّ الحرفيّ: 4a = 32 − 8 = 24، نقسم على 4: a = 24 ÷ 4 = 6 ✓. التحقّق: 6×4+8 = 24+8 = 32 ✓. الخطأُ الشائع: جمعُ 8 بدل طرحه يعطي 4a = 40 → a = 10، أو عكسُ الترتيب (8−32)/4 يعطي −6، أو نسيانُ القسمة يعطي 24.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b58ca8e4-b8af-5d93-9c85-f46503a97ad2', 'a015f48c-e5b7-5fd5-91ec-790aaeaee58d', 'أخوان: يوسف وكريم. عمرُ كريم يفوق عمرَ يوسف بـ 5 سنوات. إذا كان مجموعُ عمرَي يوسف وكريم يساوي 27 سنة، فما عمرُ يوسف؟', '[{"id":"a","text":"6"},{"id":"b","text":"11"},{"id":"c","text":"16"},{"id":"d","text":"22"}]'::jsonb, 'b', 'نسمّي x عمرَ يوسف، فيكون عمرُ كريم x + 5. المجموع: x + (x+5) = 27 → 2x + 5 = 27. نعزل الحدّ الحرفيّ: 2x = 27 − 5 = 22، نقسم على 2: x = 22 ÷ 2 = 11 ✓. عمرُ يوسف 11 سنة (وعمرُ كريم 16 سنة؛ التحقّق: 11+16=27 ✓). الخطأُ الشائع: جمعُ 5 بدل طرحه يعطي 2x = 32 → x = 16، أو نسيانُ مضاعفة x (معاملةُ المعادلة كأنّها x+5=27) يعطي 22، أو نسيانُ القسمة النهائية يعطي 22 أيضًا كتوقّفٍ مبكر.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('32b2e4b9-50aa-5f8e-875f-bd1b2e90459f', 'a015f48c-e5b7-5fd5-91ec-790aaeaee58d', 'أيُّ العبارات التالية صحيحة؟', '[{"id":"a","text":"حلّ المعادلة 2x − 4 = 10 هو x = 3"},{"id":"b","text":"حلّ المعادلة 5x + 1 = 16 هو x = 4"},{"id":"c","text":"حلّ المعادلة 7x + 2 = 30 هو x = 4"},{"id":"d","text":"حلّ المعادلة −2x + 3 = 9 هو x = 3"}]'::jsonb, 'c', 'نتحقّق من كلّ عبارة: (a) 2×3−4=2≠10، فحلُّ 2x−4=10 هو في الحقيقة x=7 لا 3. (b) 5×4+1=21≠16، فحلُّ 5x+1=16 هو في الحقيقة x=3 لا 4. (c) 7×4+2=30 ✓ صحيحة. (d) −2×3+3=−3≠9، فحلُّ −2x+3=9 هو في الحقيقة x=−3 لا 3. العبارةُ الصحيحة الوحيدة هي (c).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3afd0a1a-3d45-5491-9b41-28a02f1d1516', 'a015f48c-e5b7-5fd5-91ec-790aaeaee58d', 'حاول سليمٌ حلَّ المعادلة 7x − 4 = 24 على النحو التالي: 7x = 24 − 4 = 20، ثمّ x = 20 ÷ 7 (لم يُكمل القسمة لأنّها ليست عددًا صحيحًا)، فاستنتج أنّ المعادلة **ليس لها حلّ**. هل استنتاجُ سليم صحيح؟', '[{"id":"a","text":"نعم، لأنّ 20 لا يقبل القسمة على 7"},{"id":"b","text":"لا، لكنّ الحلّ الصحيح هو x = 20 ÷ 7"},{"id":"c","text":"نعم، كلّ معادلة من هذا الشكل تكون بلا حلّ عندما لا يُقسم العددُ تمامًا"},{"id":"d","text":"لا، استنتاجُه خاطئ؛ نسي تغييرَ إشارة −4 فحصل على 7x = 20 بدل 7x = 28؛ الحلُّ الصحيح x = 4"}]'::jsonb, 'd', 'عند نقل الحدّ −4 من الطرف الأوّل، يجب تغييرُ إشارته إلى +4: 7x = 24 + 4 = 28، ثمّ x = 28 ÷ 7 = 4، وهو عددٌ صحيح. التحقّق: 7×4−4 = 28−4 = 24 ✓. خطأُ سليم هو نسيانُ تغيير الإشارة عند النقل، ما جعله يصل إلى 7x = 20 (عددٌ لا يقبل القسمة على 7) بدل القيمة الصحيحة 7x = 28، فاستنتج خطأً أنّ المعادلة بلا حلّ.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('30a2c678-52df-54c2-95f2-1791983283fe', 'a015f48c-e5b7-5fd5-91ec-790aaeaee58d', 'قطع محمدٌ على درّاجته مسافةً x كم في الصباح، ثمّ قطع في المساء مسافةً تعادل ضِعفَ مسافة الصباح زائدَ 3 كم. إذا كانت المسافةُ الكليّةُ التي قطعها في اليوم 27 كم، فما المسافةُ التي قطعها في الصباح؟', '[{"id":"a","text":"24"},{"id":"b","text":"19"},{"id":"c","text":"10"},{"id":"d","text":"8"}]'::jsonb, 'd', 'نسمّي x المسافةَ في الصباح، فتكون مسافةُ المساء 2x + 3. المجموع: x + (2x+3) = 27 → 3x + 3 = 27. نعزل الحدّ الحرفيّ: 3x = 27 − 3 = 24، نقسم على 3: x = 24 ÷ 3 = 8 ✓. مسافةُ الصباح 8 كم (ومسافةُ المساء 2×8+3=19 كم؛ التحقّق: 8+19=27 ✓). الخطأُ الشائع: الإجابةُ بمسافة المساء (19) بدل مسافة الصباح المطلوبة، أو جمعُ 3 بدل طرحه يعطي 3x = 30 → x = 10، أو نسيانُ مضاعفة x يعطي 24.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8ee3833f-38d7-598a-b92b-62d288ac97f5', 'a015f48c-e5b7-5fd5-91ec-790aaeaee58d', 'لدى عمرَ مبلغٌ من المال قدرُه x دينارًا. اشترى بهذا المبلغ 3 كتبٍ متماثلة الثمن، ثمّ تبقّى معه 5 دنانير. عِلمًا أنّ ثمنَ الكتاب الواحد 12 دينارًا، أيُّ معادلةٍ تمثّل هذا الوضع؟', '[{"id":"a","text":"x − 12 = 5"},{"id":"b","text":"x + 36 = 5"},{"id":"c","text":"x − 36 = 5"},{"id":"d","text":"3x − 12 = 5"}]'::jsonb, 'c', 'أنفق عمرُ ثمنَ 3 كتبٍ، أي 3×12=36 دينارًا، فتبقّى معه من مبلغه الأصليّ x: x − 36 = 5 ✓ (وهذا يعطي x=41). الخيارُ (a) ينسى ضربَ ثمن الكتاب في 3، و(b) يخطئ في الإشارة (الإنفاقُ طرحٌ لا جمع)، و(d) يضرب x نفسَه في 3 بدل ثمن الكتاب، فيخلط بين الكمّيّة المتكرّرة والكمّيّة الأصليّة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

