INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ac1aea19-72f5-5bc3-8deb-fc233c8d062b', '7f7f30de-32dd-518e-952f-8fa074c4a2a2', 'هل x = 9 حلٌّ للمعادلة 3x − 7 = 20؟', '[{"id":"a","text":"نعم، لأنّ 3 × 9 − 7 = 20"},{"id":"b","text":"لا، لأنّ 3 × 9 − 7 = 27"},{"id":"c","text":"نعم، لأنّ 9 − 7 = 20"},{"id":"d","text":"لا، المعادلة ليس لها حلّ"}]'::jsonb, 'a', 'نعوّض x = 9 في الطرف الأوّل: 3 × 9 − 7 = 27 − 7 = 20، وهو يساوي الطرفَ الثاني (20)، فـ x = 9 حلٌّ للمعادلة ✓.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('06708d34-62fa-5f15-8df8-18029abcfdec', '7f7f30de-32dd-518e-952f-8fa074c4a2a2', 'ما حلّ المعادلة x − 15 = 8؟', '[{"id":"a","text":"−7"},{"id":"b","text":"7"},{"id":"c","text":"15"},{"id":"d","text":"23"}]'::jsonb, 'd', 'نضيف 15 إلى الطرفَين: x = 8 + 15 = 23 ✓. التحقّق: 23 − 15 = 8 ✓. الخطأُ الشائع: طرحُ 15 بدل جمعه يعطي −7، أو عكسُ الترتيب (15 − 8) يعطي 7، أو تكرارُ العدد المعطى (15).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('aab2fa79-4ede-5290-9913-37c73d3759d1', '7f7f30de-32dd-518e-952f-8fa074c4a2a2', 'ما حلّ المعادلة 9x = 63؟', '[{"id":"a","text":"7"},{"id":"b","text":"54"},{"id":"c","text":"72"},{"id":"d","text":"567"}]'::jsonb, 'a', 'نقسم الطرفَين على 9: x = 63 ÷ 9 = 7 ✓. التحقّق: 9 × 7 = 63 ✓. الخطأُ الشائع: ضربُ 63 × 9 بدل القسمة يعطي 567، أو جمعُ 9 بدل القسمة عليه يعطي 72، أو طرحُ 9 بدل القسمة عليه يعطي 54.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5c2987b9-7c54-568c-99ba-4d266ee6db03', '7f7f30de-32dd-518e-952f-8fa074c4a2a2', 'ثمنُ القميص يساوي أربعةَ أضعاف ثمن الجورب زائدَ 6 دنانير. إذا كان ثمنُ القميص 42 دينارًا، فما ثمنُ الجورب؟', '[{"id":"a","text":"−9"},{"id":"b","text":"9"},{"id":"c","text":"12"},{"id":"d","text":"36"}]'::jsonb, 'b', 'نترجم المسألة: 4x + 6 = 42. نعزل الحدّ الحرفيّ: 4x = 42 − 6 = 36، نقسم على 4: x = 36 ÷ 4 = 9 ✓. التحقّق: 4×9+6 = 42 ✓. ثمنُ الجورب 9 دنانير. الخطأُ الشائع: جمعُ 6 بدل طرحه يعطي 4x = 48 → x = 12، أو عكسُ الترتيب يعطي −9، أو نسيانُ القسمة يعطي 36.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('224ab4ff-1386-5ca5-ae5b-c1f55ebf74aa', '7f7f30de-32dd-518e-952f-8fa074c4a2a2', 'ما حلّ المعادلة −6x + 10 = −8؟', '[{"id":"a","text":"−18"},{"id":"b","text":"−3"},{"id":"c","text":"3"},{"id":"d","text":"18"}]'::jsonb, 'c', 'نعزل الحدّ الحرفيّ: −6x = −8 − 10 = −18، نقسم على −6: x = −18 ÷ (−6) = 3 ✓. التحقّق: −6×3+10 = −18+10 = −8 ✓. الخطأُ الشائع: نسيانُ إشارة القسمة (القسمة على 6 بدل −6) يعطي −3، أو نسيانُ القسمة النهائية يعطي −18، أو خلطُ الإشارات عبر الخطوات يعطي 18.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ddafef9e-5fa0-54a3-9e5e-6530405954c1', '7f7f30de-32dd-518e-952f-8fa074c4a2a2', 'اشترك ثلاثةُ أصدقاء في شراء هديّة: دفع أحمد x دينارًا، ودفع صديقاه معًا ضِعفَ ما دفعه أحمد، وأضافوا من صندوق النادي 6 دنانير، فكان الثمنُ الكليّ للهديّة 42 دينارًا. كم دفع أحمد؟', '[{"id":"a","text":"−12"},{"id":"b","text":"12"},{"id":"c","text":"16"},{"id":"d","text":"36"}]'::jsonb, 'b', 'مجموعُ ما دفعه الأصدقاءُ الثلاثة: x + 2x = 3x، زائدَ 6 دنانير من الصندوق: 3x + 6 = 42. نعزل الحدّ الحرفيّ: 3x = 42 − 6 = 36، نقسم على 3: x = 36 ÷ 3 = 12 ✓. دفع أحمد 12 دينارًا (وصديقاه معًا 24 دينارًا؛ التحقّق: 12+24+6=42 ✓). الخطأُ الشائع: جمعُ 6 بدل طرحه يعطي 3x = 48 → x = 16، أو عكسُ الترتيب يعطي −12، أو نسيانُ القسمة يعطي 36.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('29fce431-edff-5f05-893f-2d8c59309314', '70ff2bb3-60dd-5004-85d1-75e1cd839ea8', 'math-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّةُ فصل المعادلات', 4, 300, 60, 'challenge', 'admin', 6)
