INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d47961b6-a7a9-5143-b181-553cb5637ea0', '29fce431-edff-5f05-893f-2d8c59309314', 'معادلةٌ من الشكل 8x + b = c، حيث حلُّها x = 5، وc = 47. ما قيمةُ b؟', '[{"id":"a","text":"−7"},{"id":"b","text":"7"},{"id":"c","text":"40"},{"id":"d","text":"42"}]'::jsonb, 'b', 'نعوّض x = 5: 8×5 + b = 47 → 40 + b = 47. نعزل b: b = 47 − 40 = 7 ✓. التحقّق: 8×5+7 = 40+7 = 47 ✓. الخطأُ الشائع: نسيانُ ضرب 8×5 والاكتفاءُ بـ 47−5=42، أو عكسُ ترتيب الطرح (40−47) يعطي −7، أو التوقّفُ عند حساب 8×5=40 دون طرحٍ.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('84200b07-7e6a-58b4-97de-c012675fc7e1', '29fce431-edff-5f05-893f-2d8c59309314', 'حاول أربعةُ تلاميذ حلَّ معادلاتٍ مختلفة: هالة حلّت 5x + 3 = 28 ووجدت x = 5. نور حلّت 6x − 4 = 32 ووجدت x = 5. سامي حلّ 4x + 9 = 33 ووجد x = 7. ياسين حلّ −3x + 8 = −4 ووجد x = 5. أيُّ تلميذٍ توصّل إلى الحلّ الصحيح؟', '[{"id":"a","text":"هالة"},{"id":"b","text":"نور"},{"id":"c","text":"سامي"},{"id":"d","text":"ياسين"}]'::jsonb, 'a', 'نتحقّق من كلٍّ منهم: هالة: 5×5+3=28 ✓ صحيح. نور: 6×5−4=26≠32 (الحلُّ الصحيحُ لمعادلتها x=6). سامي: 4×7+9=37≠33 (الحلُّ الصحيحُ x=6). ياسين: −3×5+8=−7≠−4 (الحلُّ الصحيحُ x=4). التلميذةُ الوحيدةُ التي توصّلت إلى حلٍّ صحيحٍ هي هالة.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('03a593ee-eeda-573d-b593-235a0b4d9784', '29fce431-edff-5f05-893f-2d8c59309314', 'اشترى مزارعٌ 4 أرانبَ إضافية فأصبح لديه 10 أرانب. عددُ الدجاج في مزرعته x، ويحقّق العلاقةَ: x − 3 × (عددُ الأرانب قبل الشراء) = 3. ما قيمةُ x؟', '[{"id":"a","text":"−15"},{"id":"b","text":"15"},{"id":"c","text":"21"},{"id":"d","text":"33"}]'::jsonb, 'c', 'عددُ الأرانب قبل الشراء = 10 − 4 = 6. المعادلة: x − 3×6 = 3 → x − 18 = 3. نضيف 18 إلى الطرفَين: x = 3 + 18 = 21 ✓. التحقّق: 21 − 18 = 3 ✓. الخطأُ الشائع: استعمالُ عدد الأرانب الحاليّ (10) بدل العدد قبل الشراء (6) يعطي x−30=3 → x=33، أو طرحُ 18 بدل جمعه يعطي x=3−18=−15، أو عكسُ الترتيب (18−3) يعطي 15.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d74a9e19-a8c2-54b1-9c34-c842b40e911f', '29fce431-edff-5f05-893f-2d8c59309314', 'معادلةٌ من الشكل ax − 5 = c، حيث a = 7 وحلُّها x = −2. ما قيمةُ c؟', '[{"id":"a","text":"−19"},{"id":"b","text":"−14"},{"id":"c","text":"−9"},{"id":"d","text":"9"}]'::jsonb, 'a', 'نعوّض a=7 وx=−2 في المعادلة: c = 7×(−2) − 5 = −14 − 5 = −19 ✓. الخطأُ الشائع: نسيانُ طرح 5 يعطي −14، أو تغييرُ إشارة 5 خطأً (7×(−2)+5=−9)، أو نسيانُ الإشارة السالبة لـ x فيعطي 7×2−5=9.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('fdd77ac9-ca8f-527a-b3db-e9d546d9bc48', '29fce431-edff-5f05-893f-2d8c59309314', 'لمعادلةٍ 4x + b = 20، إذا كان b عددًا صحيحًا موجبًا، وكان حلُّ المعادلة x عددًا صحيحًا موجبًا أيضًا، فأيُّ القيم التالية **لا يمكن** أن تكون قيمةَ b؟', '[{"id":"a","text":"4"},{"id":"b","text":"8"},{"id":"c","text":"12"},{"id":"d","text":"15"}]'::jsonb, 'd', 'نحلّ عمومًا: 4x = 20 − b → x = (20−b) ÷ 4. لكي يكون x عددًا صحيحًا موجبًا، يجب أن يكون (20−b) مضاعفًا موجبًا لـ4. عند b=4: x=4 ✓. عند b=8: x=3 ✓. عند b=12: x=2 ✓. عند b=15: x=(20−15)÷4=5÷4، وهذا ليس عددًا صحيحًا، فلا يمكن أن تكون b=15 ✓ (وهي الإجابة). الخطأُ الشائع: اختيارُ إحدى القيم الصالحة (4 أو 8 أو 12) ظنًّا أنّ أيَّ عددٍ موجبٍ أصغرَ من 20 يصلح.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('13bf477a-0e3a-5b3e-8e52-d4b0f94068bb', '29fce431-edff-5f05-893f-2d8c59309314', 'وزّع أستاذٌ أقلامًا على 4 تلاميذ بالتساوي (x قلمًا لكلّ تلميذ)، ثمّ تبرّع بـ 5 أقلامٍ لجمعيّة القسم، فاستعمل في المجموع 45 قلمًا. إذا وزّع لاحقًا العددَ نفسَه x على 6 تلاميذ بلا تبرّعٍ هذه المرّة، فكم قلمًا استعمل في هذا التوزيع الثاني؟', '[{"id":"a","text":"10"},{"id":"b","text":"40"},{"id":"c","text":"60"},{"id":"d","text":"65"}]'::jsonb, 'c', 'نكوّن معادلةَ التوزيع الأوّل: 4x + 5 = 45. نعزل الحدّ الحرفيّ: 4x = 45 − 5 = 40، نقسم على 4: x = 40 ÷ 4 = 10، أي 10 أقلام لكلّ تلميذ. في التوزيع الثاني: 6 تلاميذ × 10 أقلام = 60 قلمًا، بلا تبرّعٍ هذه المرّة ✓. الخطأُ الشائع: الإجابةُ بقيمة x نفسِها (10) بدل عدد أقلام التوزيع الثاني المطلوب، أو نسيانُ القسمة في الخطوة الأولى فيُعطى 40، أو إضافةُ تبرّعٍ وهميّ في التوزيع الثاني (6×10+5=65) رغم أنّ السؤال ينصّ صراحةً على عدم وجود تبرّعٍ هذه المرّة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

