INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('dee98221-376e-5784-b362-8fe09a258451', '2780639b-a498-52d7-b864-50808bed07ee', 'ما الشرطُ الذي يجعل جدولًا جدولَ تناسب؟', '[{"id":"a","text":"نسبةُ كلّ عمود (القيمةُ الثانية ÷ القيمةُ الأولى) ثابتةٌ في كلّ الأعمدة"},{"id":"b","text":"مجموعُ قيمتَي كلّ عمود ثابت"},{"id":"c","text":"الفرقُ بين قيمتَي كلّ عمود ثابت"},{"id":"d","text":"عددُ الأعمدة في الجدول زوجيّ"}]'::jsonb, 'a', 'جدولُ التناسب هو الجدولُ الذي تكون فيه نسبةُ القيمة الثانية إلى القيمة الأولى (الثانية ÷ الأولى) واحدةً في كلّ أعمدته؛ المجموعُ والفرقُ لا يُستعملان لهذا التحقّق.', 1, 'mcq', NULL, NULL)
