  ('6aad2024-0465-51b2-bb33-c3531c1279a7', '2780639b-a498-52d7-b864-50808bed07ee', 'في جدول تناسب، الكمّيّةُ 3 تقابل 12. بنفس معامل التناسب، ماذا يقابل 6؟', '[{"id":"a","text":"15"},{"id":"b","text":"18"},{"id":"c","text":"24"},{"id":"d","text":"72"}]'::jsonb, 'c', 'معاملُ التناسب k = 12 ÷ 3 = 4، إذن القيمةُ المقابلة لـ 6 هي 6 × 4 = 24. الخطأُ الشائع: ضربُ 6 × 3 = 18 (زوجٌ خاطئ)، أو جمعُ 12 + 3 = 15، أو ضربُ 12 × 6 = 72.', 3, 'mcq', NULL, NULL)
