  ('2a50e7c3-9a7d-58be-a7bc-3a4a918545ba', '2780639b-a498-52d7-b864-50808bed07ee', 'ما 10 % من 200؟', '[{"id":"a","text":"20"},{"id":"b","text":"190"},{"id":"c","text":"210"},{"id":"d","text":"2000"}]'::jsonb, 'a', '10 % من 200 = (10 × 200) ÷ 100 = 2000 ÷ 100 = 20. الخطأُ الشائع: نسيانُ القسمة على 100 يعطي 2000، أو طرحُ/جمعُ 10 مباشرةً من 200 يعطي 190 أو 210.', 4, 'mcq', NULL, NULL)
