INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('99f9a87a-10d4-5e7a-b25c-397fcc2288c2', '89153b76-b72d-575e-a856-5c85465513b8', 'تحتاج وصفةٌ 2 كوبٍ من الدقيق لإعداد 8 كعكات. كم كوبًا من الدقيق نحتاج لإعداد 20 كعكة، بنفس التناسب؟', '[{"id":"a","text":"5"},{"id":"b","text":"8"},{"id":"c","text":"10"},{"id":"d","text":"40"}]'::jsonb, 'a', 'نكوّن جدول التناسب: 2 كوب ↔ 8 كعكات، x كوب ↔ 20 كعكة. الضربُ التقاطعيّ: x = (20 × 2) ÷ 8 = 40 ÷ 8 = 5 ✓. الخطأُ الشائع: تكرارُ العدد 8 المعطى في المسألة دون حساب، أو قسمةُ 20 ÷ 2 = 10 دون استعمال العدد 8، أو نسيانُ القسمة النهائية يعطي 40.', 1, 'mcq', NULL, NULL)
