INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('276cd131-2a0e-547a-84e3-19523c8be15a', '89153b76-b72d-575e-a856-5c85465513b8', 'على خريطةٍ سلّمُها 1/50000، المسافةُ بين مدينتَين 8 سم. ما المسافةُ الحقيقيّة بالكيلومتر؟', '[{"id":"a","text":"0,04 كم"},{"id":"b","text":"0,4 كم"},{"id":"c","text":"4 كم"},{"id":"d","text":"400 كم"}]'::jsonb, 'c', 'المسافةُ الحقيقيّة بالسنتيمتر = 8 × 50000 = 400000 سم، وبما أنّ 1 كم = 100000 سم، فإنّ المسافة = 400000 ÷ 100000 = 4 كم ✓. الخطأُ الشائع: القسمةُ على عاملٍ أكبرَ من اللازم يعطي 0,4 كم أو 0,04 كم، أو تحويلُ الوحدة إلى مترٍ فقط دون إتمام التحويل إلى كم يعطي 400 (كم بدل م).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0d15cff8-2ff2-5460-9774-27f42f599790', '89153b76-b72d-575e-a856-5c85465513b8', 'اشترى سامي 3 كغ برتقال بـ 9 دنانير، واشترت هدى 5 كغ من النوع نفسه بـ 14 دينارًا. هل الثمنُ متناسبٌ مع الكتلة في الحالتَين معًا؟', '[{"id":"a","text":"لا، لأنّ 9 ÷ 3 ≠ 14 ÷ 5"},{"id":"b","text":"نعم، لأنّ 9 ÷ 3 = 14 ÷ 5"},{"id":"c","text":"نعم، لأنّ 9 + 3 = 14 − 5"},{"id":"d","text":"لا يمكن تحديدُ ذلك"}]'::jsonb, 'a', 'نحسب نسبةَ كلّ حالة: 9 ÷ 3 = 3 (ثمنُ سامي للكيلوغرام)، و14 ÷ 5 = 2,8 (ثمنُ هدى للكيلوغرام). النسبتان مختلفتان (3 ≠ 2,8)، إذن الثمنُ **ليس** متناسبًا مع الكتلة في الحالتَين معًا.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5372bb68-1e60-5682-9b0b-95b59895cd84', '89153b76-b72d-575e-a856-5c85465513b8', 'تصنع مصنعُ عصيرٍ مزيجًا بنسبة 4 أجزاء ماء لكلّ جزءٍ واحدٍ من العصير المركّز (تناسبٌ مباشر). إذا استُعمل 3 لترات من العصير المركّز، كم لترًا من الماء يلزم؟', '[{"id":"a","text":"0,75"},{"id":"b","text":"4"},{"id":"c","text":"7"},{"id":"d","text":"12"}]'::jsonb, 'd', 'معاملُ التناسب k = 4 (الماءُ = 4 × العصير المركّز)، فكميّةُ الماء = 4 × 3 = 12 لترًا ✓. الخطأُ الشائع: قسمةُ 3 ÷ 4 = 0,75 (عكسُ الاتّجاه)، أو الاكتفاءُ بمعامل التناسب نفسِه (4) دون ضربه في 3، أو جمعُ 3 + 4 = 7 بدل الضرب.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('4ce3f598-9dd7-5ab5-8c50-95b738b3860d', 'c4a7e1bc-90a5-544a-9c66-3687429d2adb', 'math-7eme', '⭐⭐ تمرينُ مراجعة (نمط امتحان): وضعيات التناسب', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
