  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5dfb7c24-1eeb-51ec-b0e2-8e995346cf1d', '4ce3f598-9dd7-5ab5-8c50-95b738b3860d', 'الكمّيّةُ 4 تقابل 12، والكمّيّةُ 6 تقابل 18. هل هاتان الحالتان متناسبتان؟', '[{"id":"a","text":"نعم، لأنّ 12 ÷ 4 = 18 ÷ 6 = 3"},{"id":"b","text":"نعم، لأنّ 12 + 4 = 18 − 6"},{"id":"c","text":"لا، لأنّ 12 ÷ 4 ≠ 18 ÷ 6"},{"id":"d","text":"لا، لأنّ 4 ≠ 6"}]'::jsonb, 'a', 'نحسب نسبةَ كلّ حالة: 12 ÷ 4 = 3، و18 ÷ 6 = 3. النسبتان متساويتان (3 = 3)، إذن الحالتان متناسبتان؛ الفرقُ بين القيمتَين الأوّليّتَين (4 ≠ 6) لا يمنع التناسب.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('bb304d3e-ab51-5173-abe6-9d89305cf5ce', '4ce3f598-9dd7-5ab5-8c50-95b738b3860d', 'ثمنُ 6 لترات من الحليب 12 دينارًا. ما معاملُ التناسب (الثمن بدلالة عدد اللترات)؟', '[{"id":"a","text":"0,5"},{"id":"b","text":"2"},{"id":"c","text":"18"},{"id":"d","text":"72"}]'::jsonb, 'b', 'معاملُ التناسب k = الثمن ÷ عددُ اللترات = 12 ÷ 6 = 2. الخطأُ الشائع: قسمةُ عدد اللترات على الثمن (6 ÷ 12 = 0,5) بدل العكس، أو جمعُ العددَين (18) أو ضربُهما (72).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0e9a2ae0-bebf-5a42-b31c-595485c0d895', '4ce3f598-9dd7-5ab5-8c50-95b738b3860d', 'في جدول تناسب، الكمّيّةُ 5 تقابل 30. بنفس معامل التناسب، ماذا يقابل 8؟', '[{"id":"a","text":"6"},{"id":"b","text":"40"},{"id":"c","text":"48"},{"id":"d","text":"240"}]'::jsonb, 'c', 'معاملُ التناسب k = 30 ÷ 5 = 6، إذن القيمةُ المقابلة لـ 8 هي 8 × 6 = 48. الخطأُ الشائع: الاكتفاءُ بمعامل التناسب نفسِه (6)، أو ضربُ 8 × 5 = 40 (زوجٌ خاطئ)، أو ضربُ 30 × 8 = 240 دون القسمة على 5.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('add4bc8c-c5c8-52a6-ae2e-ea70848c2f69', '4ce3f598-9dd7-5ab5-8c50-95b738b3860d', 'كيف نكتب 75 % كسرًا؟', '[{"id":"a","text":"7,5/100"},{"id":"b","text":"75/100"},{"id":"c","text":"100/75"},{"id":"d","text":"75/10"}]'::jsonb, 'b', '75 % تعني 75 من كلّ 100، أي الكسر 75/100. الخطأُ الشائع: قلبُ البسط والمقام يعطي 100/75، أو تحريكُ الفاصلة يعطي 7,5/100 أو 75/10.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e6e9f12b-daaa-5b9c-a83a-1096a671dd3f', '4ce3f598-9dd7-5ab5-8c50-95b738b3860d', 'ثمنُ قميصٍ 80 دينارًا. اشتراه أحمد بتخفيضٍ نسبتُه 25 %. كم دينارًا وفّر أحمد (قيمةُ التخفيض)؟', '[{"id":"a","text":"20"},{"id":"b","text":"55"},{"id":"c","text":"60"},{"id":"d","text":"2000"}]'::jsonb, 'a', 'قيمةُ التخفيض = 25 % من 80 = (25 × 80) ÷ 100 = 2000 ÷ 100 = 20 دينارًا. الخطأُ الشائع: الإجابةُ بالثمن بعد التخفيض (80 − 20 = 60) بدل قيمة التخفيض نفسِها، أو طرحُ 25 مباشرةً كدينارٍ (80 − 25 = 55)، أو نسيانُ القسمة على 100 يعطي 2000.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('49b7699c-b4c7-511f-9daf-8a99947fe2d3', '4ce3f598-9dd7-5ab5-8c50-95b738b3860d', 'قطع مجموعةُ مشاةٍ مسافةَ 6 كم في 45 دقيقة. ما سرعتُهم المتوسّطة بـ كم/سا؟', '[{"id":"a","text":"0,13 كم/سا"},{"id":"b","text":"6,75 كم/سا"},{"id":"c","text":"8 كم/سا"},{"id":"d","text":"270 كم/سا"}]'::jsonb, 'c', 'نحوّل الزمن: 45 دقيقة = 45 ÷ 60 = 0,75 سا. السرعةُ = 6 ÷ 0,75 = 8 كم/سا ✓. الخطأُ الشائع: قسمةُ الزمن على المسافة (0,75 ÷ 6 ≈ 0,13) عكسَ الاتّجاه، أو جمعُهما (6,75)، أو ضربُ 6 × 45 = 270 دون تحويل الدقائق إلى ساعات ولا القسمة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

