  ('7773881c-275a-5f94-9261-c7fec2f71d5d', 'c4a7e1bc-90a5-544a-9c66-3687429d2adb', 'math-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: مسائلُ التناسب', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
