INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a46d5286-2306-56d6-b166-22476662af89', '7773881c-275a-5f94-9261-c7fec2f71d5d', 'في جدول تناسب، قيمةٌ في السطر الأوّل تقابل 24 في السطر الثاني، ومعاملُ التناسب هو 4. ما هذه القيمةُ في السطر الأوّل؟', '[{"id":"a","text":"6"},{"id":"b","text":"20"},{"id":"c","text":"28"},{"id":"d","text":"96"}]'::jsonb, 'a', 'بما أنّ القيمةُ الثانية = k × القيمةُ الأولى، فإنّ القيمةَ الأولى = القيمةُ الثانية ÷ k = 24 ÷ 4 = 6 ✓. الخطأُ الشائع: طرحُ k من 24 (20) أو جمعُه (28)، أو ضربُ 24 × 4 = 96 بدل القسمة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('520ce27b-c436-5487-b720-ca9e0cf4fb41', '7773881c-275a-5f94-9261-c7fec2f71d5d', 'بعد تخفيضٍ نسبتُه 20 %، أصبح ثمنُ حذاءٍ (بعد التخفيض) 64 دينارًا. ما كان ثمنُه الأصليّ (قبل التخفيض)؟', '[{"id":"a","text":"51,2"},{"id":"b","text":"76,8"},{"id":"c","text":"80"},{"id":"d","text":"84"}]'::jsonb, 'c', 'بعد تخفيضٍ 20 %، يبقى 80 % من الثمن الأصليّ P، أي 0,8 × P = 64، إذن P = 64 ÷ 0,8 = 80 دينارًا ✓ (تحقّق: 80 × 0,8 = 64). الخطأُ الشائع: ضربُ 64 × 0,8 = 51,2 (تطبيقُ التخفيض مرّةً ثانية)، أو ضربُ 64 × 1,2 = 76,8 (إضافةُ 20 % على الثمن النهائيّ بدل إعادة بناء الأصليّ)، أو جمعُ 20 دينارًا مباشرةً (64 + 20 = 84).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('66e522e7-4185-5d31-a682-df932cfd77ad', '7773881c-275a-5f94-9261-c7fec2f71d5d', 'غادرت حافلةٌ تونسَ في تمام الساعة 8:00 صباحًا ووصلت القيروانَ (على بعد 156 كم) في تمام الساعة 10:30 صباحًا. ما سرعتُها المتوسّطة بـ كم/سا؟', '[{"id":"a","text":"52 كم/سا"},{"id":"b","text":"62,4 كم/سا"},{"id":"c","text":"67,8 كم/سا"},{"id":"d","text":"78 كم/سا"}]'::jsonb, 'b', 'مدّةُ الرحلة من 8:00 إلى 10:30 هي ساعتان و30 دقيقة، أي 2,5 سا. السرعةُ = 156 ÷ 2,5 = 62,4 كم/سا ✓. الخطأُ الشائع: تقريبُ الزمن إلى 3 سا يعطي 52، أو تحويلُ 30 دقيقة إلى 0,3 سا خطأً (156 ÷ 2,3 ≈ 67,8)، أو إهمالُ نصف الساعة الإضافيّة كليًّا يعطي 156 ÷ 2 = 78.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6e28cddd-3630-5aba-bb04-b02781e258e3', '7773881c-275a-5f94-9261-c7fec2f71d5d', 'على مخطّطٍ سلّمُه 1/25000، أراد مصمّمٌ رسمَ مسارٍ حقيقيّ طولُه 5 كم. ما طولُ هذا المسار على المخطّط، بالسنتيمتر؟', '[{"id":"a","text":"0,2 سم"},{"id":"b","text":"2 سم"},{"id":"c","text":"5 سم"},{"id":"d","text":"20 سم"}]'::jsonb, 'd', 'المسافةُ الحقيقيّة بالسنتيمتر = 5 كم = 500000 سم. طولُ المخطّط = المسافةُ الحقيقيّة ÷ 25000 = 500000 ÷ 25000 = 20 سم ✓. الخطأُ الشائع: القسمةُ على عاملٍ عشريّ إضافيّ يعطي 2 سم أو 0,2 سم، أو استعمالُ مقام سلّمٍ خاطئ (القسمة على 100000 بدل 25000) يعطي 5 سم.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2eab842c-4484-5c5c-8719-c9685390f0b7', '7773881c-275a-5f94-9261-c7fec2f71d5d', 'في مصنع، 60 % من الإنتاج اليوميّ يُعبَّأ في علبٍ كبيرة، والباقي في علبٍ صغيرة. الإنتاجُ اليوميّ 350 علبة، وكلّ علبةٍ كبيرة تحتاج 4 دقائق للتعبئة. كم دقيقةً يستغرق تعبئةُ العلب الكبيرة فقط؟', '[{"id":"a","text":"140"},{"id":"b","text":"210"},{"id":"c","text":"840"},{"id":"d","text":"1400"}]'::jsonb, 'c', 'عددُ العلب الكبيرة = 60 % من 350 = (60 × 350) ÷ 100 = 210 علبة. زمنُ تعبئتها = 210 × 4 = 840 دقيقة ✓. الخطأُ الشائع: حسابُ عدد العلب الصغيرة (40 % من 350 = 140) بدل الكبيرة، أو التوقّفُ بعد حساب عدد العلب الكبيرة (210) دون ضربه في 4، أو ضربُ الإنتاج الكليّ في 4 (350 × 4 = 1400) متجاهلين النسبة المئوية.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
