INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8a8985f2-beff-5533-9072-27ca2b083fef', '7773881c-275a-5f94-9261-c7fec2f71d5d', 'يسير قطارٌ بسرعةٍ متوسّطة قدرُها 80 كم/سا. كم من الوقت (بالدقيقة) يحتاج لقطع مسافة 100 كم؟', '[{"id":"a","text":"75 دقيقة"},{"id":"b","text":"80 دقيقة"},{"id":"c","text":"85 دقيقة"},{"id":"d","text":"125 دقيقة"}]'::jsonb, 'a', 'الزمنُ = المسافة ÷ السرعة = 100 ÷ 80 = 1,25 سا. نحوّل إلى دقائق: 1,25 × 60 = 75 دقيقة ✓. الخطأُ الشائع: تكرارُ قيمة السرعة نفسِها (80)، أو تحويلُ الجزء العشريّ خطأً (0,25 × 100 = 25 ثمّ 60 + 25 = 85)، أو قراءةُ 1,25 كأنّها «125 دقيقة» مباشرةً دون تحويلٍ صحيح.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

