  ('5ca4d12d-e154-5ca5-9ca3-6a977aa34e25', 'c4a7e1bc-90a5-544a-9c66-3687429d2adb', 'math-7eme', '📝 تدريبٌ ⭐⭐⭐ شامل: وضعيات التناسب (مراجعةٌ عامّة)', 3, 120, 30, 'boss', 'admin', 5)
