INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('084d09ee-0ad2-5a6a-9700-f6d51f6b241b', '5ca4d12d-e154-5ca5-9ca3-6a977aa34e25', 'اشترى مراد 4 كغ سكّر بـ 8 دنانير، واشترت وفاء 6 كغ من السكّر نفسه بـ 12 دينارًا. هل الثمنُ متناسبٌ مع الكتلة في الحالتَين معًا؟', '[{"id":"a","text":"نعم، لأنّ 8 ÷ 4 = 12 ÷ 6 = 2"},{"id":"b","text":"نعم، لأنّ 8 + 4 = 12 − 6"},{"id":"c","text":"لا، لأنّ 8 ÷ 4 ≠ 12 ÷ 6"},{"id":"d","text":"لا، لأنّ 4 ≠ 6"}]'::jsonb, 'a', 'نحسب نسبةَ كلّ حالة: 8 ÷ 4 = 2، و12 ÷ 6 = 2. النسبتان متساويتان (2 = 2)، إذن الثمنُ متناسبٌ مع الكتلة في الحالتَين معًا.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5d95131d-9eca-58d9-9212-3fa1b2cd8e30', '5ca4d12d-e154-5ca5-9ca3-6a977aa34e25', 'في جدول تناسب، الكمّيّةُ 7 تقابل 21. بنفس معامل التناسب، ماذا يقابل 10؟', '[{"id":"a","text":"3"},{"id":"b","text":"21"},{"id":"c","text":"30"},{"id":"d","text":"70"}]'::jsonb, 'c', 'معاملُ التناسب k = 21 ÷ 7 = 3، إذن القيمةُ المقابلة لـ 10 هي 10 × 3 = 30. الخطأُ الشائع: الاكتفاءُ بمعامل التناسب نفسِه (3)، أو تكرارُ القيمة المعطاة (21)، أو ضربُ 10 × 7 = 70 (زوجٌ خاطئ).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9c6da4de-2987-5adf-b270-51dff5c067c2', '5ca4d12d-e154-5ca5-9ca3-6a977aa34e25', 'ما 15 % من 80؟', '[{"id":"a","text":"5,33"},{"id":"b","text":"12"},{"id":"c","text":"65"},{"id":"d","text":"1200"}]'::jsonb, 'b', '15 % من 80 = (15 × 80) ÷ 100 = 1200 ÷ 100 = 12. الخطأُ الشائع: القسمةُ العكسيّة (80 ÷ 15 ≈ 5,33)، أو طرحُ 15 مباشرةً من 80 (65)، أو نسيانُ القسمة على 100 يعطي 1200.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9b601482-56dc-5dc3-84ce-444ceb39beb6', '5ca4d12d-e154-5ca5-9ca3-6a977aa34e25', 'قطع سائقُ درّاجةٍ ناريّة 45 كم في 30 دقيقة. ما سرعتُه المتوسّطة بـ كم/سا؟', '[{"id":"a","text":"1,5 كم/سا"},{"id":"b","text":"22,5 كم/سا"},{"id":"c","text":"45 كم/سا"},{"id":"d","text":"90 كم/سا"}]'::jsonb, 'd', 'نحوّل الزمن: 30 دقيقة = 30 ÷ 60 = 0,5 سا. السرعةُ = 45 ÷ 0,5 = 90 كم/سا ✓. الخطأُ الشائع: القسمةُ على 30 مباشرةً دون تحويل الدقائق إلى ساعات (45 ÷ 30 = 1,5)، أو الضربُ بدل القسمة (45 × 0,5 = 22,5)، أو تكرارُ المسافة نفسِها (45) دون حساب.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('241c9047-bf8e-56fa-b4ab-6aa0fff766e7', '5ca4d12d-e154-5ca5-9ca3-6a977aa34e25', 'على خريطةٍ سلّمُها 1/10000، طولُ طريقٍ حقيقيّ 3 كم. ما طولُه على الخريطة بالسنتيمتر؟', '[{"id":"a","text":"0,3 سم"},{"id":"b","text":"3 سم"},{"id":"c","text":"30 سم"},{"id":"d","text":"300 سم"}]'::jsonb, 'c', 'المسافةُ الحقيقيّة بالسنتيمتر = 3 كم = 300000 سم. طولُ الخريطة = 300000 ÷ 10000 = 30 سم ✓. الخطأُ الشائع: استعمالُ العدد 3 مباشرةً كأنّه بالسنتيمتر (3 سم)، أو القسمةُ على عاملٍ أصغرَ من اللازم (300 سم)، أو على عاملٍ أكبرَ من اللازم (0,3 سم).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a0d20422-193e-54f9-b1e5-0b1872687960', '5ca4d12d-e154-5ca5-9ca3-6a977aa34e25', 'استهلكت درّاجةٌ ناريّة 10 لترات من الوقود لقطع 80 كم. بنفس معدّل الاستهلاك (تناسبٌ مباشر)، كم كيلومترًا تقطع بـ 25 لترًا من الوقود؟', '[{"id":"a","text":"8"},{"id":"b","text":"200"},{"id":"c","text":"250"},{"id":"d","text":"2000"}]'::jsonb, 'b', 'نكوّن جدولَ التناسب: 10 لتر ↔ 80 كم، 25 لتر ↔ x كم. الضربُ التقاطعيّ: x = (25 × 80) ÷ 10 = 2000 ÷ 10 = 200 ✓. الخطأُ الشائع: التوقّفُ عند حساب معامل التناسب (80 ÷ 10 = 8) دون ضربه في 25، أو ضربُ 25 × 10 = 250 (زوجٌ خاطئ)، أو نسيانُ القسمة النهائية يعطي 2000.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('dfd4db71-e1e4-5132-8c76-a9941a687b20', 'c4a7e1bc-90a5-544a-9c66-3687429d2adb', 'math-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّةُ فصل التناسب', 4, 300, 60, 'challenge', 'admin', 6)
