INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('34d5295a-a7fb-5665-9ff2-de48b042cc8e', 'dfd4db71-e1e4-5132-8c76-a9941a687b20', 'معاملُ تناسبٍ بين الزمن (بالدقيقة) والمسافة (بالمتر) هو 50 (كلّ دقيقة تقطع الدرّاجةُ 50 مترًا). إذا قطعت الدرّاجةُ 600 متر، كم دقيقة استغرقت؟', '[{"id":"a","text":"12"},{"id":"b","text":"550"},{"id":"c","text":"650"},{"id":"d","text":"30000"}]'::jsonb, 'a', 'بما أنّ المسافةَ = k × الزمن، فإنّ الزمنَ = المسافة ÷ k = 600 ÷ 50 = 12 دقيقة ✓. الخطأُ الشائع: طرحُ k من المسافة (550) أو جمعُه (650)، أو ضربُ 600 × 50 = 30000 بدل القسمة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('dfbb3094-d310-50f4-af1f-e4ed0593d48b', 'dfd4db71-e1e4-5132-8c76-a9941a687b20', 'حاول أربعةُ تلاميذ حسابَ 30 % من كمّيّاتٍ مختلفة: سامر حسب 30 % من 200 فوجد 60. ريم حسبت 30 % من 150 فوجدت 35. أنسٌ حسب 30 % من 90 فوجد 30. لينة حسبت 30 % من 40 فوجدت 15. أيُّ تلميذٍ توصّل إلى نتيجةٍ صحيحة؟', '[{"id":"a","text":"سامر"},{"id":"b","text":"ريم"},{"id":"c","text":"أنس"},{"id":"d","text":"لينة"}]'::jsonb, 'a', 'نتحقّق من كلٍّ منهم: سامر: (30×200)÷100 = 60 ✓ صحيح. ريم: (30×150)÷100 = 45 ≠ 35 (نتيجتُها الصحيحة 45). أنس: (30×90)÷100 = 27 ≠ 30 (نتيجتُه الصحيحة 27). لينة: (30×40)÷100 = 12 ≠ 15 (نتيجتُها الصحيحة 12). التلميذُ الوحيدُ الذي توصّل إلى نتيجةٍ صحيحة هو سامر.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('75526065-1155-58dd-87f8-4463567364c3', 'dfd4db71-e1e4-5132-8c76-a9941a687b20', 'قطع قطارٌ سياحيّ مسافةً بسرعةٍ متوسّطة قدرُها 60 كم/سا خلال ساعتَين. أراد السائقُ قطعَ المسافة نفسِها في زمنٍ أقصرَ بنسبة 25 %. ما السرعةُ المتوسّطة الجديدة اللازمة؟', '[{"id":"a","text":"45 كم/سا"},{"id":"b","text":"60 كم/سا"},{"id":"c","text":"80 كم/سا"},{"id":"d","text":"160 كم/سا"}]'::jsonb, 'c', 'المسافةُ = 60 × 2 = 120 كم. الزمنُ الجديد = 2 × (1 − 0,25) = 2 × 0,75 = 1,5 سا. السرعةُ الجديدة = 120 ÷ 1,5 = 80 كم/سا ✓. الخطأُ الشائع: تطبيقُ نسبة 25 % مباشرةً على السرعة (60 × 0,75 = 45) بدل الزمن، أو تكرارُ السرعة الأصليّة (60) دون إعادة حساب، أو قسمةُ المسافة على 0,75 مباشرةً (120 ÷ 0,75 = 160) بدل الزمن الجديد المحسوب.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('03e73164-c462-58bf-9b50-4701951d4d51', 'dfd4db71-e1e4-5132-8c76-a9941a687b20', 'على مخطّطٍ سلّمُه 1/20000، تفصل بين مدرستَين مسافةٌ قدرُها 5 سم. إذا سار تلميذٌ بسرعةٍ متوسّطة قدرُها 4 كم/سا، فكم دقيقةً يحتاج لقطع هذه المسافة الحقيقيّة سيرًا على الأقدام؟', '[{"id":"a","text":"4 دقائق"},{"id":"b","text":"15 دقيقة"},{"id":"c","text":"25 دقيقة"},{"id":"d","text":"60 دقيقة"}]'::jsonb, 'b', 'المسافةُ الحقيقيّة = 5 × 20000 = 100000 سم = 1000 م = 1 كم. الزمنُ = المسافة ÷ السرعة = 1 ÷ 4 = 0,25 سا = 0,25 × 60 = 15 دقيقة ✓. الخطأُ الشائع: تكرارُ قيمة السرعة نفسِها (4) كأنّها الجواب، أو أخطاءُ تحويل الوحدات أثناء حساب المسافة الحقيقيّة أو الزمن (تُعطي 25 أو 60 دقيقة).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('64101792-8062-5b85-a94c-f2a4b10294b4', 'dfd4db71-e1e4-5132-8c76-a9941a687b20', 'بعد زيادةٍ نسبتُها 20 % على راتب عاملٍ، أصبح راتبُه الجديد (شاملَ الزيادة) 480 دينارًا. ما كان راتبُه قبل الزيادة؟', '[{"id":"a","text":"384"},{"id":"b","text":"400"},{"id":"c","text":"460"},{"id":"d","text":"576"}]'::jsonb, 'b', 'الراتبُ الجديد يساوي 120 % من الراتب الأصليّ P، أي 1,2 × P = 480، إذن P = 480 ÷ 1,2 = 400 دينارًا ✓ (تحقّق: 400 × 1,2 = 480). الخطأُ الشائع: ضربُ 480 × 0,8 = 384 (تطبيقُ نسبةٍ خاطئة)، أو طرحُ 20 دينارًا مباشرةً (480 − 20 = 460)، أو ضربُ 480 × 1,2 = 576 (تكرارُ الزيادة بدل إلغائها).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d15905a3-c435-51e0-8aef-432ed1a56503', 'dfd4db71-e1e4-5132-8c76-a9941a687b20', 'اشترت جمعيّةٌ خيريّة 25 كغ من الأرزّ بثمنٍ متناسبٍ مع الكتلة قدرُه 50 دينارًا. وزّعت الجمعيّةُ 60 % من هذه الكمّية على العائلات المحتاجة. إذا أرادت شراءَ كمّيّةٍ جديدة بنفس الثمن للكيلوغرام لتعويض ما وُزِّع بالضبط، فكم دينارًا ستدفع؟', '[{"id":"a","text":"7,5"},{"id":"b","text":"20"},{"id":"c","text":"30"},{"id":"d","text":"50"}]'::jsonb, 'c', 'ثمنُ الكيلوغرام = 50 ÷ 25 = 2 دينارًا. الكمّيّةُ الموزَّعة = 60 % من 25 = (60×25)÷100 = 15 كغ. ثمنُ التعويض = 15 × 2 = 30 دينارًا ✓. الخطأُ الشائع: استعمالُ نسبة 40 % المتبقّية بدل 60 % الموزَّعة (10 كغ × 2 = 20)، أو قلبُ ثمن الكيلوغرام (25÷50=0,5 بدل 2) يعطي 15×0,5=7,5، أو تكرارُ الثمن الكليّ الأصليّ (50) دون إعادة الحساب.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a9543455-82be-569a-bada-e43d137b2cdf', '62dcbaf6-a93a-5a9a-b488-c431976a0775', 'math-7eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
