INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('03b65d80-0660-51fc-bd2c-939eab6a8043', 'a9543455-82be-569a-bada-e43d137b2cdf', 'في دراسةٍ إحصائيّة، ماذا نُسمّي الخاصّيةَ التي نلاحظها أو نسألُ عنها في كلّ عنصر (مثل وسيلة النقل المفضّلة)؟', '[{"id":"a","text":"الصفةُ المدروسة"},{"id":"b","text":"الجمعُ الإحصائيّ"},{"id":"c","text":"القيمةُ الممكنة"},{"id":"d","text":"التواترُ"}]'::jsonb, 'a', 'الصفةُ المدروسة هي الخاصّيةُ التي نلاحظها في كلّ عنصر من عناصر الجمع الإحصائيّ، مثل وسيلة النقل هنا؛ أمّا الجمعُ الإحصائيّ فهو مجموعةُ العناصر المدروسة كلِّها، والقيمةُ إحدى الإجابات الممكنة، والتواترُ عددُ مرّاتِ ظهور قيمةٍ ما.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7955c35a-8510-5110-b710-13135d600b93', 'a9543455-82be-569a-bada-e43d137b2cdf', 'ما اسمُ عددِ المرّات التي تظهر فيها قيمةٌ معيّنة ضمن مجموعة بيانات؟', '[{"id":"a","text":"الجمعُ الإحصائيّ"},{"id":"b","text":"القيمةُ الممكنة"},{"id":"c","text":"جدولُ التعدادات"},{"id":"d","text":"التواترُ (العددُ المطلق)"}]'::jsonb, 'd', 'هذا العددُ يسمّى تواترَ القيمة أو عددَها المطلق؛ أمّا الجمعُ الإحصائيّ فهو مجموعةُ العناصر المدروسة، والقيمةُ إحدى الإجاباتِ الممكنة، وجدولُ التعدادات هو الأداةُ التي نستعملها لعدّ هذه التواترات.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('db927c97-9a99-5ff6-b9ea-d6fdafe18dfd', 'a9543455-82be-569a-bada-e43d137b2cdf', 'سأل تلميذٌ 12 زميلًا عن لونهم المفضّل، فحصل على جدول التعداد التالي: أزرق: |||| — أحمر: ||| — أخضر: |||||. ما تواترُ اللون الأخضر؟', '[{"id":"a","text":"3"},{"id":"b","text":"4"},{"id":"c","text":"5"},{"id":"d","text":"12"}]'::jsonb, 'c', 'نعدّ علاماتِ التعداد أمام «أخضر»: ||||| أي 5 علامات، فتواترُ اللون الأخضر 5. (تواترُ الأزرق 4، وتواترُ الأحمر 3، والمجموع 4+3+5=12 وهو عددُ التلاميذ ✓.)', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('66fd7df5-1d43-5d9c-b1ea-106f26925a48', 'a9543455-82be-569a-bada-e43d137b2cdf', 'في جدول تعداداتٍ يخصّ 30 تلميذًا، توتراتُ القيم الأربع هي: 8؛ 10؛ 6؛ وس. ما قيمةُ س؟', '[{"id":"a","text":"4"},{"id":"b","text":"6"},{"id":"c","text":"8"},{"id":"d","text":"24"}]'::jsonb, 'b', 'مجموعُ كلّ التوترات يساوي التعدادَ الكليّ: 8+10+6+س=30، أي 24+س=30، فـ س=30−24=6.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c9a2d8b7-2fbd-531f-8031-25315fdbbaf3', 'a9543455-82be-569a-bada-e43d137b2cdf', 'يمثّل الرسمُ البيانيُّ التالي وسيلةَ النقل المفضّلة لدى 20 تلميذًا (أ: حافلة، ب: مشيًا، ج: دراجة، د: سيارة). ما وسيلةُ النقل الأكثر استعمالًا؟
<svg viewBox="0 0 220 150" xmlns="http://www.w3.org/2000/svg"><line x1="20" y1="10" x2="20" y2="130" stroke="#1f2937" stroke-width="1.5"/><line x1="20" y1="130" x2="210" y2="130" stroke="#1f2937" stroke-width="1.5"/><rect x="35" y="50" width="30" height="80" fill="#f97316" stroke="#1f2937" stroke-width="1.5"/><rect x="80" y="70" width="30" height="60" fill="#3b82f6" stroke="#1f2937" stroke-width="1.5"/><rect x="125" y="90" width="30" height="40" fill="#10b981" stroke="#1f2937" stroke-width="1.5"/><rect x="170" y="110" width="30" height="20" fill="#eab308" stroke="#1f2937" stroke-width="1.5"/><text x="50" y="45" font-size="13" text-anchor="middle" fill="#1f2937">8</text><text x="95" y="65" font-size="13" text-anchor="middle" fill="#1f2937">6</text><text x="140" y="85" font-size="13" text-anchor="middle" fill="#1f2937">4</text><text x="185" y="105" font-size="13" text-anchor="middle" fill="#1f2937">2</text><text x="50" y="145" font-size="13" text-anchor="middle" fill="#1f2937">أ</text><text x="95" y="145" font-size="13" text-anchor="middle" fill="#1f2937">ب</text><text x="140" y="145" font-size="13" text-anchor="middle" fill="#1f2937">ج</text><text x="185" y="145" font-size="13" text-anchor="middle" fill="#1f2937">د</text></svg>', '[{"id":"a","text":"سيارة"},{"id":"b","text":"دراجة"},{"id":"c","text":"مشيًا"},{"id":"d","text":"حافلة"}]'::jsonb, 'd', 'العمودُ الأعلى في الرسم هو العمودُ أ (حافلة) بارتفاعٍ يمثّل التواتر 8، وهو أكبرُ التواترات الأربعة (8؛ 6؛ 4؛ 2)، فالحافلةُ هي وسيلةُ النقل الأكثر استعمالًا.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

