INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6d026295-535f-55e2-81f9-6093bf89e184', '37c10dd2-648d-5ac8-b2ac-80b4d2f96daa', 'ماذا نسمّي مجموعةَ العناصر (الأشخاص أو الأشياء) التي نجري عليها الدراسةَ الإحصائيّة؟', '[{"id":"a","text":"الجمعُ الإحصائيّ"},{"id":"b","text":"الصفةُ المدروسة"},{"id":"c","text":"القيمةُ الممكنة"},{"id":"d","text":"التواترُ"}]'::jsonb, 'a', 'الجمعُ الإحصائيّ هو مجموعةُ العناصر (هنا تلاميذُ القسم مثلًا) التي نجري عليها الدراسةَ؛ الصفةُ المدروسة هي ما نلاحظه في كلّ عنصر، والقيمةُ إحدى الإجابات الممكنة، والتواترُ عددُ ظهورِ قيمةٍ ما.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
