  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('437adf2c-2e92-5ac4-b7cd-10abac80cabd', '37c10dd2-648d-5ac8-b2ac-80b4d2f96daa', 'في استبيانٍ عن الفاكهة المفضّلة، ما مثالٌ على «قيمةٍ ممكنة» للصفة المدروسة؟', '[{"id":"a","text":"عددُ التلاميذ"},{"id":"b","text":"تفّاح"},{"id":"c","text":"التواترُ"},{"id":"d","text":"جدولُ التعدادات"}]'::jsonb, 'b', 'القيمُ الممكنة هي الإجاباتُ التي يمكن أن يعطيَها كلُّ عنصر للصفة المدروسة؛ هنا «تفّاح» إجابةٌ ممكنة لسؤال «ما فاكهتُك المفضّلة؟»، أمّا الباقي فمفاهيمُ إحصائيّةٌ أخرى لا قيمًا.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6f3a3e66-1020-5969-9af9-c29ebc01c3db', '37c10dd2-648d-5ac8-b2ac-80b4d2f96daa', 'سأل تلميذٌ 16 زميلًا عن فاكهتهم المفضّلة، فحصل على جدول التعداد: تفّاح: ||||||| — موز: ||||| — برتقال: ||| — عنب: |. ما تواترُ فاكهة الموز؟', '[{"id":"a","text":"1"},{"id":"b","text":"3"},{"id":"c","text":"5"},{"id":"d","text":"7"}]'::jsonb, 'c', 'نعدّ علاماتِ التعداد أمام «موز»: ||||| أي 5 علامات، فتواترُ الموز 5. (تواترُ التفّاح 7، والبرتقال 3، والعنب 1؛ المجموع 7+5+3+1=16 ✓.)', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
