INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c566b0d4-abc3-5a8a-badf-166715139ae9', '38bab7bb-df2a-5b27-95fa-4913c7fa0cce', 'يمثّل الرسمُ البيانيُّ التالي توزيعَ تقديرات 30 تلميذًا (أ: ممتاز، ب: جيّد جدًّا، ج: جيّد، د: متوسّط). ما التقديرُ الأكثرُ تكرارًا؟
<svg viewBox="0 0 220 150" xmlns="http://www.w3.org/2000/svg"><line x1="20" y1="10" x2="20" y2="130" stroke="#1f2937" stroke-width="1.5"/><line x1="20" y1="130" x2="210" y2="130" stroke="#1f2937" stroke-width="1.5"/><rect x="35" y="58" width="30" height="72" fill="#f97316" stroke="#1f2937" stroke-width="1.5"/><rect x="80" y="40" width="30" height="90" fill="#3b82f6" stroke="#1f2937" stroke-width="1.5"/><rect x="125" y="49" width="30" height="81" fill="#10b981" stroke="#1f2937" stroke-width="1.5"/><rect x="170" y="103" width="30" height="27" fill="#eab308" stroke="#1f2937" stroke-width="1.5"/><text x="50" y="53" font-size="13" text-anchor="middle" fill="#1f2937">8</text><text x="95" y="35" font-size="13" text-anchor="middle" fill="#1f2937">10</text><text x="140" y="44" font-size="13" text-anchor="middle" fill="#1f2937">9</text><text x="185" y="98" font-size="13" text-anchor="middle" fill="#1f2937">3</text><text x="50" y="145" font-size="13" text-anchor="middle" fill="#1f2937">أ</text><text x="95" y="145" font-size="13" text-anchor="middle" fill="#1f2937">ب</text><text x="140" y="145" font-size="13" text-anchor="middle" fill="#1f2937">ج</text><text x="185" y="145" font-size="13" text-anchor="middle" fill="#1f2937">د</text></svg>', '[{"id":"a","text":"ممتاز"},{"id":"b","text":"جيّد جدًّا"},{"id":"c","text":"جيّد"},{"id":"d","text":"متوسّط"}]'::jsonb, 'b', 'أعلى عمودٍ في الرسم هو ب (جيّد جدًّا) بارتفاعٍ يمثّل التواتر 10، وهو أكبرُ التواترات الأربعة (8؛ 10؛ 9؛ 3)، فتقديرُ «جيّد جدًّا» هو الأكثرُ تكرارًا بين التلاميذ.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('962e95b2-7fd8-51f1-9bdf-28bc421cc33a', '38bab7bb-df2a-5b27-95fa-4913c7fa0cce', 'كم عددُ التلاميذ الذين **لم** يحصلوا على تقدير «ممتاز»؟', '[{"id":"a","text":"3"},{"id":"b","text":"8"},{"id":"c","text":"22"},{"id":"d","text":"30"}]'::jsonb, 'c', 'عددُ من لم يحصل على «ممتاز» = التعدادُ الكليّ − تواترُ «ممتاز» = 30−8=22 تلميذًا. الخطأُ الشائع: الإجابةُ بتواتر «ممتاز» نفسِه (8)، أو بتواتر «متوسّط» (3) خطأً، أو نسيانُ الطرح والاكتفاءُ بالعدد الكليّ (30).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('dba7af75-24cd-57e6-a7d7-df3b4e8d58e0', '38bab7bb-df2a-5b27-95fa-4913c7fa0cce', 'بكم يفوق تواترُ «جيّد جدًّا» تواترَ «متوسّط»؟', '[{"id":"a","text":"1"},{"id":"b","text":"3"},{"id":"c","text":"5"},{"id":"d","text":"7"}]'::jsonb, 'd', 'الفرقُ بين تواتر «جيّد جدًّا» (10) وتواتر «متوسّط» (3) هو 10−3=7 ✓. الخطأُ الشائع: الخلطُ بين «متوسّط» و«جيّد» فيُحسب 10−9=1، أو الاكتفاءُ بتواتر «متوسّط» نفسِه (3).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('163df8ed-ab2d-554b-bb29-13325523a3da', '38bab7bb-df2a-5b27-95fa-4913c7fa0cce', 'عدّ إلياسُ توتراتِ التقييم من جدولٍ فوجد: ممتاز |||||||| (8)، جيّد جدًّا |||||||||| (10)، جيّد ||||||||| (9)، متوسّط ||| (3)، فاستنتج أنّ عددَ التلاميذ الكليّ 30. تحقّق زميلُه فوجد أنّ إلياسَ عدّ عمودَ «جيّد» بـ9 علاماتٍ بينما الجدولُ الأصليّ يحوي 8 علاماتٍ فقط له. ما العددُ الكليّ الصحيحُ للتلاميذ؟', '[{"id":"a","text":"29"},{"id":"b","text":"30"},{"id":"c","text":"31"},{"id":"d","text":"33"}]'::jsonb, 'a', 'نصحّح تواترَ «جيّد» إلى 8 بدل 9: المجموعُ الصحيحُ = 8(ممتاز)+10(جيّدجدًّا)+8(جيّد)+3(متوسّط)=29 تلميذًا، لا 30 كما ظنّ إلياسُ بسبب خطئه في العدّ. الخطأُ الشائع: البقاءُ عند نتيجة إلياس الخاطئة (30)، أو أخطاءُ جمعٍ إضافية تعطي 31 أو 33.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('93c50e8b-6206-5e51-baba-cfae59763c4f', '38bab7bb-df2a-5b27-95fa-4913c7fa0cce', 'أيُّ العبارات التالية صحيحةٌ بخصوص تقييم الثلاثين تلميذًا (ممتاز 8، جيّد جدًّا 10، جيّد 9، متوسّط 3)؟', '[{"id":"a","text":"عددُ من حصل على «ممتاز» يساوي عددَ من حصل على «متوسّط»"},{"id":"b","text":"عددُ من حصل على «جيّد جدًّا» أكبرُ من عدد من حصل على «جيّد»"},{"id":"c","text":"مجموعُ توتراتِ «ممتاز» و«متوسّط» يساوي 20"},{"id":"d","text":"أقلُّ من نصف التلاميذ حصلوا على «جيّد جدًّا» أو «ممتاز»"}]'::jsonb, 'b', 'نتحقّق من كلّ عبارة: (أ) 8≠3 خطأ. (ب) 10>9 صحيح: عددُ «جيّد جدًّا» (10) أكبرُ من عدد «جيّد» (9). (ج) 8+3=11≠20 خطأ. (د) 8+10=18 تلميذًا حصلوا على ممتاز أو جيّد جدًّا، وهو أكثرُ من نصف الثلاثين (15)، فالعبارةُ خاطئة. العبارةُ الصحيحةُ الوحيدة هي (ب).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

