INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('338f4a02-83fd-5bdc-9ac4-3a0c69df5430', 'f7e388d1-1749-5c99-a68f-afd2fe5dce75', 'ما اسمُ الجدول الذي نستعمله لعدّ عناصر البيانات وتنظيمِها حسب كلّ قيمة؟', '[{"id":"a","text":"الرسمُ البيانيّ"},{"id":"b","text":"التمثيلُ الدائريّ"},{"id":"c","text":"جدولُ التعدادات"},{"id":"d","text":"قائمةُ الأسعار"}]'::jsonb, 'c', 'جدولُ التعدادات هو الأداةُ التي نستعملها لعدّ عناصر البيانات الخام (بعلامات التعداد) وتنظيمِها بحسب كلّ قيمة قبل حساب التواترات.', 1, 'mcq', NULL, NULL)
