  ('8bec0551-d9e1-5f5d-b952-f3ec0d9e78ab', 'f7e388d1-1749-5c99-a68f-afd2fe5dce75', 'يمثّل الرسمُ البيانيُّ التالي مبيعاتِ المكتبة المدرسيّة الأربعين خلال الأسبوع (أ: كراسات، ب: أقلام، ج: محافظ، د: مساطر). ما المادّةُ الأكثرُ مبيعًا؟
<svg viewBox="0 0 220 150" xmlns="http://www.w3.org/2000/svg"><line x1="20" y1="10" x2="20" y2="130" stroke="#1f2937" stroke-width="1.5"/><line x1="20" y1="130" x2="210" y2="130" stroke="#1f2937" stroke-width="1.5"/><rect x="35" y="40" width="30" height="90" fill="#f97316" stroke="#1f2937" stroke-width="1.5"/><rect x="80" y="58" width="30" height="72" fill="#3b82f6" stroke="#1f2937" stroke-width="1.5"/><rect x="125" y="82" width="30" height="48" fill="#10b981" stroke="#1f2937" stroke-width="1.5"/><rect x="170" y="100" width="30" height="30" fill="#eab308" stroke="#1f2937" stroke-width="1.5"/><text x="50" y="35" font-size="13" text-anchor="middle" fill="#1f2937">15</text><text x="95" y="53" font-size="13" text-anchor="middle" fill="#1f2937">12</text><text x="140" y="77" font-size="13" text-anchor="middle" fill="#1f2937">8</text><text x="185" y="95" font-size="13" text-anchor="middle" fill="#1f2937">5</text><text x="50" y="145" font-size="13" text-anchor="middle" fill="#1f2937">أ</text><text x="95" y="145" font-size="13" text-anchor="middle" fill="#1f2937">ب</text><text x="140" y="145" font-size="13" text-anchor="middle" fill="#1f2937">ج</text><text x="185" y="145" font-size="13" text-anchor="middle" fill="#1f2937">د</text></svg>', '[{"id":"a","text":"كراسات"},{"id":"b","text":"أقلام"},{"id":"c","text":"محافظ"},{"id":"d","text":"مساطر"}]'::jsonb, 'a', 'أعلى عمودٍ في الرسم هو أ (كراسات) بارتفاعٍ يمثّل التواتر 15، وهو أكبرُ التواترات الأربعة (15؛ 12؛ 8؛ 5)، فالكراساتُ هي الموادُّ الأكثرُ مبيعًا.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
