INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('83eeb0e1-41e5-542d-bbd8-ee96cdd11bcd', '6e440a29-0016-5670-b3a0-3b2246068bee', 'سجّل تلميذٌ حالةَ الطقس خلال 30 يومًا من الشهر: مشمس 14 يومًا، ممطر 5 أيّام، عاصف 3 أيّام، والباقي غائم. كم يومًا كان الطقسُ غائمًا؟', '[{"id":"a","text":"8"},{"id":"b","text":"11"},{"id":"c","text":"13"},{"id":"d","text":"22"}]'::jsonb, 'a', 'عددُ الأيّام الغائمة = 30−(14+5+3)=30−22=8 أيّام ✓. الخطأُ الشائع: نسيانُ طرح «ممطر» يعطي 30−14−3=13، أو نسيانُ طرح «عاصف» يعطي 30−14−5=11، أو الوقوفُ عند مجموع الثلاثة الأخرى (22) دون طرحه من 30.', 1, 'mcq', NULL, NULL)
