INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6f02dde9-e07e-5796-85c5-f66e870a24a4', '6e440a29-0016-5670-b3a0-3b2246068bee', 'يمثّل الرسمُ البيانيُّ التالي طقسَ الشهر الثلاثين يومًا بعد استكمال بيانات الطقس الغائم (أ: مشمس، ب: غائم، ج: ممطر، د: عاصف). كم يومًا كان الطقسُ مشمسًا أو غائمًا معًا؟
<svg viewBox="0 0 220 150" xmlns="http://www.w3.org/2000/svg"><line x1="20" y1="10" x2="20" y2="130" stroke="#1f2937" stroke-width="1.5"/><line x1="20" y1="130" x2="210" y2="130" stroke="#1f2937" stroke-width="1.5"/><rect x="35" y="46" width="30" height="84" fill="#f97316" stroke="#1f2937" stroke-width="1.5"/><rect x="80" y="82" width="30" height="48" fill="#3b82f6" stroke="#1f2937" stroke-width="1.5"/><rect x="125" y="100" width="30" height="30" fill="#10b981" stroke="#1f2937" stroke-width="1.5"/><rect x="170" y="112" width="30" height="18" fill="#eab308" stroke="#1f2937" stroke-width="1.5"/><text x="50" y="41" font-size="13" text-anchor="middle" fill="#1f2937">14</text><text x="95" y="77" font-size="13" text-anchor="middle" fill="#1f2937">8</text><text x="140" y="95" font-size="13" text-anchor="middle" fill="#1f2937">5</text><text x="185" y="107" font-size="13" text-anchor="middle" fill="#1f2937">3</text><text x="50" y="145" font-size="13" text-anchor="middle" fill="#1f2937">أ</text><text x="95" y="145" font-size="13" text-anchor="middle" fill="#1f2937">ب</text><text x="140" y="145" font-size="13" text-anchor="middle" fill="#1f2937">ج</text><text x="185" y="145" font-size="13" text-anchor="middle" fill="#1f2937">د</text></svg>', '[{"id":"a","text":"20"},{"id":"b","text":"22"},{"id":"c","text":"25"},{"id":"d","text":"29"}]'::jsonb, 'b', 'نجمع تواترَي «مشمس» (14) و«غائم» (8): 14+8=22 يومًا كان فيها الطقسُ مشمسًا أو غائمًا.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('166c0eac-7028-50f0-b8c9-9b652001a393', '6e440a29-0016-5670-b3a0-3b2246068bee', 'أيُّ العبارات التالية صحيحةٌ بخصوص طقس الشهر (مشمس 14، غائم 8، ممطر 5، عاصف 3)؟', '[{"id":"a","text":"عددُ الأيّام العاصفة يساوي عددَ الأيّام الممطرة"},{"id":"b","text":"أكثرُ من نصف أيّام الشهر كانت مشمسة"},{"id":"c","text":"عددُ الأيّام غير المشمسة هو 16 يومًا"},{"id":"d","text":"عددُ الأيّام الغائمة يفوق عددَ الأيّام المشمسة"}]'::jsonb, 'c', 'نتحقّق: (أ) 3≠5 خطأ. (ب) 14 أقلُّ من نصف الثلاثين (15) فالعبارةُ خاطئة. (ج) عددُ الأيّام غير المشمسة = 30−14=16 ✓ صحيحة. (د) 8<14 خطأ. العبارةُ الصحيحةُ الوحيدة هي (ج).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2aae42a7-5857-5ae0-bdce-bf59cccdd884', '6e440a29-0016-5670-b3a0-3b2246068bee', 'أراد سامي حسابَ عدد الأيّام «غير الممطرة» فكتب: 30−5−8=17. لكنّ هذا خطأ. ما مصدرُ الخطأ، وما العددُ الصحيحُ؟', '[{"id":"a","text":"لا يوجد خطأ، والعددُ 17 صحيح"},{"id":"b","text":"الخطأُ في طرح 5؛ العددُ الصحيحُ هو 30−8=22"},{"id":"c","text":"الخطأُ في طرح 8 زيادةً؛ العددُ الصحيحُ هو 30−5=25"},{"id":"d","text":"الخطأُ في العدد الكليّ؛ يجب استعمالُ 22 بدل 30"}]'::jsonb, 'c', '«غيرُ الممطر» يعني كلَّ الأيّام ما عدا الأيّامَ الممطرة فقط: 30−5=25 يومًا. أخطأ سامي بطرح تواتر «غائم» (8) أيضًا رغم أنّ الأيّامَ الغائمة جزءٌ من «غير الممطر» ويجب أن تبقى محسوبة، فحصل خطأً على 30−5−8=17.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('1dea1ac8-be0c-5a9b-b0f5-3605d02c8ae7', '6e440a29-0016-5670-b3a0-3b2246068bee', 'بأيّ ترتيبٍ تنازليّ (من الأكثر إلى الأقلّ) تظهر حالاتُ الطقس الأربع؟', '[{"id":"a","text":"مشمس، ممطر، غائم، عاصف"},{"id":"b","text":"غائم، مشمس، ممطر، عاصف"},{"id":"c","text":"مشمس، غائم، عاصف، ممطر"},{"id":"d","text":"مشمس، غائم، ممطر، عاصف"}]'::jsonb, 'd', 'نرتّب التواتراتِ تنازليًّا: 14 (مشمس) > 8 (غائم) > 5 (ممطر) > 3 (عاصف)، فالترتيبُ الصحيحُ هو: مشمس، غائم، ممطر، عاصف.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7bf25a55-4755-5c56-a43b-d0523a874c42', '6e440a29-0016-5670-b3a0-3b2246068bee', 'لو تغيّر عددُ الأيّام العاصفة إلى الضعف (بدل 3 أصبحت 6)، مع بقاء عدد أيّام الشهر 30 وبقاء مشمس 14 وممطر 5 كما هما، فما العددُ الجديدُ لأيّام الطقس الغائم؟', '[{"id":"a","text":"2"},{"id":"b","text":"5"},{"id":"c","text":"8"},{"id":"d","text":"11"}]'::jsonb, 'b', 'العددُ الجديدُ لأيّام العاصف هو 2×3=6. الأيّامُ الغائمةُ الجديدة = 30−(14+5+6)=30−25=5 يومًا. الخطأُ الشائع: نسيانُ مضاعفة أيّام العاصف والبقاءُ عند القيمة القديمة للغائم (8)، أو أخطاءُ جمعٍ أخرى تعطي 2 أو 11.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

