INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('24b0c12a-345b-5c14-89a9-28e7f104338b', 'c6a2ece9-2fe4-5323-8c77-5b07f9ca5f44', 'استُطلعت آراءُ 24 تلميذًا حول نشاط الترفيه المفضّل، فسُجّلت في جدول التعداد: قراءة: |||||| — رياضة: |||||||||| — رسم: ||||| — موسيقى: |||. ما تواترُ الرسم؟', '[{"id":"a","text":"5"},{"id":"b","text":"7"},{"id":"c","text":"9"},{"id":"d","text":"11"}]'::jsonb, 'a', 'نعدّ علاماتِ التعداد أمام «رسم»: ||||| أي 5 علامات، فتواترُ الرسم 5. (تواترُ القراءة 6، والرياضة 10، والموسيقى 3، والمجموع 6+10+5+3=24 ✓.) الخطأُ الشائع: عدّ زائد أو ناقص لعلامات التعداد يعطي نتائج مثل 7 أو 9.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('942dc36f-5812-537d-8443-fdc5b0f44ba9', 'c6a2ece9-2fe4-5323-8c77-5b07f9ca5f44', 'يمثّل الرسمُ البيانيُّ التالي نشاطَ الترفيه المفضّل لدى 24 تلميذًا (أ: قراءة، ب: رياضة، ج: رسم، د: موسيقى). ما النشاطُ الأقلُّ اختيارًا؟
<svg viewBox="0 0 220 150" xmlns="http://www.w3.org/2000/svg"><line x1="20" y1="10" x2="20" y2="130" stroke="#1f2937" stroke-width="1.5"/><line x1="20" y1="130" x2="210" y2="130" stroke="#1f2937" stroke-width="1.5"/><rect x="35" y="82" width="30" height="48" fill="#f97316" stroke="#1f2937" stroke-width="1.5"/><rect x="80" y="50" width="30" height="80" fill="#3b82f6" stroke="#1f2937" stroke-width="1.5"/><rect x="125" y="90" width="30" height="40" fill="#10b981" stroke="#1f2937" stroke-width="1.5"/><rect x="170" y="106" width="30" height="24" fill="#eab308" stroke="#1f2937" stroke-width="1.5"/><text x="50" y="77" font-size="13" text-anchor="middle" fill="#1f2937">6</text><text x="95" y="45" font-size="13" text-anchor="middle" fill="#1f2937">10</text><text x="140" y="85" font-size="13" text-anchor="middle" fill="#1f2937">5</text><text x="185" y="101" font-size="13" text-anchor="middle" fill="#1f2937">3</text><text x="50" y="145" font-size="13" text-anchor="middle" fill="#1f2937">أ</text><text x="95" y="145" font-size="13" text-anchor="middle" fill="#1f2937">ب</text><text x="140" y="145" font-size="13" text-anchor="middle" fill="#1f2937">ج</text><text x="185" y="145" font-size="13" text-anchor="middle" fill="#1f2937">د</text></svg>', '[{"id":"a","text":"قراءة"},{"id":"b","text":"رياضة"},{"id":"c","text":"رسم"},{"id":"d","text":"موسيقى"}]'::jsonb, 'd', 'أقصرُ عمودٍ في الرسم هو د (موسيقى) بارتفاعٍ يمثّل التواتر 3، وهو أصغرُ التواترات الأربعة (6؛ 10؛ 5؛ 3)، فالموسيقى هي النشاطُ الأقلُّ اختيارًا.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7c6dbb21-ffde-5a07-835f-73018384f352', 'c6a2ece9-2fe4-5323-8c77-5b07f9ca5f44', 'يمثّل التمثيلُ الدائريّ التالي نفسَ بيانات نشاط الترفيه لدى 24 تلميذًا (أ: قراءة، ب: رياضة، ج: رسم، د: موسيقى)، حيث تتناسب مساحةُ كلّ قطاعٍ مع تواتر النشاط. أيُّ قطاعٍ هو الأكبرُ في الدائرة؟
<svg viewBox="0 0 120 120" xmlns="http://www.w3.org/2000/svg"><path d="M60,60 L60,10 A50,50 0 0,1 110,60 Z" fill="#f97316" stroke="#1f2937" stroke-width="1"/><path d="M60,60 L110,60 A50,50 0 0,1 16.70,85 Z" fill="#3b82f6" stroke="#1f2937" stroke-width="1"/><path d="M60,60 L16.70,85 A50,50 0 0,1 24.64,24.64 Z" fill="#10b981" stroke="#1f2937" stroke-width="1"/><path d="M60,60 L24.64,24.64 A50,50 0 0,1 60,10 Z" fill="#eab308" stroke="#1f2937" stroke-width="1"/><text x="81" y="39" font-size="12" text-anchor="middle" fill="#1f2937">أ</text><text x="68" y="89" font-size="12" text-anchor="middle" fill="#1f2937">ب</text><text x="30" y="56" font-size="12" text-anchor="middle" fill="#1f2937">ج</text><text x="49" y="32" font-size="12" text-anchor="middle" fill="#1f2937">د</text></svg>', '[{"id":"a","text":"أ (قراءة)"},{"id":"b","text":"ب (رياضة)"},{"id":"c","text":"ج (رسم)"},{"id":"d","text":"د (موسيقى)"}]'::jsonb, 'b', 'أكبرُ قطاعٍ في الدائرة يقابل أكبرَ تواتر، وهو تواترُ الرياضة (10) من أصل 24، فقطاعُ «ب» (رياضة) هو الأكبرُ في التمثيل الدائريّ.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0afd13bc-28a3-5466-bfce-d5bf70c509b2', 'c6a2ece9-2fe4-5323-8c77-5b07f9ca5f44', 'في التمثيل الدائريّ لبيانات 24 تلميذًا، ماذا تمثّل الدائرةُ الكاملةُ (360 درجة)؟', '[{"id":"a","text":"أكبرَ تواترٍ فقط"},{"id":"b","text":"الفرقَ بين أكبر تواترٍ وأصغره"},{"id":"c","text":"العددَ الكليّ للتلاميذ (24)"},{"id":"d","text":"عددَ القيم الممكنة (4)"}]'::jsonb, 'c', 'الدائرةُ الكاملةُ في التمثيل الدائريّ تمثّل دائمًا التعدادَ الكليَّ لجميع عناصر الدراسة، أي 24 تلميذًا هنا؛ وتنقسم إلى قطاعاتٍ تتناسب مساحتُها مع تواتر كلّ قيمة، لا تمثّل فردًا واحدًا أو فرقًا بين قيمتين.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('759bc600-f35c-50d2-9d46-eddc062ec322', 'c6a2ece9-2fe4-5323-8c77-5b07f9ca5f44', 'كم تلميذًا اختاروا نشاطًا غيرَ الرياضة؟', '[{"id":"a","text":"14"},{"id":"b","text":"16"},{"id":"c","text":"20"},{"id":"d","text":"24"}]'::jsonb, 'a', 'عددُ من اختار نشاطًا غيرَ الرياضة = العددُ الكليّ − تواترُ الرياضة = 24−10=14 تلميذًا. الخطأُ الشائع: الإجابةُ بتواتر الرياضة نفسِه (10)، أو نسيانُ الطرح (24).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
