  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ab7ac322-1f50-543f-9dc2-2e59bee2740b', 'c6a2ece9-2fe4-5323-8c77-5b07f9ca5f44', 'أُضيف نشاطٌ خامسٌ «مسرح» إلى الاستطلاع فأصبح العددُ الكليّ للتلاميذ 30 (التلاميذُ الأربعةُ والعشرون السابقون + من اختار مسرح). ما تواترُ نشاط «مسرح»؟', '[{"id":"a","text":"4"},{"id":"b","text":"6"},{"id":"c","text":"8"},{"id":"d","text":"10"}]'::jsonb, 'b', 'تواترُ «مسرح» = العددُ الكليّ الجديد − العددُ الكليّ السابق = 30−24=6 تلاميذَ اختاروا المسرح. الخطأُ الشائع: الخلطُ مع تواتراتٍ أخرى موجودة كـ8 أو 10 (تواترُ الرياضة)، أو نسيانُ الطرح والإجابةُ بعددٍ عشوائيّ كـ4.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
