INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('410c84b6-1b8a-57a7-9bc4-20b074bbc2f4', 'ced80f34-ab5b-5122-ae37-e509a620dd1d', 'استُطلعت آراءُ 50 تلميذًا من عدّة أقسام حول الرياضة المفضّلة: كرةُ القدم 18، السباحةُ 9، الجري 8، والباقي كرةُ السلة. ما تواترُ كرة السلة؟', '[{"id":"a","text":"15"},{"id":"b","text":"23"},{"id":"c","text":"24"},{"id":"d","text":"33"}]'::jsonb, 'a', 'تواترُ كرة السلة = 50−(18+9+8)=50−35=15 ✓. الخطأُ الشائع: نسيانُ طرح أحد الأصناف الثلاثة الأخرى يعطي 23 أو 24 أو 33 بدل 15.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ee370bb5-f217-5f0a-9375-7f89901cc218', 'ced80f34-ab5b-5122-ae37-e509a620dd1d', 'يمثّل الرسمُ البيانيُّ التالي الرياضةَ المفضّلة لدى 50 تلميذًا بعد استكمال بيانات كرة السلة (أ: كرة القدم، ب: كرة السلة، ج: السباحة، د: الجري). كم تلميذًا اختاروا رياضةً غيرَ كرة القدم؟
<svg viewBox="0 0 220 150" xmlns="http://www.w3.org/2000/svg"><line x1="20" y1="10" x2="20" y2="130" stroke="#1f2937" stroke-width="1.5"/><line x1="20" y1="130" x2="210" y2="130" stroke="#1f2937" stroke-width="1.5"/><rect x="35" y="58" width="30" height="72" fill="#f97316" stroke="#1f2937" stroke-width="1.5"/><rect x="80" y="70" width="30" height="60" fill="#3b82f6" stroke="#1f2937" stroke-width="1.5"/><rect x="125" y="94" width="30" height="36" fill="#10b981" stroke="#1f2937" stroke-width="1.5"/><rect x="170" y="98" width="30" height="32" fill="#eab308" stroke="#1f2937" stroke-width="1.5"/><text x="50" y="53" font-size="13" text-anchor="middle" fill="#1f2937">18</text><text x="95" y="65" font-size="13" text-anchor="middle" fill="#1f2937">15</text><text x="140" y="89" font-size="13" text-anchor="middle" fill="#1f2937">9</text><text x="185" y="93" font-size="13" text-anchor="middle" fill="#1f2937">8</text><text x="50" y="145" font-size="13" text-anchor="middle" fill="#1f2937">أ</text><text x="95" y="145" font-size="13" text-anchor="middle" fill="#1f2937">ب</text><text x="140" y="145" font-size="13" text-anchor="middle" fill="#1f2937">ج</text><text x="185" y="145" font-size="13" text-anchor="middle" fill="#1f2937">د</text></svg>', '[{"id":"a","text":"18"},{"id":"b","text":"32"},{"id":"c","text":"35"},{"id":"d","text":"50"}]'::jsonb, 'b', 'عددُ من اختار رياضةً غيرَ كرة القدم = 50−18=32 تلميذًا. الخطأُ الشائع: الإجابةُ بتواتر كرة القدم نفسِه (18)، أو طرحُ تواتر كرة السلة بدل كرة القدم خطأً (50−15=35)، أو نسيانُ الطرح كليًّا (50).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('42da22c4-ce04-51ea-95cc-18c1e83ad951', 'ced80f34-ab5b-5122-ae37-e509a620dd1d', 'يمثّل التمثيلُ الدائريّ التالي نفسَ بيانات الرياضة المفضّلة لدى 50 تلميذًا (أ: كرة القدم، ب: كرة السلة، ج: السباحة، د: الجري)، حيث تتناسب مساحةُ كلّ قطاعٍ مع تواتر الرياضة. هل يتّفق أكبرُ قطاعٍ في هذا التمثيل الدائريّ مع أطول عمودٍ في التمثيل بالأعمدة للبيانات نفسها؟
<svg viewBox="0 0 120 120" xmlns="http://www.w3.org/2000/svg"><path d="M60,60 L60,10 A50,50 0 0,1 98.53,91.87 Z" fill="#f97316" stroke="#1f2937" stroke-width="1"/><path d="M60,60 L98.53,91.87 A50,50 0 0,1 17.78,86.79 Z" fill="#3b82f6" stroke="#1f2937" stroke-width="1"/><path d="M60,60 L17.78,86.79 A50,50 0 0,1 17.79,33.21 Z" fill="#10b981" stroke="#1f2937" stroke-width="1"/><path d="M60,60 L17.79,33.21 A50,50 0 0,1 60,10 Z" fill="#eab308" stroke="#1f2937" stroke-width="1"/><text x="87" y="47" font-size="12" text-anchor="middle" fill="#1f2937">أ</text><text x="58" y="90" font-size="12" text-anchor="middle" fill="#1f2937">ب</text><text x="30" y="60" font-size="12" text-anchor="middle" fill="#1f2937">ج</text><text x="46" y="34" font-size="12" text-anchor="middle" fill="#1f2937">د</text></svg>', '[{"id":"a","text":"نعم، كلاهما يمثّلان «كرة القدم» لأنّها الأكبرُ تواترًا (18)"},{"id":"b","text":"لا، القطاعُ الأكبر «كرة السلة» بينما العمودُ الأطول «كرة القدم»"},{"id":"c","text":"لا يمكن المقارنةُ بين تمثيلَين مختلفَين"},{"id":"d","text":"نعم، لكنّهما يمثّلان «كرة السلة» في الحالتَين"}]'::jsonb, 'a', 'التمثيلان يعرضان البياناتِ نفسَها بطريقتَين مختلفتَين: أكبرُ عمودٍ (وأكبرُ قطاع) يقابلان دائمًا أكبرَ تواتر، وهو هنا تواترُ كرة القدم (18)؛ إذن يتّفق التمثيلان في الإشارة إلى «كرة القدم» بوصفها الرياضةَ الأكثر اختيارًا.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a5286e43-9f48-5cec-92d8-8dd17d5bb388', 'ced80f34-ab5b-5122-ae37-e509a620dd1d', 'عدّ منيرُ توتراتِ الرياضة من جدول التعداد فوجد: كرةُ القدم 18، كرةُ السلة 15، السباحةُ 9، الجري 8، فاستنتج أنّ العددَ الكليّ للتلاميذ 52. تحقّق زميلُه فوجد أنّ منيرًا أخطأ في عدّ عمود «السباحة» بزيادة علامتَين. ما العددُ الصحيحُ للتلاميذ؟', '[{"id":"a","text":"40"},{"id":"b","text":"44"},{"id":"c","text":"46"},{"id":"d","text":"48"}]'::jsonb, 'd', 'نصحّح تواترَ السباحة إلى 9−2=7 (بعد حذف العلامتَين الزائدتَين). العددُ الصحيحُ للتلاميذ = 18+15+7+8=48، لا 52 كما ظنّ منير بسبب خطئه في العدّ.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('75a0b953-d632-5e2f-a0bb-790630f64dd7', 'ced80f34-ab5b-5122-ae37-e509a620dd1d', 'في استطلاعٍ آخر مشابه لهذا الاستطلاع، تواترُ «السباحة» 8 تلاميذ، وتواترُ «كرة السلة» يفوق تواترَ «السباحة» بـ6 تلاميذ، وتواترُ «الجري» يساوي نصفَ تواتر «كرة السلة». ما تواترُ «الجري» في هذا الاستطلاع؟', '[{"id":"a","text":"4"},{"id":"b","text":"6"},{"id":"c","text":"7"},{"id":"d","text":"14"}]'::jsonb, 'c', 'تواترُ كرة السلة = تواترُ السباحة + 6 = 8+6=14. تواترُ الجري = نصفُ تواتر كرة السلة = 14÷2=7 ✓. الخطأُ الشائع: نسيانُ خطوة إيجاد كرة السلة أوّلًا والاكتفاءُ بنصف تواتر السباحة (8÷2=4)، أو الخلطُ بين النصف والفرق (6)، أو التوقّفُ عند قيمة كرة السلة (14) دون قسمتها على 2.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('31e2cdfb-dabc-5abf-9540-1460d2e7b6bb', 'ced80f34-ab5b-5122-ae37-e509a620dd1d', 'في الاستطلاع الأصليّ (50 تلميذًا: كرةُ القدم 18، كرةُ السلة 15، السباحةُ 9، الجري 8)، انضمّ إلى القسم 4 تلاميذَ جدد، اختار جميعُهم «السباحة». ثمّ غادر القسمَ نهائيًّا تلميذان كانا قد اختارا «كرة القدم». ما العددُ الكليّ الجديدُ للتلاميذ، وما تواترُ «السباحة» الجديد؟', '[{"id":"a","text":"54 تلميذًا، والسباحةُ 13"},{"id":"b","text":"52 تلميذًا، والسباحةُ 13"},{"id":"c","text":"52 تلميذًا، والسباحةُ 9"},{"id":"d","text":"48 تلميذًا، والسباحةُ 11"}]'::jsonb, 'b', 'العددُ الكليّ الجديد = 50+4−2=52 تلميذًا (إضافةُ 4 وخروجُ 2). تواترُ السباحة الجديد = 9+4=13 (الأربعةُ الجددُ اختاروا السباحة، وخروجُ التلميذَين لا يمسّ هذا الصنفَ لأنّهما كانا يختاران كرة القدم). الخطأُ الشائع: نسيانُ خروج التلميذَين فيُعطى 54، أو نسيانُ إضافة الأربعة إلى تواتر السباحة فيبقى عند 9، أو أخطاءُ جمعٍ أخرى.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

