INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('55fe97e7-bd72-5e8b-aa08-8529e5287aed', 'a3d21cdb-f467-5a75-955c-4dda6f379aef', 'نظيرُ النقطة M بالنسبة إلى محور التناظر (d) هو نقطة M′. أيُّ الشروط التالية صحيحةٌ في M′؟', '[{"id":"a","text":"(d) عموديٌّ على [MM′] ويمرّ بمنتصفها"},{"id":"b","text":"(d) يمرّ بـ M فقط دون شرطٍ آخر"},{"id":"c","text":"M′ أبعدُ عن (d) من M"},{"id":"d","text":"(d) موازٍ لِـ [MM′]"}]'::jsonb, 'a', 'نظيرُ نقطةٍ بالنسبة إلى محورٍ يتطلّب شرطَين معًا: أن يكون المحورُ عموديًّا على القطعة الواصلة بين النقطة ونظيرها، وأن يمرّ بمنتصف هذه القطعة (بُعدٌ متساوٍ من الجهتَين). المرورُ بـ M فقط أو التوازي أو اختلافُ البُعد لا يحقّق شروط التناظر.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('16ed39d8-298a-5125-a8eb-dbb52e6a53da', 'a3d21cdb-f467-5a75-955c-4dda6f379aef', 'إذا كانت النقطة N تقع على محور التناظر (d) نفسه، فما نظيرُها N′؟', '[{"id":"a","text":"نقطةٌ بعيدةٌ عن (d)"},{"id":"b","text":"N نفسُها"},{"id":"c","text":"نقطتان مختلفتان"},{"id":"d","text":"ليس لها نظير"}]'::jsonb, 'b', 'كلُّ نقطةٍ تقع على محور التناظر هي نقطةٌ ثابتة: بُعدُها عن المحور معدومٌ، فنظيرُها هو N نفسُها. النقاطُ الثابتة هي الاستثناءُ الوحيد في التناظر المحوري.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0fde16b3-7dcf-5a13-bc72-acdf2a79f0b2', 'a3d21cdb-f467-5a75-955c-4dda6f379aef', 'طولُ القطعة [AB] هو 7 سم. ما طولُ نظيرها [A′B′] بعد تناظرٍ محوريّ؟', '[{"id":"a","text":"أقلّ من 7 سم"},{"id":"b","text":"7 سم"},{"id":"c","text":"أكثرُ من 7 سم"},{"id":"d","text":"يعتمد على موضع المحور"}]'::jsonb, 'b', 'التناظرُ المحوري يحفظ الأطوالَ دائمًا: A′B′ = AB = 7 سم، مهما كان موضعُ محور التناظر أو بُعدُ القطعة عنه.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e6e1ba31-afcf-53bf-a847-6aae0de597f5', 'a3d21cdb-f467-5a75-955c-4dda6f379aef', 'كم محورَ تناظرٍ للمربّع؟', '[{"id":"a","text":"واحد"},{"id":"b","text":"اثنان"},{"id":"c","text":"أربعة"},{"id":"d","text":"عددٌ لا نهائيّ"}]'::jsonb, 'c', 'للمربّع 4 محاور تناظر: محوران يمرّان بمنتصفَي ضلعَين متقابلَين، ومحوران قُطريّان يمرّان برأسَين متقابلَين. المستطيلُ (غير المربّع) له محوران فقط، والدائرةُ لها عددٌ لا نهائي.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
