  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ead2c7e9-9e46-5b38-8b0a-94896ffd0128', 'a3d21cdb-f467-5a75-955c-4dda6f379aef', 'ما هو الموسّطُ العموديّ لقطعة [AB]؟', '[{"id":"a","text":"أيُّ مستقيمٍ يمرّ بـ A أو بـ B"},{"id":"b","text":"المستقيمُ الموازي لِـ [AB] والمارّ بمنتصفها"},{"id":"c","text":"القطعةُ [AB] نفسُها ممتدّة"},{"id":"d","text":"المستقيمُ العموديّ على [AB] والمارّ بمنتصفها"}]'::jsonb, 'd', 'الموسّطُ العموديّ لقطعة [AB] هو المستقيمُ الذي يجمع شرطَين معًا: العموديّةَ على [AB]، والمرورَ بمنتصفها. مستقيمٌ موازٍ لـ [AB] أو مارٌّ بأحد طرفَيها فقط لا يحقّق هذا التعريف.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
