INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2e9958d8-27d2-5611-b6ea-c0dafd7212d9', '0e3791e0-a8e0-56ac-9eb6-40b167062a5c', 'النقطة M تبعد 5 سم عن محور التناظر (d)، على العمود النازل منها إلى (d). ما بُعدُ نظيرها M′ عن (d)؟', '[{"id":"a","text":"5 سم"},{"id":"b","text":"2,5 سم"},{"id":"c","text":"7,5 سم"},{"id":"d","text":"10 سم"}]'::jsonb, 'a', 'الشرطُ الثاني للتناظر هو تساوي البُعد عن المحور: بُعدُ M′ عن (d) يساوي بُعدَ M عن (d)، أي 5 سم ✓. الخطأُ الشائع: حسابُ نصف البُعد (2,5 سم) أو ضِعفه (10 سم) ظنًّا أنّ البُعد يتغيّر بالتناظر.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('52c4fd59-4b0a-5966-ba67-8b7ee46e0925', '0e3791e0-a8e0-56ac-9eb6-40b167062a5c', 'لكي تكون النقطة M′ نظيرَ M بالنسبة إلى المحور (d)، يجب أن يتحقّق:', '[{"id":"a","text":"عموديّةُ (d) على [MM′] فقط"},{"id":"b","text":"الشرطان معًا: العموديّةُ والمرورُ بمنتصف [MM′]"},{"id":"c","text":"المرورُ بمنتصف [MM′] فقط"},{"id":"d","text":"لا شرط، يكفي القربُ من (d)"}]'::jsonb, 'b', 'الشرطان لا ينفصلان: يجب أن يكون (d) عموديًّا على [MM′] وأن يمرّ بمنتصفها معًا. توفّرُ العموديّة وحدها أو المرور بالمنتصف وحده دون الشرط الآخر لا يضمن التناظر.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
