  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('cb932125-8fe2-55ca-9d98-ee3e07ea805b', '0e3791e0-a8e0-56ac-9eb6-40b167062a5c', 'طولُ القطعة [CD] هو 9 سم. ما طولُ نظيرها [C′D′] بالنسبة إلى محورٍ ما؟', '[{"id":"a","text":"4,5 سم"},{"id":"b","text":"18 سم"},{"id":"c","text":"9 سم"},{"id":"d","text":"11 سم"}]'::jsonb, 'c', 'التناظرُ المحوري يحفظ الأطوال: C′D′ = CD = 9 سم ✓. الخطأُ الشائع: حسابُ نصف الطول (4,5 سم) أو ضِعفه (18 سم) ظنًّا أنّ التناظر يغيّر الحجم، أو إضافةُ قيمةٍ عشوائيّة (11 سم).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
