  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8758bf91-ecf4-584f-b686-728db139fc99', '0e3791e0-a8e0-56ac-9eb6-40b167062a5c', 'زاويةٌ قياسُها 40 درجة. ما قياسُ نظيرتها بالتناظر المحوري؟', '[{"id":"a","text":"20 درجة"},{"id":"b","text":"50 درجة"},{"id":"c","text":"80 درجة"},{"id":"d","text":"40 درجة"}]'::jsonb, 'd', 'التناظرُ المحوري يحفظ قياسَ الزوايا: نظيرةُ زاويةٍ قياسُها 40 درجة لها القياسُ نفسُه، 40 درجة ✓. الخطأُ الشائع: حسابُ نصف القياس (20 درجة) أو ضِعفه (80 درجة) أو متمّمها إلى 90 درجة (50 درجة).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
