  ('38ad6063-f2b4-5bae-8614-1bea45f88048', '0e3791e0-a8e0-56ac-9eb6-40b167062a5c', 'كم محورَ تناظرٍ للدائرة؟', '[{"id":"a","text":"عددٌ لا نهائيّ"},{"id":"b","text":"أربعة"},{"id":"c","text":"اثنان"},{"id":"d","text":"واحد"}]'::jsonb, 'a', 'كلُّ قُطرٍ من أقطار الدائرة محورُ تناظرٍ لها، وعددُ الأقطار لا نهائيّ، فللدائرة عددٌ لا نهائيّ من محاور التناظر — خلافًا للمربّع (4 محاور) أو المستطيل (2).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
