  ('70c29e1e-a38c-5e63-a6d3-2f5998ca057f', '0e3791e0-a8e0-56ac-9eb6-40b167062a5c', 'كم محورَ تناظرٍ للمثلّث متساوي الساقين؟', '[{"id":"a","text":"لا يوجد"},{"id":"b","text":"واحد"},{"id":"c","text":"اثنان"},{"id":"d","text":"ثلاثة"}]'::jsonb, 'b', 'للمثلّث متساوي الساقين محورُ تناظرٍ واحد: الموسّطُ العموديّ لقاعدته، وهو يمرّ أيضًا برأسه المقابل لهذه القاعدة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
