INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c3ee4b4e-87d9-5345-8cc9-c3296b4a9683', 'cca7b3e3-de7c-507f-9e84-f18257c20250', 'مستقيمٌ (m) عموديٌّ على محور التناظر (d). ما نظيرُ (m) بالنسبة إلى (d)؟', '[{"id":"a","text":"مستقيمٌ موازٍ لِـ (m)"},{"id":"b","text":"نقطةٌ واحدة"},{"id":"c","text":"المستقيمُ (m) نفسُه"},{"id":"d","text":"مستقيمٌ عموديٌّ على (m)"}]'::jsonb, 'c', 'إذا كان المستقيمُ عموديًّا على محور التناظر، فإنّ نظيرَه هو نفسُ المستقيم (m): كلُّ نقطةٍ من (m) تنعكس إلى نقطةٍ أخرى تقع أيضًا على (m)، فالمستقيمُ يُطابق نفسَه ككلٍّ ✓. الخطأُ الشائع: الاعتقادُ بأنّ نظير أيّ مستقيمٍ يكون موازيًا له دائمًا.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('00ba5fa0-7bb6-5e45-a705-13240781f869', 'cca7b3e3-de7c-507f-9e84-f18257c20250', 'مستقيمٌ (m) موازٍ لمحور التناظر (d) ويبعد عنه 3 سم. أين يقع نظيرُ (m)؟', '[{"id":"a","text":"على (d) نفسه"},{"id":"b","text":"مستقيمٌ موازٍ لِـ (d)، يبعد عنه 3 سم على الجهة الأخرى"},{"id":"c","text":"مستقيمٌ عموديٌّ على (d)"},{"id":"d","text":"مستقيمٌ يبعد عن (d) بمسافةٍ مختلفة"}]'::jsonb, 'b', 'نظيرُ مستقيمٍ موازٍ لمحور التناظر هو مستقيمٌ موازٍ له أيضًا، على الجهة الأخرى من المحور، وعلى البُعد نفسه (3 سم) ✓. الخطأُ الشائع: الاعتقادُ بأنّ نظيرَ مستقيمٍ موازٍ يتقاطع مع المحور أو يتغيّر بُعدُه.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('53368eea-c010-553a-8f76-2f638b061b3a', 'cca7b3e3-de7c-507f-9e84-f18257c20250', 'النقطُ A وB وC مستقيميّة (تقع على استقامةٍ واحدة). بعد تناظرٍ محوريّ بالنسبة إلى (d)، ماذا يمكن قولُه عن نظيراتها A′ وB′ وC′؟', '[{"id":"a","text":"تبقى مستقيميّةً أيضًا"},{"id":"b","text":"تصير رؤوسَ مثلّث"},{"id":"c","text":"تتباعد عن بعضها بلا نظام"},{"id":"d","text":"تصير متطابقةً في نقطةٍ واحدة"}]'::jsonb, 'a', 'من خصائص التناظر المحوري: الاستقامةُ محفوظة — إذا كانت نقطٌ ثلاثٌ مستقيميّة، فإنّ نظيراتها تبقى مستقيميّةً أيضًا، على مستقيمٍ آخر (نظير المستقيم الأصلي) ✓.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0bdddea5-5b0c-5dd3-b6d9-65ab99f4e3b6', 'cca7b3e3-de7c-507f-9e84-f18257c20250', 'أراد سامي إنشاءَ نظير النقطة M (تبعد 6 سم عن المحور (d)) فرسم M′ على العمود نفسه، لكن على بُعد 4 سم فقط من (d). ما الخطأُ في إنشاء سامي؟', '[{"id":"a","text":"لا يوجد خطأ، الإنشاءُ صحيح"},{"id":"b","text":"نسي رسمَ العمود أصلًا"},{"id":"c","text":"لم يحترم شرطَ تساوي البُعد؛ يجب أن يبعد M′ أيضًا 6 سم عن (d)"},{"id":"d","text":"رسم M′ على المحور (d) نفسه"}]'::jsonb, 'c', 'الشرطُ الثاني للتناظر هو تساوي البُعد عن المحور: بما أنّ M تبعد 6 سم عن (d)، يجب أن يبعد M′ أيضًا 6 سم عن (d) على الجهة الأخرى من العمود نفسه، لا 4 سم. خطأُ سامي هو عدم احترام هذا التساوي ✓.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5270ef65-ea3a-5802-8078-600ab1631f00', 'cca7b3e3-de7c-507f-9e84-f18257c20250', 'أيُّ العبارات التالية **خاطئة**؟', '[{"id":"a","text":"للمربّع 4 محاور تناظر"},{"id":"b","text":"قُطرا المستطيل محورا تناظرٍ له"},{"id":"c","text":"للمثلّث متساوي الساقين محورُ تناظرٍ واحد"},{"id":"d","text":"كلُّ قُطرٍ في الدائرة محورُ تناظرٍ لها"}]'::jsonb, 'b', 'العبارةُ الخاطئة هي (b): قُطرا المستطيل (غير المربّع) ليسا محوري تناظرٍ له، لأنّ طيَّ المستطيل على أحد قُطريه لا يُطابق النصفين؛ محورا تناظر المستطيل هما المستقيمان المارّان بمنتصفَي كلّ زوجٍ من الأضلاع المتقابلة. العباراتُ الأخرى (a, c, d) صحيحةٌ جميعًا.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5212a476-a3d0-597a-addb-1b47fad1c4ec', 'cca7b3e3-de7c-507f-9e84-f18257c20250', '(d) هو الموسّطُ العموديّ لقطعة [AB]. ما نظيرُ النقطة A بالنسبة إلى (d)؟', '[{"id":"a","text":"نقطةٌ أخرى غيرُ A وغيرُ B"},{"id":"b","text":"منتصفُ [AB]"},{"id":"c","text":"A نفسُها"},{"id":"d","text":"B"}]'::jsonb, 'd', 'بما أنّ (d) موسّطٌ عموديٌّ لِـ [AB]، فهو عموديٌّ على [AB] ويمرّ بمنتصفها — وهذا هو بالضبط شرطُ كون B نظيرَ A بالنسبة إلى (d) ✓. لذلك نظيرُ A هو B، ونظيرُ B هو A.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

