  ('70fa5fea-ab41-5ade-9bab-18e65c92ff06', '88709f82-0a2f-54fb-a2f9-e2a8ca4adbde', 'النقطة P تبعد 3 سم عن محور التناظر (d). ما بُعدُ نظيرها P′ عن (d)؟', '[{"id":"a","text":"3 سم"},{"id":"b","text":"1,5 سم"},{"id":"c","text":"6 سم"},{"id":"d","text":"9 سم"}]'::jsonb, 'a', 'بُعدُ نظير نقطةٍ عن المحور يساوي بُعدَ النقطة الأصليّة نفسَه: بُعدُ P′ = بُعدُ P = 3 سم ✓.', 1, 'mcq', NULL, NULL)
