INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('27660574-6f49-503a-8b98-3ff54b8d0adc', '88709f82-0a2f-54fb-a2f9-e2a8ca4adbde', 'كم محورَ تناظرٍ للمستطيل (غير المربّع)؟', '[{"id":"a","text":"واحد"},{"id":"b","text":"اثنان"},{"id":"c","text":"أربعة"},{"id":"d","text":"عددٌ لا نهائيّ"}]'::jsonb, 'b', 'للمستطيل غيرِ المربّع محورا تناظرٍ فقط: يمرّان بمنتصفَي كلّ زوجٍ من الأضلاع المتقابلة. قُطرا المستطيل ليسا محوري تناظرٍ له (بخلاف المربّع الذي له 4 محاور).', 3, 'mcq', NULL, NULL)
