INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c2715f83-5d71-5827-a44f-3063016484e1', '88709f82-0a2f-54fb-a2f9-e2a8ca4adbde', 'زاويتان متناظرتان بالنسبة إلى محورٍ، وقياسُ إحداهما 65 درجة. ما قياسُ الأخرى؟', '[{"id":"a","text":"25 درجة"},{"id":"b","text":"50 درجة"},{"id":"c","text":"65 درجة"},{"id":"d","text":"130 درجة"}]'::jsonb, 'c', 'التناظرُ المحوري يحفظ قياسَ الزوايا: الزاويتان المتناظرتان لهما القياسُ نفسُه، 65 درجة ✓. الخطأُ الشائع: حسابُ متمّمها (90 − 65 = 25 درجة) أو مضاعفتها (130 درجة) أو قيمةٍ عشوائيّة (50 درجة).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('75fac750-9527-5bf7-9bc1-715908a98dfb', '88709f82-0a2f-54fb-a2f9-e2a8ca4adbde', 'مستقيمٌ (m) يمرّ بمنتصف القطعة [EF] لكنّه **ليس** عموديًّا عليها. هل (m) موسّطٌ عموديٌّ لِـ [EF]؟', '[{"id":"a","text":"نعم، لأنّه يمرّ بالمنتصف"},{"id":"b","text":"نعم، لأنّ كلَّ مستقيمٍ يمرّ بالمنتصف يكون موسّطًا"},{"id":"c","text":"لا، لأنّه يفتقر إلى شرط العموديّة"},{"id":"d","text":"لا يمكن تحديدُ ذلك دون رسم"}]'::jsonb, 'c', 'الموسّطُ العموديّ لقطعةٍ يتطلّب شرطَين معًا: المرورَ بالمنتصف والعموديّةَ. مستقيمٌ يمرّ بالمنتصف فقط دون أن يكون عموديًّا على القطعة ليس موسّطًا عموديًّا لها، حتّى لو مرّ بمنتصفها تمامًا ✓.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d165190a-b268-56a4-8ff1-e52b44638afe', '88709f82-0a2f-54fb-a2f9-e2a8ca4adbde', 'مثلّثٌ ABC ونظيرُه A′B′C′ بالنسبة إلى محورٍ (d). أيُّ العبارات التالية صحيحة؟', '[{"id":"a","text":"طولُ [A′B′] يساوي طولَ [AB]، وقياسُ الزاوية في A′ يساوي قياسَها في A"},{"id":"b","text":"طولُ [A′B′] أكبرُ من طول [AB] دائمًا"},{"id":"c","text":"قياسُ الزوايا يتغيّر بعد التناظر"},{"id":"d","text":"المثلّث A′B′C′ له مساحةٌ مختلفة عن ABC"}]'::jsonb, 'a', 'التناظرُ المحوري يحفظ الأطوالَ والزوايا معًا: A′B′ = AB، وقياسُ زاوية A′ = قياسُ زاوية A، وبالتالي المثلّثان متطابقان (نفسُ المساحة) ✓. الخياراتُ الأخرى تناقض خاصيّةَ حفظ القياسات.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

