  ('4ca97c5a-642c-5c94-a865-1578d613972d', '4556562b-c75f-5e8b-9b96-d244b28c9845', 'math-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: مسائلُ التناظر المحوري', 4, 300, 60, 'challenge', 'admin', 4)
