INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('10dad03c-fbfc-58ee-ae88-f2822067ce17', '4ca97c5a-642c-5c94-a865-1578d613972d', 'نظيرُ النقطة R بالنسبة إلى محور (d) هو R′، ويبعد R′ عن (d) مسافةَ 7 سم. ما بُعدُ R عن (d)؟', '[{"id":"a","text":"7 سم"},{"id":"b","text":"3,5 سم"},{"id":"c","text":"10,5 سم"},{"id":"d","text":"14 سم"}]'::jsonb, 'a', 'خاصيّةُ تساوي البُعد تعمل في الاتّجاهَين: إذا كان R′ يبعد 7 سم عن (d)، فإنّ R تبعد المسافةَ نفسَها، 7 سم ✓. الخطأُ الشائع: قسمةُ المسافة أو مضاعفتُها ظنًّا أنّ الاتّجاه العكسي يغيّر القيمة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('dc9fc2ab-b1f5-58c2-8028-7d7f3d9c81fe', '4ca97c5a-642c-5c94-a865-1578d613972d', 'قطعةٌ [XY] طولُها 12 سم. الموسّطُ العموديّ لِـ [XY] هو المحور (d). ما بُعدُ X عن (d)؟', '[{"id":"a","text":"3 سم"},{"id":"b","text":"9 سم"},{"id":"c","text":"12 سم"},{"id":"d","text":"6 سم"}]'::jsonb, 'd', 'الموسّطُ العموديّ يمرّ بمنتصف القطعة، وبما أنّ [XY] = 12 سم، فإنّ منتصفَها يبعد نصفَ الطول عن كلّ طرف: 12 ÷ 2 = 6 سم. إذن X يبعد 6 سم عن (d) (وكذلك Y) ✓. الخطأُ الشائع: استعمالُ الطول الكامل (12 سم) أو ربعه (3 سم) بدل نصفه.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('be59cf3d-0bb4-55e2-b8f1-91972acf1208', '4ca97c5a-642c-5c94-a865-1578d613972d', 'شكلٌ هندسيٌّ له محورا تناظرٍ فقط، يمرّان بمنتصفَي زوجَي أضلاعه المتقابلة، وليس أيٌّ من قُطريه محورًا. ما هذا الشكل؟', '[{"id":"a","text":"مربّع"},{"id":"b","text":"مستطيلٌ غيرُ مربّع"},{"id":"c","text":"مثلّث متساوي الساقين"},{"id":"d","text":"دائرة"}]'::jsonb, 'b', 'الشكلُ الذي له محورا تناظرٍ فقط (يمرّان بمنتصفَي الأضلاع المتقابلة، دون أن يكون القُطران محوري تناظرٍ) هو المستطيلُ غيرُ المربّع. المربّعُ له 4 محاور (منها القُطران)، والمثلّثُ متساوي الساقين له محورٌ واحد، والدائرةُ عددٌ لا نهائي ✓.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f90c7b8d-47a8-54ff-b95b-64371d28791a', '4ca97c5a-642c-5c94-a865-1578d613972d', 'قال أحمد: «إذا كانت النقطُ A وB وC مستقيميّة، فإنّ نظيراتها A′ وB′ وC′ تشكّل مثلّثًا بعد التناظر». هل قولُ أحمد صحيح؟', '[{"id":"a","text":"نعم، التناظرُ يحوّل الاستقامةَ إلى مثلّث دائمًا"},{"id":"b","text":"نعم، لكن فقط إذا كان المحورُ عموديًّا على [AC]"},{"id":"c","text":"لا، لأنّ الاستقامةَ خاصيّةٌ محفوظةٌ بالتناظر، فتبقى A′ وB′ وC′ مستقيميّةً أيضًا"},{"id":"d","text":"لا يمكن معرفةُ ذلك دون قياس الزوايا"}]'::jsonb, 'c', 'خطأُ أحمد هو تجاهلُ خاصيّة حفظ الاستقامة: التناظرُ المحوري يحوّل النقطَ المستقيميّة إلى نقطٍ مستقيميّةٍ أيضًا، فلا يمكن أن تشكّل A′ وB′ وC′ مثلّثًا (لأنّ المثلّث يتطلّب ثلاثَ نقطٍ غيرَ مستقيميّة) ✓.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7127adc6-2866-5407-9298-53f3d0f3d1c2', '4ca97c5a-642c-5c94-a865-1578d613972d', 'مربّعٌ ABCD، ومحورُ التناظر (d) هو أحدُ قُطريه [AC]. ما نظيرُ الرأس B بالنسبة إلى (d)؟', '[{"id":"a","text":"A"},{"id":"b","text":"B نفسُها"},{"id":"c","text":"D"},{"id":"d","text":"C"}]'::jsonb, 'c', 'قُطرا المربّع محورا تناظرٍ له. بالنسبة إلى القُطر [AC]، يتبادل الرأسان الآخران B وD مكانَيهما (لأنّهما على بُعدٍ متساوٍ من [AC] وعموديّين عليه)، بينما A وC (الواقعان على المحور نفسه) ثابتان. إذن نظيرُ B هو D ✓.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8150a376-d16c-5c37-a67e-a2f383675ebe', '4ca97c5a-642c-5c94-a865-1578d613972d', 'مستطيلٌ عرضُه 6 سم. أحدُ محوري تناظره يمرّ بمنتصفَي الضلعين الكبيرين، موازيًا لهما. ما بُعدُ كلّ ضلعٍ كبيرٍ عن هذا المحور؟', '[{"id":"a","text":"3 سم"},{"id":"b","text":"1,5 سم"},{"id":"c","text":"6 سم"},{"id":"d","text":"12 سم"}]'::jsonb, 'a', 'هذا المحورُ يمرّ بمنتصف العرض (6 سم)، فيقسمه إلى نصفَين متساويَين: كلُّ ضلعٍ كبيرٍ يبعد عن المحور 6 ÷ 2 = 3 سم ✓. الخطأُ الشائع: استعمالُ العرض الكامل (6 سم) أو ربعه (1,5 سم) بدل نصفه، أو مضاعفةُ العرض خطأً (12 سم).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

