INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5101ff28-bf2e-515c-82d9-41939e66af2f', 'e98684e1-5e4f-5a05-bc80-b8c7db6ad474', 'النقطة K تبعد 4,5 سم عن محور التناظر (d). ما بُعدُ نظيرها K′ عن (d)؟', '[{"id":"a","text":"4,5 سم"},{"id":"b","text":"2,25 سم"},{"id":"c","text":"9 سم"},{"id":"d","text":"13,5 سم"}]'::jsonb, 'a', 'بُعدُ نظيرِ نقطةٍ عن المحور يساوي بُعدَ النقطة الأصليّة: بُعدُ K′ = بُعدُ K = 4,5 سم ✓.', 1, 'mcq', NULL, NULL)
