INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5d55302d-0411-5ddc-bdf8-2681155f06dd', 'e98684e1-5e4f-5a05-bc80-b8c7db6ad474', 'شبهُ منحرفٍ (رباعيّ) EFGH، ونظيرُه E′F′G′H′ بالنسبة إلى محورٍ (d). أيُّ عبارةٍ صحيحة؟', '[{"id":"a","text":"الشكلُ الناتج ليس له نفسُ عدد الأضلاع"},{"id":"b","text":"أطوالُ أضلاع E′F′G′H′ مختلفةٌ عن EFGH"},{"id":"c","text":"زوايا E′F′G′H′ أصغرُ من زوايا EFGH"},{"id":"d","text":"E′F′G′H′ مطابقٌ لِـ EFGH في الأطوال والزوايا، لكنّه معكوسُ الاتّجاه"}]'::jsonb, 'd', 'نظيرُ أيّ شكلٍ (رباعيٍّ هنا) بالتناظر المحوري مطابقٌ للشكل الأصليّ تمامًا في عدد الأضلاع والأطوال والزوايا، والفرقُ الوحيد هو انعكاسُ الاتّجاه (كصورة المرآة) ✓.', 2, 'mcq', NULL, NULL)
