INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('dc07e38c-e7d5-5730-9328-bc70b38a95e4', 'e98684e1-5e4f-5a05-bc80-b8c7db6ad474', 'مثلّثٌ متساوي الساقين قياسُ زاويته عند الرأس 50 درجة. بعد تناظرٍ محوريّ بالنسبة إلى محور تناظره (الموسّط العموديّ لقاعدته)، ما قياسُ نظير هذه الزاوية؟', '[{"id":"a","text":"25 درجة"},{"id":"b","text":"50 درجة"},{"id":"c","text":"40 درجة"},{"id":"d","text":"100 درجة"}]'::jsonb, 'b', 'بما أنّ محور التناظر المستعمَل هو محورُ تناظر المثلّث نفسه، فإنّ نظيرَ المثلّث هو المثلّثُ نفسُه (ينطبق على نفسه)، ونظيرُ الزاوية عند الرأس له القياسُ نفسُه، 50 درجة — كما تقتضي خاصيّةُ حفظ الزوايا في كلّ الأحوال ✓.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
