INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9e4953b8-034b-5f86-af63-4d5e8c5ff54f', 'e98684e1-5e4f-5a05-bc80-b8c7db6ad474', 'شكلٌ رباعيٌّ له 4 محاور تناظر. أيُّ الأشكال التالية يُحقّق هذا الشرط؟', '[{"id":"a","text":"مستطيلٌ غيرُ مربّع"},{"id":"b","text":"شبهُ منحرف"},{"id":"c","text":"مربّع"},{"id":"d","text":"متوازي أضلاع"}]'::jsonb, 'c', 'المربّعُ هو الرباعيّ الذي يملك 4 محاور تناظر (محوران يمرّان بمنتصفَي الأضلاع المتقابلة، ومحوران قُطريّان). المستطيلُ غيرُ المربّع له محوران فقط، وشبهُ المنحرف ومتوازي الأضلاع العامّان لا محورَ تناظرٍ لهما عمومًا ✓.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b9b20f77-6d6e-52a8-8cee-b647b18e97af', 'e98684e1-5e4f-5a05-bc80-b8c7db6ad474', 'أرادت هدى إنشاءَ الموسّط العموديّ للقطعة [LM]، فرسمت مستقيمًا عموديًّا على [LM] لكنّه يمرّ بنقطةٍ قريبةٍ من L لا بمنتصف [LM]. هل إنشاؤها صحيح؟', '[{"id":"a","text":"لا، لأنّها لم تُحقّق شرطَ المرور بالمنتصف رغم تحقيق العموديّة"},{"id":"b","text":"نعم، يكفي أن يكون المستقيمُ عموديًّا على القطعة"},{"id":"c","text":"نعم، لأنّ أيّ مستقيمٍ عموديٍّ على القطعة يكون موسّطًا"},{"id":"d","text":"لا، لأنّها لم ترسم المستقيمَ عموديًّا أصلًا"}]'::jsonb, 'a', 'الموسّطُ العموديّ يتطلّب شرطَين معًا: العموديّةَ والمرورَ بمنتصف القطعة. رسمُ هدى عموديٌّ بالفعل، لكنّه لا يمرّ بالمنتصف، فليس موسّطًا عموديًّا لِـ [LM] رغم تحقيق شرطٍ واحد فقط ✓.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0dc0f090-4fc3-512a-87cc-cefd1fb2a775', 'e98684e1-5e4f-5a05-bc80-b8c7db6ad474', 'قطعةٌ [OP] طولُها 16 سم. محورُ التناظر (d) هو موسّطُها العموديّ. نقطةٌ Q تقع على (d). ما الفرقُ بين QO وQP؟', '[{"id":"a","text":"8 سم"},{"id":"b","text":"0 سم"},{"id":"c","text":"16 سم"},{"id":"d","text":"لا يمكن تحديدُه"}]'::jsonb, 'b', 'بما أنّ Q تقع على الموسّط العموديّ لِـ [OP]، فهي على بُعدٍ متساوٍ من طرفَي القطعة: QO = QP (خاصيّةُ كلّ نقطةٍ من الموسّط العموديّ). إذن الفرقُ بينهما معدوم: QO − QP = 0 سم ✓. الخطأُ الشائع: استعمالُ نصف الطول (8 سم) أو الطول الكامل (16 سم) ظنًّا أنّ السؤال يطلب طولَ [OP] لا الفرق بين QO وQP.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

