  ('6a5c4ba4-b112-5b76-9e91-34acc76ad7d6', '4556562b-c75f-5e8b-9b96-d244b28c9845', 'math-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّةُ فصل التّناظر المحوريّ', 4, 300, 60, 'challenge', 'admin', 6)
