INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('dd96246a-365e-56d9-9b9f-8cf4d6f1bc40', '6a5c4ba4-b112-5b76-9e91-34acc76ad7d6', 'نظيرُ القطعة [ST] بالنسبة إلى محورٍ (d) هو [S′T′]، وطولُ [S′T′] يساوي 11 سم. ما طولُ [ST]؟', '[{"id":"a","text":"5,5 سم"},{"id":"b","text":"11 سم"},{"id":"c","text":"16,5 سم"},{"id":"d","text":"22 سم"}]'::jsonb, 'b', 'حفظُ الأطوال يعمل في الاتّجاهَين: بما أنّ [S′T′] = 11 سم، فإنّ [ST] = 11 سم أيضًا ✓.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('cdfb8e00-3d13-595d-8dfc-ace8ac43553d', '6a5c4ba4-b112-5b76-9e91-34acc76ad7d6', 'المحورُ (d) موسّطٌ عموديٌّ لقطعة [AB] طولُها 14 سم. نقطةٌ M تقع على (d)، وتبعد عن A مسافةَ 9 سم. ما بُعدُ M عن B؟', '[{"id":"a","text":"5 سم"},{"id":"b","text":"7 سم"},{"id":"c","text":"9 سم"},{"id":"d","text":"14 سم"}]'::jsonb, 'c', 'كلُّ نقطةٍ من الموسّط العموديّ لقطعةٍ تبعد المسافةَ نفسَها عن طرفَيها: بما أنّ M تقع على (d) (موسّط [AB])، فإنّ MB = MA = 9 سم ✓. طولُ [AB] (14 سم) معطًى إضافيٌّ لا يدخل في هذا الحساب مباشرةً. الخطأُ الشائع: الخلطُ بين طول [AB] وبُعد M عن أحد طرفَيه.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('89459177-fadd-54fb-9bf1-5db47510f6dc', '6a5c4ba4-b112-5b76-9e91-34acc76ad7d6', 'دائرةٌ مركزُها O. أيُّ العبارات التالية **خاطئة** بخصوص محاور تناظرها؟', '[{"id":"a","text":"كلُّ قُطرٍ من أقطارها محورُ تناظرٍ لها"},{"id":"b","text":"عددُ محاور تناظرها لا نهائيّ"},{"id":"c","text":"كلُّ محاور تناظرها تمرّ بالمركز O"},{"id":"d","text":"وترٌ لا يمرّ بالمركز O يمكن أن يكون محورَ تناظرٍ لها"}]'::jsonb, 'd', 'العبارةُ الخاطئة هي (d): محاورُ تناظر الدائرة هي أقطارُها فقط (المستقيماتُ المارّة بالمركز)، أمّا الوترُ الذي لا يمرّ بالمركز فلا يقسم الدائرةَ إلى نصفَين متطابقَين، فليس محورَ تناظرٍ لها. العباراتُ الأخرى (a, b, c) صحيحةٌ جميعًا: كلُّ الأقطار محاور، عددُها لا نهائي، وكلُّها تمرّ بالمركز.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('557e54ad-8e32-59f4-a36c-675d56e4ef8d', '6a5c4ba4-b112-5b76-9e91-34acc76ad7d6', 'نقطةٌ R تبعد عن A مسافةَ 7 سم وعن B مسافةَ 7 سم أيضًا، حيث [AB] قطعةٌ معطاة. هل يمكن الجزمُ بأنّ R تقع على الموسّط العموديّ لِـ [AB]؟', '[{"id":"a","text":"لا، المسافتان المتساويتان لا تكفيان أبدًا"},{"id":"b","text":"نعم، لأنّ كلَّ نقطةٍ تبعد مسافاتٍ متساويةً عن طرفَي قطعةٍ تقع على موسّطها العموديّ"},{"id":"c","text":"نعم، لكن فقط إذا كانت R على استقامة A وB"},{"id":"d","text":"لا يمكن الجزمُ إلّا برسم العمود أوّلًا"}]'::jsonb, 'b', 'خاصيّةُ الموسّط العموديّ تنطبق في الاتّجاهَين: كلُّ نقطةٍ تبعد مسافاتٍ متساويةً عن طرفَي قطعةٍ تقع بالضرورة على موسّطها العموديّ. بما أنّ RA = RB = 7 سم، فإنّ R تقع على الموسّط العموديّ لِـ [AB] ✓.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7f735595-c7f3-59de-8f41-26bedb9b59c3', '6a5c4ba4-b112-5b76-9e91-34acc76ad7d6', 'مربّعٌ ABCD طولُ ضلعه 10 سم. محورُ تناظره (d) هو القُطر [AC]. ما هو نظيرُ القطعة [AB] بالنسبة إلى (d)، وما طولُه؟', '[{"id":"a","text":"[AD]، بطول 10 سم"},{"id":"b","text":"[AB] نفسُها، بطول 10 سم"},{"id":"c","text":"[CD]، بطول 10 سم"},{"id":"d","text":"[AC]، بطول غير معروف"}]'::jsonb, 'a', 'بما أنّ A تقع على المحور (d) = [AC] فهي ثابتة (A′ = A)، ونظيرُ B بالنسبة إلى [AC] هو D (لأنّهما متقابلان حول القُطر). إذن نظيرُ [AB] هو [AD]، وطولُه محفوظٌ بالتناظر فيساوي طولَ [AB]، أي 10 سم (وهو أيضًا طولُ ضلع المربّع نفسِه) ✓.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('481ebcf9-ff9d-5ac2-9239-258f5f5e9874', '6a5c4ba4-b112-5b76-9e91-34acc76ad7d6', 'قطعةٌ [UV] طولُها 20 سم، ومحورُ تناظرها (d) هو موسّطُها العموديّ. نقطتان W وZ تقعان كلتاهما على (d)، حيث WU = 13 سم. أيُّ العبارات التالية صحيحة؟', '[{"id":"a","text":"WV = 13 سم، وZU = ZV بالضرورة"},{"id":"b","text":"WV = 7 سم لأنّ 20 − 13 = 7"},{"id":"c","text":"WV = 10 سم لأنّه نصفُ طول [UV]"},{"id":"d","text":"لا يمكن تحديدُ WV لأنّ موضعَ W على (d) غيرُ معروف بدقّة"}]'::jsonb, 'a', 'كلُّ نقطةٍ تقع على الموسّط العموديّ لقطعةٍ تبعد المسافةَ نفسَها عن طرفَي هذه القطعة، مهما كان موضعُها بالضبط على المحور. إذن WV = WU = 13 سم بغضّ النظر عن موضع W على (d)، وبالمثل ZU = ZV لأيّ نقطةٍ Z على (d) ✓. طولُ [UV] (20 سم) لا يتدخّل في حساب WV مباشرةً، وهو معطًى إضافيٌّ لتشتيت الانتباه. الخطأُ الشائع: طرحُ 13 من 20 (b) أو أخذُ نصف [UV] (c) ظنًّا خطأً أنّ هذه القيم لها علاقة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

