INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a66745e2-a4e8-5ba1-9a1e-0228eb662328', '4ad813e3-2cb9-5347-bf1c-d30ab5457dfe', 'أيُّ رمزٍ من التالية يدلّ على أنّ المستقيمَين (d) و(d′) متعامدان؟', '[{"id":"a","text":"∥"},{"id":"b","text":"="},{"id":"c","text":"⊥"},{"id":"d","text":"≠"}]'::jsonb, 'c', 'الرمزُ ⊥ يُقرأ «عموديٌّ على» ويدلّ على التعامد (تكوين زاويةٍ قائمة)؛ أمّا ∥ فيدلّ على التوازي، و= و≠ لا علاقةَ لهما بالمستقيمات.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
