  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ece85619-9290-5cc6-ab38-ffcad89d7324', '4ad813e3-2cb9-5347-bf1c-d30ab5457dfe', 'ما تعريفُ مستقيمَين متوازيَين؟', '[{"id":"a","text":"يتقاطعان في نقطةٍ واحدة"},{"id":"b","text":"لا يلتقيان مهما امتدّا (في المستوى نفسه)"},{"id":"c","text":"يُكوّنان زاويةً قائمة"},{"id":"d","text":"يتقاطعان في نقطتَين"}]'::jsonb, 'b', 'المستقيمان المتوازيان مستقيمان في المستوى نفسه لا يلتقيان مهما امتدّا (أو يتطابقان)؛ التقاطعُ في نقطةٍ واحدة يصف مستقيمَين متقاطعَين، والزاويةُ القائمة تصف التعامد.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
