  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('da37883e-37a1-5713-b096-e3a2ede2b0b6', '4ad813e3-2cb9-5347-bf1c-d30ab5457dfe', 'يتقاطع مستقيمان في نقطة O فتتكوّن زاويةٌ قياسُها 40°. ما قياسُ الزاوية المقابلة لها بالرأس؟

<svg viewBox="0 0 200 150">
<title>زاويتان عند O</title>
<line x1="15" y1="74" x2="185" y2="74" stroke="#0f172a" stroke-width="2"/>
<line x1="143.1" y1="18.84" x2="56.9" y2="129.16" stroke="#0f172a" stroke-width="2"/>
<circle cx="100" cy="74" r="2.2" fill="#0f172a"/>
<path d="M 116.01 53.51 A 26 26 0 0 1 126 74" fill="none" stroke="#ef4444" stroke-width="2"/>
<text x="135.95" y="60.47" text-anchor="middle" fill="#ef4444" font-size="12" font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">40°</text>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="105" y="89" text-anchor="middle" fill="#0f172a" font-size="13">O</text><text x="188" y="78" text-anchor="start" fill="#64748b" font-size="11">(d)</text><text x="52.9" y="141.16" text-anchor="middle" fill="#64748b" font-size="11">(d′)</text></g>
</svg>', '[{"id":"a","text":"40°"},{"id":"b","text":"50°"},{"id":"c","text":"140°"},{"id":"d","text":"320°"}]'::jsonb, 'a', 'الزاويتان المتقابلتان بالرأس متقايستان دائمًا، فقياسُ الزاوية المقابلة أيضًا 40°. القيمة 140° = 180 − 40 هي قياسُ الزاوية المجاورة المكمّلة لا المقابلة.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
