INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e72acd67-4cfc-5492-8958-46ece5787ae7', '4ad813e3-2cb9-5347-bf1c-d30ab5457dfe', 'مستقيمان (d) و(d′) يقطعهما قاطعٌ (Δ) في نقطتَين. أين تقع الزاويتان المتبادلتان داخليًّا؟', '[{"id":"a","text":"بين المستقيمَين، وعلى نفس الجهة من القاطع"},{"id":"b","text":"عند نقطة تقاطع المستقيمَين معًا"},{"id":"c","text":"بين المستقيمَين، وعلى جهتَين مختلفتَين من القاطع"},{"id":"d","text":"خارج المستقيمَين، وعلى جهتَين مختلفتَين من القاطع"}]'::jsonb, 'c', 'الزاويتان المتبادلتان داخليًّا داخليّتان (بين المستقيمَين) وتقعان على جهتَين مختلفتَين من القاطع؛ إذا كانتا على نفس الجهة فهما متناظرتان لا متبادلتان، وإذا كانتا خارج المستقيمَين فهما زاويتان خارجيّتان.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
