  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('59c85b49-7d56-5a44-9517-ba845385822b', '4ad813e3-2cb9-5347-bf1c-d30ab5457dfe', 'قاطعٌ يقطع (d) و(d′) فينتج زاويتَين متناظرتَين متقايستَين. ماذا نستنتج؟', '[{"id":"a","text":"(d) و(d′) متقاطعان في نقطتَين"},{"id":"b","text":"(d) ⊥ (d′)"},{"id":"c","text":"لا يمكن الاستنتاج"},{"id":"d","text":"(d) ∥ (d′)"}]'::jsonb, 'd', 'بحسب معيار التوازي، تقايسُ زاويتَين متناظرتَين ناتجتَين عن قاطعٍ لمستقيمَين يعني أنّ المستقيمَين متوازيان: (d) ∥ (d′).', 5, 'mcq', NULL, NULL)
