INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e9021713-8ed1-5f2e-a820-46986f8decc1', '063e2343-a9e8-5bc3-8731-f8e9424f68a4', 'أيُّ رمزٍ يدلّ على أنّ (d) موازٍ لِـ(d′)؟', '[{"id":"a","text":"⊥"},{"id":"b","text":"∈"},{"id":"c","text":"∥"},{"id":"d","text":"⊂"}]'::jsonb, 'c', 'الرمزُ ∥ يُقرأ «موازٍ لِـ» ويدلّ على التوازي؛ ⊥ يدلّ على التعامد، و∈ و⊂ رمزا انتماء واحتواء لا علاقة لهما بالمستقيمات هنا.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
