  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0dd4e65f-a29e-5291-aef2-7acf8c5de546', '063e2343-a9e8-5bc3-8731-f8e9424f68a4', 'لبناء مستقيمٍ عموديٍّ على مستقيم (d) يمرّ بنقطةٍ A، أيّ أداتَين نستعمل؟', '[{"id":"a","text":"الفرجار والمنقلة"},{"id":"b","text":"المسطرة والكوس"},{"id":"c","text":"المسطرة والفرجار"},{"id":"d","text":"الكوس والمنقلة"}]'::jsonb, 'b', 'نستعمل المسطرةَ والكوس (المثلّث القائم الزاوية): نُزحلق الكوسَ على طول (d) حتّى يلامس ضلعُه الثاني النقطةَ A، ثمّ نرسم المستقيمَ العموديّ على طول هذا الضلع.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
