  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5fb9864d-f381-535f-8291-cae1e34c8003', '063e2343-a9e8-5bc3-8731-f8e9424f68a4', 'أيُّ زاويتَين تُسمَّيان «متناظرتَين» بالنسبة لمستقيمَين وقاطع؟', '[{"id":"a","text":"زاويتان تشتركان في الرأس نفسِه"},{"id":"b","text":"زاويتان تقعان بين المستقيمَين وعلى جهتَين مختلفتَين من القاطع"},{"id":"c","text":"زاويتان مجموعُهما 180° دائمًا"},{"id":"d","text":"زاويتان تقعان على نفس الجهة من القاطع، إحداهما عند كلّ مستقيمٍ وفي الوضع نفسِه"}]'::jsonb, 'd', 'الزاويتان المتناظرتان تقعان على نفس الجهة من القاطع، إحداهما عند نقطة تقاطعه بالمستقيم الأوّل والأخرى عند نقطة تقاطعه بالمستقيم الثاني، وفي الوضع نفسِه بالنسبة لكلّ مستقيم. الخيارُ (b) يصف الزاويتَين المتبادلتَين داخليًّا لا المتناظرتَين.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
