INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c0f7794a-d994-5cbb-b234-b6c903184a85', '416e8eee-9b83-5910-9650-05e22c3f51e9', 'مستقيمٌ (d₃) عموديٌّ على (d₁)، و(d₁) ∥ (d₂). ماذا يمكن قولُه عن (d₃) و(d₂)؟', '[{"id":"a","text":"(d₃) ⊥ (d₂)"},{"id":"b","text":"(d₃) ∥ (d₂)"},{"id":"c","text":"لا يمكن تحديد العلاقة"},{"id":"d","text":"(d₃) و(d₂) متقاطعان بزاويةٍ غير قائمة"}]'::jsonb, 'a', 'إذا كان مستقيمٌ عموديًّا على أحد مستقيمَين متوازيَين، فهو عموديٌّ على الآخر أيضًا: بما أنّ (d₃) ⊥ (d₁) و(d₁) ∥ (d₂)، فإنّ (d₃) ⊥ (d₂).', 1, 'mcq', NULL, NULL)
