INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ad7c7e49-653b-567a-9157-9e4a008edd16', '416e8eee-9b83-5910-9650-05e22c3f51e9', 'قاطعٌ يقطع (d) و(d′) فينتج زاويةً متناظرةً عند A قياسُها 78°، وزاويةً متناظرةً عند B قياسُها 78° أيضًا. ماذا نستنتج؟', '[{"id":"a","text":"(d) ⊥ (d′)"},{"id":"b","text":"(d) و(d′) متطابقان (نفسُ المستقيم)"},{"id":"c","text":"لا يمكن الاستنتاج، نحتاج زاويتَين متبادلتَين لا متناظرتَين"},{"id":"d","text":"(d) ∥ (d′)"}]'::jsonb, 'd', 'تقايسُ زاويتَين متناظرتَين ناتجتَين عن قاطعٍ لمستقيمَين هو معيارٌ كافٍ للاستنتاج أنّ المستقيمَين متوازيان: (d) ∥ (d′).', 2, 'mcq', NULL, NULL)
