  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d52e572b-7dec-58e1-af00-466fe9721616', '416e8eee-9b83-5910-9650-05e22c3f51e9', 'زاويتان متبادلتان داخليًّا، إحداهما عند A قياسُها 85°، والأخرى عند B قياسُها 95°. ماذا نستنتج عن المستقيمَين (d) و(d′)؟', '[{"id":"a","text":"(d) ∥ (d′) لأنّ 85 + 95 = 180"},{"id":"b","text":"(d) ∥ (d′) لأنّ الزاويتَين متكاملتان"},{"id":"c","text":"(d) و(d′) غير متوازيَين، لأنّ الزاويتَين المتبادلتَين داخليًّا غيرُ متقايستَين"},{"id":"d","text":"لا يمكن الاستنتاج مهما كانت القياسات"}]'::jsonb, 'c', 'معيارُ التوازي يشترط تقايسَ الزاويتَين المتبادلتَين داخليًّا، لا تكاملَهما. بما أنّ 85° ≠ 95°، فإنّ (d) و(d′) غير متوازيَين.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
