  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('bad6954e-30a1-57b1-84ae-58178f04866e', '416e8eee-9b83-5910-9650-05e22c3f51e9', 'سكّتا حديدٍ متوازيتان (d) و(d′)، يقطعهما طريقٌ (قاطع) بزاويةٍ. القاطعُ يُنتج عند تقاطعه بـ(d) زاويةً داخليّةً قياسُها 112° (يمين القاطع). ما قياسُ الزاوية الداخليّة المتبادلة لها عند (d′) (يسار القاطع)؟', '[{"id":"a","text":"68°"},{"id":"b","text":"90°"},{"id":"c","text":"112°"},{"id":"d","text":"124°"}]'::jsonb, 'c', 'بما أنّ سكّتَي الحديد متوازيتان، فإنّ الزاويتَين المتبادلتَين داخليًّا الناتجتَين عن القاطع متقايستان: 112° أيضًا. القيمة 68° = 180 − 112 تخصّ الزاويةَ المجاورة لا المتبادلة.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('82b27eeb-95a8-5ec5-9233-6a0634759a91', '416e8eee-9b83-5910-9650-05e22c3f51e9', 'حاول طارقٌ إثباتَ أنّ (d) ∥ (d′): لاحظ أنّ زاويتَين متجاورتَين (على نفس المستقيم) متقايستان، فاستنتج أنّ (d) ∥ (d′). أين الخطأُ في استدلال طارق؟', '[{"id":"a","text":"نسي أن يتحقّق من أنّ الزاويتَين قائمتان"},{"id":"b","text":"الزاويتان المتجاورتان لا يمكن أن تتقايسا أبدًا"},{"id":"c","text":"لا يوجد خطأ، استدلالُه صحيح"},{"id":"d","text":"استعمل زاويتَين متجاورتَين، ومعيارُ التوازي يشترط زاويتَين متبادلتَين داخليًّا أو متناظرتَين لا متجاورتَين"}]'::jsonb, 'd', 'معيارُ التوازي يُطبَّق فقط على زاويتَين متبادلتَين داخليًّا أو متناظرتَين ناتجتَين عن قاطعٍ لمستقيمَين، لا على زاويتَين متجاورتَين على المستقيم نفسِه. خطأُ طارق هو استعمالُ نوعِ الزوايا الخطأ.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

