INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ab91811d-ffb3-5b8b-bd69-287fc09b53bd', '40a70303-3051-5e4c-82a7-9347d3508189', 'لبناء مستقيمٍ (d″) موازٍ لمستقيمٍ (d) يمرّ بنقطةٍ B خارج (d)، ماذا نُثبّت لتزحليق الكوس؟', '[{"id":"a","text":"مسطرةً نُلامس بها الضلعَ الآخر للكوس، تبقى ثابتةً أثناء التزحليق"},{"id":"b","text":"قلمًا فقط دون أيّ أداةٍ إضافية"},{"id":"c","text":"منقلةً لقياس الزاوية أوّلًا"},{"id":"d","text":"فرجارًا لتحديد المسافة"}]'::jsonb, 'a', 'لبناء التوازي، نُثبّت مسطرةً تلامس الضلعَ الآخر للكوس وتبقى ثابتة، ثمّ نُزحلق الكوسَ على طولها حتّى يصل ضلعُه الملامسُ لـ(d) إلى النقطة B، فنرسم على طول هذا الضلع الجديد.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
