  ('77a5a41d-6e72-5cc3-b2f7-dd6c6638c3ed', '40a70303-3051-5e4c-82a7-9347d3508189', 'أيُّ زاويتَين تُسمَّيان «متقابلتَين بالرأس»؟', '[{"id":"a","text":"زاويتان تشتركان في ضلعٍ واحد فقط"},{"id":"b","text":"زاويتان ناتجتان عن تقاطع مستقيمَين، وضلعا إحداهما امتدادٌ لضلعَي الأخرى"},{"id":"c","text":"زاويتان مجموعُهما 90°"},{"id":"d","text":"زاويتان تقعان على قاطعٍ لمستقيمَين متوازيَين"}]'::jsonb, 'b', 'الزاويتان المتقابلتان بالرأس تتكوّنان من تقاطع مستقيمَين، بحيث يكون ضلعا إحداهما امتدادًا مستقيمًا لضلعَي الأخرى عبر نقطة التقاطع، وهما متقايستان دائمًا.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
