INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ef4996ea-dd5c-5c12-86af-36b9e8ae0427', '40a70303-3051-5e4c-82a7-9347d3508189', 'زاويتان متبادلتان داخليًّا قياسُ كلٍّ منهما 90°. ماذا نستنتج عن المستقيمَين؟', '[{"id":"a","text":"متعامدان فقط"},{"id":"b","text":"لا يمكن الاستنتاج لأنّ 90° حالةٌ خاصّة"},{"id":"c","text":"متوازيان فقط"},{"id":"d","text":"متوازيان، والقاطعُ عموديٌّ على كليهما أيضًا"}]'::jsonb, 'd', 'تقايسُ الزاويتَين المتبادلتَين داخليًّا (90° = 90°) يعني أنّ المستقيمَين متوازيان. وبما أنّ كلَّ زاويةٍ قائمة، فإنّ القاطعَ نفسَه عموديٌّ على المستقيمَين كليهما.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5bd04bbd-bf52-54f3-8ae6-f86d4cb57679', '40a70303-3051-5e4c-82a7-9347d3508189', 'أرادت منى أن تتأكّد من توازي حافّتَي طاولةٍ مستطيلة (d) و(d′). قاسَت بمنقلةٍ زاويةً متبادلةً داخليّةً عند إحدى الحافّتَين فوجدَتها 89°، وعند الحافّة الأخرى 91°. هل الحافّتان متوازيتان؟', '[{"id":"a","text":"لا يمكن الحكم دون قياس زاويةٍ ثالثة"},{"id":"b","text":"لا، لأنّ الزاويتَين المتبادلتَين غيرُ متقايستَين تمامًا (89° ≠ 91°)"},{"id":"c","text":"نعم، لأنّ 89 + 91 = 180"},{"id":"d","text":"نعم، لأنّ الفرقَ بينهما بسيط"}]'::jsonb, 'b', 'معيارُ التوازي يشترط تقايسًا تامًّا بين الزاويتَين المتبادلتَين داخليًّا. بما أنّ 89° ≠ 91°، فإنّ الحافّتَين ليستا متوازيتَين تمامًا حسب هذا القياس، حتّى لو كان الفرقُ صغيرًا.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

