INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('fb9d04bf-7534-533a-ac16-22dc8ddac59f', 'ace4d5d5-f73c-5433-92b0-201cb4062c6f', 'مستقيمان (d₁) و(d₂) عموديّان معًا على (d₃). قاطعٌ يقطع (d₁) و(d₂) فينتج زاويةً متناظرةً عند تقاطعه بـ(d₁) قياسُها 74°. ما قياسُ الزاوية المتناظرة لها عند تقاطعه بـ(d₂)؟', '[{"id":"a","text":"74°"},{"id":"b","text":"90°"},{"id":"c","text":"106°"},{"id":"d","text":"148°"}]'::jsonb, 'a', 'أوّلًا: بما أنّ (d₁) ⊥ (d₃) و(d₂) ⊥ (d₃)، فإنّ (d₁) ∥ (d₂) (خاصّيةُ التعامد المشترك). ثانيًا: بما أنّهما متوازيان، فإنّ الزاويتَين المتناظرتَين الناتجتَين عن القاطع متقايستان: 74° أيضًا. القيمة 106° = 180 − 74 ناتجةٌ عن خلطٍ بالتكامل، و148° = 2 × 74 خطأُ مضاعفة، و90° افتراضٌ غيرُ مبرَّر بأنّ الزاوية قائمة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8fd32f0f-8dd1-5989-ae6c-dd9d01c80edc', 'ace4d5d5-f73c-5433-92b0-201cb4062c6f', '(d) ∥ (d′)، وقاطعٌ ينتج زاويتَين متبادلتَين داخليًّا: إحداهما قياسُها (2x + 10)° والأخرى قياسُها (3x − 15)°. ما قيمةُ x؟', '[{"id":"a","text":"5"},{"id":"b","text":"15"},{"id":"c","text":"25"},{"id":"d","text":"35"}]'::jsonb, 'c', 'بما أنّ (d) ∥ (d′)، فالزاويتان المتبادلتان داخليًّا متقايستان: 2x + 10 = 3x − 15. نعزل: 10 + 15 = 3x − 2x → x = 25 ✓. (التحقّق: 2 × 25 + 10 = 60 و3 × 25 − 15 = 60، متقايستان ✓).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6b98004e-0caf-5d38-a9d0-9a9355dfe1db', 'ace4d5d5-f73c-5433-92b0-201cb4062c6f', 'مستطيلٌ ABCD (زواياه الأربع قائمة). امتدّ الضلعُ [AB] والضلعُ [DC] كمستقيمَين (d) و(d′). هل (d) ∥ (d′)؟ ولماذا؟', '[{"id":"a","text":"لا يمكن الاستنتاج من زوايا المستطيل وحدها"},{"id":"b","text":"لا، لأنّ (d) و(d′) يتقاطعان حتمًا"},{"id":"c","text":"نعم، لكن فقط إذا كان المستطيلُ مربّعًا"},{"id":"d","text":"نعم، لأنّ (AD) عموديٌّ على كلٍّ من (d) و(d′) (زوايا المستطيل قائمة)، فهما متوازيان"}]'::jsonb, 'd', 'بما أنّ زوايا المستطيل قائمة، فإنّ الضلعَ [AD] عموديٌّ على [AB] وعلى [DC] معًا، أي (AD) ⊥ (d) و(AD) ⊥ (d′). وبما أنّ مستقيمَين عموديَّين على مستقيمٍ ثالثٍ متوازيان، فإنّ (d) ∥ (d′).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('666ee659-5698-58dc-8db7-d48d0f6d94f2', 'ace4d5d5-f73c-5433-92b0-201cb4062c6f', 'أيُّ العبارات التالية صحيحة؟', '[{"id":"a","text":"زاويتان متقابلتان بالرأس مجموعُ قياسَيهما 180° دائمًا"},{"id":"b","text":"إذا كانت زاويتان متناظرتان متقايستَين فالمستقيمان متوازيان"},{"id":"c","text":"الزاويتان المتبادلتان داخليًّا تقعان دائمًا خارج المستقيمَين"},{"id":"d","text":"مستقيمان عموديّان على مستقيمَين مختلفَين متوازيان حتمًا"}]'::jsonb, 'b', 'العبارةُ (b) صحيحة: هذا هو معيارُ التوازي المباشر. أمّا (a) فخطأ: الزاويتان المتقابلتان بالرأس متقايستان لا متكاملتَين. و(c) خطأ: الزاويتان المتبادلتان داخليّتان بالتعريف لا خارجيّتَين. و(d) خطأ: يجب أن يكون المستقيمان عموديَّين على المستقيم الثالث نفسِه، لا على مستقيمَين مختلفَين.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('705fe264-3cb5-5ac5-a34b-b731afd204b0', 'ace4d5d5-f73c-5433-92b0-201cb4062c6f', 'حلّت هدى مسألةً: (d) ∥ (d′)، وقاطعٌ ينتج زاويةً داخليّةً عند A قياسُها 130° (يمين القاطع)، وطُلب منها إيجادُ قياس الزاوية المتناظرة عند B. كتبت: «الزاويتان متناظرتان فهما متكاملتان، إذن القياسُ = 180 − 130 = 50°». أين خطأُ هدى؟', '[{"id":"a","text":"الخطأُ في عمليّة الطرح فقط؛ الصحيحُ 60°"},{"id":"b","text":"لا يوجد خطأ، الجوابُ 50° صحيح"},{"id":"c","text":"الزاويتان المتناظرتان متقايستان لا متكاملتَين؛ الصحيحُ 130°"},{"id":"d","text":"نسيت أنّ القاطعَ لا يُنتج زوايا متناظرة أصلًا"}]'::jsonb, 'c', 'الزاويتان المتناظرتان الناتجتان عن قاطعٍ لمستقيمَين متوازيَين متقايستان، لا متكاملتَين. خطأُ هدى هو استعمالُ قاعدة التكامل (180°) الخاصّة بالزوايا المتجاورة، بينما القاعدةُ الصحيحة هنا هي التقايس: القياسُ الصحيح عند B هو 130° أيضًا.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('414b1587-ce21-5b2c-b8e8-05646ba99490', 'ace4d5d5-f73c-5433-92b0-201cb4062c6f', 'في شبكةِ طرقٍ، يتقاطع طريقٌ رئيسيٌّ (قاطع) مع طريقَين جانبيَّين (d) و(d′) يُفترض أنّهما متوازيان. عند التقاطع الأوّل، تكوّنت زاويةٌ داخليّةٌ قياسُها (4x)°، وعند التقاطع الثاني تكوّنت الزاويةُ المتبادلةُ لها داخليًّا وقياسُها (2x + 50)°. إذا كان الطريقان فعلًا متوازيَين، فما قياسُ كلّ زاوية؟', '[{"id":"a","text":"25°"},{"id":"b","text":"50°"},{"id":"c","text":"100°"},{"id":"d","text":"150°"}]'::jsonb, 'c', 'بما أنّ الطريقَين متوازيان، الزاويتان المتبادلتان داخليًّا متقايستان: 4x = 2x + 50. نعزل: 4x − 2x = 50 → 2x = 50 → x = 25. إذن قياسُ الزاوية = 4 × 25 = 100° (والتحقّق: 2 × 25 + 50 = 100 أيضًا ✓). القيمة 25° هي قيمةُ x نفسِها لا قياسَ الزاوية المطلوب، و50° هو الحدّ الثابت في العبارة 2x + 50 فقط.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

