  ('6da4baf4-fba1-56d5-8715-09dd2be99397', 'b42d9061-a86f-51f4-a4e5-07c77e8b8778', 'math-7eme', '📝 تدريبٌ ⭐⭐⭐ شامل: الزوايا والاستقامة والتوازي (مراجعةٌ عامّة)', 3, 120, 30, 'boss', 'admin', 5)
