INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('35c957d8-4720-5557-91ba-ca45ad50b575', '6da4baf4-fba1-56d5-8715-09dd2be99397', 'أيُّ العبارات التالية تصف بشكل صحيح مستقيمَين متعامدَين؟', '[{"id":"a","text":"لا يلتقيان مهما امتدّا"},{"id":"b","text":"يتقاطعان في نقطتَين"},{"id":"c","text":"يُكوّنان زاويةً منفرجة"},{"id":"d","text":"يُكوّنان زاويةً قائمة (90°) عند تقاطعهما"}]'::jsonb, 'd', 'المستقيمان المتعامدان يتقاطعان مكوِّنَين زاويةً قائمةً قياسُها 90°؛ عدمُ الالتقاء يصف التوازي، والتقاطعُ في نقطتَين مستحيلٌ لمستقيمَين مختلفَين.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('36bdef79-cc9d-5dc4-b06b-fb727c56e68f', '6da4baf4-fba1-56d5-8715-09dd2be99397', 'زاويتان متقابلتان بالرأس، قياسُ إحداهما 118°. ما قياسُ زاويةٍ مجاورةٍ لهما على نفس المستقيم؟

<svg viewBox="0 0 200 150">
<title>زاويتان عند O</title>
<line x1="15" y1="74" x2="185" y2="74" stroke="#0f172a" stroke-width="2"/>
<line x1="143.1" y1="18.84" x2="56.9" y2="129.16" stroke="#0f172a" stroke-width="2"/>
<circle cx="100" cy="74" r="2.2" fill="#0f172a"/>
<path d="M 126 74 A 26 26 0 0 1 83.99 94.49" fill="none" stroke="#ef4444" stroke-width="2"/>
<text x="117.53" y="113.95" text-anchor="middle" fill="#ef4444" font-size="12" font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">118°</text>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="105" y="89" text-anchor="middle" fill="#0f172a" font-size="13">O</text><text x="188" y="78" text-anchor="start" fill="#64748b" font-size="11">(d)</text><text x="52.9" y="141.16" text-anchor="middle" fill="#64748b" font-size="11">(d′)</text></g>
</svg>', '[{"id":"a","text":"62°"},{"id":"b","text":"118°"},{"id":"c","text":"152°"},{"id":"d","text":"242°"}]'::jsonb, 'a', 'الزاويةُ المجاورة على نفس المستقيم مكمّلةٌ للزاوية المعطاة: 180 − 118 = 62°. القيمة 118° هي قياسُ الزاوية المقابلة بالرأس لا المجاورة.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4e0c25d1-fc9f-5211-a209-e754c545efc6', '6da4baf4-fba1-56d5-8715-09dd2be99397', '(d) ∥ (d′)، وقاطعٌ ينتج زاويةً عند A قياسُها 105°. زاويتُها المتناظرةُ عند B تقع في الوضع نفسِه بالنسبة لِـ(d′). ما قياسُها؟', '[{"id":"a","text":"15°"},{"id":"b","text":"75°"},{"id":"c","text":"90°"},{"id":"d","text":"105°"}]'::jsonb, 'd', 'الزاويتان المتناظرتان الناتجتان عن قاطعٍ لمستقيمَين متوازيَين متقايستان دائمًا: القياسُ عند B = 105° أيضًا. القيم 75° = 180 − 105 و90° و15° = 105 − 90 ناتجةٌ عن عمليّاتٍ حسابيّةٍ لا علاقة لها بخاصّية التقايس المباشر.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('39e3115e-abfd-5cb1-856b-096067e699fb', '6da4baf4-fba1-56d5-8715-09dd2be99397', 'مستقيمان (d) و(d′) يقطعهما قاطعٌ. الزاويةُ الداخليّةُ عند A (يمين القاطع) قياسُها 98°، والزاويةُ الداخليّةُ عند B (يسار القاطع) قياسُها 82°. هل (d) ∥ (d′)؟', '[{"id":"a","text":"لا يمكن الحكم دون معرفة زاويةٍ ثالثة"},{"id":"b","text":"نعم، لأنّهما متكاملتان"},{"id":"c","text":"لا، لأنّ الزاويتَين المتبادلتَين داخليًّا غيرُ متقايستَين (98° ≠ 82°)"},{"id":"d","text":"نعم، لأنّ 98 + 82 = 180"}]'::jsonb, 'c', 'معيارُ التوازي يشترط تقايسَ الزاويتَين المتبادلتَين داخليًّا، لا تكاملَهما. بما أنّ 98° ≠ 82°، فإنّ (d) و(d′) غير متوازيَين.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e2d0ef0c-8663-5711-93c3-a539bbee8a8b', '6da4baf4-fba1-56d5-8715-09dd2be99397', '(d₁) ⊥ (d₃) و(d₂) ⊥ (d₃) (فـ(d₁) ∥ (d₂) بحسب الخاصّية). قاطعٌ آخر (Δ) يقطع (d₁) و(d₂) فينتج عند تقاطعه بـ(d₁) زاويةً متبادلةً داخليًّا قياسُها 63°. ما قياسُ الزاوية المتبادلة لها عند تقاطع (Δ) بـ(d₂)؟', '[{"id":"a","text":"27°"},{"id":"b","text":"63°"},{"id":"c","text":"117°"},{"id":"d","text":"153°"}]'::jsonb, 'b', 'بما أنّ (d₁) ⊥ (d₃) و(d₂) ⊥ (d₃)، فإنّ (d₁) ∥ (d₂). وبما أنّهما متوازيان، فإنّ الزاويتَين المتبادلتَين داخليًّا الناتجتَين عن القاطع (Δ) متقايستان: 63° أيضًا.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8b998672-659f-5028-84b4-fee328bfa20d', '6da4baf4-fba1-56d5-8715-09dd2be99397', 'في نسيجِ سلّةٍ، تتقاطع أعوادٌ أفقيّةٌ (d) مع عودٍ مائلٍ (قاطع)، وتتقاطع أعوادٌ أفقيّةٌ أخرى (d′) مع العود نفسِه. قِيسَت زاويةٌ متبادلةٌ داخليّةٌ عند (d) فكانت 76°، وعند (d′) فكانت أيضًا 76°. هل الأعوادُ الأفقيّةُ (d) و(d′) متوازية، وهل يمكن التأكّد من ذلك بالكوس أيضًا؟', '[{"id":"a","text":"لا يمكن معرفة ذلك إلّا بالمنقلة فقط"},{"id":"b","text":"لا، لأنّ 76° ليست 90°"},{"id":"c","text":"نعم متوازيتان (تقايسُ الزاويتَين المتبادلتَين)، ويمكن أيضًا التحقّقُ بالكوس والمسطرة"},{"id":"d","text":"نعم، لكن فقط لأنّ العودَ قاطعٌ مائل"}]'::jsonb, 'c', 'تقايسُ الزاويتَين المتبادلتَين داخليًّا (76° = 76°) دليلٌ كافٍ حسب معيار التوازي على أنّ (d) ∥ (d′)، والكوسُ والمسطرةُ أداةٌ عمليّةٌ إضافيّةٌ للتحقّق من التوازي أو لإنشائه.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

