  ('2bd4a24c-ea8e-5384-a438-8122879b9b24', 'b42d9061-a86f-51f4-a4e5-07c77e8b8778', 'math-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّةُ فصل الزوايا والتوازي', 4, 300, 60, 'challenge', 'admin', 6)
