INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ab42bf4b-ecee-563c-bace-a13ddd7ebece', '2bd4a24c-ea8e-5384-a438-8122879b9b24', 'قاطعٌ يقطع مستقيمَين (d) و(d′). عند A تكوّنت زاويتان متجاورتان قياسُ إحداهما (3x)° والأخرى (x + 40)°. إذا علمتَ أنّ الزاويتَين المتجاورتَين على المستقيم (d) متكاملتان، فما قيمةُ x؟', '[{"id":"a","text":"35"},{"id":"b","text":"40"},{"id":"c","text":"45"},{"id":"d","text":"60"}]'::jsonb, 'a', 'الزاويتان المتجاورتان على نفس المستقيم متكاملتان: 3x + (x + 40) = 180 → 4x + 40 = 180 → 4x = 140 → x = 35 ✓. (التحقّق: 3 × 35 = 105، و35 + 40 = 75؛ 105 + 75 = 180 ✓). القيم 40° و45° و60° ناتجةٌ عن أخطاءٍ في تجميع حدود x أو في قسمة المجموع 180 دون طرح الحدّ الثابت 40 أوّلًا.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7f407767-d5bb-5695-a203-38a9784a6547', '2bd4a24c-ea8e-5384-a438-8122879b9b24', '(d₁) ∥ (d₂)، وقاطعٌ ينتج عند تقاطعه بـ(d₁) زاويةً داخليّةً قياسُها (5x − 10)°، وعند تقاطعه بـ(d₂) الزاويةَ المتبادلةَ لها داخليًّا قياسُها (3x + 30)°. ما قياسُ كلٍّ من الزاويتَين (وهما متقايستان)؟', '[{"id":"a","text":"30°"},{"id":"b","text":"50°"},{"id":"c","text":"70°"},{"id":"d","text":"90°"}]'::jsonb, 'd', 'بما أنّ (d₁) ∥ (d₂)، الزاويتان المتبادلتان داخليًّا متقايستان: 5x − 10 = 3x + 30 → 2x = 40 → x = 20. القياسُ = 5 × 20 − 10 = 90° (والتحقّق: 3 × 20 + 30 = 90° أيضًا ✓).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('1f91419f-2525-5efb-b463-aa2029837ffd', '2bd4a24c-ea8e-5384-a438-8122879b9b24', 'زاويتان متناظرتان ناتجتان عن قاطعٍ لمستقيمَين (d) و(d′)، قياسُهما (2x + 15)° و(4x − 5)°. ما القيمةُ الوحيدة لِـ x الّتي تجعل (d) ∥ (d′)؟', '[{"id":"a","text":"5"},{"id":"b","text":"10"},{"id":"c","text":"15"},{"id":"d","text":"20"}]'::jsonb, 'b', 'لكي يكون (d) ∥ (d′)، يجب أن تتقايسَ الزاويتان المتناظرتان: 2x + 15 = 4x − 5 → 15 + 5 = 4x − 2x → 2x = 20 → x = 10 ✓. (عند x = 10: كلتا الزاويتَين = 2 × 10 + 15 = 35°).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('737b6c39-0385-594a-8157-3501a56d0fb5', '2bd4a24c-ea8e-5384-a438-8122879b9b24', 'أيُّ العبارات التالية **خاطئة**؟', '[{"id":"a","text":"إذا كان مستقيمان متوازيَين، فإنّ أيّ قاطعٍ لهما يُنتج زوايا متبادلةً داخليًّا متقايسة"},{"id":"b","text":"زاويتان متقابلتان بالرأس متقايستان بغضّ النظر عن وضع المستقيمَين"},{"id":"c","text":"مستقيمان عموديّان على المستقيم نفسِه متوازيان"},{"id":"d","text":"زاويتان متبادلتان داخليًّا متقايستان تلزم أن يكون قياسُ كلٍّ منهما 90°"}]'::jsonb, 'd', 'العبارةُ (d) خاطئة: تقايسُ الزاويتَين المتبادلتَين داخليًّا يعني أنّهما متساويتان في القياس أيًّا كانت القيمة (30° أو 60° أو أيّ قياسٍ آخر)، وليس بالضرورة 90°. أمّا (a) و(b) و(c) فعباراتٌ صحيحةٌ تطابق خصائصَ الفصل.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0207b987-b8d0-5428-8915-5f1a99f12e0c', '2bd4a24c-ea8e-5384-a438-8122879b9b24', 'حلّ سامرٌ مسألةً: (d₁) ⊥ (d₃) و(d₂) ∥ (d₃). استنتج سامرٌ أنّ (d₁) ∥ (d₂). ثمّ قاسَ زاويةً متبادلةً داخليّةً عند تقاطع قاطعٍ بـ(d₁) فوجدها (6x)°، وعند (d₂) وجد الزاويةَ المتبادلةَ لها (4x + 26)°. كتب: «بما أنّهما متبادلتان، فهما متكاملتان: 6x + 4x + 26 = 180». صحّح خطأَي سامر إن وُجدا.', '[{"id":"a","text":"لا يوجد خطأ، الحلُّ صحيحٌ بالكامل"},{"id":"b","text":"الخطأُ الوحيد هو استعمالُ التكامل بدل التقايس؛ الصحيحُ 6x = 4x + 26"},{"id":"c","text":"خطآن: الاستنتاجُ الأوّل خاطئ (الصحيحُ (d₁) ⊥ (d₂))، وبما أنّهما ليسا متوازيَين فلا معنى لتطبيق خاصّية تقايس أو تكامل الزوايا المتبادلة أصلًا"},{"id":"d","text":"خطأٌ واحدٌ فقط: الصحيحُ (d₁) ⊥ (d₂) لا (d₁) ∥ (d₂)، لكنّ معادلته صحيحة"}]'::jsonb, 'c', 'خطأُ سامر الأوّل: مستقيمٌ عموديٌّ على أحد مستقيمَين متوازيَين يكون عموديًّا على الآخر أيضًا، فالصحيحُ (d₁) ⊥ (d₂) لا (d₁) ∥ (d₂). وبما أنّ (d₁) و(d₂) ليسا متوازيَين، فلا تنطبق عليهما خاصّيةُ تقايس (ولا تكامل) الزوايا المتبادلة أصلًا؛ معادلتُه غيرُ مبرَّرةٍ هنا مهما كانت صيغتُها.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0801a3d3-29db-5aee-88b7-d9fb2c3f9613', '2bd4a24c-ea8e-5384-a438-8122879b9b24', 'صمّم مهندسٌ جسرًا بحيث تكون العارضتان الرئيسيّتان (d) و(d′) متوازيتَين. دعامةٌ مائلة (قاطع) تربط بينهما. عند العارضة (d)، الزاويةُ الداخليّةُ (يمين الدعامة) قياسُها (7x + 5)°. عند العارضة (d′)، الزاويةُ المتناظرةُ لها (نفس الجهة، نفس الوضع) قياسُها 89°. إذا كان التصميمُ سليمًا (العارضتان فعلًا متوازيتان)، فما قيمةُ x؟', '[{"id":"a","text":"12"},{"id":"b","text":"14"},{"id":"c","text":"18"},{"id":"d","text":"24"}]'::jsonb, 'a', 'بما أنّ العارضتَين متوازيتان، الزاويتان المتناظرتان متقايستان: 7x + 5 = 89 → 7x = 84 → x = 12 ✓. (التحقّق: 7 × 12 + 5 = 84 + 5 = 89 ✓).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

