INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('1f681c94-3ede-5e7b-986f-6dc9da1728d7', 'dbe82d73-74e1-506e-a283-3026c9f702d8', 'ما الشرطُ اللازمُ لكي تشكّل 3 أطوالٍ معطاة مثلّثًا حقيقيًّا؟', '[{"id":"a","text":"أن يكون كلُّ طولٍ أصغرَ من مجموع الطولَين الآخرَين"},{"id":"b","text":"أن تكون الأطوالُ الثلاثة متساوية"},{"id":"c","text":"أن يساوي مجموعُ الأطوال الثلاثة 180"},{"id":"d","text":"أن يكون أطولُ ضلعٍ يساوي مجموع الضلعَين الآخرَين"}]'::jsonb, 'a', 'هذه القاعدةُ تُسمّى المتراجحةَ المثلّثيّة: كلُّ طولٍ يجب أن يكون أصغرَ من مجموع الطولَين الآخرَين. الأطوالُ لا يلزم أن تكون متساوية، ومجموعُ الأطوال ليس له علاقةٌ بـ 180، والمساواةُ التامّة (لا الأصغرية) تعني أنّ النقاطَ تصطفّ على استقامةٍ واحدة بلا مثلّث.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3e580c6e-ccc0-5435-b5d5-30b2c3202d0b', 'dbe82d73-74e1-506e-a283-3026c9f702d8', 'هل يمكن بناءُ مثلّثٍ أضلاعُه 4 سم و5 سم و10 سم؟', '[{"id":"a","text":"نعم، لأنّ 10 < 4 + 5"},{"id":"b","text":"لا، لأنّ 10 > 4 + 5 = 9"},{"id":"c","text":"نعم، لأنّ مجموع الأضلاع الثلاثة يساوي 19"},{"id":"d","text":"لا، لأنّ الأضلاع الثلاثة غيرُ متساوية"}]'::jsonb, 'b', 'أطولُ ضلعٍ هو 10 سم، ومجموعُ الضلعَين الآخرَين هو 4 + 5 = 9 سم. بما أنّ 10 أكبرُ من 9 (لا أصغر)، فالشرطُ غيرُ متحقّق والبناءُ مستحيل.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b1a3943b-24bb-57d2-8062-c82f1abdb339', 'dbe82d73-74e1-506e-a283-3026c9f702d8', 'بأيّ أداتَين نبني مثلّثًا معلومَ الأضلاع الثلاثة؟', '[{"id":"a","text":"المسطرةُ والفرجار"},{"id":"b","text":"المنقلةُ فقط"},{"id":"c","text":"الحاسبةُ فقط"},{"id":"d","text":"الكوسُ فقط"}]'::jsonb, 'a', 'نرسم أحدَ الأضلاع بالمسطرة، ثمّ نستعمل الفرجارَ لرسم قوسَي دائرة نصفُ قطر كلٍّ منهما طولُ ضلعٍ معطى؛ تقاطعُهما يعطي الرأسَ الثالث.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b72d495a-b64d-5d48-86b9-343a0322093b', 'dbe82d73-74e1-506e-a283-3026c9f702d8', 'في مثلّثٍ ABC، قياسُ Â = 40° وقياسُ B̂ = 90°. ما قياسُ Ĉ؟

<svg viewBox="0 0 200 150">
<title>مثلّث ABC</title>
<polygon points="45,28 45,120 170,120" fill="none" stroke="#0f172a" stroke-width="2"/>
<polyline points="45,108 57,108 57,120" fill="none" stroke="#0f172a" stroke-width="1.6"/>
<path d="M 45 48 A 20 20 0 0 0 61.11 39.86" fill="none" stroke="#ef4444" stroke-width="2"/>
<text x="58.54" y="58.77" text-anchor="middle" fill="#ef4444" font-size="12" font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">40°</text>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="37" y="24" text-anchor="middle" fill="#2563eb" font-size="13">A</text><text x="37" y="132" text-anchor="middle" fill="#2563eb" font-size="13">B</text><text x="178" y="130" text-anchor="middle" fill="#2563eb" font-size="13">C</text></g>
</svg>', '[{"id":"a","text":"50°"},{"id":"b","text":"90°"},{"id":"c","text":"130°"},{"id":"d","text":"230°"}]'::jsonb, 'a', 'مجموعُ زوايا المثلّث يساوي 180°. نجمع الزاويتَين المعلومتَين: 40° + 90° = 130°، ثمّ نطرح من 180°: قياسُ Ĉ = 180° − 130° = 50°.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6b41f509-2777-5dc5-8d6d-d9c8d09ea425', 'dbe82d73-74e1-506e-a283-3026c9f702d8', 'أيُّ تعريفٍ يوافق «الارتفاعَ» الصادرَ من رأسٍ في مثلّث؟', '[{"id":"a","text":"المستقيمُ الصادرُ من الرأس والعموديُّ على الضلع المقابل"},{"id":"b","text":"القطعةُ الواصلةُ بين الرأس ومنتصف الضلع المقابل"},{"id":"c","text":"المستقيمُ الذي يقسم زاويةَ الرأس إلى زاويتَين متساويتَين"},{"id":"d","text":"المستقيمُ العموديّ على ضلعٍ في منتصفه"}]'::jsonb, 'a', 'الارتفاعُ الصادرُ من رأسٍ هو المستقيمُ العموديّ على الضلع المقابل. أمّا (b) فهو تعريفُ المتوسّط، و(c) تعريفُ منصّف الزاوية، و(d) تعريفُ الواسطة (المرتبطة بضلعٍ لا برأس).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
