INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('615bf704-6dff-5125-9ebd-bff74bc85f9d', '7cb2a090-cadc-58ef-8749-a457fd1e7c36', 'ما الاسمُ العلميُّ للشرط الذي يحدّد إمكانَ بناء مثلّثٍ بثلاثة أطوال معطاة؟', '[{"id":"a","text":"نظريّةُ فيثاغورس"},{"id":"b","text":"التناسبُ"},{"id":"c","text":"التناظرُ المحوريّ"},{"id":"d","text":"المتراجحةُ المثلّثيّة"}]'::jsonb, 'd', 'الشرطُ الذي يحدّد إمكانَ بناء مثلّثٍ بثلاثة أطوال معطاة يُسمّى المتراجحةَ المثلّثيّة (كلُّ طولٍ أصغرُ من مجموع الطولَين الآخرَين). الخياراتُ الأخرى مفاهيمُ رياضيّةٌ مختلفة لا علاقةَ لها بهذا الشرط.', 1, 'mcq', NULL, NULL)
