  ('3034a776-7453-5110-842a-4400d33b29fb', '7cb2a090-cadc-58ef-8749-a457fd1e7c36', 'هل يمكن بناءُ مثلّثٍ أضلاعُه 6 سم و8 سم و15 سم؟', '[{"id":"a","text":"لا، لأنّ 15 > 6 + 8 = 14"},{"id":"b","text":"نعم، لأنّ 15 < 6 + 8"},{"id":"c","text":"لا، لأنّ الأضلاع الثلاثة غير متساوية"},{"id":"d","text":"نعم، لأنّ مجموع الأضلاع 29 عددٌ موجب"}]'::jsonb, 'a', 'أطولُ ضلعٍ هو 15 سم، ومجموعُ الضلعَين الآخرَين هو 6 + 8 = 14 سم. بما أنّ 15 أكبرُ من 14، فالشرطُ غيرُ متحقّق والبناءُ **مستحيل**.', 2, 'mcq', NULL, NULL)
