INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9216971f-bb1b-56f4-bb07-33d6696b7450', '7cb2a090-cadc-58ef-8749-a457fd1e7c36', 'هل يمكن بناءُ مثلّثٍ أضلاعُه 7 سم و8 سم و12 سم؟', '[{"id":"a","text":"لا، لأنّ 12 > 7 + 8"},{"id":"b","text":"نعم، لأنّ 12 < 7 + 8 = 15"},{"id":"c","text":"لا، لأنّ الأضلاع غير متساوية"},{"id":"d","text":"نعم، لأنّ الأضلاع الثلاثة أعدادٌ صحيحة"}]'::jsonb, 'b', 'أطولُ ضلعٍ هو 12 سم، ومجموعُ الضلعَين الآخرَين هو 7 + 8 = 15 سم. بما أنّ 12 أصغرُ من 15، فالشرطُ متحقّقٌ والبناءُ **ممكن** ✓.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('427328ff-b013-5638-aa77-a05eba373444', '7cb2a090-cadc-58ef-8749-a457fd1e7c36', 'عند بناء مثلّثٍ بأطواله الثلاثة بالمسطرة والفرجار، ماذا نرسم أوّلًا؟', '[{"id":"a","text":"قوسَ الدائرة الأوّل"},{"id":"b","text":"قوسَ الدائرة الثاني"},{"id":"c","text":"أحدَ الأضلاع بالمسطرة"},{"id":"d","text":"الزاويةَ بالمنقلة"}]'::jsonb, 'c', 'نبدأ دائمًا برسم أحد الأضلاع بطوله المعطى باستعمال المسطرة، ثمّ نرسم قوسَي الدائرة بالفرجار من طرفَي هذا الضلع للحصول على الرأس الثالث. المنقلةُ لا تُستعمل في هذا النوع من البناء.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5c400738-d74f-5567-a911-6daa839312d3', '7cb2a090-cadc-58ef-8749-a457fd1e7c36', 'في مثلّثٍ ABC، قياسُ Â = 90° وقياسُ B̂ = 60°. ما قياسُ Ĉ؟

<svg viewBox="0 0 200 150">
<title>مثلّث ABC</title>
<polygon points="45,120 175,120 45,28" fill="none" stroke="#0f172a" stroke-width="2"/>
<polyline points="57,120 57,108 45,108" fill="none" stroke="#0f172a" stroke-width="1.6"/>
<path d="M 155 120 A 20 20 0 0 1 158.67 108.45" fill="none" stroke="#ef4444" stroke-width="2"/>
<text x="146.41" y="114.91" text-anchor="middle" fill="#ef4444" font-size="12" font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">60°</text>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="37" y="116" text-anchor="middle" fill="#2563eb" font-size="13">A</text><text x="167" y="132" text-anchor="middle" fill="#2563eb" font-size="13">B</text><text x="53" y="38" text-anchor="middle" fill="#2563eb" font-size="13">C</text></g>
</svg>', '[{"id":"a","text":"30°"},{"id":"b","text":"90°"},{"id":"c","text":"120°"},{"id":"d","text":"150°"}]'::jsonb, 'a', 'مجموعُ زوايا المثلّث يساوي 180°. نجمع الزاويتَين المعلومتَين: 90° + 60° = 150°، ثمّ نطرح من 180°: قياسُ Ĉ = 180° − 150° = 30°.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('30f18599-d59f-5060-8e1d-78b4032a7049', '7cb2a090-cadc-58ef-8749-a457fd1e7c36', 'أيّ مستقيمٍ مميّزٍ في المثلّث يمرّ دائمًا بمنتصف الضلع المقابل، دون أن يكون بالضرورة عموديًّا عليه؟', '[{"id":"a","text":"الواسطة"},{"id":"b","text":"الارتفاع"},{"id":"c","text":"المتوسّط"},{"id":"d","text":"منصّفُ الزاوية"}]'::jsonb, 'c', 'المتوسّطُ الصادرُ من رأسٍ هو القطعةُ الواصلةُ بينه وبين منتصف الضلع المقابل، دون شرط التعامد. أمّا الواسطةُ فهي مرتبطةٌ بضلعٍ لا برأس (وتفرض التعامد)، والارتفاعُ يفرض التعامدَ، ومنصّفُ الزاوية يقسم الزاويةَ لا الضلع.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

