  ('38dfdb6f-f363-57a7-8168-2f9532b3bf5e', '16aac082-2efa-5690-924d-2b7ec98cc6f6', 'math-7eme', '⚔️ زعيمُ الفصل ⭐⭐⭐: مسائلُ المثلّثات', 3, 120, 30, 'boss', 'admin', 2)
