INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5dea2f3e-6202-5689-9652-365e09dad8cc', '38dfdb6f-f363-57a7-8168-2f9532b3bf5e', 'هل يمكن بناءُ مثلّثٍ أضلاعُه 5 سم و5 سم و10 سم؟', '[{"id":"a","text":"نعم، لأنّ 10 = 5 + 5"},{"id":"b","text":"نعم، لأنّ الضلعَين متساويان"},{"id":"c","text":"لا، لأنّ الأضلاع غيرُ صحيحة"},{"id":"d","text":"لا، لأنّ 10 يساوي 5 + 5 تمامًا فتصطفّ النقاطُ الثلاث على استقامةٍ واحدة"}]'::jsonb, 'd', 'الشرطُ يفرض أن يكون أطولُ ضلعٍ **أصغرَ** من مجموع الضلعَين الآخرَين، لا مساويًا له. هنا 10 = 5 + 5 بالضبط، فالنقاطُ الثلاث تصطفّ على استقامةٍ واحدة ولا يتكوّن مثلّثٌ حقيقيّ.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0347a0ca-658f-5e83-99b8-ba1686a3f323', '38dfdb6f-f363-57a7-8168-2f9532b3bf5e', 'في مثلّثٍ ABC، قياسُ Â يساوي ضِعفَ قياس Ĉ، وقياسُ B̂ = 60°. إذا رمزنا لقياس Ĉ بـ x، فما قياسُ Â؟', '[{"id":"a","text":"40°"},{"id":"b","text":"80°"},{"id":"c","text":"100°"},{"id":"d","text":"120°"}]'::jsonb, 'b', 'المعادلة: x + 2x + 60 = 180 → 3x + 60 = 180 → 3x = 120 → x = 40. إذن قياسُ Ĉ = 40° وقياسُ Â = 2 × 40 = 80°. التحقّق: 80 + 40 + 60 = 180 ✓.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('61121e25-157c-52b3-b033-122e8fa4fc18', '38dfdb6f-f363-57a7-8168-2f9532b3bf5e', 'ما اسمُ نقطة تلاقي المتوسّطات الثلاث لمثلّث؟', '[{"id":"a","text":"مركزُ ثقل المثلّث"},{"id":"b","text":"نقطةُ تلاقي الارتفاعات"},{"id":"c","text":"نقطةٌ تبعد بالتساوي عن الرؤوس"},{"id":"d","text":"نقطةٌ تبعد بالتساوي عن الأضلاع"}]'::jsonb, 'a', 'المتوسّطاتُ الثلاثة لمثلّثٍ تلتقي دائمًا في نقطةٍ واحدة تُسمّى مركزَ ثقل المثلّث. الخيارُ (c) يصف نقطةَ تلاقي الواسطات، و(d) يصف نقطةَ تلاقي منصّفات الزوايا.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0209b15a-d38b-5052-a2c0-7bd8fdc36e34', '38dfdb6f-f363-57a7-8168-2f9532b3bf5e', 'أضلاعُ مثلّثٍ طولاها 4 سم و9 سم، والضلعُ الثالث طولُه عددٌ صحيحٌ x سم. ما أصغرُ قيمةٍ صحيحةٍ يمكن أن يأخذها x؟', '[{"id":"a","text":"5"},{"id":"b","text":"6"},{"id":"c","text":"9"},{"id":"d","text":"13"}]'::jsonb, 'b', 'يجب أن يحقّق x المتراجحةَ المثلّثيّة مع الضلعَين 4 و9: يجب أن يكون x أكبرَ من 9 − 4 = 5 (وإلّا كان 9 أطولَ من مجموع الضلعَين الآخرَين)، وأصغرَ من 9 + 4 = 13. إذن 5 < x < 13، وأصغرُ عددٍ صحيحٍ أكبرَ تمامًا من 5 هو 6.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e2ec625d-ea36-5bfd-802a-7194aa4b2fd7', '38dfdb6f-f363-57a7-8168-2f9532b3bf5e', 'أراد أحمدُ بناءَ مثلّثٍ أضلاعُه 2 سم و3 سم و6 سم، ففتح الفرجارَ على 2 سم من طرفٍ، وعلى 3 سم من الطرف الآخر لضلعٍ طولُه 6 سم، لكنّ القوسَين لم يتقاطعا أبدًا. ما تفسيرُ ذلك؟', '[{"id":"a","text":"أخطأ أحمدُ في استعمال الفرجار فقط"},{"id":"b","text":"يجب استعمالُ المنقلة بدل الفرجار"},{"id":"c","text":"الأطوالُ الثلاثة لا تحقّق المتراجحة المثلّثيّة لأنّ 6 > 2 + 3 = 5"},{"id":"d","text":"القوسان يتقاطعان دائمًا مهما كانت الأطوال"}]'::jsonb, 'c', 'أطولُ ضلعٍ هو 6 سم، ومجموعُ الضلعَين الآخرَين هو 2 + 3 = 5 سم. بما أنّ 6 > 5، فالمتراجحةُ المثلّثيّة غيرُ متحقّقة، فلا يمكن أن يتكوّن مثلّثٌ حقيقيّ، ولذلك لن يتقاطع القوسان مهما أعاد أحمدُ المحاولة.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c93a39eb-77ab-5899-8eb6-9124d6b0483d', '38dfdb6f-f363-57a7-8168-2f9532b3bf5e', 'قال تلميذٌ: «الارتفاعُ الصادرُ من رأسٍ يمرّ دائمًا بمنتصف الضلع المقابل». هل هذا القولُ صحيح؟', '[{"id":"a","text":"صحيح، لأنّ كلَّ ارتفاعٍ يمرّ بالمنتصف"},{"id":"b","text":"صحيح، لكن فقط إذا كان المثلّثُ قائمَ الزاوية"},{"id":"c","text":"خطأ، لأنّ الارتفاعَ لا علاقةَ له بالرأس أصلًا"},{"id":"d","text":"خطأ، لأنّ الذي يمرّ بمنتصف الضلع المقابل هو المتوسّط لا الارتفاع"}]'::jsonb, 'd', 'الارتفاعُ الصادرُ من رأسٍ يفرض شرطَ **التعامد** فقط على الضلع المقابل، ولا يمرّ بمنتصفه إلّا في حالاتٍ خاصّة. المستقيمُ الذي يمرّ دائمًا بالمنتصف (دون شرط التعامد) هو **المتوسّط**، لا الارتفاع.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

