INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b4ab58b8-ebfc-5cc2-ac09-76ea8420f0e2', '0e485efe-a1d1-59fa-96b6-986e0610d361', 'هل يمكن بناءُ مثلّثٍ أضلاعُه 6 سم و7 سم و13 سم؟', '[{"id":"a","text":"نعم، لأنّ 13 = 6 + 7"},{"id":"b","text":"نعم، لأنّ الأضلاعَ الثلاثة أعدادٌ صحيحة"},{"id":"c","text":"لا، لأنّ 13 يساوي 6 + 7 تمامًا فتصطفّ النقاطُ على استقامةٍ واحدة"},{"id":"d","text":"لا، لأنّ أحدَ الأضلاع أكبرُ من 10"}]'::jsonb, 'c', 'أطولُ ضلعٍ هو 13 سم، ويساوي بالضبط مجموعَ الضلعَين الآخرَين (6 + 7 = 13). المساواةُ التامّةُ تعني أنّ النقاطَ الثلاث تصطفّ على استقامةٍ واحدة، فلا يتكوّن مثلّثٌ حقيقيّ.', 1, 'mcq', NULL, NULL)
