  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('719487f9-fe11-5e46-a9a8-5c8efebec395', '0e485efe-a1d1-59fa-96b6-986e0610d361', 'بعد رسم الضلع [BC] وقوسَي الدائرة عند بناء مثلّثٍ بأطواله الثلاثة، ماذا نفعل للحصول على الرأس الثالث A؟', '[{"id":"a","text":"نرسم منصّفَ الزاوية عند B"},{"id":"b","text":"نصل مركزَي القوسَين مباشرةً"},{"id":"c","text":"نأخذ نقطةَ تقاطع القوسَين ونصلها بـ B وبـ C"},{"id":"d","text":"نقيس الزاويةَ بالمنقلة"}]'::jsonb, 'c', 'نقطةُ تقاطع القوسَين هي بالضبط الرأسُ الثالث A، لأنّها تبعد المسافةَ المطلوبة عن كلٍّ من B وC في آنٍ واحد. نصلها بـ B وبـ C فنحصل على أضلاع المثلّث الثلاثة.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e4ada8fe-3f25-51eb-b7f2-f396769ca4c2', '0e485efe-a1d1-59fa-96b6-986e0610d361', 'في مثلّثٍ ABC، قياسُ Â = 35° وقياسُ Ĉ = 95°. ما قياسُ B̂؟

<svg viewBox="0 0 200 150">
<title>مثلّث ABC</title>
<polygon points="30,122 175,122 92,30" fill="none" stroke="#0f172a" stroke-width="2"/>
<path d="M 50 122 A 20 20 0 0 0 41.18 105.41" fill="none" stroke="#ef4444" stroke-width="2"/>
<text x="56.49" y="111.91" text-anchor="middle" fill="#ef4444" font-size="12" font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">35°</text>
<path d="M 80.82 46.59 A 20 20 0 0 0 105.4 44.85" fill="none" stroke="#ef4444" stroke-width="2"/>
<text x="94.11" y="63.93" text-anchor="middle" fill="#ef4444" font-size="12" font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">95°</text>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="22" y="118" text-anchor="middle" fill="#2563eb" font-size="13">A</text><text x="167" y="134" text-anchor="middle" fill="#2563eb" font-size="13">B</text><text x="100" y="40" text-anchor="middle" fill="#2563eb" font-size="13">C</text></g>
</svg>', '[{"id":"a","text":"50°"},{"id":"b","text":"130°"},{"id":"c","text":"145°"},{"id":"d","text":"180°"}]'::jsonb, 'a', 'مجموعُ زوايا المثلّث يساوي 180°. نجمع الزاويتَين المعلومتَين: 35° + 95° = 130°، ثمّ نطرح من 180°: قياسُ B̂ = 180° − 130° = 50°.', 3, 'mcq', NULL, NULL)
