INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a340f19f-3bac-5c65-950b-6576f04523b6', '0e485efe-a1d1-59fa-96b6-986e0610d361', 'أيّ مستقيمٍ مميّزٍ في المثلّث يقسم زاويةَ الرأس إلى زاويتَين متساويتَين؟', '[{"id":"a","text":"الواسطة"},{"id":"b","text":"الارتفاع"},{"id":"c","text":"المتوسّط"},{"id":"d","text":"منصّفُ الزاوية"}]'::jsonb, 'd', 'منصّفُ الزاوية هو المستقيمُ الصادرُ من رأسٍ الذي يقسم زاويةَ هذا الرأس إلى زاويتَين متساويتَين. الواسطةُ مرتبطةٌ بضلعٍ لا برأس، والارتفاعُ يفرض التعامدَ، والمتوسّطُ يمرّ بمنتصف الضلع المقابل.', 4, 'mcq', NULL, NULL)
