  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('fa2097ab-6901-5f3f-9301-121674a7eac9', '0e485efe-a1d1-59fa-96b6-986e0610d361', 'أضلاعُ مثلّثٍ 4 سم و4 سم، والضلعُ الثالث x سم عددٌ صحيح. ما أكبرُ قيمةٍ صحيحةٍ يمكن أن يأخذها x؟', '[{"id":"a","text":"4"},{"id":"b","text":"7"},{"id":"c","text":"8"},{"id":"d","text":"16"}]'::jsonb, 'b', 'يجب أن يكون x أصغرَ من مجموع الضلعَين الآخرَين: x < 4 + 4 = 8. أكبرُ عددٍ صحيحٍ أصغرَ تمامًا من 8 هو 7 (القيمةُ 8 نفسُها ممنوعة لأنّها تجعل النقاطَ تصطفّ على استقامةٍ واحدة).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
