  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9d48f74c-4d2b-5b6c-a92b-20b15585601f', '0e485efe-a1d1-59fa-96b6-986e0610d361', 'ما اسمُ النقطة التي تبعد المسافةَ نفسَها عن الرؤوس الثلاثة لمثلّث؟', '[{"id":"a","text":"نقطةُ تلاقي الواسطات"},{"id":"b","text":"نقطةُ تلاقي الارتفاعات"},{"id":"c","text":"مركزُ ثقل المثلّث"},{"id":"d","text":"نقطةُ تلاقي منصّفات الزوايا"}]'::jsonb, 'a', 'الواسطاتُ الثلاث لأضلاع المثلّث تلتقي في نقطةٍ واحدة تبعد المسافةَ نفسَها عن الرؤوس الثلاثة. مركزُ ثقل المثلّث هو نقطةُ تلاقي المتوسّطات، أمّا النقطةُ التي تبعد بالتساوي عن الأضلاع فهي نقطةُ تلاقي منصّفات الزوايا.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

