INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2ca4ae4d-cb8b-56ad-a978-b073ef86abce', '916923e3-319b-590b-afd6-6e5b619bf5a7', 'أضلاعُ مثلّثٍ هي 7 سم و15 سم، والضلعُ الثالث x سم عددٌ صحيحٌ زوجيّ يحقّق المتراجحةَ المثلّثيّة. ما أصغرُ قيمةٍ ممكنةٍ لـ x؟', '[{"id":"a","text":"8"},{"id":"b","text":"9"},{"id":"c","text":"10"},{"id":"d","text":"22"}]'::jsonb, 'c', 'يجب أن يحقّق x الشرطَ: 15 − 7 < x < 15 + 7، أي 8 < x < 22. أصغرُ عددٍ صحيحٍ أكبرَ تمامًا من 8 هو 9، لكن x يجب أن يكون **زوجيًّا**، فأصغرُ عددٍ زوجيٍّ في المجال هو 10 ✓.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0bccc62b-2db8-57e4-bc3a-6c0f73d477cf', '916923e3-319b-590b-afd6-6e5b619bf5a7', 'في مثلّثٍ ABC، قياسُ Â يقلّ عن قياس B̂ بـ 10°، وقياسُ Ĉ = 70°. ما قياسُ Â؟', '[{"id":"a","text":"40°"},{"id":"b","text":"50°"},{"id":"c","text":"60°"},{"id":"d","text":"70°"}]'::jsonb, 'b', 'بما أنّ Â + B̂ = 180° − 70° = 110°، وÂ = B̂ − 10، فإنّ (B̂ − 10) + B̂ = 110 → 2×B̂ = 120 → B̂ = 60°، ومنه Â = 60° − 10° = 50°. التحقّق: 50 + 60 + 70 = 180 ✓.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('600a26b4-a66d-5761-a309-13888e7e32da', '916923e3-319b-590b-afd6-6e5b619bf5a7', 'أضلاعُ مثلّثٍ هي (x + 2) سم و9 سم و15 سم، حيث x عددٌ صحيحٌ موجب، والضلعُ (x + 2) هو الأطول. ما أصغرُ قيمةٍ صحيحةٍ ممكنة لـ x؟', '[{"id":"a","text":"14"},{"id":"b","text":"15"},{"id":"c","text":"20"},{"id":"d","text":"24"}]'::jsonb, 'a', 'لكي يكون (x + 2) الضلعَ الأطول، يجب أن يكون أكبرَ من 15: x + 2 > 15 → x > 13. ولتحقيق المتراجحة المثلّثيّة يجب أيضًا x + 2 < 9 + 15 = 24 → x < 22. أصغرُ عددٍ صحيحٍ أكبرَ تمامًا من 13 هو 14 (وبالفعل 14 + 2 = 16، وهو أطولُ من 15 وأصغرُ من 24) ✓.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d3b48d94-e71c-5a5f-aa25-518a83353884', '916923e3-319b-590b-afd6-6e5b619bf5a7', 'أيّ العبارات التالية صحيحة؟', '[{"id":"a","text":"الواسطةُ لضلعٍ تمرّ دائمًا برأس المثلّث المقابل لذلك الضلع"},{"id":"b","text":"الارتفاعُ الصادرُ من رأسٍ يكون دائمًا عموديًّا على الضلع المقابل"},{"id":"c","text":"منصّفُ الزاوية الصادرُ من رأسٍ يمرّ دائمًا بمنتصف الضلع المقابل"},{"id":"d","text":"مجموعُ زوايا أيّ مثلّثٍ يساوي 360°"}]'::jsonb, 'b', 'العبارةُ (b) صحيحةٌ لأنّها بالضبط تعريفُ الارتفاع. أمّا (a) فخطأٌ عمومًا (الواسطةُ تمرّ برأسٍ مقابل فقط في حالاتٍ خاصّة كالمثلّث متساوي الساقين)، و(c) خطأٌ (المرورُ بالمنتصف خاصيّةُ المتوسّط لا منصّف الزاوية)، و(d) خطأٌ (المجموعُ يساوي 180° لا 360°).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('380916f7-09fc-57ed-98f6-d89417fd13a8', '916923e3-319b-590b-afd6-6e5b619bf5a7', 'قال تلميذٌ إنّ أضلاع مثلّثٍ هي 2 سم و3 سم و4 سم، وإنّ إحدى زواياه يمكن أن تساوي 200°. لماذا هذا القولُ غيرُ ممكن؟', '[{"id":"a","text":"لأنّ الأضلاعَ لا تحقّق المتراجحة المثلّثيّة أصلًا"},{"id":"b","text":"لأنّ زوايا المثلّث يجب أن تكون قائمةً دائمًا"},{"id":"c","text":"لأنّ الأضلاعَ صغيرةٌ جدًّا"},{"id":"d","text":"لأنّ أيّ زاويةٍ في مثلّثٍ تكون دائمًا أصغرَ من 180°، إذ مجموعُ الزوايا الثلاث لا يتجاوز 180°"}]'::jsonb, 'd', 'الأضلاعُ 2 و3 و4 تحقّق فعلًا المتراجحةَ المثلّثيّة (4 < 2 + 3 = 5)، فالخيارُ (a) خاطئ. المثلّثاتُ ليست قائمةً دائمًا، فالخيارُ (b) خاطئ أيضًا. السببُ الحقيقيّ هو أنّ مجموعَ زوايا أيّ مثلّثٍ يساوي 180° بالضبط، فلا يمكن لزاويةٍ واحدةٍ فيه أن تبلغ 200° مهما كانت الزاويتان الأخريان.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f5182673-7c06-562f-a72d-49b1ed128246', '916923e3-319b-590b-afd6-6e5b619bf5a7', 'لاحظ تلميذٌ أنّ ثلاثةَ مستقيماتٍ مميّزة في مثلّثٍ تلتقي في نقطةٍ تبعد المسافةَ نفسَها عن الأضلاع الثلاثة. ما نوعُ هذه المستقيمات الثلاثة؟', '[{"id":"a","text":"منصّفاتُ الزوايا"},{"id":"b","text":"الواسطات"},{"id":"c","text":"الارتفاعات"},{"id":"d","text":"المتوسّطات"}]'::jsonb, 'a', 'منصّفاتُ الزوايا الثلاث لمثلّثٍ تلتقي دائمًا في نقطةٍ واحدة تبعد المسافةَ نفسَها عن الأضلاع الثلاثة. الواسطاتُ تلتقي في نقطةٍ تبعد بالتساوي عن الرؤوس (لا الأضلاع)، والمتوسّطاتُ تلتقي في مركز ثقل المثلّث.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

