INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5b808530-aba4-5b1a-aba6-b00e29c635c7', '2e6e8f20-1e04-59af-9748-82b709a4926e', 'أراد فلاحٌ إحاطةَ أرضٍ مثلّثيّة الشكل بسياج، فقاس أضلاعَها فوجدها 15م و20م و38م. هل هذه القياساتُ ممكنةٌ لمثلّثٍ حقيقيّ؟', '[{"id":"a","text":"نعم، لأنّ 38 < 15 + 20"},{"id":"b","text":"نعم، لأنّ مجموع الأضلاع الثلاثة 73"},{"id":"c","text":"لا، لأنّ الأرضَ ليست مربّعةَ الشكل"},{"id":"d","text":"لا، لأنّ 38 > 15 + 20 = 35"}]'::jsonb, 'd', 'أطولُ ضلعٍ هو 38م، ومجموعُ الضلعَين الآخرَين هو 15 + 20 = 35م. بما أنّ 38 أكبرُ من 35، فالمتراجحةُ المثلّثيّة غيرُ متحقّقة، فهذه القياساتُ **لا يمكن** أن تكون أضلاعَ مثلّثٍ حقيقيّ.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6112d415-47ef-5e41-9526-ccc850345e4c', '2e6e8f20-1e04-59af-9748-82b709a4926e', 'في مثلّثٍ حديقةٍ ABC، قياسُ الزاوية عند A يساوي 40°، وقياسُ الزاوية عند B يساوي قياسَ الزاوية عند A. ما قياسُ الزاوية عند C؟

<svg viewBox="0 0 200 150">
<title>مثلّث ABC</title>
<polygon points="30,122 175,122 102,34" fill="none" stroke="#0f172a" stroke-width="2"/>
<path d="M 50 122 A 20 20 0 0 0 42.66 106.52" fill="none" stroke="#ef4444" stroke-width="2"/>
<text x="57.11" y="113.15" text-anchor="middle" fill="#ef4444" font-size="12" font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">40°</text>
<path d="M 155 122 A 20 20 0 0 1 162.23 106.61" fill="none" stroke="#ef4444" stroke-width="2"/>
<text x="147.85" y="113.24" text-anchor="middle" fill="#ef4444" font-size="12" font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">40°</text>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="22" y="118" text-anchor="middle" fill="#2563eb" font-size="13">A</text><text x="167" y="134" text-anchor="middle" fill="#2563eb" font-size="13">B</text><text x="110" y="44" text-anchor="middle" fill="#2563eb" font-size="13">C</text></g>
</svg>', '[{"id":"a","text":"40°"},{"id":"b","text":"80°"},{"id":"c","text":"100°"},{"id":"d","text":"140°"}]'::jsonb, 'c', 'بما أنّ قياسَي الزاويتَين عند A وB متساويان (40° لكلٍّ منهما)، فمجموعُهما 40° + 40° = 80°. قياسُ الزاوية عند C = 180° − 80° = 100°. التحقّق: 40 + 40 + 100 = 180 ✓.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
