  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5c348804-2203-5ac5-8256-4996f6394fda', '2e6e8f20-1e04-59af-9748-82b709a4926e', 'أيّ مستقيمٍ مميّزٍ في المثلّث هو الوحيدُ المرتبطُ بضلعٍ لا برأس؟', '[{"id":"a","text":"الواسطة"},{"id":"b","text":"الارتفاع"},{"id":"c","text":"المتوسّط"},{"id":"d","text":"منصّفُ الزاوية"}]'::jsonb, 'a', 'الواسطةُ هي المستقيمُ المميّزُ الوحيدُ المرتبطُ بضلعٍ (المستقيمُ العموديّ على الضلع في منتصفه)؛ أمّا الارتفاعُ والمتوسّطُ ومنصّفُ الزاوية فكلُّها صادرةٌ من رأسٍ.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('446c819b-6b70-5eae-bcf5-eeb604a41d63', '2e6e8f20-1e04-59af-9748-82b709a4926e', 'يريد مهندسٌ بناءَ إطارٍ مثلّثيّ الشكل بثلاثة قضبانٍ معدنيّة، طولُ اثنَين منها 5م و12م، وطولُ الثالث x م عددٌ صحيح. كم عددُ القيم الصحيحة الممكنة لـ x؟', '[{"id":"a","text":"7"},{"id":"b","text":"8"},{"id":"c","text":"9"},{"id":"d","text":"17"}]'::jsonb, 'c', 'يجب أن يحقّق x الشرطَ: 12 − 5 < x < 12 + 5، أي 7 < x < 17. القيمُ الصحيحةُ الممكنة هي 8، 9، 10، …، 16، وعددُها 16 − 8 + 1 = 9 قيمًا.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3eaaf196-4b3e-50be-916d-edae8fe6f6ef', '2e6e8f20-1e04-59af-9748-82b709a4926e', 'أيّ عائلةٍ من المستقيمات المميّزة الأربع في المثلّث هي الوحيدةُ التي لم يمنحها الدرسُ اسمًا خاصًّا لنقطة تلاقيها ولا خاصيّةَ «بعدٍ متساوٍ»؟', '[{"id":"a","text":"الواسطات"},{"id":"b","text":"الارتفاعات"},{"id":"c","text":"منصّفاتُ الزوايا"},{"id":"d","text":"المتوسّطات"}]'::jsonb, 'b', 'نقطةُ تلاقي المتوسّطات لها اسمٌ خاصّ (مركزُ ثقل المثلّث)، ونقطةُ تلاقي الواسطات تبعد بالتساوي عن الرؤوس، ونقطةُ تلاقي منصّفات الزوايا تبعد بالتساوي عن الأضلاع. أمّا نقطةُ تلاقي الارتفاعات فلم تُوصف بخاصيّة بعدٍ متساوٍ ولا اسمٍ خاصّ، فهي الإجابةُ الوحيدةُ الصحيحة.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('71c7b530-d3c5-5362-9823-734cca8a0f52', '2e6e8f20-1e04-59af-9748-82b709a4926e', 'حلّ تلميذٌ مسألةً: أضلاعُ مثلّثٍ 8 سم و15 سم وx سم، وقال: «بما أنّ x يمكن أن يكون أيّ عددٍ موجب، سأختار x = 30 سم». هل اختيارُه صحيح؟', '[{"id":"a","text":"لا، لأنّ 30 أكبرُ من 8 + 15 = 23 فلا يحقّق المتراجحة المثلّثيّة"},{"id":"b","text":"نعم، لأنّ x يمكن أن يكون أيّ عددٍ موجب"},{"id":"c","text":"نعم، لأنّ 30 عددٌ صحيح"},{"id":"d","text":"لا، لأنّ 8 و15 غيرُ متساويين"}]'::jsonb, 'a', 'الضلعُ x يجب أن يحقّق المتراجحةَ المثلّثيّة مع الضلعَين 8 و15، أي أن يكون أصغرَ من 8 + 15 = 23. بما أنّ 30 أكبرُ من 23، فاختيارُ التلميذ **خاطئ**؛ x ليس أيَّ عددٍ موجب، بل يجب أن يحقّق 7 < x < 23.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('598529f9-6fb2-5975-ab1e-4fe3ed325506', '16aac082-2efa-5690-924d-2b7ec98cc6f6', 'math-7eme', '👑 قمّة التحدّي ⭐⭐⭐⭐: سلسلةُ المثلّثات الكاملة', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
