  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('896ab2e1-29b3-542d-ba06-f4da3e9fd923', '598529f9-6fb2-5975-ab1e-4fe3ed325506', 'مثلّثٌ ABC قياسُ زواياه الثلاث أعدادٌ صحيحةٌ متتالية (مثل n وn+1 وn+2). ما قياسُ أصغر زاويةٍ فيه؟', '[{"id":"a","text":"59°"},{"id":"b","text":"60°"},{"id":"c","text":"61°"},{"id":"d","text":"58°"}]'::jsonb, 'a', 'مجموعُ الزوايا الثلاث المتتالية n + (n+1) + (n+2) = 3n + 3 = 180°، ومنه 3n = 177 → n = 59°. أصغرُ الزوايا الثلاث هي n، أي 59° (والأخريان 60° و61°، ومجموعُهنّ 180° ✓).', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c8aec561-a44e-5444-a3ab-8ff901fe7e76', '598529f9-6fb2-5975-ab1e-4fe3ed325506', 'ثلاثةُ تلاميذ يبنون كلٌّ منهم مثلّثًا بمعطياتٍ مختلفة: الأوّلُ أضلاعُه 4 سم و5 سم و10 سم، والثاني أضلاعُه 6 سم و6 سم و12 سم، والثالثُ أضلاعُه 5 سم و6 سم و7 سم. كم مثلّثًا حقيقيًّا يمكن بناؤه فعلًا من بين الثلاثة؟', '[{"id":"a","text":"لا أحد منهم"},{"id":"b","text":"الثالثُ فقط"},{"id":"c","text":"الأوّلُ والثالث"},{"id":"d","text":"الثلاثةُ جميعًا"}]'::jsonb, 'b', 'الأوّل: أطولُ ضلعٍ 10، والمجموعُ الآخر 4+5=9، وبما أنّ 10 > 9 فالبناءُ مستحيل. الثاني: أطولُ ضلعٍ 12، والمجموعُ الآخر 6+6=12؛ بما أنّ الطولَ **يساوي** المجموع (لا أصغرَ منه)، فالنقاطُ الثلاث تصطفّ على استقامةٍ واحدة ولا مثلّثَ حقيقيًّا يتكوّن. الثالث: أطولُ ضلعٍ 7، والمجموعُ الآخر 5+6=11، وبما أنّ 7 < 11 فالبناءُ ممكنٌ ✓. إذن الثالثُ وحدَه يعطي مثلّثًا حقيقيًّا.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9f011f0a-2d5c-5da9-9bb6-8c08e8e85fb4', '598529f9-6fb2-5975-ab1e-4fe3ed325506', 'في مثلّثٍ ABC متساوي الساقين (AB = AC)، قياسُ الزاوية عند الرأس A يساوي 36°. أيّ مستقيمٍ يكفي رسمُه من A ليؤدّي دورَ الارتفاع والمتوسّط ومنصّف الزاوية في آنٍ واحد؟

<svg viewBox="0 0 200 150">
<title>مثلّث متساوي الساقين</title>
<polygon points="100,26 50,124 150,124" fill="none" stroke="#0f172a" stroke-width="2"/>
<line x1="79.45" y1="77.27" x2="70.55" y2="72.73" stroke="#0f6e56" stroke-width="2"/>
<line x1="129.45" y1="72.73" x2="120.55" y2="77.27" stroke="#0f6e56" stroke-width="2"/>
<path d="M 90 45.6 A 22 22 0 0 0 110 45.6" fill="none" stroke="#ef4444" stroke-width="2"/>
<text x="100" y="62" text-anchor="middle" fill="#ef4444" font-size="12" font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">36°</text>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="100" y="18" text-anchor="middle" fill="#2563eb" font-size="13">A</text><text x="40" y="130" text-anchor="middle" fill="#2563eb" font-size="13">B</text><text x="160" y="130" text-anchor="middle" fill="#2563eb" font-size="13">C</text></g>
</svg>', '[{"id":"a","text":"لا يوجد مستقيمٌ واحد يؤدّي الأدوار الثلاثة معًا"},{"id":"b","text":"الواسطةُ لضلع [BC] وحدها"},{"id":"c","text":"المستقيمُ الصادرُ من A نحو منتصف [BC]"},{"id":"d","text":"أيّ مستقيمٍ يمرّ برأس B"}]'::jsonb, 'c', 'في المثلّث متساوي الساقين، المستقيمُ الصادرُ من رأس القمّة A نحو منتصف القاعدة [BC] هو استثناءٌ مميّز: يجمع بين كونه ارتفاعًا (عموديًّا على [BC]) ومتوسّطًا (يمرّ بالمنتصف) ومنصّفَ زاويةِ Â، في آنٍ واحد. هذا لا يحدث في المثلّث العام (غير متساوي الساقين)، حيث تبقى هذه المستقيمات الأربعةُ مختلفةً عمومًا.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e86971df-94f4-5517-aae8-1da2ee48a5ba', '598529f9-6fb2-5975-ab1e-4fe3ed325506', 'قال تلميذٌ: «بما أنّ نقطةَ تلاقي منصّفات الزوايا تبعد المسافةَ نفسَها عن الأضلاع الثلاثة، فهي إذن نفسُ نقطة تلاقي الواسطات، لأنّ الواسطاتِ أيضًا تخصّ المسافات المتساوية». أين الخطأ في هذا القول؟', '[{"id":"a","text":"القولُ صحيحٌ تمامًا، النقطتان متطابقتان دائمًا"},{"id":"b","text":"الخطأ في الخلط بين نوعَي المسافة: نقطةُ الواسطات تبعد بالتساوي عن الرؤوس، لا عن الأضلاع"},{"id":"c","text":"الخطأ أنّ منصّفاتِ الزوايا لا تلتقي أبدًا في نقطةٍ واحدة"},{"id":"d","text":"الخطأ أنّ الواسطاتِ لا تلتقي أبدًا في نقطةٍ واحدة"}]'::jsonb, 'b', 'نقطةُ تلاقي منصّفات الزوايا تبعد المسافةَ نفسَها عن **الأضلاع** الثلاثة، بينما نقطةُ تلاقي الواسطات تبعد المسافةَ نفسَها عن **الرؤوس** الثلاثة. النقطتان مختلفتان عمومًا (إلّا في حالاتٍ خاصّة كالمثلّث متساوي الأضلاع)، والتلميذُ خلط بين نوعَي المسافة (إلى الأضلاع مقابلَ إلى الرؤوس).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0ee54c8f-31a8-5a00-9b07-df54fa8c11c7', '598529f9-6fb2-5975-ab1e-4fe3ed325506', 'أرادت مهندسةٌ التحقّقَ من أنّ قطعةَ أرضٍ مثلّثيّةَ الشكل قِيست أضلاعُها 30 م و40 م و50 م تحتوي بالفعل زاويةً قائمة، فحسبت مجموعَ زوايا المثلّث فوجدته 180°، واستنتجت أنّ إحدى الزوايا لا بدّ أن تكون قائمة. هل استنتاجُها صحيح؟', '[{"id":"a","text":"نعم، لأنّ مجموعَ 180° يعني دائمًا وجودَ زاويةٍ قائمة"},{"id":"b","text":"لا، مجموعُ زوايا أيّ مثلّثٍ يساوي 180° دائمًا، وهذا وحدَه لا يثبت وجودَ زاويةٍ قائمة بعينها"},{"id":"c","text":"لا، لأنّ 30 و40 و50 لا تحقّق المتراجحة المثلّثيّة أصلًا"},{"id":"d","text":"نعم، لأنّ 30 + 40 + 50 = 120 وهو أقلّ من 180"}]'::jsonb, 'b', 'مجموعُ زوايا **أيّ** مثلّثٍ يساوي 180° دائمًا، سواءٌ كان فيه زاويةٌ قائمةٌ أم لا؛ فهذه الخاصيّةُ لا تخبرنا شيئًا عن قياس زاويةٍ بعينها. (يمكن التحقّقُ من وجود زاويةٍ قائمة بأدواتٍ أخرى غير مطروحةٍ في هذا الفصل.) أضلاعُ 30 و40 و50 تحقّق المتراجحةَ المثلّثيّة فعلًا (50 < 30+40=70)، فالخيارُ (c) خاطئ أيضًا.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e96eaf99-482b-51fe-b076-882f0825126b', '598529f9-6fb2-5975-ab1e-4fe3ed325506', 'في مثلّثٍ ABC، الزاويةُ عند A تساوي ضعفَ الزاوية عند B، والزاويةُ عند C تزيد عن الزاوية عند B بـ 20°. ما قياسُ الزاوية الأكبر في هذا المثلّث؟', '[{"id":"a","text":"40°"},{"id":"b","text":"80°"},{"id":"c","text":"60°"},{"id":"d","text":"100°"}]'::jsonb, 'b', 'لتكن الزاويةُ عند B تساوي x. إذن Â = 2x وĈ = x + 20. المجموع: 2x + x + (x + 20) = 180 → 4x + 20 = 180 → 4x = 160 → x = 40°. إذن B̂ = 40°، Â = 80°، Ĉ = 60°. الزاويةُ الأكبرُ هي Â = 80° (التحقّق: 80+40+60=180 ✓).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

