INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0e1be5ba-381c-560e-a1fc-850720ac422b', '58f276f8-bd22-5315-8610-9c4d5f2f6b9e', 'ما الشرطُ الذي يكفي لوصف رباعيٍّ ABCD بأنّه متوازي أضلاع؟', '[{"id":"a","text":"[AB] و[DC] متوازيان ومتساويا الطول"},{"id":"b","text":"زواياه الأربع قائمة"},{"id":"c","text":"أضلاعه الأربعة متساوية الطول"},{"id":"d","text":"قُطراه متعامدان"}]'::jsonb, 'a', 'متوازي الأضلاع هو رباعيٌّ له ضلعان متقابلان متوازيان ومتساويا الطول. الزوايا القائمة الأربع خاصّةٌ زائدة للمستطيل، وتساوي الأضلاع الأربعة خاصّةٌ زائدة للمعيّن، وتعامدُ القطرين خاصّةٌ زائدة للمعيّن أيضًا.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
