INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2ea5452a-4332-5e28-9c3c-efcb4a0a5917', '58f276f8-bd22-5315-8610-9c4d5f2f6b9e', 'ما الخاصيّةُ الإضافيّة التي يتميّز بها المستطيل عن متوازي الأضلاع العاديّ؟', '[{"id":"a","text":"قُطراه متساويا الطول"},{"id":"b","text":"أضلاعه الأربعة متساوية"},{"id":"c","text":"قُطراه متعامدان"},{"id":"d","text":"ليس له أيّ زاويةٍ قائمة"}]'::jsonb, 'a', 'المستطيلُ متوازي أضلاعٍ له زاويةٌ قائمة واحدة على الأقلّ (فتصير زواياه الأربع قائمة)، ونتيجةُ ذلك أنّ قُطرَيه متساويا الطول. تساوي الأضلاع الأربعة وتعامدُ القطرين خاصّتان تخصّان المعيّن لا المستطيل.', 2, 'mcq', NULL, NULL)
