INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c0551265-f851-5977-8f69-33d513ec214b', '01149780-c99b-589a-bb89-6afb23c2fdfe', 'أيُّ الشروط التالية يكفي لوصف رباعيٍّ ABCD بأنّه متوازي أضلاع؟', '[{"id":"a","text":"AB = DC و[AB] ∥ [DC]"},{"id":"b","text":"AB = BC فقط"},{"id":"c","text":"زواياه الأربع قائمة فقط"},{"id":"d","text":"أضلاعه الأربعة متساوية فقط"}]'::jsonb, 'a', 'يكفي أن يكون ضلعان متقابلان متوازيَين ومتساويَي الطول ليكون الرباعيُّ متوازي أضلاع. الشرطُ (c) يصف المستطيل، والشرطُ (d) يصف المعيّن، وهما حالتان خاصّتان لا شرطٌ عامّ.', 1, 'mcq', NULL, NULL)
