INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d25701e4-12a5-5cfd-a706-8caffe6f782a', 'f0550008-76b8-5222-a145-5915eae82878', 'قرصٌ نصفُ قطره 10 سم (نأخذ π ≈ 3,14). ما مساحةُ هذا القرص؟

<svg viewBox="0 0 200 160">
<title>دائرة</title>
<circle cx="100" cy="78" r="52" fill="none" stroke="#0f172a" stroke-width="2"/>
<line x1="100" y1="78" x2="142.6" y2="48.17" stroke="#2563eb" stroke-width="1.8"/>
<circle cx="100" cy="78" r="2" fill="#0f172a"/>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="92" y="92" text-anchor="middle" fill="#0f172a" font-size="12">O</text><text x="125.3" y="59.09" text-anchor="start" fill="#2563eb" font-size="12">r = 10</text></g>
</svg>', '[{"id":"a","text":"31,4 سم²"},{"id":"b","text":"62,8 سم²"},{"id":"c","text":"100 سم²"},{"id":"d","text":"314 سم²"}]'::jsonb, 'd', 'مساحةُ القرص = π × r² = 3,14 × 10² = 3,14 × 100 = 314 سم². الخطأُ الشائع: نسيانُ تربيع نصف القطر (31,4)، حسابُ محيط الدائرة 2×π×r=62,8 بدل المساحة، أو تربيعُ نصف القطر دون ضربه في π (100).', 1, 'mcq', NULL, NULL)
