  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7bb6337a-112d-58e8-abca-fb2e0d25ebb1', 'f0550008-76b8-5222-a145-5915eae82878', 'متوازي أضلاعٍ محيطُه 36 سم، وطولُ أحد ضلعيه المتتاليين 8 سم. ما طولُ الضلع الآخر؟', '[{"id":"a","text":"9 سم"},{"id":"b","text":"10 سم"},{"id":"c","text":"18 سم"},{"id":"d","text":"28 سم"}]'::jsonb, 'b', 'المحيطُ = 2 × (a + b) = 36، إذن a + b = 18. بما أنّ أحدَ الضلعين 8 سم، فالآخرُ = 18 − 8 = 10 سم. الخطأُ الشائع: قسمةُ المحيط على 4 كما في المربّع (9)، أو التوقّفُ عند مجموع الضلعين (18) دون طرح الضلع المعلوم، أو حسابُ 36 − 8 مباشرةً دون القسمة على 2 أوّلًا (28).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2c5ae102-31d5-527a-a8b1-c005efc5257e', 'f0550008-76b8-5222-a145-5915eae82878', 'أراد فلاحٌ إحاطةَ حقلٍ مستطيل الشكل طولُه 40 م وعرضُه 25 م بسياج. ما طولُ السياج اللازم؟

<svg viewBox="0 0 200 150">
<title>مستطيل</title>
<rect x="45" y="40" width="115" height="70" fill="none" stroke="#0f172a" stroke-width="2"/>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="102.5" y="32" text-anchor="middle" fill="#2563eb" font-size="13">40</text><text x="33" y="79" text-anchor="middle" fill="#2563eb" font-size="13">25</text></g>
</svg>', '[{"id":"a","text":"65 م"},{"id":"b","text":"130 م"},{"id":"c","text":"260 م"},{"id":"d","text":"1 000 م"}]'::jsonb, 'b', 'السياجُ يُحيط بالحقل، أي يساوي محيطَه: 2 × (40 + 25) = 2 × 65 = 130 م. الخطأُ الشائع: نسيانُ الضرب في 2 (65)، مضاعفةُ الناتج مرّةً زائدة (260)، أو حسابُ مساحة الحقل 40×25=1 000 بدل محيطه.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('85aa9d42-3d08-5fd5-9a58-72afb8a920f9', 'f0550008-76b8-5222-a145-5915eae82878', 'مستطيلٌ مساحتُه 48 سم² وطولُه 8 سم. ما محيطُ هذا المستطيل؟', '[{"id":"a","text":"6 سم"},{"id":"b","text":"14 سم"},{"id":"c","text":"28 سم"},{"id":"d","text":"48 سم"}]'::jsonb, 'c', 'نجد العرضَ أوّلًا: العرضُ = المساحة ÷ الطول = 48 ÷ 8 = 6 سم. ثمّ المحيطُ = 2 × (8 + 6) = 2 × 14 = 28 سم. الخطأُ الشائع: التوقّفُ عند العرض وحدَه (6) أو عند مجموع البُعدَين دون مضاعفته (14)، أو الخلطُ بين المساحة والمحيط (48).', 4, 'mcq', NULL, NULL)
