  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4a20f6d5-4355-5740-80fd-23d105e3edc9', 'f0550008-76b8-5222-a145-5915eae82878', 'أيُّ الأشكال التالية قُطراه متساويا الطول ومتعامدان معًا في آنٍ واحد؟', '[{"id":"a","text":"المستطيل"},{"id":"b","text":"المعيّن"},{"id":"c","text":"متوازي الأضلاع العاديّ"},{"id":"d","text":"المربّع"}]'::jsonb, 'd', 'المربّعُ وحدَه يجمع الخاصيّتين معًا: قُطراه متساويان (خاصيّةُ المستطيل) ومتعامدان (خاصيّةُ المعيّن)، لأنّه مستطيلٌ ومعيّنٌ في آنٍ واحد. المستطيلُ قُطراه متساويان دون تعامد، والمعيّنُ قُطراه متعامدان دون تساوٍ، ومتوازي الأضلاع العاديّ لا هذا ولا ذاك.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('879e7b32-81be-5960-9c55-dcbe93a727d9', 'f0550008-76b8-5222-a145-5915eae82878', 'دائرةٌ نصفُ قطرها 6 سم (نأخذ π ≈ 3,14). ما محيطُ هذه الدائرة؟

<svg viewBox="0 0 200 160">
<title>دائرة</title>
<circle cx="100" cy="78" r="52" fill="none" stroke="#0f172a" stroke-width="2"/>
<line x1="100" y1="78" x2="142.6" y2="48.17" stroke="#2563eb" stroke-width="1.8"/>
<circle cx="100" cy="78" r="2" fill="#0f172a"/>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="92" y="92" text-anchor="middle" fill="#0f172a" font-size="12">O</text><text x="125.3" y="59.09" text-anchor="start" fill="#2563eb" font-size="12">r = 6</text></g>
</svg>', '[{"id":"a","text":"18,84 سم"},{"id":"b","text":"37,68 سم"},{"id":"c","text":"75,36 سم"},{"id":"d","text":"113,04 سم"}]'::jsonb, 'b', 'محيطُ الدائرة = 2 × π × r = 2 × 3,14 × 6 = 37,68 سم. الخطأُ الشائع: نسيانُ الضرب في 2 (18,84 = π×r فقط)، مضاعفةُ الناتج مرّةً زائدة (75,36)، أو حسابُ مساحة القرص π×r²=113,04 بدل محيط الدائرة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

