INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a403c4d7-371f-5b80-b7a5-fce233a280e1', '24e8497d-923e-5cf6-ae50-a781e0447dfd', 'ما الخاصيّةُ المميّزة لقُطرَي المعيّن؟', '[{"id":"a","text":"متوازيان"},{"id":"b","text":"لا يتقاطعان"},{"id":"c","text":"متساويان في الطول"},{"id":"d","text":"متعامدان"}]'::jsonb, 'd', 'قُطرا المعيّن متعامدان دائمًا. تساوي القطرين خاصّةٌ تخصّ المستطيل لا المعيّن؛ وقُطرا أيّ متوازي أضلاعٍ يتقاطعان دائمًا في منتصفَيهما، فلا يمكن أن يكونا متوازيَين أو ألّا يتقاطعا.', 1, 'mcq', NULL, NULL)
