INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8ed008b3-ac9f-54d8-9a82-a4a4ed8b5df3', '24e8497d-923e-5cf6-ae50-a781e0447dfd', 'أيُّ العبارات التالية صحيحة؟', '[{"id":"a","text":"قُطرا المستطيل متساويان في الطول"},{"id":"b","text":"قُطرا المستطيل متعامدان"},{"id":"c","text":"قُطرا المعيّن متساويان في الطول"},{"id":"d","text":"قُطرا متوازي الأضلاع العاديّ متساويان في الطول"}]'::jsonb, 'a', 'قُطرا المستطيل متساويان في الطول: هذه خاصّيتُه المميّزة. التعامدُ خاصّةٌ للمعيّن لا المستطيل، وتساوي القطرين لا يتحقّق في المعيّن العاديّ ولا في متوازي الأضلاع العاديّ إلّا إذا كانا مستطيلَين أيضًا.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
