  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('398921c6-a1aa-55bb-9bc6-93c92f6cd6e5', '24e8497d-923e-5cf6-ae50-a781e0447dfd', 'أين يقع مركزُ تناظر متوازي الأضلاع؟', '[{"id":"a","text":"عند أحد رؤوسه"},{"id":"b","text":"خارج الشكل دائمًا"},{"id":"c","text":"عند نقطة تقاطع قُطريه"},{"id":"d","text":"في منتصف أحد أضلاعه"}]'::jsonb, 'c', 'مركزُ تناظر متوازي الأضلاع هو نقطةُ تقاطع قُطريه، وهي أيضًا منتصفُ كلٍّ منهما في آنٍ واحد. هذه النقطةُ داخلَ الشكل دائمًا، لا عند رأسٍ ولا عند منتصف ضلع.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('1c8bf899-5b9a-5891-be58-922c197c61f7', '24e8497d-923e-5cf6-ae50-a781e0447dfd', 'ما مساحةُ مثلّثٍ قاعدتُه 10 سم وارتفاعُه (بالنسبة لهذه القاعدة) 6 سم؟

<svg viewBox="0 0 200 150">
<title>مثلّث</title>
<polygon points="40,120 168,120 118,40" fill="none" stroke="#0f172a" stroke-width="2"/>
<line x1="118" y1="40" x2="118" y2="120" stroke="#64748b" stroke-width="1.5" stroke-dasharray="4 3"/>
<polyline points="109,120 109,111 118,111" fill="none" stroke="#0f172a" stroke-width="1.6"/>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="104" y="136" text-anchor="middle" fill="#2563eb" font-size="12">10</text><text x="130" y="80" text-anchor="start" fill="#0f6e56" font-size="12">h = 6</text></g>
</svg>', '[{"id":"a","text":"16 سم²"},{"id":"b","text":"30 سم²"},{"id":"c","text":"60 سم²"},{"id":"d","text":"90 سم²"}]'::jsonb, 'b', 'مساحةُ المثلّث = (القاعدة × الارتفاع) ÷ 2 = (10 × 6) ÷ 2 = 60 ÷ 2 = 30 سم². الخطأُ الشائع: جمعُ القاعدة والارتفاع بدل ضربهما (16)، أو نسيانُ القسمة على 2 (60).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('46bf11a3-1a4b-5d33-ad83-8c9b44f40aed', '24e8497d-923e-5cf6-ae50-a781e0447dfd', 'دائرةٌ نصفُ قطرها 4 سم (نأخذ π ≈ 3,14). ما محيطُ هذه الدائرة؟

<svg viewBox="0 0 200 160">
<title>دائرة</title>
<circle cx="100" cy="78" r="52" fill="none" stroke="#0f172a" stroke-width="2"/>
<line x1="100" y1="78" x2="142.6" y2="48.17" stroke="#2563eb" stroke-width="1.8"/>
<circle cx="100" cy="78" r="2" fill="#0f172a"/>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="92" y="92" text-anchor="middle" fill="#0f172a" font-size="12">O</text><text x="125.3" y="59.09" text-anchor="start" fill="#2563eb" font-size="12">r = 4</text></g>
</svg>', '[{"id":"a","text":"8 سم"},{"id":"b","text":"12,56 سم"},{"id":"c","text":"25,12 سم"},{"id":"d","text":"50,24 سم"}]'::jsonb, 'c', 'محيطُ الدائرة = 2 × π × r = 2 × 3,14 × 4 = 25,12 سم. الخطأُ الشائع: نسيانُ π واستعمالُ 2×r فقط (8)، نسيانُ الضرب في 2 (12,56 = π×r فقط)، أو حسابُ مساحة القرص π×r²=50,24 بدل محيط الدائرة.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d2ca9089-f87a-575e-b1c6-f61e9c41b3f3', '24e8497d-923e-5cf6-ae50-a781e0447dfd', 'معيّنٌ طولُ قُطريه 8 سم و5 سم. ما مساحةُ هذا المعيّن؟

<svg viewBox="0 0 200 160">
<title>معيّن</title>
<polygon points="38,78 100,32 162,78 100,124" fill="none" stroke="#0f172a" stroke-width="2"/>
<line x1="38" y1="78" x2="162" y2="78" stroke="#64748b" stroke-width="1.4" stroke-dasharray="4 3"/>
<line x1="100" y1="32" x2="100" y2="124" stroke="#64748b" stroke-width="1.4" stroke-dasharray="4 3"/>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="120" y="74" text-anchor="middle" fill="#2563eb" font-size="12">8</text><text x="112" y="58" text-anchor="middle" fill="#2563eb" font-size="12">5</text></g>
</svg>', '[{"id":"a","text":"13 سم²"},{"id":"b","text":"20 سم²"},{"id":"c","text":"40 سم²"},{"id":"d","text":"64 سم²"}]'::jsonb, 'b', 'مساحةُ المعيّن = (القطر الأوّل × القطر الثاني) ÷ 2 = (8 × 5) ÷ 2 = 40 ÷ 2 = 20 سم². الخطأُ الشائع: جمعُ القُطرين بدل ضربهما (13)، نسيانُ القسمة على 2 (40)، أو معاملةُ أحد القطرين كضلعٍ وتربيعُه (64 = 8²) كما لو كان مربّعًا.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

