INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f9ae3564-9a9e-5135-80b2-3cb28f2abd86', '17288385-f894-5c5e-a78e-86b10d445e89', 'قطعةُ أرضٍ مستطيلة الشكل مساحتُها 96 م² وعرضُها 8 م. أراد صاحبُها إحاطتَها بسياج. ما طولُ السياج اللازم؟', '[{"id":"a","text":"12 م"},{"id":"b","text":"32 م"},{"id":"c","text":"40 م"},{"id":"d","text":"96 م"}]'::jsonb, 'c', 'نجد الطولَ أوّلًا: الطولُ = المساحة ÷ العرض = 96 ÷ 8 = 12 م. ثمّ السياجُ يساوي المحيطَ: 2 × (12 + 8) = 2 × 20 = 40 م. الخطأُ الشائع: التوقّفُ عند الطول وحدَه (12)، افتراضُ أنّ الشكلَ مربّعٌ وحسابُ 2×(8+8)=32، أو الخلطُ بين المساحة والمحيط (96).', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d264bb5c-7416-531c-a812-821558084eb4', '17288385-f894-5c5e-a78e-86b10d445e89', 'معيّنٌ طولُ أحد قُطريه 12 سم، ومساحتُه 42 سم². ما طولُ القُطر الآخر؟

<svg viewBox="0 0 200 160">
<title>معيّن</title>
<polygon points="38,78 100,32 162,78 100,124" fill="none" stroke="#0f172a" stroke-width="2"/>
<line x1="38" y1="78" x2="162" y2="78" stroke="#64748b" stroke-width="1.4" stroke-dasharray="4 3"/>
<line x1="100" y1="32" x2="100" y2="124" stroke="#64748b" stroke-width="1.4" stroke-dasharray="4 3"/>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="120" y="74" text-anchor="middle" fill="#2563eb" font-size="12">12</text></g>
</svg>', '[{"id":"a","text":"1,75 سم"},{"id":"b","text":"3,5 سم"},{"id":"c","text":"5 سم"},{"id":"d","text":"7 سم"}]'::jsonb, 'd', 'من صيغة مساحة المعيّن: المساحة = (قُطر1 × قُطر2) ÷ 2، إذن 42 = (12 × قُطر2) ÷ 2، أي 84 = 12 × قُطر2، ومنه قُطر2 = 84 ÷ 12 = 7 سم. الخطأُ الشائع: نسيانُ الضرب في 2 قبل القسمة على القُطر المعلوم فيُحصل على 42 ÷ 12 = 3,5 (أو أخطاءُ حسابيّةٌ أخرى تعطي قيمًا أصغر مثل 1,75 أو 5).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('66a9342f-cdbc-591a-bb2f-04d9463030b7', '17288385-f894-5c5e-a78e-86b10d445e89', 'دائرةٌ محيطُها 62,8 سم (نأخذ π ≈ 3,14). ما نصفُ قطر هذه الدائرة؟', '[{"id":"a","text":"6,28 سم"},{"id":"b","text":"10 سم"},{"id":"c","text":"20 سم"},{"id":"d","text":"31,4 سم"}]'::jsonb, 'b', 'من صيغة المحيط: المحيط = 2 × π × r، إذن r = المحيط ÷ (2 × π) = 62,8 ÷ 6,28 = 10 سم. الخطأُ الشائع: القسمةُ على π فقط دون الضرب في 2، فيُحصل بذلك على القطر D=20 سم بدل نصف القطر، أو القسمةُ على 2 فقط دون π (31,4).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
