  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('beebaad0-5784-5d78-a83c-0b5596445ea5', '17288385-f894-5c5e-a78e-86b10d445e89', 'لوحةٌ مستطيلة الشكل طولُها 12 سم وعرضُها 8 سم، رُسم داخلَها أكبرُ مربّعٍ ممكن ضلعُه يساوي عرضَ اللوحة (8 سم). ما مساحةُ الجزء المتبقّي من اللوحة خارج المربّع؟', '[{"id":"a","text":"32 سم²"},{"id":"b","text":"64 سم²"},{"id":"c","text":"96 سم²"},{"id":"d","text":"128 سم²"}]'::jsonb, 'a', 'مساحةُ اللوحة المستطيلة = 12 × 8 = 96 سم². مساحةُ المربّع = 8 × 8 = 64 سم². الجزءُ المتبقّي = 96 − 64 = 32 سم². الخطأُ الشائع: الاكتفاءُ بمساحة المربّع وحدَها (64) أو اللوحة وحدَها (96)، أو جمعُ المساحتين بدل طرحهما (128).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3cdf771a-a484-5db0-8599-3d49fc56390b', '17288385-f894-5c5e-a78e-86b10d445e89', 'أيُّ العبارات التالية **خاطئة**؟', '[{"id":"a","text":"قُطرا المستطيل متساويان في الطول"},{"id":"b","text":"قُطرا المعيّن متعامدان"},{"id":"c","text":"قُطرا متوازي الأضلاعٍ متعامدان"},{"id":"d","text":"قُطرا متوازي الأضلاعٍ يتقاطعان في منتصفَيهما"}]'::jsonb, 'c', 'العبارةُ الخاطئة هي (c): تعامدُ القطرين ليس خاصّةً عامّة لكلّ متوازي أضلاع، بل هي خاصّةٌ زائدة تخصّ المعيّن فقط. أمّا العباراتُ الثلاث الأخرى فصحيحة: تساوي قُطري المستطيل، تعامدُ قُطري المعيّن، وتقاطعُ قُطري أيّ متوازي أضلاعٍ في منتصفَيهما.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9dde5970-c07f-5ba5-82d4-4be3541fb377', '17288385-f894-5c5e-a78e-86b10d445e89', 'قال تلميذٌ: «معيّنٌ قُطراه 10 سم و6 سم، إذن مساحتُه = 6 × 6 = 36 سم² (باعتبار طول الضلع تقريبًا 6 سم)». أين الخطأُ في حلّه؟', '[{"id":"a","text":"لا خطأ، الحلُّ صحيح"},{"id":"b","text":"الخطأُ أنّه استعمل الضلعَ بدل القُطرين؛ الصوابُ (10×6)÷2 = 30 سم²"},{"id":"c","text":"الخطأُ في الضرب فقط؛ الصوابُ 6×6=42"},{"id":"d","text":"المعيّنُ ليس له مساحةٌ أصلًا"}]'::jsonb, 'b', 'مساحةُ المعيّن تُحسب بصيغة القطرين لا بضرب طول الضلع في نفسه: مساحةٌ = (قُطر1 × قُطر2) ÷ 2 = (10 × 6) ÷ 2 = 60 ÷ 2 = 30 سم². خطأُ التلميذ هو استعمالُ صيغة مساحة المربّع (ضلع × ضلع) على المعيّن، وهو الفخُّ الأشهر في هذا الفصل.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

