  ('5435a0c9-99fa-5472-80ba-c048da117d7f', 'a3b87e9f-398e-55ed-a37f-9e8120a59dcf', 'math-7eme', '📝 تدريبٌ ⭐⭐⭐ (مراجعةٌ شاملة): الرّباعيّات والمساحات', 3, 120, 30, 'boss', 'admin', 5)
