INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b00c4fd5-dd6b-5fb9-a57e-a1245fe76d7d', '5435a0c9-99fa-5472-80ba-c048da117d7f', 'شكلٌ رباعيٌّ قُطراه متساويان ومتعامدان معًا في آنٍ واحد. ما اسمُ هذا الشكل؟', '[{"id":"a","text":"مربّع"},{"id":"b","text":"مستطيل"},{"id":"c","text":"معيّن"},{"id":"d","text":"متوازي أضلاع"}]'::jsonb, 'a', 'المربّعُ وحدَه يجمع الخاصيّتين معًا: تساوي القطرين (خاصيّةُ المستطيل) وتعامدُهما (خاصيّةُ المعيّن)، لأنّه مستطيلٌ ومعيّنٌ في آنٍ واحد.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8b2e8432-98ca-5efb-8b3c-7fdc0e91762c', '5435a0c9-99fa-5472-80ba-c048da117d7f', 'حديقةٌ على شكل متوازي أضلاع، طولُ قاعدتها 14 م وارتفاعُها (بالنسبة لهذه القاعدة) 6 م. ما مساحةُ هذه الحديقة؟

<svg viewBox="0 0 200 150">
<title>متوازي أضلاع</title>
<polygon points="36,118 150,118 184,52 70,52" fill="none" stroke="#0f172a" stroke-width="2"/>
<line x1="124" y1="52" x2="90" y2="118" stroke="#64748b" stroke-width="1.5" stroke-dasharray="4 3"/>
<polyline points="81,118 81,109 90,109" fill="none" stroke="#0f172a" stroke-width="1.6"/>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="93" y="134" text-anchor="middle" fill="#2563eb" font-size="12">14</text><text x="134" y="85" text-anchor="start" fill="#0f6e56" font-size="12">h = 6</text></g>
</svg>', '[{"id":"a","text":"40 م²"},{"id":"b","text":"42 م²"},{"id":"c","text":"84 م²"},{"id":"d","text":"168 م²"}]'::jsonb, 'c', 'مساحةُ متوازي الأضلاع = القاعدة × الارتفاع = 14 × 6 = 84 م². الخطأُ الشائع: حسابُ المحيط 2×(14+6)=40 بدل المساحة، قسمةُ الناتج على 2 كما في المثلّث (42)، أو مضاعفةُ الناتج سهوًا (168).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('18e432d0-aa36-558d-aa4d-056871c5686c', '5435a0c9-99fa-5472-80ba-c048da117d7f', 'أرضيّةُ غرفةٍ مستطيلة الشكل طولُها 2,4 م وعرضُها 1,5 م. أراد عاملٌ تبليطَها ببلاطٍ مربّع الشكل ضلعُه 0,3 م. كم بلاطةً متماثلة يلزمه لتغطية الأرضيّة بالكامل (دون احتساب الفواقد)؟', '[{"id":"a","text":"24 بلاطة"},{"id":"b","text":"36 بلاطة"},{"id":"c","text":"40 بلاطة"},{"id":"d","text":"48 بلاطة"}]'::jsonb, 'c', 'مساحةُ الأرضيّة = 2,4 × 1,5 = 3,6 م². مساحةُ البلاطة الواحدة = 0,3 × 0,3 = 0,09 م². عددُ البلاطات = 3,6 ÷ 0,09 = 40 بلاطة. الخطأُ الشائع: أخطاءُ في القسمة على عددٍ عشريّ صغير تعطي قيمًا مقاربة كـ 24 أو 36 أو 48.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0d38eb44-c809-5d17-b35c-4064c6efd13c', '5435a0c9-99fa-5472-80ba-c048da117d7f', 'دائرةٌ نصفُ قطرها 7 سم (نأخذ π ≈ 3,14). ما مساحةُ القرص الذي تحيط به هذه الدائرة؟

<svg viewBox="0 0 200 160">
<title>دائرة</title>
<circle cx="100" cy="78" r="52" fill="none" stroke="#0f172a" stroke-width="2"/>
<line x1="100" y1="78" x2="142.6" y2="48.17" stroke="#2563eb" stroke-width="1.8"/>
<circle cx="100" cy="78" r="2" fill="#0f172a"/>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="92" y="92" text-anchor="middle" fill="#0f172a" font-size="12">O</text><text x="125.3" y="59.09" text-anchor="start" fill="#2563eb" font-size="12">r = 7</text></g>
</svg>', '[{"id":"a","text":"43,96 سم²"},{"id":"b","text":"153,86 سم²"},{"id":"c","text":"307,72 سم²"},{"id":"d","text":"615,44 سم²"}]'::jsonb, 'b', 'مساحةُ القرص = π × r² = 3,14 × 7² = 3,14 × 49 = 153,86 سم². الخطأُ الشائع: حسابُ محيط الدائرة 2×π×r=43,96 بدل المساحة، أو أخطاءٌ في التربيع تعطي قيمًا أكبر بضِعفَين أو أربعةِ أضعاف (307,72 أو 615,44، وهذه الأخيرةُ تُشبه استعمالَ القُطر 14 بدل نصف القطر 7).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('bdc58dc6-bc10-5137-8b90-15b39b87afc4', '5435a0c9-99fa-5472-80ba-c048da117d7f', 'أيُّ الرّباعيّات التالية له مركزُ تناظرٍ لكن ليس له أيّ محور تناظر؟', '[{"id":"a","text":"المربّع"},{"id":"b","text":"المستطيل"},{"id":"c","text":"المعيّن"},{"id":"d","text":"متوازي الأضلاعٍ العاديّ"}]'::jsonb, 'd', 'متوازي الأضلاعٍ العاديّ (غيرُ المستطيل ولا المعيّن) له مركزُ تناظرٍ دائمًا (نقطةُ تقاطع قُطريه)، لكنّه لا محورَ تناظرٍ له إطلاقًا. المربّعُ والمستطيلُ والمعيّنُ لكلٍّ منها محاورُ تناظرٍ أيضًا (4 أو 2 أو 2 على الترتيب).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('63c1b12d-2b26-5289-ae63-468d18d3f39c', '5435a0c9-99fa-5472-80ba-c048da117d7f', 'حديقةٌ مثلّثة الشكل قاعدتُها 12 م وارتفاعُها 5 م. أراد صاحبُها زرعَ العشب على كامل مساحتها بتكلفة 2 دينارٍ للمتر المربّع الواحد. ما التكلفةُ الكليّة؟', '[{"id":"a","text":"30 دينارًا"},{"id":"b","text":"60 دينارًا"},{"id":"c","text":"90 دينارًا"},{"id":"d","text":"120 دينارًا"}]'::jsonb, 'b', 'مساحةُ الحديقة = (القاعدة × الارتفاع) ÷ 2 = (12 × 5) ÷ 2 = 60 ÷ 2 = 30 م². التكلفةُ الكليّة = 30 × 2 = 60 دينارًا. الخطأُ الشائع: التوقّفُ عند المساحة دون احتساب التكلفة (30)، أو أخطاءٌ حسابيّةٌ تعطي قيمًا أكبر (90 أو 120).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('aa273724-754f-59fc-96dd-509b6dbfb067', 'a3b87e9f-398e-55ed-a37f-9e8120a59dcf', 'math-7eme', '👑 تحدّي النخبة القُصوى ⭐⭐⭐⭐: سقفُ الفصل', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
