  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5c387a7b-5f4b-5c94-90f2-581b9c3e413e', 'aa273724-754f-59fc-96dd-509b6dbfb067', 'مستطيلٌ طولُه (x + 2) سم وعرضُه x سم، ومحيطُه 28 سم. ما قيمةُ x؟', '[{"id":"a","text":"4"},{"id":"b","text":"6"},{"id":"c","text":"7"},{"id":"d","text":"13"}]'::jsonb, 'b', 'المحيطُ = 2 × ((x+2) + x) = 2 × (2x + 2) = 4x + 4 = 28. نعزل الحدّ الحرفيّ: 4x = 28 − 4 = 24، ثمّ x = 24 ÷ 4 = 6. التحقّق: الطولُ 8 سم والعرضُ 6 سم، فالمحيطُ = 2×(8+6)=28 ✓. الخطأُ الشائع: القسمةُ على 6 بدل 4 (4)، نسيانُ الحدّ +2 كليًّا فحلّ 4x=28→x=7، أو نسيانُ مضاعفة الحدّ الحرفيّ فحلّ 2x+2=28→x=13.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0a92c846-842a-5000-be82-34b5f0949c19', 'aa273724-754f-59fc-96dd-509b6dbfb067', 'أرضٌ على شكل معيّن، طولُ قُطريها 20 م و15 م. أراد صاحبُها تقسيمَها إلى قطعتين متساويتَي المساحة بخطٍّ يمرّ بأحد قُطريها، ثمّ باع إحدى القطعتين بسعر 6 دنانيرَ للمتر المربّع الواحد. ما ثمنُ القطعة المَبيعة؟', '[{"id":"a","text":"75 دينارًا"},{"id":"b","text":"300 دينار"},{"id":"c","text":"450 دينارًا"},{"id":"d","text":"900 دينار"}]'::jsonb, 'c', 'مساحةُ الأرض الكليّة = (20 × 15) ÷ 2 = 300 ÷ 2 = 150 م². نصفُ هذه المساحة (القطعة المَبيعة) = 150 ÷ 2 = 75 م². ثمنُها = 75 × 6 = 450 دينارًا. الخطأُ الشائع: نسيانُ الضرب في السعر (75)، نسيانُ القسمة على 2 في صيغة مساحة المعيّن فيُحصل على 300، أو تسعيرُ الأرض كاملةً بدل نصفها (150×6=900).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0dd68f45-3b7d-5224-96a8-e4c150cdb706', 'aa273724-754f-59fc-96dd-509b6dbfb067', 'حديقةٌ مربّعة الشكل ضلعُها 20 م، رُسمت داخلها أكبرُ دائرةٍ ممكنة نصفُ قطرها 10 م (تُلامس أضلاعَ المربّع). ما مساحةُ الجزء من الحديقة الواقع خارج هذه الدائرة؟ (نأخذ π ≈ 3,14)', '[{"id":"a","text":"86 م²"},{"id":"b","text":"314 م²"},{"id":"c","text":"400 م²"},{"id":"d","text":"714 م²"}]'::jsonb, 'a', 'مساحةُ الحديقة المربّعة = 20 × 20 = 400 م². مساحةُ القرص = π × 10² = 3,14 × 100 = 314 م². الجزءُ الواقع خارجَ الدائرة = 400 − 314 = 86 م². الخطأُ الشائع: الاكتفاءُ بمساحة القرص وحدَها (314) أو المربّع وحدَه (400)، أو جمعُ المساحتين بدل طرحهما (714).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
