INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('61094c68-fc36-58dc-88df-6551c95eb161', 'aa273724-754f-59fc-96dd-509b6dbfb067', 'أرادت بلديّةٌ إنشاءَ حوضٍ دائريّ الشكل نصفُ قطره 5 م، ثمّ إحاطتَه بممرٍّ مبلّط بعرض 3 م حولَه بالكامل (فيصير نصفُ قطر الدائرة الخارجية للممرّ 8 م). ما مساحةُ الممرّ وحدَه؟ (نأخذ π ≈ 3,14)', '[{"id":"a","text":"78,5 م²"},{"id":"b","text":"122,46 م²"},{"id":"c","text":"200,96 م²"},{"id":"d","text":"279,46 م²"}]'::jsonb, 'b', 'مساحةُ القرص الخارجيّ (نصفُ قطره 8 م) = π × 8² = 3,14 × 64 = 200,96 م². مساحةُ القرص الداخليّ، أي الحوضُ نفسُه (نصفُ قطره 5 م) = π × 5² = 3,14 × 25 = 78,5 م². مساحةُ الممرّ وحدَه = 200,96 − 78,5 = 122,46 م². الخطأُ الشائع: الاكتفاءُ بمساحة الحوض (78,5) أو الدائرة الخارجيّة وحدَها (200,96)، أو جمعُ المساحتين بدل طرحهما (279,46).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('81776b5f-8bd4-526b-819a-9cb033e1a617', 'aa273724-754f-59fc-96dd-509b6dbfb067', 'لوحةٌ إعلانيّة مستطيلة الشكل طولُها 6 م وعرضُها 4 م، رُسم على واجهتها مثلّثٌ قاعدتُه تساوي عرضَ اللوحة كاملًا (4 م) وارتفاعُه يساوي طولَ اللوحة كاملًا (6 م). كم بالمئة من مساحة اللوحة تمثّل مساحةُ هذا المثلّث؟', '[{"id":"a","text":"25%"},{"id":"b","text":"50%"},{"id":"c","text":"75%"},{"id":"d","text":"100%"}]'::jsonb, 'b', 'مساحةُ اللوحة المستطيلة = 6 × 4 = 24 م². مساحةُ المثلّث = (4 × 6) ÷ 2 = 24 ÷ 2 = 12 م². النسبةُ = 12 ÷ 24 = 0,5 = 50%. الخطأُ الشائع: نسيانُ القسمة على 2 في صيغة مساحة المثلّث، فيظنّ التلميذُ أنّ المثلّث يساوي اللوحةَ كاملةً (100%)، أو أخطاءٌ حسابيّةٌ أخرى (25% أو 75%).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('57d0127c-e828-50db-b143-eacccc96f6a1', 'aa273724-754f-59fc-96dd-509b6dbfb067', 'أيُّ العبارات التالية صحيحة؟', '[{"id":"a","text":"كلُّ معيّنٍ مستطيلٌ"},{"id":"b","text":"كلُّ مستطيلٍ معيّنٌ"},{"id":"c","text":"كلُّ مربّعٍ معيّنٌ ومستطيلٌ في آنٍ واحد"},{"id":"d","text":"كلُّ متوازي أضلاعٍ مربّعٌ"}]'::jsonb, 'c', 'المربّعُ هو الحالةُ الخاصّة التي تجمع كلَّ خصائص المستطيل (زوايا قائمة) وكلَّ خصائص المعيّن (أضلاعٌ متساوية) معًا، فهو معيّنٌ ومستطيلٌ في آنٍ واحد. أمّا المعيّنُ العاديّ فليس مستطيلًا (لا زوايا قائمة له بالضرورة)، والمستطيلُ العاديّ ليس معيّنًا (لا أضلاعَ متساوية له بالضرورة)، ومتوازي الأضلاعٍ العاديّ ليس مربّعًا بالضرورة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

