  ('8a7e964a-fab0-5846-a07d-ec6138ca1ce8', 'e9712f44-9687-53a2-b6ca-cf5976a34bfc', 'كم قاعدةً للموشور القائم؟', '[{"id":"a","text":"لا قاعدة له"},{"id":"b","text":"قاعدتان"},{"id":"c","text":"ثلاثُ قواعد"},{"id":"d","text":"قاعدةٌ واحدة"}]'::jsonb, 'b', 'للموشور القائم قاعدتان متوازيتان ومتطابقتان (متساويتان تمامًا في الشكل والقياس)؛ أمّا بقيّةُ وجوهه فهي جانبيّة.', 1, 'mcq', NULL, NULL)
