  ('2545b340-012a-5384-9825-f6ad752f1c73', '397ed27f-463d-5a71-9530-19d9de501b91', 'موشورٌ قائمٌ قاعدتُه مثلّث. كم وجهًا جانبيًّا له؟', '[{"id":"a","text":"2"},{"id":"b","text":"3"},{"id":"c","text":"4"},{"id":"d","text":"5"}]'::jsonb, 'b', 'عددُ الوجوه الجانبيّة للموشور القائم يساوي عددَ أضلاع القاعدة؛ قاعدتُه مثلّثٌ له 3 أضلاع، إذن له 3 أوجهٍ جانبيّة (مستطيلات).', 1, 'mcq', NULL, NULL)
