INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f3d83fc1-46f6-5dfb-b4fa-b32edfda4e13', '397ed27f-463d-5a71-9530-19d9de501b91', 'موشورٌ قائمٌ قاعدتُه مربّع. كم حرفًا (حافّة) له؟', '[{"id":"a","text":"6"},{"id":"b","text":"8"},{"id":"c","text":"10"},{"id":"d","text":"12"}]'::jsonb, 'd', 'حروفُ القاعدتين: 4 + 4 = 8، والحروفُ الجانبيّة الواصلة بينهما: 4، فمجموعُ الحروف = 8 + 4 = 12 حرفًا. الخطأُ الشائع: الخلطُ بين عدد الحروف وعددِ الأوجه (2 قاعدتان + 4 أوجه جانبيّة = 6)، أو بينه وبين عدد الرؤوس (4 + 4 = 8)، أو نسيانُ حرفٍ جانبيّ واحد أثناء العدّ (10 بدل 12).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
