INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0e6f7035-0e53-503d-9ad9-c8626a353683', '397ed27f-463d-5a71-9530-19d9de501b91', 'موشورٌ قائمٌ مساحةُ قاعدته 12 سم² وارتفاعُه 7 سم. ما حجمُه؟', '[{"id":"a","text":"42 سم³"},{"id":"b","text":"84 سم³"},{"id":"c","text":"96 سم³"},{"id":"d","text":"168 سم³"}]'::jsonb, 'b', 'الحجمُ = مساحةُ القاعدة × الارتفاع = 12 × 7 = 84 سم³. الخطأُ الشائع: أخذُ نصف الجداء (كما في مساحة المثلّث) يعطي 42، أو الضربُ بارتفاعٍ خاطئ (12 × 8 بدل 12 × 7) يعطي 96، أو مضاعفةُ الجداء ظنًّا أنّ هناك قاعدتين تُحسبان في الحجم يعطي 168.', 5, 'mcq', NULL, NULL)
