INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2eeb267d-bc1e-5795-adf0-25e008d6378a', '1adff896-9a9d-590a-9943-dd3a5e6ee03c', 'علبةٌ على شكل متوازي مستطيلات طولُها 6 سم وعرضُها 4 سم وارتفاعُها 9 سم. ما مساحتُها الجانبيّة؟

<svg viewBox="0 0 200 150">
<title>متوازي مستطيلات</title>
<rect x="40" y="60" width="90" height="60" fill="none" stroke="#0f172a" stroke-width="2"/>
<line x1="130" y1="60" x2="164" y2="36" stroke="#0f172a" stroke-width="2"/>
<line x1="130" y1="120" x2="164" y2="96" stroke="#0f172a" stroke-width="2"/>
<line x1="40" y1="60" x2="74" y2="36" stroke="#0f172a" stroke-width="2"/>
<line x1="74" y1="36" x2="164" y2="36" stroke="#0f172a" stroke-width="2"/>
<line x1="164" y1="36" x2="164" y2="96" stroke="#0f172a" stroke-width="2"/>
<line x1="74" y1="36" x2="74" y2="36" stroke="#0f172a" stroke-width="2"/>
<line x1="74" y1="36" x2="74" y2="96" stroke="#64748b" stroke-width="1.2" stroke-dasharray="3 3"/>
<line x1="74" y1="96" x2="164" y2="96" stroke="#64748b" stroke-width="1.2" stroke-dasharray="3 3"/>
<line x1="74" y1="96" x2="40" y2="120" stroke="#64748b" stroke-width="1.2" stroke-dasharray="3 3"/>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="85" y="135" text-anchor="middle" fill="#2563eb" font-size="12">6</text><text x="30" y="94" text-anchor="middle" fill="#0f6e56" font-size="12">9</text><text x="155" y="46" text-anchor="start" fill="#d97706" font-size="12">4</text></g>
</svg>', '[{"id":"a","text":"24 سم²"},{"id":"b","text":"54 سم²"},{"id":"c","text":"90 سم²"},{"id":"d","text":"180 سم²"}]'::jsonb, 'd', 'المساحةُ الجانبيّةُ = محيطُ القاعدة × الارتفاع = 2×(6+4) × 9 = 20 × 9 = 180 سم². الخطأُ الشائع: نسيانُ مضاعفة نصف المحيط (استعمالُ (6+4)×9=90 بدل 20×9)، أو الخلطُ مع مساحة القاعدة (6×4=24)، أو استعمالُ بُعدٍ واحدٍ فقط مضروبًا في الارتفاع (6×9=54) مع إهمال العرض.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0b9d63ab-02bb-5ab0-9731-0403863db80e', '1adff896-9a9d-590a-9943-dd3a5e6ee03c', 'علبةُ شوكولاطة على شكل موشورٍ قائم قاعدتُه مثلّثٌ قائمُ الزاوية ساقاه 6 سم و8 سم، وطولُ العلبة (ارتفاعُ الموشور) 20 سم. ما حجمُ هذه العلبة؟

<svg viewBox="0 0 200 150">
<title>موشور قائم قاعدته مثلّث</title>
<polygon points="60,118 60,46 122,118" fill="none" stroke="#0f172a" stroke-width="2"/>
<polyline points="60,108 70,108 70,118" fill="none" stroke="#0f172a" stroke-width="1.6"/>
<line x1="60" y1="46" x2="100" y2="24" stroke="#0f172a" stroke-width="2"/>
<line x1="122" y1="118" x2="162" y2="96" stroke="#0f172a" stroke-width="2"/>
<line x1="60" y1="118" x2="100" y2="96" stroke="#64748b" stroke-width="1.2" stroke-dasharray="3 3"/>
<line x1="100" y1="24" x2="162" y2="96" stroke="#0f172a" stroke-width="2"/>
<line x1="100" y1="24" x2="100" y2="96" stroke="#64748b" stroke-width="1.2" stroke-dasharray="3 3"/>
<line x1="100" y1="96" x2="162" y2="96" stroke="#64748b" stroke-width="1.2" stroke-dasharray="3 3"/>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="48" y="82" text-anchor="middle" fill="#2563eb" font-size="12">6</text><text x="91" y="133" text-anchor="middle" fill="#2563eb" font-size="12">8</text><text x="150" y="109" text-anchor="start" fill="#0f6e56" font-size="12">20</text></g>
</svg>', '[{"id":"a","text":"48 سم³"},{"id":"b","text":"240 سم³"},{"id":"c","text":"480 سم³"},{"id":"d","text":"960 سم³"}]'::jsonb, 'c', 'مساحةُ القاعدة (مثلّثٌ قائمُ الزاوية) = (6 × 8) ÷ 2 = 24 سم²، والحجمُ = 24 × 20 = 480 سم³. الخطأُ الشائع: نسيانُ ضرب المساحة في الارتفاع (الاكتفاءُ بـ 6×8=48)، أو أخذُ نصف الحجم الصحيح خطأً يعطي 240، أو نسيانُ القسمة على 2 عند حساب مساحة القاعدة (6×8×20) يعطي 960.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b5af8c66-51db-5cf1-ba07-8a799cba15f3', '1adff896-9a9d-590a-9943-dd3a5e6ee03c', 'خزّانُ ماءٍ أسطوانيُّ الشكل نصفُ قطره 3 أمتار وارتفاعُه 6 أمتار (π ≈ 3,14). ما مساحتُه الجانبيّة (بالمتر المربّع)؟

<svg viewBox="0 0 200 150">
<title>أسطوانة</title>
<line x1="60" y1="34" x2="60" y2="122" stroke="#0f172a" stroke-width="2"/>
<line x1="140" y1="34" x2="140" y2="122" stroke="#0f172a" stroke-width="2"/>
<ellipse cx="100" cy="122" rx="40" ry="12" fill="none" stroke="#0f172a" stroke-width="2"/>
<ellipse cx="100" cy="34" rx="40" ry="12" fill="none" stroke="#0f172a" stroke-width="2"/>
<line x1="100" y1="34" x2="140" y2="34" stroke="#2563eb" stroke-width="1.6"/>
<circle cx="100" cy="34" r="1.8" fill="#0f172a"/>
<line x1="150" y1="34" x2="150" y2="122" stroke="#0f6e56" stroke-width="1.4"/>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="120" y="29" text-anchor="middle" fill="#2563eb" font-size="11">r = 3</text><text x="154" y="82" text-anchor="start" fill="#0f6e56" font-size="11">h = 6</text></g>
</svg>', '[{"id":"a","text":"56,52 م²"},{"id":"b","text":"113,04 م²"},{"id":"c","text":"169,56 م²"},{"id":"d","text":"226,08 م²"}]'::jsonb, 'b', 'المساحةُ الجانبيّةُ = محيطُ القاعدة × الارتفاع = 2πr × h = 2 × 3,14 × 3 × 6 = 18,84 × 6 = 113,04 م². الخطأُ الشائع: نسيانُ مضاعفة π×r (استعمالُ πr×h بدل 2πr×h) يعطي 56,52، أو الخلطُ مع صيغة الحجم (π×r²×h) يعطي 169,56، أو استعمالُ القطر (6 أمتار) مكانَ نصف القطر في صيغة 2πr يعطي 226,08.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('68df26e6-bd01-5e93-9381-7981fdf372fa', '1adff896-9a9d-590a-9943-dd3a5e6ee03c', 'موشورٌ قائمٌ محيطُ قاعدته 25 سم، ومساحتُه الجانبيّة 300 سم². ما ارتفاعُه؟', '[{"id":"a","text":"12 سم"},{"id":"b","text":"13 سم"},{"id":"c","text":"25 سم"},{"id":"d","text":"300 سم"}]'::jsonb, 'a', 'المساحةُ الجانبيّةُ = محيطُ القاعدة × الارتفاع، إذن الارتفاعُ = المساحةُ الجانبيّة ÷ محيطُ القاعدة = 300 ÷ 25 = 12 سم. التحقّق: 25 × 12 = 300 ✓. الخطأُ الشائع: خطأٌ حسابيٌّ بسيط في القسمة يعطي 13، أو كتابةُ محيط القاعدة نفسِه كجواب دون إتمام القسمة (25)، أو نسيانُ خطوة القسمة كليًّا والاكتفاءُ بالمساحة الجانبيّة المعطاة (300).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2a8a8d0e-9d45-5194-adc5-81c0083ffed5', '1adff896-9a9d-590a-9943-dd3a5e6ee03c', 'خزّانٌ أسطوانيُّ الشكل نصفُ قطره 5 أمتار وحجمُه 471 م³ (π ≈ 3,14). ما ارتفاعُ هذا الخزّان؟', '[{"id":"a","text":"6 م"},{"id":"b","text":"18,84 م"},{"id":"c","text":"30 م"},{"id":"d","text":"94,2 م"}]'::jsonb, 'a', 'مساحةُ القاعدة = π × r² = 3,14 × 5² = 3,14 × 25 = 78,5 م². الحجمُ = مساحةُ القاعدة × الارتفاع، إذن الارتفاعُ = 471 ÷ 78,5 = 6 أمتار. التحقّق: 78,5 × 6 = 471 ✓. الخطأُ الشائع: نسيانُ π عند حساب مساحة القاعدة (يُعطي 25 بدل 78,5) فيَنتج ارتفاعٌ خاطئ 471÷25=18,84، أو نسيانُ تربيع نصف القطر (3,14×5=15,7) فيَنتج 471÷15,7=30، أو القسمةُ على نصف القطر مباشرةً بدل مساحة القاعدة (471÷5=94,2).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

