INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('584a8eae-949c-5ac4-b4e3-84e17731b0db', 'a1a9e43d-8eae-5956-b34b-c96a5df75cb3', 'أيٌّ ممّا يلي **ليس** موشورًا قائمًا؟', '[{"id":"a","text":"متوازي مستطيلات"},{"id":"b","text":"أسطوانة"},{"id":"c","text":"مكعّب"},{"id":"d","text":"موشورٌ قاعدتُه مثلّث"}]'::jsonb, 'b', 'الموشورُ القائم قاعدتُه مضلّعٌ (أضلاعٌ مستقيمة)؛ متوازي المستطيلات والمكعّبُ والموشورُ المثلّثيُّ القاعدة كلُّها موشوراتٌ قائمة. أمّا الأسطوانةُ فقاعدتُها دائرةٌ منحنية، فهي ليست موشورًا.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
