  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('cad40dec-950b-546e-8809-e64066cb1038', 'a1a9e43d-8eae-5956-b34b-c96a5df75cb3', 'أسطوانةٌ نصفُ قطر قاعدتها 6 سم. ما طولُ مستطيل بترونها (أي محيطُ القاعدة)، إذا كان π ≈ 3,14؟', '[{"id":"a","text":"12 سم"},{"id":"b","text":"18,84 سم"},{"id":"c","text":"37,68 سم"},{"id":"d","text":"75,36 سم"}]'::jsonb, 'c', 'طولُ مستطيل البترون = محيطُ الدائرة = 2πr = 2 × 3,14 × 6 = 37,68 سم. الخطأُ الشائع: نسيانُ مضاعفة π×r يعطي 18,84، أو الاكتفاءُ بالقطر (2r=12) دون احتساب π، أو مضاعفةُ الجداء الصحيح خطأً يعطي 75,36.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
