INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7f473e08-3194-5391-836b-164c78624a88', 'a1a9e43d-8eae-5956-b34b-c96a5df75cb3', 'علبةُ هديّةٍ على شكل موشورٍ قائم، محيطُ قاعدتها 40 سم وارتفاعُها 15 سم. ما مساحةُ الورق اللاّزم لتغليف سطحها الجانبيّ فقط؟', '[{"id":"a","text":"25 سم²"},{"id":"b","text":"55 سم²"},{"id":"c","text":"300 سم²"},{"id":"d","text":"600 سم²"}]'::jsonb, 'd', 'المساحةُ الجانبيّةُ = محيطُ القاعدة × الارتفاع = 40 × 15 = 600 سم². الخطأُ الشائع: جمعُ العددَين بدل ضربهما يعطي 55، أو طرحُهما يعطي 25، أو أخذُ نصف الجداء يعطي 300.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('135057e9-fa42-509d-bf12-d0f28f2a15e2', 'a1a9e43d-8eae-5956-b34b-c96a5df75cb3', 'قارورةٌ أسطوانيّةُ الشكل نصفُ قطرها 3 سم وارتفاعُها 20 سم (π ≈ 3,14). ما حجمُها التقريبيّ (بالسنتيمتر المكعّب)؟

<svg viewBox="0 0 200 150">
<title>أسطوانة</title>
<line x1="60" y1="34" x2="60" y2="122" stroke="#0f172a" stroke-width="2"/>
<line x1="140" y1="34" x2="140" y2="122" stroke="#0f172a" stroke-width="2"/>
<ellipse cx="100" cy="122" rx="40" ry="12" fill="none" stroke="#0f172a" stroke-width="2"/>
<ellipse cx="100" cy="34" rx="40" ry="12" fill="none" stroke="#0f172a" stroke-width="2"/>
<line x1="100" y1="34" x2="140" y2="34" stroke="#2563eb" stroke-width="1.6"/>
<circle cx="100" cy="34" r="1.8" fill="#0f172a"/>
<line x1="150" y1="34" x2="150" y2="122" stroke="#0f6e56" stroke-width="1.4"/>
<g font-weight="700" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round"><text x="120" y="29" text-anchor="middle" fill="#2563eb" font-size="11">r = 3</text><text x="154" y="82" text-anchor="start" fill="#0f6e56" font-size="11">h = 20</text></g>
</svg>', '[{"id":"a","text":"180 سم³"},{"id":"b","text":"188,4 سم³"},{"id":"c","text":"565,2 سم³"},{"id":"d","text":"2 260,8 سم³"}]'::jsonb, 'c', 'الحجمُ = π × r² × h = 3,14 × 3² × 20 = 3,14 × 9 × 20 = 565,2 سم³. الخطأُ الشائع: نسيانُ تربيع نصف القطر يعطي 3,14×3×20=188,4، أو نسيانُ π كليًّا يعطي 9×20=180، أو استعمالُ القطر (6 سم) مكانَ نصف القطر يعطي 2 260,8.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3723ebae-90d0-5715-8edd-b9a629bb01bb', 'a1a9e43d-8eae-5956-b34b-c96a5df75cb3', 'أسطوانةٌ نصفُ قطرها 2 سم وارتفاعُها 5 سم (π ≈ 3,14). ما حجمُها؟', '[{"id":"a","text":"15,7 سم³"},{"id":"b","text":"20 سم³"},{"id":"c","text":"31,4 سم³"},{"id":"d","text":"62,8 سم³"}]'::jsonb, 'd', 'الحجمُ = π × r² × h = 3,14 × 2² × 5 = 3,14 × 4 × 5 = 62,8 سم³. الخطأُ الشائع: نسيانُ نصف القطر كليًّا والاكتفاءُ بـ π×الارتفاع (3,14×5=15,7)، أو نسيانُ π فقط (2²×5=20)، أو نسيانُ تربيع نصف القطر (3,14×2×5=31,4).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
