INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7d916cb0-43d7-5674-8e85-4798a00ab513', '1e547a30-164a-5063-b984-d3649d57515e', 'موشورٌ قائمٌ قاعدتُه مستطيلٌ طولُه x سم وعرضُه 6 سم، ومساحةُ هذه القاعدة 48 سم². عُلم أنّ حجمَ الموشور 720 سم³. ما ارتفاعُ الموشور؟', '[{"id":"a","text":"6 سم"},{"id":"b","text":"8 سم"},{"id":"c","text":"15 سم"},{"id":"d","text":"60 سم"}]'::jsonb, 'c', 'أوّلًا نستنتج x من مساحة القاعدة: x × 6 = 48 ⟹ x = 48 ÷ 6 = 8 سم (وهذا طولُ القاعدة، وليس المطلوب). ثمّ نستعمل صيغةَ الحجم: الحجمُ = مساحةُ القاعدة × الارتفاع، إذن الارتفاعُ = 720 ÷ 48 = 15 سم. التحقّق: 48 × 15 = 720 ✓. الخطأُ الشائع: التوقّفُ عند القيمة الوسيطة x=8 دون إتمام السلسلة، أو الخلطُ مع عرض القاعدة المعطى (6)، أو خطأٌ حسابيٌّ في القسمة (720÷12=60).', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('dee612a9-e641-5d89-88e7-bdd9a047f385', '1e547a30-164a-5063-b984-d3649d57515e', 'موشورٌ قائمٌ قاعدتُه مستطيلٌ عرضُه 5 سم وطولُه x سم. عُلم أنّ محيطَ هذه القاعدة يحقّق المعادلة 2(x + 5) = 26. إذا كان ارتفاعُ الموشور 10 سم، فما حجمُه؟', '[{"id":"a","text":"8 سم³"},{"id":"b","text":"13 سم³"},{"id":"c","text":"40 سم³"},{"id":"d","text":"400 سم³"}]'::jsonb, 'd', 'نحلّ المعادلة أوّلًا: 2(x + 5) = 26 ⟹ x + 5 = 13 ⟹ x = 8 سم (عرضُ... طولُ القاعدة). مساحةُ القاعدة = x × 5 = 8 × 5 = 40 سم². الحجمُ = مساحةُ القاعدة × الارتفاع = 40 × 10 = 400 سم³. الخطأُ الشائع: التوقّفُ عند قيمة x (8)، أو عند x+5 (13)، أو عند مساحة القاعدة (40) دون إتمام حساب الحجم المطلوب.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7290307c-e82c-5525-a839-97b45045d41b', '1e547a30-164a-5063-b984-d3649d57515e', 'خزّانُ ماءٍ أسطوانيُّ الشكل نصفُ قطره 5 أمتار وارتفاعُه 8 أمتار (π ≈ 3,14). امتلأ الخزّانُ بالكامل بالماء، ثمّ استُهلك ربعُ كمّيّة الماء. كم مترًا مكعّبًا من الماء استُهلك؟', '[{"id":"a","text":"157 م³"},{"id":"b","text":"314 م³"},{"id":"c","text":"471 م³"},{"id":"d","text":"628 م³"}]'::jsonb, 'a', 'الحجمُ الكلّي = π × r² × h = 3,14 × 5² × 8 = 3,14 × 25 × 8 = 628 م³. الكمّيّةُ المستهلكة = ربعُ 628 = 628 ÷ 4 = 157 م³. الخطأُ الشائع: حسابُ نصف الكمّية بدل ربعها يعطي 314، أو الإجابةُ بالكمّية المتبقّية (3/4 من الحجم = 471) بدل المستهلكة، أو نسيانُ الاستهلاكَ كليًّا وإعطاءُ السعة الكاملة (628).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('8a57d4e7-f7de-57fd-ba5e-19c8b9f8903e', '1e547a30-164a-5063-b984-d3649d57515e', 'حاول تلميذٌ حسابَ حجم موشورٍ قائم قاعدتُه مثلّثٌ قائمُ الزاوية ساقاه القائمتان 4 سم و10 سم، وارتفاعُ الموشور 12 سم، فكتب: «مساحةُ القاعدة = 4 × 10 = 40 سم²، ثمّ الحجمُ = 40 × 12 = 480 سم³». أين الخطأُ في حلّه؟', '[{"id":"a","text":"نسي القسمةَ على 2 عند حساب مساحة المثلّث؛ الحجمُ الصحيحُ 240 سم³"},{"id":"b","text":"لا يوجد خطأ، حلُّه صحيح"},{"id":"c","text":"أخطأ في الارتفاع فقط"},{"id":"d","text":"أخطأ لأنّ الحجم الصحيح هو 960 سم³"}]'::jsonb, 'a', 'مساحةُ مثلّثٍ قائم الزاوية ساقاه a وb هي (a × b) ÷ 2، فمساحةُ القاعدة هنا = (4 × 10) ÷ 2 = 20 سم² لا 40 سم². الحجمُ الصحيح = 20 × 12 = 240 سم³. خطأُ التلميذ هو نسيانُ القسمة على 2 عند حساب مساحة المثلّث، فحصل على ضعف المساحة الصحيحة ومن ثمّ ضعف الحجم الصحيح.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('75956a3c-f030-568a-988e-c5b4093dbf04', '1e547a30-164a-5063-b984-d3649d57515e', 'علبةٌ على شكل موشورٍ قائم قاعدتُها مربّعةٌ ضلعُها 5 سم، ومساحتُها الجانبيّة 100 سم². ما ارتفاعُ العلبة؟', '[{"id":"a","text":"4 سم"},{"id":"b","text":"5 سم"},{"id":"c","text":"20 سم"},{"id":"d","text":"500 سم"}]'::jsonb, 'b', 'محيطُ القاعدة المربّعة = 4 × 5 = 20 سم. الارتفاعُ = المساحةُ الجانبيّة ÷ محيطُ القاعدة = 100 ÷ 20 = 5 سم. التحقّق: 20 × 5 = 100 ✓. الخطأُ الشائع: القسمةُ على مربّع ضلع القاعدة بدل محيطها (100 ÷ 25 = 4)، أو كتابةُ محيط القاعدة نفسه كإجابة دون إتمام القسمة (20)، أو الضربُ بدل القسمة (100 × 5 = 500).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('9f0ad5ff-5661-5200-94d0-da73b9ef78b1', '1e547a30-164a-5063-b984-d3649d57515e', 'امتلأ خزّانٌ أسطوانيُّ الشكل نصفُ قطره 10 أمتار وارتفاعُه 6 أمتار بنسبة 80% من سعته الكلّية (π ≈ 3,14). كم مترًا مكعّبًا من الماء يوجد فيه؟', '[{"id":"a","text":"376,8 م³"},{"id":"b","text":"1 130,4 م³"},{"id":"c","text":"1 507,2 م³"},{"id":"d","text":"1 884 م³"}]'::jsonb, 'c', 'الحجمُ الكلّي للخزّان = π × r² × h = 3,14 × 10² × 6 = 3,14 × 100 × 6 = 1 884 م³. الكمّيّةُ الموجودة = 80% من 1 884 = (80 ÷ 100) × 1 884 = 1 507,2 م³. الخطأُ الشائع: حسابُ الجزء الناقص (20%) بدل الجزء الموجود يعطي 376,8، أو استعمالُ 60% خطأً بدل 80% يعطي 1 130,4، أو نسيانُ النسبة المئويّة كليًّا وإعطاءُ السعة الكاملة (1 884).', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

