INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ea4f4964-e2f1-5bd7-990c-35e4737029b9', '87c03569-a3cf-58c2-a407-5dbf920c947d', 'بترونُ موشورٍ قائم قاعدتُه مربّعٌ ضلعُه 4 سم يتكوّن من مربّعَين (القاعدتان) وأربعة مستطيلاتٍ جانبيّة. إذا كان ارتفاعُ الموشور 9 سم، فما أبعادُ كلّ مستطيلٍ جانبيّ؟', '[{"id":"a","text":"4 سم × 9 سم"},{"id":"b","text":"9 سم × 9 سم"},{"id":"c","text":"4 سم × 4 سم"},{"id":"d","text":"16 سم × 9 سم"}]'::jsonb, 'a', 'كلُّ وجهٍ جانبيّ في الموشور القائم مستطيلٌ عرضُه ضلعُ القاعدة (4 سم) وطولُه ارتفاعُ الموشور (9 سم)، فأبعادُه 4 سم × 9 سم. الخطأُ الشائع: الخلطُ بين ضلع المربّع (4) ومحيطه (16)، أو استعمالُ الارتفاع في البُعدَين معًا (9×9).', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
