  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('42beb35a-63d6-51db-ad38-a35ed7102e15', '87c03569-a3cf-58c2-a407-5dbf920c947d', 'أسطوانةٌ نصفُ قطرها 3 سم وارتفاعُها 7 سم (π ≈ 3,14). ما أبعادُ المستطيل في بترونها؟', '[{"id":"a","text":"3 سم × 7 سم"},{"id":"b","text":"6 سم × 7 سم"},{"id":"c","text":"18,84 سم × 7 سم"},{"id":"d","text":"9,42 سم × 7 سم"}]'::jsonb, 'c', 'طولُ المستطيل = محيطُ القاعدة = 2πr = 2×3,14×3 = 18,84 سم، وعرضُه = الارتفاع = 7 سم. الخطأُ الشائع: استعمالُ نصف القطر مباشرةً (3) أو القطر (6) بدل المحيط، أو نسيانُ مضاعفة π×r فيُعطى πr=9,42.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('009c840b-5014-5bdb-986a-680e7e77741c', '87c03569-a3cf-58c2-a407-5dbf920c947d', 'صندوقُ كتبٍ على شكل متوازي مستطيلات طولُه 8 سم وعرضُه 5 سم وارتفاعُه 6 سم. ما مساحتُه الجانبيّة؟

<svg viewBox="0 0 200 150">
<title>متوازي مستطيلات</title>
<rect x="40" y="60" width="90" height="60" fill="none" stroke="#0f172a" stroke-width="2"/>
<line x1="130" y1="60" x2="164" y2="36" stroke="#0f172a" stroke-width="2"/>
<line x1="130" y1="120" x2="164" y2="96" stroke="#0f172a" stroke-width="2"/>
<line x1="40" y1="60" x2="74" y2="36" stroke="#0f172a" stroke-width="2"/>
