INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('64239451-da80-5887-9903-7939b77f7ca5', '87c03569-a3cf-58c2-a407-5dbf920c947d', 'صومعةُ حبوبٍ أسطوانيّةُ الشكل نصفُ قطرها 6 أمتار وارتفاعُها 15 مترًا (π ≈ 3,14). ما حجمُها (بالمتر المكعّب)؟', '[{"id":"a","text":"282,6 م³"},{"id":"b","text":"540 م³"},{"id":"c","text":"847,8 م³"},{"id":"d","text":"1 695,6 م³"}]'::jsonb, 'd', 'الحجمُ = π×r²×h = 3,14×6²×15 = 3,14×36×15 = 1 695,6 م³. الخطأُ الشائع: نسيانُ تربيع نصف القطر (3,14×6×15=282,6)، أو نسيانُ π كليًّا (36×15=540)، أو أخذُ نصف الحجم الصحيح خطأً (847,8).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('dc7214e1-d3fa-53a5-a8ad-e566d8e28d75', '87c03569-a3cf-58c2-a407-5dbf920c947d', 'موشورٌ قائمٌ ارتفاعُه 9 سم وحجمُه 198 سم³. ما مساحةُ قاعدته؟', '[{"id":"a","text":"22 سم²"},{"id":"b","text":"189 سم²"},{"id":"c","text":"207 سم²"},{"id":"d","text":"1 782 سم²"}]'::jsonb, 'a', 'مساحةُ القاعدة = الحجم ÷ الارتفاع = 198 ÷ 9 = 22 سم². التحقّق: 22 × 9 = 198 ✓. الخطأُ الشائع: طرحُ الارتفاع من الحجم بدل القسمة عليه يعطي 189، أو جمعُهما يعطي 207، أو ضربُهما بدل القسمة يعطي 1 782.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('f48d41af-143b-59c0-adc0-4c537f09de15', '87c03569-a3cf-58c2-a407-5dbf920c947d', 'لموشورٍ قائم محيطُ قاعدته 30 سم وارتفاعُه 12 سم، ولأسطوانةٍ محيطُ قاعدتها أيضًا 30 سم ونفسُ الارتفاع 12 سم. ماذا يمكن أن نستنتج بخصوص مساحتَيهما الجانبيّتَين؟', '[{"id":"a","text":"مساحةُ الأسطوانة أكبر لأنّ قاعدتها دائرة"},{"id":"b","text":"مساحتُهما الجانبيّتان متساويتان، كلٌّ منهما 360 سم²"},{"id":"c","text":"مساحةُ الموشور أكبر لأنّ له وجوهًا مسطّحة"},{"id":"d","text":"لا يمكن معرفةُ ذلك بلا معرفة شكل القاعدة"}]'::jsonb, 'b', 'صيغةُ المساحة الجانبيّة (محيطُ القاعدة × الارتفاع) واحدةٌ للموشور والأسطوانة معًا، ولا تعتمد على شكل القاعدة بل على محيطها فقط. بما أنّ المحيطَين متساويان (30 سم) والارتفاعَين متساويان (12 سم)، فالمساحتان الجانبيّتان متساويتان: 30 × 12 = 360 سم² لكلٍّ منهما.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

