  ('eeff44fc-749e-57b8-82a2-7b3c57168209', 'b6e48e13-6a0c-5a7d-949e-49a6d5fbb564', 'math-7eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قمّةُ برنامج السنة السابعة', 4, 300, 60, 'challenge', 'admin', 6)
