INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b3a7f39e-61f9-5f3d-8b0a-e9a7ec6d43db', 'eeff44fc-749e-57b8-82a2-7b3c57168209', 'امتلأ خزّانٌ أسطوانيُّ الشكل نصفُ قطره 5 أمتار وارتفاعُه 8 أمتار (π ≈ 3,14) على مدى 3 أيّام حتّى امتلأ بالكامل: في اليوم الأوّل دخل x م³ من الماء، وفي اليوم الثاني ضِعفُ كمّية اليوم الأوّل، وفي اليوم الثالث 52 م³ إضافيّة. ما قيمةُ x (كمّيّةُ اليوم الأوّل)؟', '[{"id":"a","text":"96 م³"},{"id":"b","text":"192 م³"},{"id":"c","text":"576 م³"},{"id":"d","text":"628 م³"}]'::jsonb, 'b', 'الحجمُ الكلّي للخزّان = π×r²×h = 3,14×5²×8 = 3,14×25×8 = 628 م³. نكوّن المعادلة: x + 2x + 52 = 628 ⟹ 3x + 52 = 628 ⟹ 3x = 628 − 52 = 576 ⟹ x = 576 ÷ 3 = 192 م³. التحقّق: 192 + 384 + 52 = 628 ✓. الخطأُ الشائع: التوقّفُ عند القيمة الوسيطة 3x=576 دون القسمة على 3، أو الخلطُ مع الحجم الكلّي (628)، أو القسمةُ على عددٍ خاطئ (576÷6=96).', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('622228d7-42b9-5ced-9b66-3ce57ff3926a', 'eeff44fc-749e-57b8-82a2-7b3c57168209', 'موشورٌ قائمٌ قاعدتُه مثلّثٌ قائمُ الزاوية، إحدى ساقَيه 8 سم والأخرى تساوي ثلاثةَ أرباع الأولى. إذا كان حجمُ الموشور 288 سم³، فما ارتفاعُه؟', '[{"id":"a","text":"6 سم"},{"id":"b","text":"12 سم"},{"id":"c","text":"24 سم"},{"id":"d","text":"264 سم"}]'::jsonb, 'b', 'الساقُ الثانيةُ = (3/4) × 8 = 6 سم. مساحةُ القاعدة (مثلّثٌ قائمُ الزاوية) = (8 × 6) ÷ 2 = 24 سم². الارتفاعُ = الحجم ÷ مساحة القاعدة = 288 ÷ 24 = 12 سم. التحقّق: 24 × 12 = 288 ✓. الخطأُ الشائع: التوقّفُ عند طول الساق الثانية (6) أو عند مساحة القاعدة (24) دون إتمام حساب الارتفاع، أو طرحُ مساحة القاعدة من الحجم بدل القسمة عليها (288−24=264).', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b0e75bfc-5194-58a8-b4c8-4cb346410fe5', 'eeff44fc-749e-57b8-82a2-7b3c57168209', 'أربعةُ تلاميذ حسبوا حجمَ أسطوانةٍ نصفُ قطرها 4 سم وارتفاعُها 5 سم (π ≈ 3,14): كريمٌ وجد 62,8 سم³، سامي وجد 125,6 سم³، ريمُ وجدت 251,2 سم³، وهالةُ وجدت 20 سم³. أيُّهم أصاب؟', '[{"id":"a","text":"كريم"},{"id":"b","text":"سامي"},{"id":"c","text":"ريم"},{"id":"d","text":"هالة"}]'::jsonb, 'c', 'الحجمُ الصحيح = π×r²×h = 3,14×4²×5 = 3,14×16×5 = 251,2 سم³، وهو ما وجدته ريم. كريمٌ نسي تربيعَ نصف القطر (3,14×4×5=62,8)، وسامي أخذ نصف الحجم الصحيح خطأً (125,6)، وهالةُ نسيت π والتربيعَ معًا (4×5=20).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d63aa2d8-3283-56df-a91d-13b936dc23c5', 'eeff44fc-749e-57b8-82a2-7b3c57168209', 'لموشورَين قائمَين قاعدتاهما مختلفتا الشكل لكنّ مساحتَيهما متساويتان (كلٌّ منهما 30 سم²)، وارتفاعاهما متساويان أيضًا (7 سم). ماذا يمكن أن نستنتج عن حجمَيهما؟', '[{"id":"a","text":"حجمُ الموشور ذي القاعدة الأكبر عددًا من الأضلاع أكبر"},{"id":"b","text":"لا يمكن مقارنةُ حجمَيهما بلا معرفة شكل القاعدة بالتحديد"},{"id":"c","text":"حجماهما مختلفان حتمًا لاختلاف شكل القاعدة"},{"id":"d","text":"حجماهما متساويان، كلٌّ منهما 210 سم³"}]'::jsonb, 'd', 'الحجمُ = مساحةُ القاعدة × الارتفاع، ولا يعتمد على شكل القاعدة بل على مساحتها فقط. بما أنّ مساحتَي القاعدتين متساويتان (30 سم²) والارتفاعَين متساويان (7 سم)، فحجماهما متساويان: 30×7=210 سم³ لكلٍّ منهما، مهما اختلف شكلُ القاعدة (مثلّثًا كان أو مربّعًا أو غير ذلك).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('371dca1e-50ed-5633-8916-8784af0676fc', 'eeff44fc-749e-57b8-82a2-7b3c57168209', 'خزّانان: الأوّلُ أسطوانيُّ الشكل نصفُ قطره 5 أمتار وارتفاعُه 4 أمتار، والثاني على شكل متوازي مستطيلات طولُه 10 أمتار وعرضُه 8 أمتار وارتفاعُه 4 أمتار (π ≈ 3,14). كم بالمائة تمثّل سعةُ الخزّان الأسطوانيّ من سعة الخزّان الثاني؟ (قرّب النتيجةَ إلى أقرب عدد صحيح)', '[{"id":"a","text":"98%"},{"id":"b","text":"99%"},{"id":"c","text":"100%"},{"id":"d","text":"102%"}]'::jsonb, 'a', 'سعةُ الخزّان الأسطوانيّ = π×r²×h = 3,14×5²×4 = 3,14×25×4 = 314 م³. سعةُ الخزّان الثاني = 10×8×4 = 320 م³. النسبةُ = (314 ÷ 320) × 100 ≈ 98,1%، أي 98% بالتقريب. الخطأُ الشائع: تقريبٌ في الاتّجاه الخاطئ يعطي 99% أو الظنُّ بأنّ السعتَين متساويتان (100%)، أو حسابُ النسبة العكسيّة (320 ÷ 314 × 100 ≈ 102%) بدل النسبة المطلوبة.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ea06ef94-b478-5e6a-8cc0-cb518a73c759', 'eeff44fc-749e-57b8-82a2-7b3c57168209', 'أراد فلاحٌ بناء خزّان ماءٍ أسطوانيّ الشكل نصفُ قطره 10 أمتار وحجمِه 942 م³ (π ≈ 3,14). بعد استعماله، احتاج الفلاحُ زيادةَ السعة بنسبة 20% ببناء خزّانٍ ثانٍ بجانبه بنفس نصف القطر. ما ارتفاعُ الخزّان الأوّل (الأصليّ) الذي بناه أوّلًا؟', '[{"id":"a","text":"3 أمتار"},{"id":"b","text":"3,6 أمتار"},{"id":"c","text":"314 مترًا"},{"id":"d","text":"1 130,4 مترًا"}]'::jsonb, 'a', 'مساحةُ قاعدة الخزّان = π×r² = 3,14×10² = 3,14×100 = 314 م². الارتفاعُ الأصليّ = الحجم ÷ مساحة القاعدة = 942 ÷ 314 = 3 أمتار (وهذا هو المطلوب؛ الزيادةُ بنسبة 20% تخصّ خزّانًا ثانيًا منفصلًا ولا تُغيّر ارتفاعَ الخزّان الأوّل). الخطأُ الشائع: تطبيقُ الزيادة 20% على الارتفاع نفسِه خطأً (3×1,2=3,6)، أو الإجابةُ بمساحة القاعدة دون إتمام القسمة (314)، أو الإجابةُ بحجم الخزّان الثاني المطلوب (942×1,2=1 130,4) بدل ارتفاع الخزّان الأوّل المطلوب.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

-- Converge question → competency mappings for this subject (étude 07 D-2).
DO $$
BEGIN
  IF to_regclass('public.question_competencies') IS NOT NULL THEN
    DELETE FROM public.question_competencies qc
    USING public.questions q, public.exercises e
    WHERE qc.question_id = q.id
      AND q.exercise_id = e.id
      AND e.subject_id = 'math-7eme'
      AND e.source = 'admin';
  END IF;
END $$;

